-- Poems batch 158
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a14926e2-6007-45f3-be6e-1ef0d0040c04','吳江道中  其二','楊冠卿','宋','宋诗','song-poetry','','[]','壞郭郊丘裏，長橋煙浪間。',48,'全唐诗/poet.song.159000.json','["壞郭郊丘裏，長橋煙浪間。", "幽花經雨潤，獨鳥受風還。", "春水圍叢薄，晴雲吐亂山。", "莫將吳越恨，添入二毛斑。"]'),
('3990546f-397e-41f9-af42-4f1c0942728a','即事  其一','楊冠卿','宋','宋诗','song-poetry','','[]','歡悰憑淺酌，衰相怯單衣。',48,'全唐诗/poet.song.159000.json','["歡悰憑淺酌，衰相怯單衣。", "詩向貧中好，春從雨際歸。", "氣寒憂麥瘦，桑濕恐蠶饑。", "豫學田園計，他時恐願違。"]'),
('d25acfd2-8d74-4f26-9d6c-c66e29f11157','即事  其二','楊冠卿','宋','宋诗','song-poetry','','[]','人事悲懽裏，交情冷暖中。',48,'全唐诗/poet.song.159000.json','["人事悲懽裏，交情冷暖中。", "山林催晚計，顔面久秋風。", "有傳記耆舊，無書問子公。", "反關違世久，幽事亦怱怱。"]'),
('aad16209-a24e-44e9-a74a-ed99c51e7721','句','蕭固','宋','宋诗','song-poetry','','[]','風變尉佗國，聲歡舜帝民。',12,'全唐诗/poet.song.16000.json','["風變尉佗國，聲歡舜帝民。"]'),
('a13baa16-63b0-4abe-8dc9-9dd426a97b2c','送梵才上人歸天台  其一','皇甫泌','宋','宋诗','song-poetry','','[]','昔在童蒙歲，學禮暨詩書。',168,'全唐诗/poet.song.16000.json','["昔在童蒙歲，學禮暨詩書。", "肅肅秉庭訓，罔敢甯斯須。", "積習將一紀，心目多勤劬。", "本此修拙辭，階之登仕途。", "得以施所學，聞者謂之迂。", "吾道固未行，或嗤爲腐儒。", "腐誠如所云，儒非吾敢居。", "時英賤民政，亦誚官之麄。", "嘉言屢詒勗，周旋畫偉謨。", "胡不事章句，清貴無加于。", "我聞今學者，爲人不自圖。", "六朝文物壅，化源由是枯。", "華文媿不能，迷深甘守株。", "古人不得見，臨風重欷歔。"]'),
('fa55d9e8-0b29-4a42-90b5-d933d6ee64c0','送梵才上人歸天台  其二','皇甫泌','宋','宋诗','song-poetry','','[]','美玉不自貴，貴之者良工。',144,'全唐诗/poet.song.16000.json','["美玉不自貴，貴之者良工。", "高才不自明，明之者至公。", "和璞文未刻，他山石正同。", "子虛賦未行，相如車不東。", "我今徵此詞，亦將擬未通。", "粵有空門子，孕秀赤城中。", "性靜不欲俗，詩癖俄在躬。", "意淳自高古，言雅思變風。", "勞勞不稱年，名尚高遠聰。", "我來山月鄉，即貌知困蒙。", "吾師道雖否，天子方文崇。", "一旦因得意，誦之于六宮。"]'),
('5685f317-9475-47b9-908c-40c34645f9ca','飛霞洞','曹觀','宋','宋诗','song-poetry','','[]','巖前春草萋萋色，巖上春風淡淡陰。',32,'全唐诗/poet.song.16000.json','["巖前春草萋萋色，巖上春風淡淡陰。", "數百年來無謝客，□□依舊到如今。"]'),
('2dc175e0-4d58-45bd-9441-f1de7e64ea97','向來','趙師民','宋','宋诗','song-poetry','','[]','向來情思已陳陳，旅思無端不及春。',32,'全唐诗/poet.song.16000.json','["向來情思已陳陳，旅思無端不及春。", "潘子形容傷白髮，沈郎文字暗丹唇。"]'),
('85ab5ff2-dfd1-4c5a-8242-9e8ebb450766','句  其一','趙師民','宋','宋诗','song-poetry','','[]','露臺枉惜千金費，却把銅山錫幸臣。',16,'全唐诗/poet.song.16000.json','["露臺枉惜千金費，却把銅山錫幸臣。"]'),
('e73eac26-36a6-47cf-b1b1-26ebed03cd50','句  其二','趙師民','宋','宋诗','song-poetry','','[]','菱天晨氣潤，槐夏午風清。',12,'全唐诗/poet.song.16000.json','["菱天晨氣潤，槐夏午風清。"]'),
('5a7c15ea-d848-433d-9d4e-96300badc95a','句  其三','趙師民','宋','宋诗','song-poetry','','[]','委地露花啼曉恨，拂提煙柳弄春容。',16,'全唐诗/poet.song.16000.json','["委地露花啼曉恨，拂提煙柳弄春容。"]'),
('e862d7b3-46a6-488b-a158-33e207d2fc1f','句  其四','趙師民','宋','宋诗','song-poetry','','[]','霜女遺靈長著素，玉妃餘恨結成酸。',16,'全唐诗/poet.song.16000.json','["霜女遺靈長著素，玉妃餘恨結成酸。"]'),
('b79cc8b2-93bf-4d53-9913-c2a831ab3ac2','寄甘露舒公上人','雷簡夫','宋','宋诗','song-poetry','','[]','成都多少寺，梵學競推能。',48,'全唐诗/poet.song.16000.json','["成都多少寺，梵學競推能。", "到老不破戒，滿城唯此僧。", "池龍聽夜講，海客施年燈。", "別後空相憶，塵勞正可憎。"]'),
('db696e3f-e802-4119-aea2-6bde8a63338a','襄州太守王侯復峴山羊公祠','李康伯','宋','宋诗','song-poetry','','[]','賢哉西晉鉅平侯，刻碑立祠在荆州。',128,'全唐诗/poet.song.16000.json','["賢哉西晉鉅平侯，刻碑立祠在荆州。", "州民萬家見之者，揜面汍瀾雙淚下。", "逮今緜歷幾百祀，峴首巍然臨漢水。", "碑鈋祠廢榛莽中，蕭蕭只有悲風起。", "內閣深沈侍從臣，赤帷皁蓋來行春。", "殷勤拂碑復祠貌，一朝舊迹重如新。", "山光葱蒨水清冽，天長地久無時別。", "古人今人空茫茫，惟是功名不能滅。"]'),
('be4e6bda-f651-4354-96d7-e154d8fd5d9f','題張公洞','王繹','宋','宋诗','song-poetry','','[]','高上宸居隔紫煙，洞中金闕暗相連。',64,'全唐诗/poet.song.16000.json','["高上宸居隔紫煙，洞中金闕暗相連。", "輔光竈冷留香壤，太素淵清湧玉泉。", "後夜龍歸雲浪濕，未明人起月華鮮。", "秋光不老巖前麓，到此偷閒亦自賢。"]'),
('e90c8ad8-ef46-4ccd-bcd2-501ab7de7cd1','句  其一','王繹','宋','宋诗','song-poetry','','[]','直自牧之懷古後，適當慧遠送圖來。',16,'全唐诗/poet.song.16000.json','["直自牧之懷古後，適當慧遠送圖來。"]'),
('456d6301-ac76-4b29-a14e-3ca37f50d6d9','句  其二','王繹','宋','宋诗','song-poetry','','[]','荔陳貢篚清香馥，峯倚三山秘篆奇。',16,'全唐诗/poet.song.16000.json','["荔陳貢篚清香馥，峯倚三山秘篆奇。"]'),
('d8d77d15-f4b1-4080-b76c-1b3829cd6c11','懷天台隠士','王堯臣','宋','宋诗','song-poetry','','[]','先生高蹈晦巖扉，沐髮晞陽遠帝暉。',64,'全唐诗/poet.song.16000.json','["先生高蹈晦巖扉，沐髮晞陽遠帝暉。", "自是鸞皇終瑞世，莫同魚鳥便忘機。", "江鳬汎汎隨波遠，朔雁冥冥避弋歸。", "他日彤庭如應聘，夢魂休繞故山薇。"]'),
('c483d5fe-c1f5-466a-9c4f-859a7c0f444a','頌二首  其一','釋慧南','宋','宋诗','song-poetry','','[]','傑出叢林是趙州，老婆勘破有來由。',32,'全唐诗/poet.song.16000.json','["傑出叢林是趙州，老婆勘破有來由。", "而今四海清如鏡，行人莫與路爲讎。"]'),
('bd0ef83c-597d-461a-b736-454a64071659','頌二首  其二','釋慧南','宋','宋诗','song-poetry','','[]','生緣斷處伸馿脚，馿脚伸時佛手開。',32,'全唐诗/poet.song.16000.json','["生緣斷處伸馿脚，馿脚伸時佛手開。", "爲報五湖參學者，三關一一透將來。"]'),
('90aecad8-99f0-47e0-b618-c7b6053af001','偈二首  其一','釋慧南','宋','宋诗','song-poetry','','[]','心王不妄動，六國一時通。',24,'全唐诗/poet.song.16000.json','["心王不妄動，六國一時通。", "罷拈三尺劒，休弄一張弓。"]'),
('a33c637b-7c96-4006-b853-f2e222329f03','偈二首  其二','釋慧南','宋','宋诗','song-poetry','','[]','得不得，傳不得，歸根得旨復何言。',32,'全唐诗/poet.song.16000.json','["得不得，傳不得，歸根得旨復何言。", "憶得首山曾漏泄，新婦騎馿阿家牽。"]'),
('977de85c-d492-43f6-82b9-3ee76a65a340','招桐柏李道士','葛閎','宋','宋诗','song-poetry','','[]','海嶺重重接紫虛，高人還肯敞仙裾。',32,'全唐诗/poet.song.16000.json','["海嶺重重接紫虛，高人還肯敞仙裾。", "玉蟾點滴有清露，少費研朱寫道書。"]'),
('fe17d268-7332-43fc-9daa-e4eb8e1cd9c2','巾山廣軒','葛閎','宋','宋诗','song-poetry','','[]','勝地藏東越，嚴城聳二岑。',48,'全唐诗/poet.song.16000.json','["勝地藏東越，嚴城聳二岑。", "萬燈迎日早，孤磬出雲深。", "雪霽茗初試，雨涵山半陰。", "茲焉即方廣，有路到天心。"]'),
('a19a0d63-f227-4244-8d88-84bc015c83ea','遊白雲軒贈沖一道正','葛閎','宋','宋诗','song-poetry','','[]','無事之時無事身，天將沖淡養吾真。',32,'全唐诗/poet.song.16000.json','["無事之時無事身，天將沖淡養吾真。", "鴟鳶啄腐成滋味，豈識朝霞吐嚥人。"]'),
('1cc7f688-099f-40e3-a913-3c39f4ab7feb','題白雲環翠亭','葛閎','宋','宋诗','song-poetry','','[]','六月好風吹玉林，地浮鼇海越山深。',32,'全唐诗/poet.song.16000.json','["六月好風吹玉林，地浮鼇海越山深。", "愛師終日無餘事，一點塵埃不受侵。"]'),
('626a3641-bad0-4f83-a0e6-9e86b8a5ee4e','題清輝堂','葛閎','宋','宋诗','song-poetry','','[]','歸老雲邊一翠岑，靜中觀動照人心。',32,'全唐诗/poet.song.16000.json','["歸老雲邊一翠岑，靜中觀動照人心。", "溪湖北上又東去，不似青山無古今。"]'),
('75b02270-e649-4cb3-b3d7-6a2e372a2843','羅漢閣煎茶應供','葛閎','宋','宋诗','song-poetry','','[]','山泉飛出白雲寒，來獻靈芽秉燭看。',32,'全唐诗/poet.song.16000.json','["山泉飛出白雲寒，來獻靈芽秉燭看。", "俄頃有花過數百，三甌如吸玉腴乾。"]'),
('776c179b-b1f7-4725-93e8-5c589a0985bb','遊日山','葛閎','宋','宋诗','song-poetry','','[]','六時香火集宗雷，日上雲收紫翠開。',32,'全唐诗/poet.song.16000.json','["六時香火集宗雷，日上雲收紫翠開。", "應笑守麾公暇少，二年官滿一曾來。"]'),
('7faaa319-b3b8-4590-885b-3a6a46ecbef4','迎神','葛閎','宋','宋诗','song-poetry','','[]','符法千年人尚畏，神林三鼓酒盈杯。',32,'全唐诗/poet.song.16000.json','["符法千年人尚畏，神林三鼓酒盈杯。", "油囊爲取天河水，更折蟠桃海上來。"]'),
('74355959-eaac-4603-aa94-bc1f4bd42051','送神','葛閎','宋','宋诗','song-poetry','','[]','丹霞縹緲海三峯，歸去瓊臺第幾重。',32,'全唐诗/poet.song.16000.json','["丹霞縹緲海三峯，歸去瓊臺第幾重。", "仙驥一聲風馭遠，月明清露滴金松。"]'),
('a960e90b-2875-4b1b-ab09-2be4b4f076cf','桐柏崇道觀','葛閎','宋','宋诗','song-poetry','','[]','昔賢書洞石，臺有伯陽經。',48,'全唐诗/poet.song.16000.json','["昔賢書洞石，臺有伯陽經。", "碧海船多却，金霞夜不扃。", "爐成九轉藥，階布六符星。", "捷徑非君意，深游不死庭。"]'),
('4fcc8f3e-eb1e-45e6-ad83-01e3fed2c49f','桐柏觀','葛閎','宋','宋诗','song-poetry','','[]','桃花爛熳春溪暖，紫玉簫沉月樹昏。',32,'全唐诗/poet.song.16000.json','["桃花爛熳春溪暖，紫玉簫沉月樹昏。", "未覺臺中光景晚，人間歸去見來孫。"]'),
('747f371e-9532-4006-99f4-d71b125f5c89','存目  其一','葛閎','宋','宋诗','song-poetry','','[]','詩題：寄睦州朱少卿首句：何幸鄉枌託使麾。',20,'全唐诗/poet.song.16000.json','["詩題：寄睦州朱少卿首句：何幸鄉枌託使麾。"]'),
('fb3efaf9-822f-4246-b77e-3ce4e33d61b9','存目  其二','葛閎','宋','宋诗','song-poetry','','[]','詩題：經大洋吳氏別業首句：漸老故人少。',19,'全唐诗/poet.song.16000.json','["詩題：經大洋吳氏別業首句：漸老故人少。"]'),
