('6e354c89-b0ca-4700-a865-89b1dbf206df','存目  其七','葛閎','宋','宋诗','song-poetry','','[]','詩題：同孝叔游玉泉首句：石磴松陰一化成。',20,'全唐诗/poet.song.16000.json','["詩題：同孝叔游玉泉首句：石磴松陰一化成。"]'),
('6da92a2c-d9b2-44d4-ad2b-85fade418c6b','存目  其八','葛閎','宋','宋诗','song-poetry','','[]','詩題：初夏同孝叔游普光寺首句：魚跳蓮葉青錢小。',23,'全唐诗/poet.song.16000.json','["詩題：初夏同孝叔游普光寺首句：魚跳蓮葉青錢小。"]'),
('e4edf020-e8a5-4937-820e-607738bab016','存目  其九','葛閎','宋','宋诗','song-poetry','','[]','詩題：初夏同孝叔游朱氏園首句：凍醪廬橘助登臨。',23,'全唐诗/poet.song.16000.json','["詩題：初夏同孝叔游朱氏園首句：凍醪廬橘助登臨。"]'),
('1a5e6845-81a8-452c-a1bc-21c0fb4d8d92','存目  其一○','葛閎','宋','宋诗','song-poetry','','[]','詩題：留題千峯榭呈孝叔首句：君把玄英詩集披。',22,'全唐诗/poet.song.16000.json','["詩題：留題千峯榭呈孝叔首句：君把玄英詩集披。"]'),
('4c6ced42-8d79-447f-a882-ce66321e59d4','存目  其一一','葛閎','宋','宋诗','song-poetry','','[]','詩題：題新定郡齋寄孝叔二首首句：主人今向日邊歸，花意知君改外臺。',32,'全唐诗/poet.song.16000.json','["詩題：題新定郡齋寄孝叔二首首句：主人今向日邊歸，花意知君改外臺。"]'),
('04f7317d-1ef4-49ac-a6ef-678eccadad84','存目  其一二','葛閎','宋','宋诗','song-poetry','','[]','詩題：留題玉泉山堂首句：動非緣境靜非禪。',20,'全唐诗/poet.song.16000.json','["詩題：留題玉泉山堂首句：動非緣境靜非禪。"]'),
('92e28888-d627-4df8-9a66-c163c84ba2d0','存目  其一三','葛閎','宋','宋诗','song-poetry','','[]','詩題：題新定紅蕖閣首句：烟捲龍綃艷格林。',20,'全唐诗/poet.song.16000.json','["詩題：題新定紅蕖閣首句：烟捲龍綃艷格林。"]'),
('627f94bc-5f65-43e6-864d-54ebf3761aac','遺徐禧','釋倚遇','宋','宋诗','song-poetry','','[]','今年七十七，出行須擇日。',24,'全唐诗/poet.song.16000.json','["今年七十七，出行須擇日。", "昨夜問龜哥，報道明朝吉。"]'),
('d21c4490-2c9d-47ea-924a-7021e8353b5b','偈二首  其一','釋倚遇','宋','宋诗','song-poetry','','[]','春山青，春水綠，一覺南柯夢初足。',64,'全唐诗/poet.song.16000.json','["春山青，春水綠，一覺南柯夢初足。", "携筇縱步出松門，是處桃英香馥鬰。", "因思昔日靈雲老，三十年來無處討。", "如今競愛摘楊花，紅香滿地無人掃。"]'),
('a1131b87-673b-4bf9-bd62-269ba721f7fe','偈二首  其二','釋倚遇','宋','宋诗','song-poetry','','[]','法昌今日開爐，行脚僧無一個。',70,'全唐诗/poet.song.16000.json','["法昌今日開爐，行脚僧無一個。", "唯有十八高人，緘口圍爐打坐。", "不是規矩嚴難，免見諸人話墮。", "直饒口似秤鎚，未免燈籠勘破。", "不知道絕功勳，妄自修因證果。"]'),
('c941cad4-d2b2-4fdc-8823-d492a572f20b','偈','釋懷祥','宋','宋诗','song-poetry','','[]','南山高，北山低，日出東方夜落西。',32,'全唐诗/poet.song.16000.json','["南山高，北山低，日出東方夜落西。", "白牛上樹覓不得，烏雞入水大家知。"]'),
('6c56f20f-7a10-4c45-be83-ca50434e305d','偈','釋行德','宋','宋诗','song-poetry','','[]','新冬新寶壽，言是舊時言。',24,'全唐诗/poet.song.16000.json','["新冬新寶壽，言是舊時言。", "若會西來意，波斯上舶船。"]'),
('838424b2-ea09-4b9b-9984-316078077b40','偈三首  其一','釋本逸','宋','宋诗','song-poetry','','[]','開口是，合口是，眼下無妨更著鼻。',64,'全唐诗/poet.song.16000.json','["開口是，合口是，眼下無妨更著鼻。", "開口錯，合口錯，眼與鼻孔都拈却。", "佛也打，祖也打，真人面前不說假。", "佛也安，祖也安，衲僧肚皮似海寬。"]'),
('d28317ef-08b4-4e7f-9b2b-603d2eb086e3','偈三首  其二','釋本逸','宋','宋诗','song-poetry','','[]','寒原耕種罷，牽犢負薪歸。',24,'全唐诗/poet.song.16000.json','["寒原耕種罷，牽犢負薪歸。", "此夜一爐火，渾家身上衣。"]'),
('f5fdc458-c271-449b-9989-3ab8231a6ba4','偈三首  其三','釋本逸','宋','宋诗','song-poetry','','[]','菜園牆倒晴方築，房店籬穿雨過修。',32,'全唐诗/poet.song.16000.json','["菜園牆倒晴方築，房店籬穿雨過修。", "院宇漏時隨分整，兒孫大小盡風流。"]'),
('fbb7c173-4a03-4a3e-b555-bbe480f60a2b','句  其一','釋本逸','宋','宋诗','song-poetry','','[]','有時放步東湖上，與僧遥指遠山青。',16,'全唐诗/poet.song.16000.json','["有時放步東湖上，與僧遥指遠山青。"]'),
('4f6fad63-bba2-4c83-af72-713c6ddb9f34','句  其二','釋本逸','宋','宋诗','song-poetry','','[]','醫王不是無方義，千里蘇香象不回。',16,'全唐诗/poet.song.16000.json','["醫王不是無方義，千里蘇香象不回。"]'),
('138cdc89-69da-44e8-bbae-986f62b40e77','句  其三','釋本逸','宋','宋诗','song-poetry','','[]','罥鶴顛崖上，沖天昧米民。',12,'全唐诗/poet.song.16000.json','["罥鶴顛崖上，沖天昧米民。"]'),
('ecec768d-8809-45f8-a4b3-5476e9508ba4','偈','釋惟簡','宋','宋诗','song-poetry','','[]','莫離蓋纏，莫求佛祖。',40,'全唐诗/poet.song.16000.json','["莫離蓋纏，莫求佛祖。", "去此二圖，以何依怙。", "江淹夢筆，天龍見虎。", "古老相傳，月不跨五。"]'),
('012e8a25-cedf-493c-bbbd-bf8ccec03f9d','偈二首  其一','釋守道','宋','宋诗','song-poetry','','[]','日月遶須彌，人間分晝夜。',27,'全唐诗/poet.song.16000.json','["日月遶須彌，人間分晝夜。", "南閻浮提人，祇被明暗色空留礙。"]'),
('47884d23-508b-4918-b1ec-afeef9eaaf9f','偈二首  其二','釋守道','宋','宋诗','song-poetry','','[]','不從一地至一地，寂滅性中寧有位。',32,'全唐诗/poet.song.16000.json','["不從一地至一地，寂滅性中寧有位。", "釋迦稽首問然燈，仁者何名爲受記。"]'),
('b0f81653-a1ce-4ec6-bc44-3809bf3d19fd','句','釋守道','宋','宋诗','song-poetry','','[]','柳色黄金嫩，黎花白雪香。',12,'全唐诗/poet.song.16000.json','["柳色黄金嫩，黎花白雪香。"]'),
('30756bb9-0763-41f0-b4a5-8ad8796caa66','送鈐轄館使王公','田瑜','宋','宋诗','song-poetry','','[]','閫外膺宸寄，坤維握虎兵。',96,'全唐诗/poet.song.16000.json','["閫外膺宸寄，坤維握虎兵。", "真純逾璞玉，方重敵長城。", "肯構詩名著，承家將略明。", "四年凝茂績，一節促歸程。", "水際旌旗影，風前鼓吹聲。", "西州懷惠愛，北闕被恩榮。", "護衛親嚴近，雍容侍穆清。", "分携暫銷黯，良會在神京。"]'),
('298385f6-01ac-4386-bb23-1a40362949f8','送鈐轄館使王公','高惟幾','宋','宋诗','song-poetry','','[]','遊宦俱爲關外人，與君五看海棠春。',64,'全唐诗/poet.song.16000.json','["遊宦俱爲關外人，與君五看海棠春。", "園林選勝聯鑣徧，風月相思命駕頻。", "大斾先時辭蜀道，短轅何日見京塵。", "子牟又起離羣恨，欲操行祛重愴神。"]'),
('f351021e-13ab-45ad-9a6a-5d2ad448b870','海棠','高惟幾','宋','宋诗','song-poetry','','[]','故國庸岷外，孤根楚苑中。',48,'全唐诗/poet.song.16000.json','["故國庸岷外，孤根楚苑中。", "使梅休妬白，仙杏已饒紅。", "旋恐陽城破，尋憂下蔡空。", "幾時夢巫峽，獨立怨春風。"]'),
('a90d229e-2e22-4b2f-8915-1e387d112a6a','送鈐轄館使王公','解程','宋','宋诗','song-poetry','','[]','武帳推恩詔十行，雍容鳴玉覲清光。',63,'全唐诗/poet.song.16000.json','["武帳推恩詔十行，雍容鳴玉覲清光。", "四年愛日民謠浹，五月炎風驛路長。", "劍閣煙雲迷斾，柳營笳鼓慘離觴。", "浣花紙貴傳新集，留待詩名繼許昌。"]'),
('9eae1a7c-bc4f-492f-bbca-4a0fe14183ff','承原父以鳳凰篇爲况謹用來韻和酬','吳育','宋','宋诗','song-poetry','','[]','丹山鬰世表，巖巖千仞巔。',96,'全唐诗/poet.song.16000.json','["丹山鬰世表，巖巖千仞巔。", "自非常雛輩，安得參周旋。", "胡爲此弱羽，越簉祥儀鮮。", "飛鳴過所據，飆駭俄翻然。", "退則安棲地，翔風娛楚天。", "始病孰儔侶，乃與朱鸞攀。", "英英日相照，老翮徒愧前。", "少別正傾聽，覽輝當聖年。"]'),
('237f8f91-9138-4b48-9bba-418daa186dac','次韻奉和給事中','吳育','宋','宋诗','song-poetry','','[]','律上陽和雖始煦，罇前人意已生春。',64,'全唐诗/poet.song.16000.json','["律上陽和雖始煦，罇前人意已生春。", "濠梁且欲觀魚樂，淮郡何能致鹿馴。", "爲訪心朋猶縱棹，況逢時雋與均茵。", "別車豈必辭沉醉，更有高陽倒載人。"]'),
('4be68d73-7500-40cc-9110-cc62b29fae77','過郭店謁文靖公墓','吳育','宋','宋诗','song-poetry','','[]','漢相巖巖真國英，門庭曾是接諸生。',32,'全唐诗/poet.song.16000.json','["漢相巖巖真國英，門庭曾是接諸生。", "陽秋談論四時具，河嶽精神一座傾。"]'),
('f05a14ec-3c43-43e3-a653-fb10bda00de0','送梵才上人歸天台','吳育','宋','宋诗','song-poetry','','[]','幾年瓶鉢帝城棲，看盡塵勞息盡機。',64,'全唐诗/poet.song.16000.json','["幾年瓶鉢帝城棲，看盡塵勞息盡機。", "詩妙偶因餘力到，名高却與本心違。", "雲深路入千山去，歲晚身携一錫歸。", "林下應逢舊猿鶴，得無驚見紫檀衣。"]'),
('f8114e7d-22b5-480a-b798-0063525d6532','煙雨樓','吳育','宋','宋诗','song-poetry','','[]','一上危樓七澤分，勝遊平日此怡神。',32,'全唐诗/poet.song.16000.json','["一上危樓七澤分，勝遊平日此怡神。", "荆臺蕪沒千年地，楚望雲披四面春。"]'),
('5e88c774-ff9f-4fb4-a295-e3710362b223','重建羊太傅祠和王原叔句','吳育','宋','宋诗','song-poetry','','[]','羊公千載得清吟，芳迹雖遥契昔心。',32,'全唐诗/poet.song.16000.json','["羊公千載得清吟，芳迹雖遥契昔心。", "更與峴山爲故事，凜然風格照來今。"]'),
('b0252a10-8ddc-46fc-8879-bda7642dcaa2','句','吳育','宋','宋诗','song-poetry','','[]','石存裴令老臣心。',8,'全唐诗/poet.song.16000.json','["石存裴令老臣心。"]'),
('7884daf2-b12e-42d7-91d2-1464bb5c7b85','題會稽谿口躬師上人房','施昌言','宋','宋诗','song-poetry','','[]','谿口佳山水，高人住此中。',48,'全唐诗/poet.song.16000.json','["谿口佳山水，高人住此中。", "生臺下沙鳥，疎磬逐江風。", "倚檻千巖寂，焚香萬法空。", "如何憑小筆，一爲寫衰翁。"]'),
('5ed5e3e2-f875-4a25-9a45-ff2680b9ab8b','送鈐轄館使王公','姚渙','宋','宋诗','song-poetry','','[]','家傳勳力世能賢，四載坤維領帥權。',160,'全唐诗/poet.song.16000.json','["家傳勳力世能賢，四載坤維領帥權。", "南詔酋豪彌款附，西州士庶頼蕃宣。", "輸忠感慨由誠府，接下恩勤自意筌。", "月夕過從多命席，花時酬唱旋成編。", "雅歌餘暇軍容肅，陟狀升聞帝願延。", "馳驛遽趨三召節，執圭俄覲九重天。", "漢廷儀衛咸祗若，蜀郡朋僚共黯然。", "賜封定應留晷刻，疇庸當便進班聯。", "聖神倚注期蕃錫，宥密崇高待九遷。", "下客塵勞遇知己，願言攀附跂英躔。"]'),
('fcd8624f-f0c4-4a9d-a911-3ca11e233fc5','寄題徑山懷郎簡侍郎','張瓌','宋','宋诗','song-poetry','','[]','天地一洲渚，北平南欹危。',192,'全唐诗/poet.song.16000.json','["天地一洲渚，北平南欹危。", "幽并深以厚，江浙清且奇。", "武林頗英秀，川匯仍山卑。", "應接殫天巧，類非人力爲。", "徑山最佳處，有巖稱玉芝。", "居防俗士駕，地乃賢人宜。", "郎公留名德，平時爲羽儀。", "引年歸故里，不復衣朝衣。", "留侯黄石心，白傅香山期。", "結宇名勝外，日與塵事違。", "泉石景物狀，盡任諸賢詩。", "伊予來東藩，濫持使者麾。", "平生愛山水，弗憚命駕之。", "當候秋風高，遠造巖下扉。", "澣濯纓上塵，散步松間綦。", "未能繼高躅，聊用慰所思。"]'),
('24ffd9d6-359c-4c45-a90c-8179f5127f5c','送梵才上人歸天台','張瓌','宋','宋诗','song-poetry','','[]','往問維摩疾，來探般若心。',48,'全唐诗/poet.song.16000.json','["往問維摩疾，來探般若心。", "本源雖自在，因地亦行深。", "灑落溪山色，蒼凉竹樹陰。", "宦途如磨蟻，何日重登臨。"]'),
('0b7c94ba-3509-43d0-839a-cd897b6a45ae','句  其一','張瓌','宋','宋诗','song-poetry','','[]','洲圍淮口江形狹，亭上石頭月色多。',16,'全唐诗/poet.song.16000.json','["洲圍淮口江形狹，亭上石頭月色多。"]'),
('12d3a5bc-a31f-4cdd-b613-ca49b16cfd55','句  其二','張瓌','宋','宋诗','song-poetry','','[]','人間獨有當時月，山際猶無後世樵。',16,'全唐诗/poet.song.16000.json','["人間獨有當時月，山際猶無後世樵。"]'),
('86ca28b6-2dec-4cd8-8047-8c3d697b57a0','涵虛閣','富弼','宋','宋诗','song-poetry','','[]','畫閣高連百雉城，涵虛應不愧標名。',64,'全唐诗/poet.song.16000.json','["畫閣高連百雉城，涵虛應不愧標名。", "門前柳色兼旗色，座上琴聲雜佩聲。", "肯羨五湖歸范蠡，未饒三徑隠淵明。", "我來恰值初晴後，山影波光分外清。"]'),
('5e29753e-9173-4583-9b58-a994f3e17a90','定州閱古堂','富弼','宋','宋诗','song-poetry','','[]','朔方之兵，勁于九土。',240,'全唐诗/poet.song.16000.json','["朔方之兵，勁于九土。", "尤勁而要，粵惟定武。", "兵勁在馭，用則羆虎。", "失馭而勁，驕不可舉。", "曰保曰貝，閉壁連阻。", "武爵新守，束手就虜。", "皇帝曰噫，汝武曷取。", "有敝必革，以儒于撫。", "公來帥定，始以威怒。", "有兵悍橫，一用于斧。", "連營怛之，膽栗腰傴。", "既懼而教，如餔如乳。", "以刺以射，以鉦以鼓。", "無一不若，師師旅旅。", "列城自刺，靡不和附。", "陰沴爲梗，降此大雨。", "大河破洩，在河之滸。", "民被黜墊，田入莽污。", "流離蕩析，不得其所。", "公慼曰吁，予敢寧處。", "迺大招來，迺大保聚。", "乃營帛粟，寒衣饑茹。", "民歸而安，水下孰禦。", "强弱死生，由公復慮。"]'),
('33b1e75b-77df-477d-9310-ec7341ff9ce9','題范希文手書伯夷頌墨蹟','富弼','宋','宋诗','song-poetry','','[]','夷清韓頌古皆無，更得高平小楷書。',32,'全唐诗/poet.song.16000.json','["夷清韓頌古皆無，更得高平小楷書。", "舊相嘉篇題卷後，蘇家能事復何如。"]'),
('2985d65f-cdbf-4d5f-9488-cc2baa9eaca2','睢陽五老圖','富弼','宋','宋诗','song-poetry','','[]','休官致政老年閒，廟堂嘗享著袍冠。',64,'全唐诗/poet.song.16000.json','["休官致政老年閒，廟堂嘗享著袍冠。", "調和鼎鼐施霖雨，燮理陰陽佐武桓。", "念國不忘先世烈，歸鄉豈念舊廬寒。", "我輩若從親炙授，儀容如在使人看。"]'),
('331fd201-8473-4280-af35-9e93d87cba73','過邵堯夫先生','富弼','宋','宋诗','song-poetry','','[]','先生自衛客西畿，樂道安閒絕世機。',64,'全唐诗/poet.song.16000.json','["先生自衛客西畿，樂道安閒絕世機。", "再命初筵終不起，獨甘窮巷寂無依。", "貫穿百代嘗探古，吟咏千篇亦造微。", "珍重相知忽相訪，醉和風雨夜深歸。"]'),
('b9bb071e-8ff0-4cf4-a1d3-569a2751c2ea','答鄭州祖龍圖見寄原韻','富弼','宋','宋诗','song-poetry','','[]','坐擁雙旌甫浚郊，總戎曾未屬鞬橐。',64,'全唐诗/poet.song.16000.json','["坐擁雙旌甫浚郊，總戎曾未屬鞬橐。", "千金寡妙方移疾，二府交修敢憚勞。", "處世機牙都不競，攝生權柄急須操。", "他時病起君恩報，始信林泉屬我曹。"]'),
('0bcb3f37-3706-4b63-8250-ce60dfba813b','留守太尉相公就居爲耆年之會承命賦詩','富弼','宋','宋诗','song-poetry','','[]','西洛古帝都，衣冠走集地。',168,'全唐诗/poet.song.16000.json','["西洛古帝都，衣冠走集地。", "豈惟名利場，驟爲耆德會。", "大尹吾舊相，曠懷輕富貴。", "日與退老游，臺閣并省寺。", "予慚最衰老，亦許預其次。", "遂俗肖儀容，爛然彤繪事。", "閩嶠訪精華，鮫綃布絕藝。", "令復崇宴衎，聊以示慈惠。", "幽居近銅駝，荒敝仍湫庳。", "塞路移君庖，盈車載春醴。", "獻酬互相趣，歡處不知止。", "商嶺有四翁，晉林惟七子。", "較我集諸賢，盛衰何遠爾。", "茲事實可矜，傳之足千祀。"]'),
('0baecc06-6a61-4681-b040-c29d8b498da4','堯夫先生示秋霽登石閣之句病中聊以短章戲答','富弼','宋','宋诗','song-poetry','','[]','高閣岧嶤對遠山，雨餘愁望不成歡。',32,'全唐诗/poet.song.16000.json','["高閣岧嶤對遠山，雨餘愁望不成歡。", "擬將歛黛强消遣，却是幽思苦未闌。"]'),
('32ccbe47-4c42-42bb-97e5-2303e2260580','十月二十四日早始見雪登白雲臺閑望亂道走書呈堯夫先生','富弼','宋','宋诗','song-poetry','','[]','氣候隨時應，初寒雪已盈。',48,'全唐诗/poet.song.16000.json','["氣候隨時應，初寒雪已盈。", "乾坤一色白，山水萬重清。", "是處人煙合，無窮鳥雀驚。", "忻然不成下，連把玉罍傾。"]'),
('cef736bf-9577-468b-ba80-fc7d6091be69','臺上再成亂道走書呈堯夫','富弼','宋','宋诗','song-poetry','','[]','密雪終宵下，晨登百尺端。',48,'全唐诗/poet.song.16000.json','["密雪終宵下，晨登百尺端。", "瑞光翻怯日，和氣不成寒。", "天末無織翳，雲頭未少乾。", "四郊聞擊壤，農望已多歡。"]'),
('5ec233ba-ba86-41c8-ba9a-e9f2a5db71bf','歲在癸丑年始七十正旦日書事  其一','富弼','宋','宋诗','song-poetry','','[]','人生七十古來稀，今日愚年已及期。',32,'全唐诗/poet.song.16000.json','["人生七十古來稀，今日愚年已及期。", "從此光陰猶不測，只應天道始相知。"]'),
('56be2bd5-e780-406c-ae1b-ccdeb035f34e','歲在癸丑年始七十正旦日書事  其二','富弼','宋','宋诗','song-poetry','','[]','親賓何用舉椒觴，已覺閑中歲月長。',32,'全唐诗/poet.song.16000.json','["親賓何用舉椒觴，已覺閑中歲月長。", "不學香山醉歌舞，只將吟嘯敵流光。"]'),
('f88467bd-a073-49d6-92ee-fb312bf207c6','歲在癸丑年始七十正旦日書事  其三','富弼','宋','宋诗','song-poetry','','[]','先聖明明許縱心，山川風月恣遊尋。',32,'全唐诗/poet.song.16000.json','["先聖明明許縱心，山川風月恣遊尋。", "此中若更論規矩，籍外閑人不易禁。"]'),
('1ebec151-720e-4841-a41e-09a8ed30fe87','歲在癸丑年始七十正旦日書事  其四','富弼','宋','宋诗','song-poetry','','[]','今年始是乞骸年，我向年前已掛冠。',32,'全唐诗/poet.song.16000.json','["今年始是乞骸年，我向年前已掛冠。", "都爲君王憐久疾，肯教先去養衰殘。"]'),
('86d9b939-10c9-41de-a2ed-c13b226433a9','弼承索近詩復貺佳句輙次元韻奉和詩以語志不必更及乎詩也伏惟一覽而已  其一','富弼','宋','宋诗','song-poetry','','[]','出入高車耀縉紳，從來天幸喜逢辰。',64,'全唐诗/poet.song.16000.json','["出入高車耀縉紳，從來天幸喜逢辰。", "道孤常恐難逃悔，性拙徒能不失真。", "風雨坐生无妄疾，林泉歸作自由身。", "歲寒未必輸松柏，已見人間七十春。"]'),
('4bcdf7cf-0e41-4146-9f23-3c5e20249466','弼承索近詩復貺佳句輙次元韻奉和詩以語志不必更及乎詩也伏惟一覽而已  其二','富弼','宋','宋诗','song-poetry','','[]','賦分蕭條只自如，生平常向官情踈。',64,'全唐诗/poet.song.16000.json','["賦分蕭條只自如，生平常向官情踈。", "亡功每歎孤明主，得謝何妨作老夫。", "官品尚叨三事貴，世緣應信一毫無。", "病來髀肉消幾盡，尤覺陰陽繫慘舒。"]'),
('5b4af159-3337-4360-bef0-d47254a9c6c7','弼觀罷走筆書後卷','富弼','宋','宋诗','song-poetry','','[]','黎民於變是堯時，便字堯夫德可知。',32,'全唐诗/poet.song.16000.json','["黎民於變是堯時，便字堯夫德可知。", "更覽新詩名擊壤，生生全道略無遺。"]'),
('48b9e0d4-7859-451c-8b17-6ca1c2682986','弼竊覽長篇斷章有十二人中第二人之句又賦一絕上呈','富弼','宋','宋诗','song-poetry','','[]','顧我年齡雖第一，在公勳德自無雙。',32,'全唐诗/poet.song.16000.json','["顧我年齡雖第一，在公勳德自無雙。", "不推行業終難敵，富貴康寧亦可降。"]'),
('32fc6459-0af3-42b4-8f10-92935c1fdd50','偈','富弼','宋','宋诗','song-poetry','','[]','執相誠非，破相亦妄。',20,'全唐诗/poet.song.16000.json','["執相誠非，破相亦妄。", "不執不破，是名實相。"]'),
('3fa50e74-91b5-41b4-af6f-09d3e7b7e7a7','寄歐陽公','富弼','宋','宋诗','song-poetry','','[]','滁州太守文章公，謫官來此稱醉翁。',64,'全唐诗/poet.song.16000.json','["滁州太守文章公，謫官來此稱醉翁。", "醉翁醉道不醉酒，陶然豈有遷客容。", "公年四十號翁早，有德亦與耆年同。", "意古直出茫昧始，氣豪一吐閶闔風。"]'),
('300fc22c-58b5-4864-a0d4-bdf9beaaa9b7','寄題醉翁亭','富弼','宋','宋诗','song-poetry','','[]','偏州地狹民事簡，醉翁自放山水中。',32,'全唐诗/poet.song.16000.json','["偏州地狹民事簡，醉翁自放山水中。", "琅琊倚天色蒼翠，遜泉落石聲玲瓏。"]'),
('34a91a46-2bb4-466d-b548-3ab9cc17b7ce','寄裴士林','富弼','宋','宋诗','song-poetry','','[]','渤澥宣和旅翮飛，不堪朱邸負前期。',64,'全唐诗/poet.song.16000.json','["渤澥宣和旅翮飛，不堪朱邸負前期。", "東城曉騎思行樂，南浦春波怨別離。", "對竹豈能忘舊主，折麻方喜遇深知。", "冕旒正注方臣重，應許州人借一朞。"]'),
('235c5ad6-72e5-4ab3-b658-466c0143ff75','嵩巫亭','富弼','宋','宋诗','song-poetry','','[]','平地烟霄此半分，繡楣丹檻照清汾。',32,'全唐诗/poet.song.16000.json','["平地烟霄此半分，繡楣丹檻照清汾。", "風簾暮捲秋空碧，剩見西山數嶺雲。"]'),
('27a290aa-8e41-4701-a47b-dbd5fee0b4c0','句  其一','富弼','宋','宋诗','song-poetry','','[]','遺德被生民。',6,'全唐诗/poet.song.16000.json','["遺德被生民。"]'),
('6355db60-de11-460f-9411-bb6f650d8ca5','句  其二','富弼','宋','宋诗','song-poetry','','[]','昔年曾作瀟湘客，憔悴東秦歸不得。',48,'全唐诗/poet.song.16000.json','["昔年曾作瀟湘客，憔悴東秦歸不得。", "西軒忽見好溪山，如何却有楚鄉憶。", "讀書誤人四十年，有時醉把闌干拍。"]'),
('c9414ac8-a277-4394-853b-be0aab93f4f2','句  其三','富弼','宋','宋诗','song-poetry','','[]','古云伏日當早歸，况今著令許休暇。',16,'全唐诗/poet.song.16000.json','["古云伏日當早歸，况今著令許休暇。"]'),
('6414debb-0fd9-438a-94fd-f9e02280d670','送程給事知越州','盧革','宋','宋诗','song-poetry','','[]','金門人訪竹林人，云向蓬萊駐畫輪。',64,'全唐诗/poet.song.16000.json','["金門人訪竹林人，云向蓬萊駐畫輪。", "百越江山初作主，五湖圖史未生塵。", "勸耕定带齋船雨，卷白應留燕榭春。", "論道頻年有虛席，摶風一擊好收身。"]'),
('78ff2abf-5548-4bf8-bc6e-d6e941af484c','校書朱君示及園居勝概新篇一軸皆有標目輒成長調格詩奉紀清𨅛','盧革','宋','宋诗','song-poetry','','[]','姑蘇右浙會，園榭森相望。',240,'全唐诗/poet.song.16000.json','["姑蘇右浙會，園榭森相望。", "之子脫名鎖，自主無何鄉。", "虛堂布遺經，周孔之文章。", "靜齋播風雅，絃音日洋洋。", "吮毫濯曲溪，泚墨散芳塘。", "抱琴獨登臺，望山閒涉岡。", "釣渚閱游泳，竹路排青蒼。", "亭幽小勺迥，紅白相低昂。", "予此謝病歸，旅吳歲月長。", "常聞君園勝，欲往兩足僵。", "開緘味題咏，恍若披圖詳。", "吾聞玉川子，破屋洛之陽。", "東野廢官守，止坐叢瀨傍。", "豈如吾子樂，遊息藹有方。", "朝廷日清明，百官良弛張。", "子既難其進，論撰亦有光。", "退之謂子厚，窮久道益强。", "文辭燁垂後，將相未可當。", "窮愁乃著書，心志能渾剛。", "倘來奚足卹，令名期自將。"]'),
('02e6fb7b-fbfc-4eaa-ab08-d238e6b53783','詩一首','盧革','宋','宋诗','song-poetry','','[]','疊嶂最驚目，排青隠星絡。',24,'全唐诗/poet.song.16000.json','["疊嶂最驚目，排青隠星絡。", "雙溪頗醒心，激素出林薄。"]'),
('e2f687ca-ffcb-4d29-ad88-580c5f3014b2','登福全山','林石','宋','宋诗','song-poetry','','[]','嘗聞陶隠居，經行到茲地。',36,'全唐诗/poet.song.16000.json','["嘗聞陶隠居，經行到茲地。", "君王屢飛詔，高尚心愈厲。", "一幅畫雙牛，誰人知此意。"]'),
('13831fee-cc9d-4c6e-bb0c-351aa78a1944','梅雨潭','林石','宋','宋诗','song-poetry','','[]','去夏曾同潭上遊，蔭松坐石濯清流。',64,'全唐诗/poet.song.16000.json','["去夏曾同潭上遊，蔭松坐石濯清流。", "論文聲雜飛泉響，話道心齊邃谷幽。", "盛暑忽思尋舊好，煩襟頓覺似新秋。", "也知關决多餘暇，能更重爲勝賞不。"]'),
('70c82bcb-1dae-4d11-85a7-ad3e0e4d6374','遊翠陰洞和朱履常韻','林石','宋','宋诗','song-poetry','','[]','松桂擢危岑，烟雲晝亦陰。',24,'全唐诗/poet.song.16000.json','["松桂擢危岑，烟雲晝亦陰。", "洞門雖不鎖，誰測洞中深。"]'),
('b48e1093-f0e6-44fe-96e9-ce751b5917fd','重建羊侯祠和王原叔句','張去惑','宋','宋诗','song-poetry','','[]','漢江千里清溶溶，惟此南夏奠其中。',352,'全唐诗/poet.song.16000.json','["漢江千里清溶溶，惟此南夏奠其中。", "因山爲城峙險固，一國形勝何高雄。", "嶷然巨首名曰峴，回壓面勢尊且崇。", "東扼迅流疑引翼，西峙羣阜如盤龍。", "嶔巇峻拔不可擬，絕岸萬丈凌長空。", "下闞澄潭迥無際，旁睨比屋幾可封。", "天意造物豈虛設，控蠻鎮楚舒隆隆。", "自昔登憩且非一，此山振動惟羊公。", "有志平吳運祕略，竭心衛晉推元功。", "綏懷遠邇人所服，開墾田疇時以豐。", "慨然置酒適清曠，中郎幕府賢而通。", "語公令望高四海，當與斯山永無窮。", "自是綿綿歲歷久，閱碑墮淚存遺蹤。", "亭祠浸壞詎可究，山歸民籍木以童。", "前知興衰故有日，覽者歎息追無從。", "龍圖王公守茲土，修舉廢墜詰初終。", "感物思人但長息，剡章疾置聞四聰。", "聖宸動色可其請，茲山復興氣象融。", "耽耽大厦揭亭宇，肅肅真像嚴祠宮。", "遂使靈光享血食，禁樵復祀資恪恭。", "大抵有功及民物，盛德期興天地充。", "今之視古皆一致，休哉千載懷清風。"]'),
('1d055903-d2f3-4782-9135-8635a2c79401','句','雍明遠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭湖裏固深根。',8,'全唐诗/poet.song.16000.json','["洞庭湖裏固深根。"]'),
('3981c4c2-e755-416a-be2a-a87df6fa3163','句','張謨','宋','宋诗','song-poetry','','[]','佳嶺花光紛似雪，荔江波色綠於苔。',16,'全唐诗/poet.song.16000.json','["佳嶺花光紛似雪，荔江波色綠於苔。"]'),
('1524b95c-45a1-4933-a57c-db03f7fe8478','頂山寺','何若谷','宋','宋诗','song-poetry','','[]','百尺寒崖一徑分，攀蘿步步陟青雲。',64,'全唐诗/poet.song.16000.json','["百尺寒崖一徑分，攀蘿步步陟青雲。", "江山好景吟新句，猿鶴歡聲識舊羣。", "壁爲題詩塵不染，池因供硯水猶薰。", "旁人莫訝登科久，二十年前此論文。"]'),
('85367d1e-a3de-462c-b476-77f63a0c1c3e','句','卓祐之','宋','宋诗','song-poetry','','[]','山色列屏分左右，水聲鳴玉遶西東。',16,'全唐诗/poet.song.16000.json','["山色列屏分左右，水聲鳴玉遶西東。"]'),
('7005f440-ab06-47bc-92ae-a6fc88dff662','覩宜春萍鄉二邑大夫政事作詩一章','朱景陽','宋','宋诗','song-poetry','','[]','政在寬民戢吏奸，忍爲苛嬈恣貪殘。',64,'全唐诗/poet.song.16000.json','["政在寬民戢吏奸，忍爲苛嬈恣貪殘。", "東鄰老幼足和氣，西邑生靈皆病顔。", "萬乘至聰聞不及，兩司端坐匹如閒。", "行人過此還知否，地獄天堂咫尺間。"]'),
('35306548-11cd-4d40-b9c2-f5a0c4c72472','和孔司封題蓬萊閣','吳可幾','宋','宋诗','song-poetry','','[]','皇唐舊相元才子，曾作蕃宣式燕遨。',64,'全唐诗/poet.song.16000.json','["皇唐舊相元才子，曾作蕃宣式燕遨。", "郛郭上當星紀分，軒甍全壓閬風高。", "賓僚會集簪裾盛，衙隊周環鼓吹豪。", "不出公庭得仙館，豈同徐福絕雲濤。"]'),
('2b7eca17-ef83-4f65-a2ad-ae069738ba41','題疊石山院僧壁','吳可幾','宋','宋诗','song-poetry','','[]','緇客幽棲常苦吟，水邊松下靜愔愔。',32,'全唐诗/poet.song.16000.json','["緇客幽棲常苦吟，水邊松下靜愔愔。", "有時一室焚香坐，不以詩情廢道心。"]'),
('b0e61c94-4b9a-4e7f-8425-1590e66d39c5','釣臺','吳可幾','宋','宋诗','song-poetry','','[]','君王取天下，有人將甲兵。',168,'全唐诗/poet.song.16000.json','["君王取天下，有人將甲兵。", "君王得天下，有人相昇平。", "我欲介其間，區區安取成。", "莫若歸養高，高卧嵓之扃。", "直使萬乘意，慕仰非鴻冥。", "身雖隠漁釣，心豈忘朝廷。", "常慮天下定，君王志驕盈。", "羣臣習見聞，力諫不爾聽。", "不有不臣者，不足回其清。", "商山四老人，用是定西京。", "潛希絕世躅，萬一助皇明。", "年當建武日，上下咸清寧。", "所懷憶不陳，終焉爲客星。", "如何逸民傳，乃有狂奴名。"]'),
('a63d40d6-e5b1-47c0-ad34-7f02f304206d','謁林廟','吳秘','宋','宋诗','song-poetry','','[]','高天之有文，星辰豔窮碧。',132,'全唐诗/poet.song.16000.json','["高天之有文，星辰豔窮碧。", "厚地之有文，草木秀野色。", "草木既無辭，星辰亦難測。", "豈侔人之文，五經爲藝極。", "五經主者何，豈非至聖力。", "三才久虛位，待我先師宅。", "秘亦窮經者，自謂入閫閾。", "天地無逃數，世人猶自惑。", "代移文不移，宜在弟子職。", "薰香達誠悃，滴酒瀝胸臆。", "瞿然見威容，長林聳墳側。"]'),
('d346175f-0a67-447a-87c0-037928fed6d4','句','李堯俞','宋','宋诗','song-poetry','','[]','嶺陽山水奇，第一稱湟州。',12,'全唐诗/poet.song.16000.json','["嶺陽山水奇，第一稱湟州。"]'),
('e6b5ed96-5ea3-4c00-b1dd-39b0a3d015fb','遊大滌山','蔡準','宋','宋诗','song-poetry','','[]','大滌洞沉沉，天柱峯嶪嶪。',48,'全唐诗/poet.song.16000.json','["大滌洞沉沉，天柱峯嶪嶪。", "人世悲落花，觀松無易葉。", "朝夕樵風生，雲鶴閒情愜。", "何當採玉芝，真蹤從此躡。"]'),
('1eb62807-6f8a-4194-a128-8cb6a34c3168','題玉光亭和章郇公韻','青陽楷','宋','宋诗','song-poetry','','[]','鳴琴賢宰有三長，吟得新詞敵夜光。',32,'全唐诗/poet.song.16000.json','["鳴琴賢宰有三長，吟得新詞敵夜光。", "好是斷章無以和，神仙官職水雲鄉。"]'),
('91d60fab-2b8f-430e-a03b-56e2f31db042','小桃溪','許當','宋','宋诗','song-poetry','','[]','桃溪一何清，想像武陵水。',48,'全唐诗/poet.song.16000.json','["桃溪一何清，想像武陵水。", "所愛春風時，灼灼花數里。", "漁艇日來去，無人識歸止。", "安知歷幽源，不遇神仙子。"]'),
('6709d46a-a1f5-46f5-9289-7cd552783a66','寶峯寺','許當','宋','宋诗','song-poetry','','[]','金園敞山阿，翛然隔城市。',48,'全唐诗/poet.song.16000.json','["金園敞山阿，翛然隔城市。", "晨夕鐘梵音，颯沓五雲際。", "空山無盡香，大乘有真諦。", "簿領得餘閑，徙倚青蓮地。"]'),
('4872295a-b249-4330-9cd9-b77102327700','黄蘗山','許當','宋','宋诗','song-poetry','','[]','閩粵饒異山，峨峨此稱奇。',48,'全唐诗/poet.song.16000.json','["閩粵饒異山，峨峨此稱奇。", "青崖蔚高林，朝日常蔽虧。", "上士訪幽趣，結愛忘返期。", "所以葵藿心，江淹寄遐思。"]'),
('909a7493-00d4-4092-8896-e8455b91d2a4','小湖','許當','宋','宋诗','song-poetry','','[]','水德潤於物，此湖無謂卑。',48,'全唐诗/poet.song.16000.json','["水德潤於物，此湖無謂卑。", "溪壑有通源，風濤無險期。", "澤廣均田澮，功高濟旱時。", "好看雷雨會，騰踏起蛟螭。"]'),
('1e6fac39-c1fe-4198-8831-50411e2f1065','莫公堂','許當','宋','宋诗','song-poetry','','[]','高高莫公堂，孕秀龍淵西。',120,'全唐诗/poet.song.16000.json','["高高莫公堂，孕秀龍淵西。", "造化秘奇勝，路斷無輪蹄。", "金霞烘石門，古木蟠雙溪。", "中流峙鼇首，勢若吞雲霓。", "下招巢由隠，上揖松喬棲。", "往往春風時，桃花滿深蹊。", "漁郎信波去，仙源歸槳迷。", "誰結物外賞，嚴冬此攀躋。", "旋磨苔蘚壁，更作磊落題。", "萬世萬斯年，巖巖穹壤齊。"]'),
('19417edd-ac09-4872-b405-22b4e58aa235','贈陳公衮','黄師道','宋','宋诗','song-poetry','','[]','玉皇詔我自旴城，下車期年微政聲。',176,'全唐诗/poet.song.16000.json','["玉皇詔我自旴城，下車期年微政聲。", "唯得奇童穎川子，年始七歲業老成。", "手揮椽筆書大字，口誦五經富强記。", "君非祖德積餘慶，來裔安能具神智。", "一見降羨增嗟呼，寄言昭武元正夫。", "長歌大軸貽褒贊，比擬劉晏李泌徒。", "近來詩思復清峻，辭贍格老實奇俊。", "居嘗親試一一精，奏達帝聰彰聖運。", "英廟激賞人中祥，俞旨頒降政事堂。", "臨軒未暇召入對，龍駕俄聞升上蒼。", "舉世才命各有待，俊氣尚幼佳名在。"]'),
('7a728e6e-191f-482d-acdc-35fea4f08898','西峯院','林嗣復','宋','宋诗','song-poetry','','[]','參遍曹溪衆所欽，玄堂虛寂砌蟲吟。',32,'全唐诗/poet.song.16000.json','["參遍曹溪衆所欽，玄堂虛寂砌蟲吟。", "定回瞑目誰相顧，好鳥啣花下翠林。"]'),
('84e473e4-d594-488a-a5dc-54fe799a2e60','題曲水閣','林槩','宋','宋诗','song-poetry','','[]','勝絕千巖地，清涵一水濱。',48,'全唐诗/poet.song.16000.json','["勝絕千巖地，清涵一水濱。", "石泉寒繞澗，山木翠和春。", "秀入壺中望，幽凝物外身。", "賢侯足真賞，王謝有芳塵。"]'),
('c8a1b25e-b691-44b0-9dd8-beb95a7034ab','鑑湖月夜行舟','林槩','宋','宋诗','song-poetry','','[]','湖光如鑑月如珪，月下湖中兩槳飛。',32,'全唐诗/poet.song.16000.json','["湖光如鑑月如珪，月下湖中兩槳飛。", "鶴氅四垂冰骨爽，夜深疑自廣寒歸。"]'),
('7c36df53-0645-4297-b842-4ff599b93f94','剡郊野思','林槩','宋','宋诗','song-poetry','','[]','密樹芳穠碧草齊，春華微度綠陰低。',64,'全唐诗/poet.song.16000.json','["密樹芳穠碧草齊，春華微度綠陰低。", "谿連嵊水興何盡，路接仙源人自迷。", "落絮有情風上下，好花無語日東西。", "故園桃李經年別，一望歸心遶翠蹊。"]'),
('6cb2774a-a309-4e1e-88e2-d0f8a550801b','越中五詠','林槩','宋','宋诗','song-poetry','','[]','越絕煙光隠翠微，蘭亭春色送行衣。',64,'全唐诗/poet.song.16000.json','["越絕煙光隠翠微，蘭亭春色送行衣。", "風清漢相鳴樵徑，臺古任公落釣磯。", "繡被歌殘人竟遠，桃花源靜客忘歸。", "憑君莫上秦山望，千古驪宮對夕暉。"]'),
('7633a566-c6ca-4744-b1f3-28dffae5db8d','越中五詠 野望讌集','林槩','宋','宋诗','song-poetry','','[]','碧樹陰穠曲沼濱，賞心何處樂遊頻。',64,'全唐诗/poet.song.16000.json','["碧樹陰穠曲沼濱，賞心何處樂遊頻。", "東吳景物蘭亭晚，西洛煙光梓澤春。", "香散落梅忘怨笛，綠鋪幽草妒芳茵。", "風雲流散苦無定，且學陽池倒載身。"]'),
('b6784db1-6161-4b69-aabd-7947bea2ef6e','越中五詠 離席','林槩','宋','宋诗','song-poetry','','[]','何處驪駒雜楚歌，楚人歸思託雲蘿。',64,'全唐诗/poet.song.16000.json','["何處驪駒雜楚歌，楚人歸思託雲蘿。", "河陽望竟妾心遠，金谷別來郎恨多。", "往事一春空物態，閒情千里舊風波。", "歸時莫聽隴頭水，腸斷不禁年少何。"]'),
('57e51e44-555c-4cca-ba2b-7b778faea672','越中五詠 西村','林槩','宋','宋诗','song-poetry','','[]','綠郊凝望久徘徊，落日川原映古臺。',64,'全唐诗/poet.song.16000.json','["綠郊凝望久徘徊，落日川原映古臺。", "江上晚風三弄笛，隴頭春信一枝梅。", "東西陌外煙光度，紫翠峯前霽色開。", "不是羅敷莫迴首，城南五馬使君來。"]'),
('2dde8441-1d08-4770-913e-3563be22fe90','越中五詠 野塘','林槩','宋','宋诗','song-poetry','','[]','漠漠橫塘一水通，霏霏輕藹夕陽中。',64,'全唐诗/poet.song.16000.json','["漠漠橫塘一水通，霏霏輕藹夕陽中。", "吳娘晚唱穿菱葉，楚客春心託蕙叢。", "煙外蒹葭閒倚路，波間舴艋半凌風。", "江南景好游人去，二月大堤花艷紅。"]'),
('c1e61631-ee92-47a3-b4c9-080bc563a599','伏波將軍廟','林槩','宋','宋诗','song-poetry','','[]','尉佗尺檄黄關閉，天欲亡秦盛漢家。',32,'全唐诗/poet.song.16000.json','["尉佗尺檄黄關閉，天欲亡秦盛漢家。", "一目將軍通戰棹，何曾五嶺限中華。"]'),
('5cfdf4d4-a798-4afb-9248-43f91b8ade88','韓退之廟','林槩','宋','宋诗','song-poetry','','[]','退之皆負□□志，作邑當年來此中。',32,'全唐诗/poet.song.16000.json','["退之皆負□□志，作邑當年來此中。", "謾道陽山是窮處，先生於道未嘗窮。"]'),
('7e23c81e-6596-4229-a1eb-7b4a84d68b5f','賦新繁周表權如詔亭','李慎修','宋','宋诗','song-poetry','','[]','昔年曾見鯉趨庭，締構開基敞燕楹。',64,'全唐诗/poet.song.16000.json','["昔年曾見鯉趨庭，締構開基敞燕楹。", "教子義方居可法，褒賢恩詔榜爲名。", "人知一玉能成器，家鄙千金任滿籝。", "從此里閭爲盛事，握蘭華省有才英。"]'),
('2ebff962-d569-4ddd-955b-ef78c84989ab','和燕龍圖海棠','楊諤','宋','宋诗','song-poetry','','[]','西漢欺盧橘，東陽愛野棠。',240,'全唐诗/poet.song.16000.json','["西漢欺盧橘，東陽愛野棠。", "許昌奇此遇，子美欠先揚。", "杜宇三春艷，蠶叢一國香。", "燕脂點亂雨，猩色麗斜陽。", "富艷東君節，暄妍白帝方。", "錦樓祈水色，玉壘換山光。", "風格林檎細，腰支郁李長。", "天生笑容質，時樣舞衣裳。", "少吐深深染，全開淡淡妝。", "煙媒護綠蔕，風陣損朱房。", "旋失因臨水，閒飄弗過牆。", "佩亡愁殺甫，簪脫即連姜。", "蝶舞菱花照，鶑啼罨畫堂。", "僊如弄玉少，墜似綠珠常。", "不見還成悔，相思幾欲狂。", "春深濯錦水，日晚浣紗坊。", "卧對移簾押，吟看近筆牀。", "池清滿園倒，鳥起一枝昂。", "紫燕銜泥急，黄蜂趁蜜忙。", "化工真用意，銷得與携觴。"]'),
('968eb758-b712-4333-b209-7fac36617446','句  其一','楊諤','宋','宋诗','song-poetry','','[]','草不驚皇轍，山能護帝輿。',12,'全唐诗/poet.song.16000.json','["草不驚皇轍，山能護帝輿。"]'),
('2ebc81e6-6f64-443f-93bc-11269bb8a2bf','句  其二','楊諤','宋','宋诗','song-poetry','','[]','願前明主席，一問洛陽人。',12,'全唐诗/poet.song.16000.json','["願前明主席，一問洛陽人。"]'),
('1d0a14c7-47c6-4aff-9f28-2cdd195fe25a','句  其三','楊諤','宋','宋诗','song-poetry','','[]','行人問宮殿，耕者得珠璣。',12,'全唐诗/poet.song.16000.json','["行人問宮殿，耕者得珠璣。"]'),
('22a25a3f-c411-4ac4-9d38-5aa417f2c8a0','句  其四','楊諤','宋','宋诗','song-poetry','','[]','遥觀一郡色，盡得二江聲。',12,'全唐诗/poet.song.16000.json','["遥觀一郡色，盡得二江聲。"]'),
('c4170160-5c12-48de-9da5-d70f9a461806','題曲水閣','劉述','宋','宋诗','song-poetry','','[]','面勢俯巖隈，雕軒映水開。',48,'全唐诗/poet.song.16000.json','["面勢俯巖隈，雕軒映水開。", "雲從棟間出，人自鑑中來。", "櫂楫歌聲度，漸裳禊事迴。", "東山如未起，好住小蓬萊。"]'),
('e54cd3fe-9dc9-4005-ae54-7051370b3677','五泄山','劉述','宋','宋诗','song-poetry','','[]','翠屏千疊水潺潺，一簇青鴛杳靄間。',64,'全唐诗/poet.song.16000.json','["翠屏千疊水潺潺，一簇青鴛杳靄間。", "惜是晚年逢此境，悔將前眼看他山。", "瀑飛蘿磴終難畫，龍蟄巖雲秪蹔閑。", "薄宦勞人無計住，可嗟歸去又塵寰。"]'),
('b244ad3d-510b-4d4f-87bf-4ba735d0e3af','留題洞巖','劉述','宋','宋诗','song-poetry','','[]','英英洞口雲，觸石纔一縷。',48,'全唐诗/poet.song.16000.json','["英英洞口雲，觸石纔一縷。", "須臾徧空山，霈然作靈雨。", "萬物一以澤，孤蹤無處所。", "我心良所珍，作詩以自矩。"]'),
('e5cb907e-d63a-4d53-87ce-ac49f8ab1ac3','涵碧亭  其一','劉述','宋','宋诗','song-poetry','','[]','兩山嶔處一泉飛，飛到亭前聚作池。',32,'全唐诗/poet.song.16000.json','["兩山嶔處一泉飛，飛到亭前聚作池。", "砌下蛟龍盤未起，席間環佩響無時。"]'),
('00faa89a-45d2-483f-8a36-d00623d89b2b','涵碧亭  其二','劉述','宋','宋诗','song-poetry','','[]','翩飜翠羽青霞色，偃亞芳叢碧玉姿。',32,'全唐诗/poet.song.16000.json','["翩飜翠羽青霞色，偃亞芳叢碧玉姿。", "却羨老僧饒歲臘，不知天上有炎曦。"]'),
('e3918772-5708-4d47-990a-55a6c7c783d5','題竹閣','劉述','宋','宋诗','song-poetry','','[]','竹閣寒相倚，雲窗晚共開。',48,'全唐诗/poet.song.16000.json','["竹閣寒相倚，雲窗晚共開。", "閒身方外去，幽意靜中來。", "聲響風隨籜，陰移石上苔。", "遲留更清夜，待月露盈杯。"]'),
('63ea23e0-9906-4bb5-ac2e-7ceb6154d9e8','重刻孫謝二公詩','劉述','宋','宋诗','song-poetry','','[]','漢興文藝推儒首，諫議才能□□師。',32,'全唐诗/poet.song.16000.json','["漢興文藝推儒首，諫議才能□□師。", "更向謝巖鎸麗句，清風千古照江湄。"]'),
('b6db267e-fc6d-4a4e-8772-66f38fdad16e','迎月','陳起','宋','宋诗','song-poetry','','[]','尊酒貪迎月，人生醉後佳。',24,'全唐诗/poet.song.16000.json','["尊酒貪迎月，人生醉後佳。", "夜來窗不掩，吹落一瓶花。"]'),
('618827d9-d1f0-43d5-98ec-20a0a282539c','凉軒','吳戭','宋','宋诗','song-poetry','','[]','便齋素迫隘，爲敞一軒清。',48,'全唐诗/poet.song.16000.json','["便齋素迫隘，爲敞一軒清。", "畏暑不能到，好風常自生。", "簷牙透山色，砌脚逗泉聲。", "事集民安堵，琴棋此適情。"]'),
('7cbf6341-d8e6-49b6-b3a9-85ca0baef787','和祖擇之學士袁州慶豐堂十詠  其一','陳詵','宋','宋诗','song-poetry','','[]','時豐公事少，筆硯任橫斜。',24,'全唐诗/poet.song.16000.json','["時豐公事少，筆硯任橫斜。", "環郭江山秀，人情等物華。"]'),
