('906f75ea-dad6-474b-a84b-c887647c72bc','和祖擇之學士袁州慶豐堂十詠  其三','陳詵','宋','宋诗','song-poetry','','[]','窮谷寓形久，慚無問俗方。',24,'全唐诗/poet.song.16000.json','["窮谷寓形久，慚無問俗方。", "文章古刺史，今昔竊餘光。"]'),
('6c2d9da6-cf5f-425c-a922-37baf9baade0','和祖擇之學士袁州慶豐堂十詠  其四','陳詵','宋','宋诗','song-poetry','','[]','穢草誅還密，浮萍去又生。',24,'全唐诗/poet.song.16000.json','["穢草誅還密，浮萍去又生。", "輒污如鑑浄，有客若爲情。"]'),
('0da3d142-c7b4-4091-b01a-e4b58a2bf2d8','和祖擇之學士袁州慶豐堂十詠  其五','陳詵','宋','宋诗','song-poetry','','[]','秀泉開舊甃，初試仰山茶。',24,'全唐诗/poet.song.16000.json','["秀泉開舊甃，初試仰山茶。", "寂寂有餘意，池蓮三五花。"]'),
('bea5f6bd-bbc7-4927-b2bf-90bc378466ed','和祖擇之學士袁州慶豐堂十詠  其六','陳詵','宋','宋诗','song-poetry','','[]','園涉日成趣，窮詩嬾綴裝。',24,'全唐诗/poet.song.16000.json','["園涉日成趣，窮詩嬾綴裝。", "梁間冰雪句，屈指歲華長。"]'),
('c1a17aa6-828a-4870-82ad-8c7277c40eda','和祖擇之學士袁州慶豐堂十詠  其七','陳詵','宋','宋诗','song-poetry','','[]','洗竹遥山出，流泉到曲池。',24,'全唐诗/poet.song.16000.json','["洗竹遥山出，流泉到曲池。", "可憐波萬頃，黽勉對淪漪。"]'),
('663030b6-aa41-4f8e-9b28-1d91b49f043d','和祖擇之學士袁州慶豐堂十詠  其八','陳詵','宋','宋诗','song-poetry','','[]','道院今猶古，閒中事可書。',24,'全唐诗/poet.song.16000.json','["道院今猶古，閒中事可書。", "鷺鷗馴不去，誰可得親疎。"]'),
('a2479ec5-dda7-4660-80a3-492b9cfee638','和祖擇之學士袁州慶豐堂十詠  其九','陳詵','宋','宋诗','song-poetry','','[]','登堂方再月，已許慶豐年。',24,'全唐诗/poet.song.16000.json','["登堂方再月，已許慶豐年。", "偶繼前賢跡，承流頗裕然。"]'),
('f4bd8e53-5746-4ab5-9ed9-105f41861db4','和祖擇之學士袁州慶豐堂十詠  其一○','陳詵','宋','宋诗','song-poetry','','[]','鴻鵠遠矰弋，魚鳥脫池籠。',24,'全唐诗/poet.song.16000.json','["鴻鵠遠矰弋，魚鳥脫池籠。", "始覺一無物，方知萬事空。"]'),
('9f8c36a6-4815-4c20-ba83-cce1c531d955','和祖擇之詠震山巖彭徵君釣臺','陳詵','宋','宋诗','song-poetry','','[]','東有徵君真逸居，有臺可釣傍漁磯。',32,'全唐诗/poet.song.16000.json','["東有徵君真逸居，有臺可釣傍漁磯。", "志高不在魚吞餌，回笑滎陽血染衣。"]'),
('082f1759-cf99-4957-8d15-bde988726895','西樓懷感','章造','宋','宋诗','song-poetry','','[]','高花古柳傍城闉，游目江城次第新。',32,'全唐诗/poet.song.16000.json','["高花古柳傍城闉，游目江城次第新。", "百感中來倚惆悵，滿城煙雨滿城春。"]'),
('3df22921-3b89-4390-84e3-e49d5835e1d3','清明林下','鄭伯玉','宋','宋诗','song-poetry','','[]','遊絲百尺飛到地，野蝶尋春有狂意。',64,'全唐诗/poet.song.16000.json','["遊絲百尺飛到地，野蝶尋春有狂意。", "一番輕雨洗梨花，啼出玉真無限淚。", "老夫不入少年場，直向南軒亭午睡。", "覺來歷省夢中事，却憶邯鄲枕中記。"]'),
('51aa2449-5ff7-4df6-a766-4c6128152d1f','和王太傅游國清塘','鄭伯玉','宋','宋诗','song-poetry','','[]','寒日一觀眺，四天雲色稀。',48,'全唐诗/poet.song.16000.json','["寒日一觀眺，四天雲色稀。", "水風迎棹起，沙鶩背人飛。", "玉縷鱸新膾，金膏蟹正肥。", "斜陽促歸旆，那得戀漁磯。"]'),
('69f10b72-6d06-4747-9785-b137ffd87ba4','遠亭','鄭伯玉','宋','宋诗','song-poetry','','[]','亭勢孤高映小池，盤盤一道出林霏。',64,'全唐诗/poet.song.16000.json','["亭勢孤高映小池，盤盤一道出林霏。", "平誅巖腹草茅盡，直望海門煙火微。", "樹石滿前供勝賞，溪山無處隠清暉。", "宣城麗句人爭誦，珍重陽春和者稀。"]'),
('08b0b2c2-05c5-4a31-9e24-40e2989a105d','綠野亭  其一','鄭伯玉','宋','宋诗','song-poetry','','[]','二月池邊景色好，天與人意相怡融。',64,'全唐诗/poet.song.16000.json','["二月池邊景色好，天與人意相怡融。", "鵝毛絮輕颺晴日，鴨頭波暖摇青空。", "幽鳥間關變新哢，高花亂旋飛斜紅。", "樽前忽爾感時節，酌酒醉倒酬東風。"]'),
('0eb4ada3-1a7d-4d6b-b569-87cc1d728208','綠野亭  其二','鄭伯玉','宋','宋诗','song-poetry','','[]','雨過黄梅夏將半，園亭清灑如山家。',64,'全唐诗/poet.song.16000.json','["雨過黄梅夏將半，園亭清灑如山家。", "白鳥窺魚立閒暇，紅蜓弄水飛交加。", "垣衣重重長舊暈，萱草節節含新花。", "薤葉簟凉一就枕，起來日抱西山斜。"]'),
('b4972890-5090-4c10-9671-313f255656f2','綠野亭  其三','鄭伯玉','宋','宋诗','song-poetry','','[]','吾愛高秋亭上望，水風凉澹愜幽情。',64,'全唐诗/poet.song.16000.json','["吾愛高秋亭上望，水風凉澹愜幽情。", "山形左右互拱揖，海氣旦暮多陰晴。", "西疇農歌罷亞熟，北埭漁唱滄浪清。", "人生得酒且自適，何必身後立空名。"]'),
('f5ff4cff-6844-44bb-9087-b5994e47a5ef','綠野亭  其四','鄭伯玉','宋','宋诗','song-poetry','','[]','路出煙村俗駕少，江天落莫憎寒威。',64,'全唐诗/poet.song.16000.json','["路出煙村俗駕少，江天落莫憎寒威。", "依依壺嶠草樹變，藹藹海門煙火微。", "日脚下時一雁度，風頭起處雙鴉歸。", "却擁殘爐撥灰坐，冷煖世途空險巇。"]'),
('fd37c3b1-0177-47d7-bc03-b5b767f958e0','和夏日國清塘泛舟','鄭伯玉','宋','宋诗','song-poetry','','[]','三篙摇漾綵帆輕，勝賞寧辭遠郡城。',64,'全唐诗/poet.song.16000.json','["三篙摇漾綵帆輕，勝賞寧辭遠郡城。", "水滿人如天上坐，波澄舟在鏡中行。", "都無暑氣侵衣袖，時有荷香入酒觥。", "野老岸前爭擁看，知公威霽不喧驚。"]'),
('f31b9349-edeb-4ad9-86ed-a5ae0b689ec7','宿僧寺','鄭伯玉','宋','宋诗','song-poetry','','[]','亭宇無塵落葉天，西風一榻稱高眠。',32,'全唐诗/poet.song.16000.json','["亭宇無塵落葉天，西風一榻稱高眠。", "夜深更愛松間月，破碎清光落枕前。"]'),
('ebb57173-cbca-4484-8b3e-f0955e159079','福唐元夕三首  其一','方孝能','宋','宋诗','song-poetry','','[]','街頭如晝火山紅，酒面生鱗錦障風。',32,'全唐诗/poet.song.16000.json','["街頭如晝火山紅，酒面生鱗錦障風。", "佳客醉醒春色裏，新妝歌舞月明中。"]'),
('88b206b2-cc84-47a3-9ad6-231f2e6a6210','福唐元夕三首  其二','方孝能','宋','宋诗','song-poetry','','[]','薄薄春衫新縷金，樽前風細怯輕陰。',32,'全唐诗/poet.song.16000.json','["薄薄春衫新縷金，樽前風細怯輕陰。", "酒香隠約生紅粉，正與桃花共淺深。"]'),
('e9040296-7dfa-4c09-ab1b-f04b28cbfc0b','福唐元夕三首  其三','方孝能','宋','宋诗','song-poetry','','[]','燈外風摇沽酒斾，月中人數買花錢。',32,'全唐诗/poet.song.16000.json','["燈外風摇沽酒斾，月中人數買花錢。", "少年心緒如飛絮，爭逐遺香拾墜鈿。"]'),
('b9e423ce-8bd1-4df3-9ad1-17316dfc5625','句','方孝能','宋','宋诗','song-poetry','','[]','壺公簪紱數如沙，三世青雲在一家。',16,'全唐诗/poet.song.16000.json','["壺公簪紱數如沙，三世青雲在一家。"]'),
('3694eb04-1455-4f09-b234-5788bd1cf9ae','贈胡侍郎榮歸','王鑾','宋','宋诗','song-poetry','','[]','南還昔別已匆匆，目斷雲飛思欲窮。',64,'全唐诗/poet.song.16000.json','["南還昔別已匆匆，目斷雲飛思欲窮。", "江水波涵天上下，海門潮湧浙西東。", "沉烟白鳥晴沙際，飄带青山夕照中。", "治世安民遺澤在，萬年史筆紀高風。"]'),
('1258ab3b-0266-4ab4-8b78-0238cd01683c','贈胡侍郎榮歸','周古','宋','宋诗','song-poetry','','[]','嘗水茫茫悵別情，悲風吹樹作離聲。',64,'全唐诗/poet.song.16000.json','["嘗水茫茫悵別情，悲風吹樹作離聲。", "酒傾銀斝臨江卧，潮落沙汀带月明。", "千里綠烟芳草合，一天紅雨落花輕。", "老懷對景成三嘆，不覺澘然淚兩傾。"]'),
('ef2257ea-adb2-4ffc-b40d-bbb31e922155','贈胡侍郎榮歸','張承','宋','宋诗','song-poetry','','[]','官路馳驅鬢且蒼，忽承恩詔許還鄉。',64,'全唐诗/poet.song.16000.json','["官路馳驅鬢且蒼，忽承恩詔許還鄉。", "尋幽好結香山社，乘興閒登綠野堂。", "未採佳苗供藥竈，謾收新句入詩囊。", "人生碩德如公少，佇看芝蘭更晚香。"]'),
('88f1ee31-89b7-4ba4-9392-2cfb1ae0befd','贈胡侍郎致仕','趙瑞','宋','宋诗','song-poetry','','[]','幾年爲國寸心丹，今喜承恩衣錦還。',64,'全唐诗/poet.song.16000.json','["幾年爲國寸心丹，今喜承恩衣錦還。", "張翰蓴鱸偏入興，陶潛松菊意休閒。", "坐邀夜月惟斟酒，笑引春風且看山。", "最好溪山多翠竹，與君日日報平安。"]'),
('d766d958-5f94-4e5b-a7c4-f514f1eab3d4','贈胡侍郎致仕','溫良玉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','送友長江上，長江水正平。',48,'全唐诗/poet.song.16000.json','["送友長江上，長江水正平。", "岸花縈別恨，風柳藴離情。", "子去添惆悵，人稱最老成。", "家鄉歸到日，童僕擁歡迎。"]'),
('f973f86c-30c5-48aa-a34c-515aae29ecbf','宋頌九首 皇祖 其一','石介','宋','宋诗','song-poetry','','[]','皇祖神武，疇敢戲豫。',40,'全唐诗/poet.song.16000.json','["皇祖神武，疇敢戲豫。", "元年四月，筠叛於潞。", "皇祖躍馬，至潞城下。", "筠窘赴火，焦頭爛骻。"]'),
('3c94c302-d949-49dd-8cc9-d9dbcfe4d5dc','宋頌九首 皇祖 其二','石介','宋','宋诗','song-poetry','','[]','皇祖龍驤，疇敢猖狂。',40,'全唐诗/poet.song.16000.json','["皇祖龍驤，疇敢猖狂。", "元年九月，進叛於揚。", "皇祖長驅，至揚城隅。", "進窘登樓，并焚其孥。"]'),
('1df80393-9241-493c-b827-95380a3f6cb1','宋頌九首 皇祖 其三','石介','宋','宋诗','song-poetry','','[]','皇祖曰嘻，物情難籌。',30,'全唐诗/poet.song.16000.json','["皇祖曰嘻，物情難籌。", "予代有周，天時人謀。", "罔有不同，予德其休。"]'),
('2222cdf2-e5c3-4cc9-94b7-1181e02953c5','宋頌九首 皇祖 其四','石介','宋','宋诗','song-poetry','','[]','予亦即祚，涵濡養撫。',20,'全唐诗/poet.song.16000.json','["予亦即祚，涵濡養撫。", "罔有失所，予德其裕。"]'),
('8161f624-22fd-4434-9399-97ec4763e530','宋頌九首 皇祖 其五','石介','宋','宋诗','song-poetry','','[]','筠胡予違，進胡不隨。',20,'全唐诗/poet.song.16000.json','["筠胡予違，進胡不隨。", "予匪汝誅，汝自取之。"]'),
('813437d9-2c77-4115-9c39-fd7cb0a7b53e','宋頌九首 皇祖 其六','石介','宋','宋诗','song-poetry','','[]','既翦二盜，聖武烜耀。',20,'全唐诗/poet.song.16000.json','["既翦二盜，聖武烜耀。", "荆潭蜀吳，如拔腐草。"]'),
('26751fc6-a704-432e-a41d-516e71add011','宋頌九首 聖神 其一','石介','宋','宋诗','song-poetry','','[]','不疾而速，不怒而威。',20,'全唐诗/poet.song.16000.json','["不疾而速，不怒而威。", "惟聖惟神，其幾其微。"]'),
('b7983732-ff31-4eb2-8aea-98cb9341c1c6','宋頌九首 聖神 其二','石介','宋','宋诗','song-poetry','','[]','二國之君，各保爾土。',40,'全唐诗/poet.song.16000.json','["二國之君，各保爾土。", "虎憑於山，莫予敢取。", "蛟憑於淵，莫予敢侮。", "萬其年兮，關鐍以固。"]'),
('9ad97a07-ed8e-4c0d-92e2-96cc25ca0535','宋頌九首 聖神 其三','石介','宋','宋诗','song-poetry','','[]','聖機神謀，天祕地藏，風行雷動。',35,'全唐诗/poet.song.16000.json','["聖機神謀，天祕地藏，風行雷動。", "旦秣我馬，夕取其疆。", "二君不知，晏眠于床。"]'),
('99017148-35d3-47cf-a580-1d57dd85d5cf','宋頌九首 聖神 其四','石介','宋','宋诗','song-poetry','','[]','具篙與舟，同朝天子。',30,'全唐诗/poet.song.16000.json','["具篙與舟，同朝天子。", "一發五豝，二君皆至。", "皇祖聖神，鴻光丕懿。"]'),
('ec64f165-2bf1-46ac-84f4-0bcecfa32caf','宋頌九首 湯湯 其一','石介','宋','宋诗','song-poetry','','[]','湯湯其江，區區爾孟。',40,'全唐诗/poet.song.16000.json','["湯湯其江，區區爾孟。", "一夫當關，不知天命。", "蟻固于穴，蛙負于井。", "咫尺之地，爲可以騁。"]'),
('46e53714-f5d7-4ef2-bcc1-dc127967928b','宋頌九首 湯湯 其二','石介','宋','宋诗','song-poetry','','[]','彼以險守，我以德懷。',40,'全唐诗/poet.song.16000.json','["彼以險守，我以德懷。", "王師東來，函谷自開。", "蜀虜授首，呼號哀哀。", "蜀人鼓舞，與我偕來。"]'),
('85ba2335-b153-42c4-8547-328363a55e49','宋頌九首 湯湯 其三','石介','宋','宋诗','song-poetry','','[]','昔時蜀道，絕人來往。',40,'全唐诗/poet.song.16000.json','["昔時蜀道，絕人來往。", "今蜀既平，王道蕩蕩。", "尉候一置，朝貢相望。", "巍巍皇祖，德聲遠暢。"]'),
('48da12ef-4879-48c9-8b97-090fcefc4844','宋頌九首 莫醜 其一','石介','宋','宋诗','song-poetry','','[]','莫醜匪虺，莫悍匪兕。',30,'全唐诗/poet.song.16000.json','["莫醜匪虺，莫悍匪兕。", "有鋹在南，毒螫不已。", "沸湯熱火，暴我赤子。"]'),
('c475aead-0387-4ef4-b0c3-0e049fc49eb8','宋頌九首 莫醜 其二','石介','宋','宋诗','song-poetry','','[]','皇祖曰嘻，天生蒸民。',30,'全唐诗/poet.song.16000.json','["皇祖曰嘻，天生蒸民。", "立之君長，以養以仁。", "乃予不恤，匪鋹之嚚。"]'),
('a9fcc6b0-e6e3-4cf1-b714-b2e8de240b97','宋頌九首 莫醜 其三','石介','宋','宋诗','song-poetry','','[]','乃謀于渭，乃將于美。',30,'全唐诗/poet.song.16000.json','["乃謀于渭，乃將于美。", "王師鷹揚，涉江萬里。", "闢其城門，鋹號請死。"]'),
('3465e6a7-4212-4bf7-8a14-3b31d59677db','宋頌九首 莫醜 其四','石介','宋','宋诗','song-poetry','','[]','皇祖有德，乾覆坤容。',30,'全唐诗/poet.song.16000.json','["皇祖有德，乾覆坤容。", "予在弔民，不殺以封。", "皇祖慈仁，感于昆蟲。"]'),
('ccd6b522-1414-4689-89ce-7bc02d7e205b','宋頌九首 金陵 其一','石介','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','金陵峨峨，長江萬里。',40,'全唐诗/poet.song.16000.json','["金陵峨峨，長江萬里。", "誰爲巢穴，養此蛇豕。", "天豈作限，而險而恃。", "不順不臣，敢亢天子。"]'),
('b258a8a3-05cd-4f9b-a0ee-6509c250b8d5','宋頌九首 金陵 其二','石介','宋','宋诗','song-poetry','','[]','帝赫斯怒，王師徐驅。',40,'全唐诗/poet.song.16000.json','["帝赫斯怒，王師徐驅。", "蕞爾螻蟻，豈勝誅鉏。", "哀哀窮俘，爰叫以呼。", "歸于京師，燀哉聖謨。"]'),
('3577cbbc-be50-4934-b728-66ba59d234db','宋頌九首 聖文 其一','石介','宋','宋诗','song-poetry','','[]','聖文安安，聖武桓桓。',50,'全唐诗/poet.song.16000.json','["聖文安安，聖武桓桓。", "朝貢萬里，正朔百蠻。", "無吳之險，無蜀之艱。", "無潭之嚚，無荆之頑。", "咸予賓順，悅色和顔。"]'),
('3e019977-7c37-4520-bd2e-c2667c995522','宋頌九首 聖文 其二','石介','宋','宋诗','song-poetry','','[]','彼俶在杭，有地千里。',50,'全唐诗/poet.song.16000.json','["彼俶在杭，有地千里。", "皮毀毛落，孤睽莫恃。", "懾服聲教，慕爲臣使。", "携彼人民，挈其土地。", "于橐于囊，歸于天子。"]'),
('bfc91502-309c-4097-b492-16780f244045','宋頌九首 聖文 其三','石介','宋','宋诗','song-poetry','','[]','天子神聖，罔不懷柔。',50,'全唐诗/poet.song.16000.json','["天子神聖，罔不懷柔。", "既懷而封，恩涵澤流。", "逆予有刑，視彼揚州。", "順予有封，視此錢侯。", "赫赫宋德，何有窮休。"]'),
('cc5bf2ce-afc7-4cfe-9649-17ff8761bedb','宋頌九首 六合雷聲 其一','石介','宋','宋诗','song-poetry','','[]','六合雷聲，中國有君。',30,'全唐诗/poet.song.16000.json','["六合雷聲，中國有君。", "塗其耳目，不使聽聞。", "隔在荒外，嗟爾并人。"]'),
('1be2fddd-6b55-45b4-bc69-a2dd3131debd','宋頌九首 六合雷聲 其二','石介','宋','宋诗','song-poetry','','[]','匪民之嚚，爲賊俘虜。',30,'全唐诗/poet.song.16000.json','["匪民之嚚，爲賊俘虜。", "往弔其民，王澤時雨。", "往伐其罪，王師虎旅。"]'),
('473c002d-ee8b-4621-8ba4-18ab346eff3b','宋頌九首 六合雷聲 其三','石介','宋','宋诗','song-poetry','','[]','昔時錢俶，有國於吳。',30,'全唐诗/poet.song.16000.json','["昔時錢俶，有國於吳。", "今俶歸我，爲吾前驅。", "并人望風，請爲臣奴。"]'),
('0c410ef8-0392-413e-b6a2-5580daf7ae40','宋頌九首 六合雷聲 其四','石介','宋','宋诗','song-poetry','','[]','舊是匈奴，爲并左臂。',30,'全唐诗/poet.song.16000.json','["舊是匈奴，爲并左臂。", "今附有德，不與賊子。", "并人失恃，求就戮死。"]'),
('f515c749-8d37-473c-a4ef-19a47d6d91c9','宋頌九首 六合雷聲 其五','石介','宋','宋诗','song-poetry','','[]','撫我則懷，并人肯來。',30,'全唐诗/poet.song.16000.json','["撫我則懷，并人肯來。", "降旗出城，并門夜開。", "并土既平，吾王休哉。"]'),
('259e4fe5-9039-4945-809d-0b997aca51e8','宋頌九首 六合雷聲 其六','石介','宋','宋诗','song-poetry','','[]','往在藝祖，未遑拓㝢。',30,'全唐诗/poet.song.16000.json','["往在藝祖，未遑拓㝢。", "遺我聖宗，啟此北土。", "敢告太廟，惟皇孝武。"]'),
('768c465b-93c7-418b-8af5-7ab5ebdaa39e','宋頌九首 聖武 其一','石介','宋','宋诗','song-poetry','','[]','聖武惟揚，鷹師虎旅。',50,'全唐诗/poet.song.16000.json','["聖武惟揚，鷹師虎旅。", "至于澶淵，執彼醜虜。", "醜虜之來，蜂蠆敢怒。", "我師如林，不怒以懼。", "既俘其帥，請示死所。"]'),
('02d4492d-c703-4b5d-b69f-e78ae140ac00','宋頌九首 聖武 其二','石介','宋','宋诗','song-poetry','','[]','聖仁如天，惡殺好生。',50,'全唐诗/poet.song.16000.json','["聖仁如天，惡殺好生。", "于以耀德，匪來觀兵。", "亟命止戈，無茲黷刑。", "不勦其類，戴我以兄。", "屈膝請和，畏我威靈。"]'),
('7e55c7b5-9c88-49e0-9a7f-00cbdb2e23ad','宋頌九首 聖武 其三','石介','宋','宋诗','song-poetry','','[]','棄甲以歸，處彼北隩。',50,'全唐诗/poet.song.16000.json','["棄甲以歸，處彼北隩。", "千斯年兮，永以爲好。", "邊人其安，養幼送老。", "民有肥田，馬有茂草。", "威德遠兮，思我聖考。"]'),
('1626809c-2c31-48b1-8da2-926abdc6f09e','宋頌九首 明道 其一','石介','宋','宋诗','song-poetry','','[]','明肅惟母，實勤養撫。',40,'全唐诗/poet.song.16000.json','["明肅惟母，實勤養撫。", "有臣有虎，有離有附。", "請王祿産，請廟考祖。", "古人有作，規呂矩武。"]'),
('430f5f34-f666-47ed-ad55-bd6b4bfec942','宋頌九首 明道 其二','石介','宋','宋诗','song-poetry','','[]','政在房帷，小人乘時。',40,'全唐诗/poet.song.16000.json','["政在房帷，小人乘時。", "十年于茲，惟幾惟微。", "聖人如天，不識不知。", "龍晦其威，神藏其爲。"]'),
('e26ac925-cad4-4597-a8e3-89e669644d9c','宋頌九首 明道 其三','石介','宋','宋诗','song-poetry','','[]','明道四月，睿德明發。',30,'全唐诗/poet.song.16000.json','["明道四月，睿德明發。", "帝褰簾箔，出臨軒榻。", "摠擥萬機，指揮六合。"]'),
('703c4d25-5191-41cf-ba11-36c9ef89aa14','宋頌九首 明道 其四','石介','宋','宋诗','song-poetry','','[]','聖人之興，雷動乾行。',30,'全唐诗/poet.song.16000.json','["聖人之興，雷動乾行。", "進退大臣，顔色和平。", "誅逐羣豎，左右不驚。"]'),
('f09d6ded-81c7-4a51-b985-1c527ce615d5','宋頌九首 明道 其五','石介','宋','宋诗','song-poetry','','[]','不怒而威，不疾而速。',30,'全唐诗/poet.song.16000.json','["不怒而威，不疾而速。", "百蠻偷息，百官重足。", "土無二主，惟辟作福。"]'),
('2586aa5b-b21b-4ce9-95cf-d736278cd115','宋頌九首 明道 其六','石介','宋','宋诗','song-poetry','','[]','圖任哲艾，拔崇賢能。',30,'全唐诗/poet.song.16000.json','["圖任哲艾，拔崇賢能。", "旌賁忠臣，死生光榮。", "洗刷敝風，宮闕清明。"]'),
('3eea130c-ad90-48f6-9f14-dc09ecb90cb5','宋頌九首 明道 其七','石介','宋','宋诗','song-poetry','','[]','惟帝之道，與時語默。',20,'全唐诗/poet.song.16000.json','["惟帝之道，與時語默。", "靜則坤闔，動則乾闢。"]'),
('d8631173-54c6-4be4-ab3c-0796338901df','宋頌九首 明道 其八','石介','宋','宋诗','song-poetry','','[]','十年深宮，不有其權。',20,'全唐诗/poet.song.16000.json','["十年深宮，不有其權。", "今日南面，退姦進賢。"]'),
('a1bb6142-fe11-49f7-858b-ae8dab69f7f3','宋頌九首 明道 其九','石介','宋','宋诗','song-poetry','','[]','宋承大紀，八十年矣。',20,'全唐诗/poet.song.16000.json','["宋承大紀，八十年矣。", "明道之政，獨爲粹美。"]'),
('0a35699e-ee9c-4cde-9ee5-3e6c1d3b2107','宋頌九首 明道 其一○','石介','宋','宋诗','song-poetry','','[]','唐三百年，時惟開元。',20,'全唐诗/poet.song.16000.json','["唐三百年，時惟開元。", "猗歟明道，開元同言。"]'),
('86e86df6-fad6-4c4c-a64a-ad75bc4ad4dc','宋頌九首 明道 其一一','石介','宋','宋诗','song-poetry','','[]','明道之政，可以歌舞。',20,'全唐诗/poet.song.16000.json','["明道之政，可以歌舞。", "小臣作頌，實慙吉甫。"]'),
('e5c18c9e-fef0-4d10-bef9-1f181dc71bc2','慶曆聖德頌','石介','宋','宋诗','song-poetry','','[]','於維慶曆，三年三月。',240,'全唐诗/poet.song.16000.json','["於維慶曆，三年三月。", "皇帝龍興，徐出闈闥。", "晨坐太極，晝開閶闔。", "躬攬英賢，手鋤姦枿。", "大聲渢渢，震摇六合。", "如乾之動，如雷之發。", "昆蟲蹢躅，妖怪藏滅。", "同明道初，天地嘉吉。", "初聞皇帝，慼然言曰。", "予父予祖，付予大業。", "予恐失墜，實頼輔弼。", "汝得象殊，重慎徽密。", "君相予久，予嘉君伐。", "君仍相予，笙鏞斯協。", "昌朝儒者，學問該洽。", "與予論政，傅以經術。", "汝貳二相，庶績咸秩。", "惟汝仲淹，汝誠予察。", "太后乘勢，湯沸火熱。", "汝時小臣，危言嶪嶪。", "爲予司諫，正予門闑。", "爲予京兆，堲予讒說。", "賊叛于夏，爲予式遏。", "六月酷日，大冬積雪。"]'),
('43ada468-587d-492b-8853-185c0606ae36','汴渠','石介','宋','宋诗','song-poetry','','[]','隋帝荒宴遊，厚地刳爲溝。',240,'全唐诗/poet.song.16000.json','["隋帝荒宴遊，厚地刳爲溝。", "萬舸東南行，四海困橫流。", "義旗舉晉陽，錦帆入揚州。", "揚州竟不返，京邑爲墟丘。", "吁哉汴渠水，至今病不瘳。", "世言汴水利，我爲汴水憂。", "利害吾豈知，吾試言其由。", "汴水濬且長，汴流湍且遒。", "千里泄地氣，萬世勞人謀。", "舳艣相屬進，餽運曾無休。", "一人奉口腹，百姓竭膏油。", "民力輸公家，斗粟不敢收。", "州侯共王都，尺租不敢留。", "太倉粟峨峨，冗兵食無羞。", "上林錢朽貫，樂官求徘優。", "吾欲塞汴水，吾欲壞官舟。", "請君簡賜予，請君節財求。", "王畿方千里，邦國用足周。", "盡省轉運使，重封富民侯。", "天下無移粟，一州食一州。"]'),
('016b19eb-253c-4160-9b37-f01c7df8a901','麥熟有感','石介','宋','宋诗','song-poetry','','[]','去年經春頻肆赦，拜赦人忙走如馬。',112,'全唐诗/poet.song.16000.json','["去年經春頻肆赦，拜赦人忙走如馬。", "五月不雨麥苗死，赦頻不能活窮寡。", "今年經春無赦書，十日一雨及時下。", "五月麥熟人民飽，一麥勝如四度赦。", "吾願吾君與吾相，調和陰陽活元化。", "陰陽無病元氣和，風雨調順苗多稼。", "使麥長熟人不饑，敢告吾君不須赦。"]'),
('04180726-ec69-44c9-a7a5-1164d4b21567','讀詔書','石介','宋','宋诗','song-poetry','','[]','關中有山生虎狼，虎狼性虣不可當。',96,'全唐诗/poet.song.16000.json','["關中有山生虎狼，虎狼性虣不可當。", "去歲食人十有一，無辜被此惡物傷。", "守臣具事奏聖帝，聖帝讀之惻上意。", "乃詔天下捕虎狼，意欲斯民無枉死。", "吾君仁覆如天地，只知虎狼有牙齒。", "害人不獨在虎狼，臣請勿捕捕貪吏。"]'),
('d007c498-19ed-4ee7-9542-67b15e4f7459','待士熙道未至','石介','宋','宋诗','song-poetry','','[]','鳳凰饑憶玉山禾，鼓翅飛下玉山阿。',64,'全唐诗/poet.song.16000.json','["鳳凰饑憶玉山禾，鼓翅飛下玉山阿。", "玉山之禾粒未熟，饑不得食心如何。", "麒麟渴憶崑山流，軒軒直出崑山幽。", "崑山之流流未長，渴不得飲予心愁。"]'),
('3e45328c-f03a-4d69-9f88-8fc6596b0baa','赴任嘉州嘉陵江泛舟  其一','石介','宋','宋诗','song-poetry','','[]','中心橫大江，兩面疊青嶂。',84,'全唐诗/poet.song.16000.json','["中心橫大江，兩面疊青嶂。", "江山相夾閒，何人事吟放。", "半鐏岸幘坐，永日開舲望。", "孤棹已夷猶，數峯更清尚。", "危影倒波底，凝嵐浮水上。", "鳴鷺答猿啼，樵歌應漁唱。", "併生泉石心，堪媿庸俗狀。"]'),
('9558f887-918a-422f-91ca-22d1727a0c5c','赴任嘉州嘉陵江泛舟  其二','石介','宋','宋诗','song-poetry','','[]','江心清照人，江面平如掌。',180,'全唐诗/poet.song.16000.json','["江心清照人，江面平如掌。", "有客去逍遥，扁舟浮蕩漾。", "遠與城市絕，深將泉石向。", "水鳥忽東西，溪雲時下上。", "軒冕誰富貴，琴鐏自閑放。", "酒色照淥波，吟聲入秋浪。", "五湖何范蠡，磻磎無呂望。", "吾家徂徠下，汶水有清響。", "常時夜雨急，隨雨來枕上。", "魂魄寒無寐，山居得真尚。", "一爲塵纓縛，不得閑時餉。", "兩耳聒欲聾，喧囂千萬狀。", "雨夜自潺湲，宦途空悲愴。", "劍南四千里，地遐接蠻瘴。", "乍聽江水聲，聊使心靈暢。"]'),
('8521e11f-d020-499a-8bd1-4739c872ccc8','三豪詩送杜默師雄','石介','宋','宋诗','song-poetry','','[]','曼卿豪於詩，社壇高數層。',168,'全唐诗/poet.song.16000.json','["曼卿豪於詩，社壇高數層。", "永叔豪於辭，舉世絕儔朋。", "師雄歌亦豪，三人宜同稱。", "曼卿苦汩沒，老死殿中丞。", "身雖埋黄泉，詩名長如冰。", "永叔亦連蹇，病鸞方騫騰。", "四海讓獨步，三館最後登。", "師雄二十二，筆距獰如鷹。", "才格自天來，辭華非學能。", "迴顧李賀輩，粗俗良可憎。", "玉川月蝕詩，猶欲相憑陵。", "曼卿苟不死，其才堪股肱。", "永叔器甚閎，用之王道興。", "師雄子勉旃，勿便生驕矜。"]'),
('21bebe48-534a-4af6-81a2-2c189b07967f','南山贈孫明復先生','石介','宋','宋诗','song-poetry','','[]','我來南山興感悲，萬物紜紜宰者誰。',192,'全唐诗/poet.song.16000.json','["我來南山興感悲，萬物紜紜宰者誰。", "衆材叢卑無奇姿，直轅曲輪皆所宜。", "大木磊磊節幹奇，撐巖拄谷無處施。", "我願天子脩明堂，坐朝諸侯會四夷。", "柱要十圍棟百尺，日責匠石搜訪之。", "千人用斧萬人拽，大根斫斷山崩欹。", "五州追牛十縣丁，載送上都天子怡。", "輪般駭汗工倕走，有目未省曾觀窺。", "黄帝合宮堯衢室，周制九筵虞總期。", "聽政朝夕有攸處，闔門左右咸以時。", "天子拱手四輔立，坐致四海爲雍熙。", "不用直棄用即大，短轅曲輪爾胡爲。"]'),
('035b3c4e-1a0f-442e-9a86-efa5d197509e','河決','石介','宋','宋诗','song-poetry','','[]','崑崙山最大，峨峨橫絕域。',288,'全唐诗/poet.song.16000.json','["崑崙山最大，峨峨橫絕域。", "黄河地下來，洶洶不可測。", "河伯一發怒，擘開崑崙石。", "水出東北陬，浩渺無涯極。", "平地水行疾，九州如咫尺。", "湯湯勢滔天，黎元多沈溺。", "上貽堯心憂，四岳舉鯀塞。", "鯀用汩彝倫，九載無成績。", "堯怒不能治，遂行羽山殛。", "有子其曰禹，命使嗣父職。", "洛中得龜書，九疇文甲坼。", "禹乃乘四載，周游視水迹。", "百川各復道，九河皆開闢。", "禹功既已成，水患方茲息。", "竊思大禹意，河九爲遠策。", "況云殺其溢，聞之孔安國。", "三代逾千年，所以無災厄。", "戰國爭土疆，諸侯用詐力。", "遷徙無常歲，湮淪不可識。", "隄障遏水勢，溝渠絕地脈。", "禹道不復究，河流有壅隔。", "頻爲中國患，不國不安席。", "從官徒負薪，河伯弗受璧。", "斫盡淇園竹，安救瓠子役。"]'),
('c37ba18b-7cfc-465f-9bc8-a80084b00323','寄永叔','石介','宋','宋诗','song-poetry','','[]','九龍行雨歲在子，皇天之命實勤止。',160,'全唐诗/poet.song.16000.json','["九龍行雨歲在子，皇天之命實勤止。", "泓湫水暖嗜慾飽，七龍嬉戲兩龍睡。", "卷藏密雲空自膏，畜聚甘雨不肯施。", "旱魃妖狂作民虐，風伯暴怒興日熾。", "訴號仰天天不聞，九州之禾皆乾瘁。", "嗟呼龍職職行雨，失職不雨民胡恃。", "驅虞義獸心實仁，不忍斯民不食死。", "向龍慢駡數龍罪，龍不能答滿面恥。", "偷向上帝讒騶虞，騶虞得罪龍竊喜。", "欲知龍與騶虞分，仁與不仁而已矣。"]'),
('7f363e15-b977-4f38-9883-7f471503ede8','南霽雲','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','祿山熾亂，火焚崑崗。',240,'全唐诗/poet.song.16000.json','["祿山熾亂，火焚崑崗。", "炎炎二京，鞠爲戰場。", "百官奔走，萬乘蒼黄。", "孰城能守，孰地不亡。", "瞻彼濉水，其流湯湯。", "有城有民，在濉之陽。", "遠位巡上，巡智我彊。", "以城授巡，巡亦克當。", "賊從西來，殺氣堂堂。", "旌旗如林，對城而行。", "巡遠登城，辭毅色康。", "城中之人，踴躍倍常。", "賊知城堅，坐甲裹糧。", "城中食盡，殺愛以嘗。", "士無二志，持病扶瘡。", "寧守城死，城不可降。", "霽雲勇烈，跳城軼出。", "走泗投賀，求兵救乏。", "賀飲霽雲，牢醴羅列。", "霽雲避席，謂衆云曰。", "濉陽之人，不食一月。", "義不獨飽，食下輒咽。", "以刀斷指，左右流泣。", "彼何人兮，忌忠嫉節。"]'),
('ae1ae6dd-206a-4855-b30b-b1d99d41551d','贈張績禹功','石介','宋','宋诗','song-poetry','','[]','李唐元和閒，文人如蠭起。',288,'全唐诗/poet.song.16000.json','["李唐元和閒，文人如蠭起。", "李翱與李觀，言雄破奸宄。", "孟郊及張籍，詩苦動天地。", "持正不退讓，子厚稱絕偉。", "元白雖小道，急名愈弗已。", "卒能霸斯文，昌黎韓夫子。", "吾宋興國來，文人如櫛比。", "黄州才專勝，漢公氣全粹。", "晦之號絕羣，平地走虎兕。", "謂之雖駮雜，亦文中騏驥。", "白稹洎盧震，江沱自爲水。", "朱嚴兼孫僅，培塿對嶽峙。", "卒能霸斯文，河東柳開氏。", "嗟吁河東沒，斯文乃屯否。", "汨汨三十年，淫哇滿人耳。", "粵從景祐後，大儒復倡始。", "文人如麻立，樅樅攢戰騎。", "徂徠山磊砢，生民實頑鄙。", "容貌不動人，心膽無有比。", "不度蹄涔微，直欲觸鯨鯉。", "有慕韓愈節，有肩柳開志。", "今讀禹功文，予戟寒相倚。", "實光千里高，飛出破屋裏。", "龍音萬丈長，拔出重淵底。"]'),
('a0e6d5a2-b6c1-4288-9187-ea9ad9a71c9d','西北','石介','宋','宋诗','song-poetry','','[]','吾嘗觀天下，西北險固形。',96,'全唐诗/poet.song.16000.json','["吾嘗觀天下，西北險固形。", "四夷皆臣順，二鄙獨不庭。", "吾君仁泰厚，曠歲稽天刑。", "孽芽遂滋大，虵豕極羶腥。", "漸聞頗驕蹇，牧馬附郊坰。", "吾恐患已深，爲之居靡寧。", "堂上守章句，將軍弄娉婷。", "不知思此否，使人堪涕零。"]'),
('3232d8be-54de-4637-86aa-e3734fccf37a','贈孫先生','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','世無伯樂不識馬，眼看騏驥如駑駘。',64,'全唐诗/poet.song.16000.json','["世無伯樂不識馬，眼看騏驥如駑駘。", "先生今年四十四，才似皋夔胡爲哉。", "泰山山下水照石，溪聲濊濊白雲堆。", "我居其間構茅屋，先生先生歸去來。"]'),
('ad6e856f-e39c-4ff6-bc28-550af3a13c9d','寄李縕仲淵','石介','宋','宋诗','song-poetry','','[]','噫吁嘻！屈原放，賈誼投。',152,'全唐诗/poet.song.16000.json','["噫吁嘻！屈原放，賈誼投。", "晦之流，子望囚。", "古人今人皆不免，才能累身才反仇。", "吾友仲淵少學古，胸中疎落羅孔周。", "點毫磨墨作文字，壯哉筆力追羣牛。", "三十青衫得一尉，尺澤寸波蟄長虬。", "清廉愛民復材武，一日得罪繫滁州。", "噫吁嘻！屈原忠臣楚之望，賈誼少年才無儔。", "晦之子望俱命世，麒麟頭角爭崔崷。", "時不與兮將柰何，仲淵仲淵勿涕流。"]'),
('573f92c7-f72d-4d59-aaba-602876b33a4f','送李生謁張侯','石介','宋','宋诗','song-poetry','','[]','李生長七尺，栖栖長自弔。',192,'全唐诗/poet.song.16000.json','["李生長七尺，栖栖長自弔。", "一飲酒一石，常懷酒甕小。", "一食牛一腔，平生未曾飽。", "負劍出門去，滿眼荒榛道。", "行行何所適，淚下沾襟袍。", "李生且收涕，不足苦悲悼。", "非無咸池音，夔曠世所少。", "不識伯樂氏，飛黄徧牛皁。", "我聞張侯者，其人非草草。", "六經探精微，九流得指要。", "荀況或言兵，杜牧曾深考。", "縱橫文武術，難以尋常較。", "磊磊公侯器，可以鎮浮躁。", "子將丈二矛，試向伊前掉。", "見子伊心喜，扶子出泥淖。", "王濟牛心炙，李生應得咬。"]'),
('714a50e5-6c1c-445e-bc23-e5a98c9fa1ac','乙亥冬富春先生以老儒醇師居我東齊濟北張泂明遠楚丘李縕仲淵皆服道就義與介同執弟子之禮北面受其業因作百八十二言相勉','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鳳凰飛來衆鳥隨，神龍遊處羣魚嬉。',208,'全唐诗/poet.song.16000.json','["鳳凰飛來衆鳥隨，神龍遊處羣魚嬉。", "先生道德如韓孟，四方學者爭奔馳。", "濟北張泂壯且勇，楚丘李縕少而奇。", "二子磊落頗驚俗，泰山石介更過之。", "三人堂堂負英氣，胸中拳攣蟠蛟螭。", "道可服兮身可屈，北面受業尊爲師。", "先生晨起坐堂上，口諷大易春秋辭。", "洪音琅琅響齒牙，鼓簧孔子與宓羲。", "先生居前三子後，恂恂如在汾河湄。", "續作六經豈必讓，焉無房杜廊廟資。", "吁嗟斯文敝已久，天生吾輩同扶持。", "二子勉旃吾不惰，先生大用終有時。", "當以斯文施天下，豈徒玩書心神疲。"]'),
('9232b36f-dbc5-4301-926e-98448b7ebfac','送路遵謁孔宣公','石介','宋','宋诗','song-poetry','','[]','薄田五頃餘，纔足共王租。',156,'全唐诗/poet.song.16000.json','["薄田五頃餘，纔足共王租。", "慈母八十四，髮白牙齒疎。", "服非帛不煖，半冬無褲襦。", "食非肉不飽，杯案惟一蔬。", "南陔孝子心，若何爲安居。", "方冬萬木折，北風裂人膚。", "凍死不敢言，長塗走崎嶇。", "二百里見我，寒荄求吹噓。", "顧我正憔悴，念子空勤劬。", "闕里有聖孫，佩服詩與書。", "孜孜行仁義，陰德及焦枯。", "三縣十萬人，其命絕而蘇。", "豈使八十老，旨甘不足歟。"]'),
('f1a7078b-a1be-458b-bdcb-994b90417900','過魏東郊','石介','宋','宋诗','song-poetry','','[]','全魏地千里，雄大視區宇。',288,'全唐诗/poet.song.16000.json','["全魏地千里，雄大視區宇。", "黄河爲血脈，太行爲筋膂。", "地靈育聖賢，土厚含文武。", "堂堂柳先生，生下如猛虎。", "十三斷賊指，聞者皆震怖。", "十七著野史，才俊淩遷固。", "二十補亡書，辭深續堯禹。", "六經皆自曉，不看注與疏。", "述作慕仲淹，文章肩韓愈。", "下唐二百年，先生固獨步。", "投篇動范杲，落筆驚王祜。", "四方交豪傑，羣公走聲譽。", "一上中高第，數年編士伍。", "五命爲御史，連出守方土。", "事業過皋夔，才能堪相輔。", "鳳凰世不容，衆鳥競嘲訴。", "獄中饑不死，特地生爪距。", "貔貅十萬師，盟津直北渡。", "塞上諸猛將，低頭若首鼠。", "渴憶海爲漿，饑思鼇爲脯。", "兩手拏人肝，大牀橫牛肚。", "一飲酒一石，賊來不怕懼。", "帳下立孫吳，罇前坐伊呂。", "笑談韜鈐閒，出入經綸務。"]'),
('7badb087-b938-443e-b0a0-adfb2dd5c205','蜀道自勉','石介','宋','宋诗','song-poetry','','[]','潮陽瘴煙黑，去京路八千。',156,'全唐诗/poet.song.16000.json','["潮陽瘴煙黑，去京路八千。", "吏部有大功，得罪斥守藩。", "朝衝江霧行，夜枕江濤眠。", "蛟蜃作怪變，時時攀船舷。", "魚龍吐火焰，往往出波閒。", "故爲相恐怖，倏忽千萬端。", "道在安可劫，處之自晏然。", "我乏尺寸効，月食二萬錢。", "自請西南來，此行非竄遷。", "蜀山險可升，蜀道高可緣。", "上無嵐氣蒸，下無波濤翻。", "步覺閣道穩，身履劒門安。", "惟懷吏部節，不知蜀道難。"]'),
('e8cc306a-c63a-4372-b056-c4d260b68e90','聞子規','石介','宋','宋诗','song-poetry','','[]','月上半峯峯樹碧，子規啼苦月無色。',240,'全唐诗/poet.song.16000.json','["月上半峯峯樹碧，子規啼苦月無色。", "壯士耳邊都不聞，兒女眼中淚自滴。", "古人出處非關身，處兮事親出事君。", "服勤至死不敢倦，避勞擇逸豈所聞。", "我看蜀道誠爲難，嗟爾子規何云云。", "王尊九折竟叱馭，班超萬里圖立勳。", "乘危蹈險盡臣節，二人至今揚清芬。", "我本魯國一男子，少小氣志凌浮雲。", "精誠許國貫白日，有心致主爲華勛。", "位卑身賤難自達，滿腹帝典與皇墳。", "有時憤懣吐一言，小人謗議已紛紛。", "宰相寬容天子慈，八年之中三從軍。", "從軍官清吾何苦，嘉州路遠爾勿語。", "地不爲我易其險，我豈守道不能固。", "子規子規謾啼絕，斷無清淚洒向汝。"]'),
('9ae0e412-cf5c-4852-8a05-cf56b3d9d277','哀鄰家','石介','宋','宋诗','song-poetry','','[]','鄰家不選醫，醫無救病術。',64,'全唐诗/poet.song.16000.json','["鄰家不選醫，醫無救病術。", "朝一醫工入，暮一醫工出。", "有加而無瘳，遑遑不安室。", "吁嗟鄰翁愚，予爲病者恤。", "瞽醫一日更千人，盲藥何能療沈疾。"]'),
('7ff67377-bd56-433f-9d06-4be64d8fa2e1','送趙澤','石介','宋','宋诗','song-poetry','','[]','子來入吾圃，纔食一寸苗。',66,'全唐诗/poet.song.16000.json','["子來入吾圃，纔食一寸苗。", "未足充子腹，饑腸猶枯焦。", "玉山禾粒大如棗，食之令人身肥饒。", "留以待鳳凰，不將食鴟梟。", "吾子何日回，遺子一粒換肝膋。"]'),
('cd55c30e-f429-4834-a268-dcd4da198e16','觀碁','石介','宋','宋诗','song-poetry','','[]','人皆稱善弈，伊我獨不能。',132,'全唐诗/poet.song.16000.json','["人皆稱善弈，伊我獨不能。", "試坐觀勝敗，白黑何分明。", "運智奇復詐，用心險且傾。", "嗟哉一枰上，奚足勞經營。", "安得百萬騎，鐵甲相磨鳴。", "西取元昊頭，獻之天子庭。", "北入匈奴域，縛戎王南行。", "東逾滄海東，射破高麗城。", "南趨交趾國，蠻子輿櫬迎。", "盡使四夷臣，歸來告太平。", "誰能憑文楸，兩人終日爭。"]'),
('554ef63f-015e-4029-83f9-ec1bdcfce0eb','贈劉中都','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾登泰山上，下視何紛紛。',132,'全唐诗/poet.song.16000.json','["吾登泰山上，下視何紛紛。", "彼角而走者，孰爲麟與麏。", "彼茁而生者，孰爲蕭與芸。", "伯樂不復出，駑驥終同羣。", "卞和不再生，珉玉將誰分。", "吁哉劉中都，高標凌浮雲。", "諸侯不薦士，外府不策勳。", "冉冉趨黄綬，勤勞徒爾云。", "我媿勢力小，不能叫吾君。", "勿改芳蘭性，林深須自薰。", "勿隠冲鶴聲，天高當自聞。"]'),
('84534e8b-d611-49cc-b3d9-951d81a13434','感事','石介','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','吾嘗觀中夏，地平如砥石。',288,'全唐诗/poet.song.16000.json','["吾嘗觀中夏，地平如砥石。", "幅員數萬里，車馬通轍迹。", "帝宅居土中，紫垣當辰極。", "長江斷其南，絕塞經其北。", "東海西流沙，天爲限夷狄。", "三代千餘年，天子雖務德。", "實以險爲恃，四夷皆潛匿。", "漢唐德稍衰，地勝豈殊昔。", "暫來還亟去，不敢窺城壁。", "石晉一失謀，六州淪胡域。", "天地破扃鐍，山川無阻阨。", "貽爾子孫患，固知非遠策。", "桓桓周世宗，三十纂堯曆。", "一歲破河東，劉崇喪精魄。", "再歲復秦鳳，不庭自柔格。", "三歲出南狩，王師拯焚溺。", "江北十四州，取之如卷席。", "四歲征關南，曾不發一鏑。", "三州相繼降，德聲暢蠻貊。", "李昪請臣妾，錢鏐修貢職。", "帝欲因兵鋒，乘勝務深擊。", "直取幽州城，拓土開疆埸。", "重收虎北口，復關閉寇賊。", "是時戰屢捷，六軍氣吞敵。"]'),
('e8393e20-4e8e-420c-99b9-20b6a44bf2be','送張革從道謁千乘縣田祕丞京','石介','宋','宋诗','song-poetry','','[]','張生何人者，琅玕滿懷抱。',144,'全唐诗/poet.song.16000.json','["張生何人者，琅玕滿懷抱。", "三十命未興，家貧親且老。", "出門無所適，獨守西山操。", "饑寒屢侵凌，仁義自充飽。", "手裏璆琳枝，不換徑寸草。", "足底麒麟文，不踏荒榛道。", "十月客路寒，霜風鳴浩浩。", "張生氣愈壯，勁髮上衝帽。", "松筠凍不折，枝葉轉青好。", "雪深徒三尺，麟麒不受淖。", "東方有賢者，開廐納騕褭。", "臨風試一鳴，應免編牛皁。"]'),
('b84fe335-c993-4753-ad90-8dde13802810','送范曙赴天雄李太尉辟命  其一','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾家泰山徂徠間，濃嵐潑翠粘衣冠。',112,'全唐诗/poet.song.16000.json','["吾家泰山徂徠間，濃嵐潑翠粘衣冠。", "君來訪我茅屋下，正值山色含春寒。", "終日把酒對山坐，幾片山色落酒盤。", "峯頭雲好望無倦，篘裏酒多傾不乾。", "臨行再拜慇勤別，請我一言披心肝。", "吾貧無錢以贈君，門前峨峨橫兩山。", "願君節似兩山高，眼看富貴如鴻毛。"]'),
('98e4edc5-16bf-4a92-a3c1-d3dbfc9d18d3','送范曙赴天雄李太尉辟命  其二','石介','宋','宋诗','song-poetry','','[]','伯樂之廐無駑駘，豫章之林多瑰材。',112,'全唐诗/poet.song.16000.json','["伯樂之廐無駑駘，豫章之林多瑰材。", "相君新坐碧油幢，之子直上黄金臺。", "秋風蕭蕭動笳皷，落葉摵摵鳴罇罍。", "將軍手持十萬騎，陣前號令如疾雷。", "從事借籌爲决勝，運於掌上何恢恢。", "蠢茲元昊命螻蟻，西師堂堂難當哉。", "況我賢相賢從事，北門無憂宜大開。"]'),
('7b5bba45-bf38-4a65-a550-30d35f6b0479','安道登茂材異等科','石介','宋','宋诗','song-poetry','','[]','嘗言春官氏，設官何齷齪。',288,'全唐诗/poet.song.16000.json','["嘗言春官氏，設官何齷齪。", "屑屑取於人，辭賦爲程約。", "一字競新奇，四聲分清濁。", "矯矯遷雄才，動爲對偶縛。", "恢恢晁董策，亦遭聲病落。", "每歲棘籬上，所得多浮薄。", "嗟哉浮薄流，不知王霸略。", "六經掛東壁，三史束高閣。", "瑣瑣事雕篆，區區衍述作。", "隨行登一第，謂身翥寥廓。", "趨衆得一官，謂身縻好爵。", "栖栖咫尺地，燕雀假安託。", "汲汲五斗米，鴈鶩資飲啄。", "壯哉張安道，少懷夫子學。", "三就禮部試，不肯露頭角。", "恥用衆人遇，羞將一賦較。", "甘心搨翼歸，志懷本卓犖。", "三賢文章師，儒林推先覺。", "百鳥聲喈喈，獨能辨鸑鷟。", "玉石方混混，獨能識至璞。", "薦之于天子，此材堪輪桷。", "遂得望清光，三接近帷幄。", "僚友視萬乘，器宇誠嶽嶽。", "願乞數刻景，古今可揚榷。"]'),
('1a0fcb1a-7010-4d2c-b260-f161b75908f1','寄明復熙道','石介','宋','宋诗','song-poetry','','[]','四五十年來，斯文何屯蹇。',288,'全唐诗/poet.song.16000.json','["四五十年來，斯文何屯蹇。", "雅正遂彫缺，浮薄競相扇。", "在上無宗主，淫哇千萬變。", "後生益纂組，少年事彫篆。", "仁義僅消亡，聖經亦離散。", "其徒日已多，天下過大半。", "路塞不可闢，甚於楊墨患。", "辭之使廓如，才比孟子淺。", "患大恐不救，有時淚如霰。", "大賢爲時生，去聖猶未遠。", "昔日到汶上，熙道始相見。", "知道在熙道，一見不敢慢。", "尊之如韓孟，與道作藩翰。", "今春來南都，明復去京輦。", "未識心相通，所懷恨未展。", "明復無羈縛，我有守官限。", "南走三百里，訪我殊不倦。", "劇談露胸臆，胸臆無畔岸。", "高文見事業，事業盈編簡。", "一一皇霸略，縱橫小管晏。", "磊磊王相才，上下包周漢。", "二賢信命世，實爲有道見。", "天使扶斯文，淳風應可逭。", "我綴二賢末，材駑媿款段。"]'),
('e4299a1b-3c0d-416f-884f-e25ec99fcca1','詔下勉諸生','石介','宋','宋诗','song-poetry','','[]','禮部文章淵，波浪百尺高。',132,'全唐诗/poet.song.16000.json','["禮部文章淵，波浪百尺高。", "進士英俊窟，蛟龍千萬條。", "吾子欲求濟，整子棹與篙。", "吾子欲求勝，操子戈與矛。", "勿謂水可狎，徒行思遊遨。", "勿謂龍可馴，空手捋鬚毛。", "波神忽洶湧，怖死填蟹螯。", "龍角忽張怒，走同蝦蟆曹。", "苟利篙楫往，跳海如溝濠。", "苟操戈矛行，拉蛟如猿猱。", "吾言有所勉，非徒聲嘈嘈。"]'),
('c1ce2491-9bb2-4d4e-af7b-e39c31ebaef9','感興','石介','宋','宋诗','song-poetry','','[]','村居何所適，種木樹桑梓。',252,'全唐诗/poet.song.16000.json','["村居何所適，種木樹桑梓。", "田園繞家舍，遠不逾十里。", "款段足乘騎，代步而已矣。", "但識畜駑駘，安知有騏驥。", "臘月北風寒，太行山色紫。", "君命急如火，城頭見烽燧。", "雪深馬僵倒，十夫扶不起。", "軍法有明訓，後期者誅死。", "倚鞍思駿骨，撫轡念綠駬。", "求之不可得，觳觫滿眼淚。", "旁聞負薪叟，竊語相譏刺。", "居安常念危，在險如處易。", "臨難始求濟，狼狽徒勞爾。", "有備則無患，古人垂深旨。", "平居無事時，華廐深祕邃。", "善穀與豐草，秣飼十廐吏。", "駑駘飽相枕，素餐不知媿。", "伯樂能識馬，每來加勸說。", "飛兔與騕褭，日牽在都市。", "爲愛千金資，貪悋不肯置。", "今日臨艱難，努力自勉勵。"]'),
('ef0039d6-9301-42c9-8ab5-676b2e9afe89','又送從道','石介','宋','宋诗','song-poetry','','[]','常欲飽煖天下人，其道未得一寸施。',128,'全唐诗/poet.song.16000.json','["常欲飽煖天下人，其道未得一寸施。", "子有二親皆七十，糠覈不充常寒饑。", "昨日訪我破屋下，具雞一隻酒一巵。", "子起却盤筯不舉，吾親未省曾食之。", "對我噓嚱涕泗下，孝子之心真可悲。", "子固與我同一體，相間豈復有毛皮。", "顧子之親則吾親，吾親凍餒無柰何。", "飽煖天下心徒爲，送子出門成此詩。"]'),
('998e6a1f-ae31-44ae-a885-5431ae6f560b','密直杜公作鎮于魏天章李公領使于魏明復先生客于魏熙道宰于魏因作詩寄之','石介','宋','宋诗','song-poetry','','[]','古魏信名地，曹劉遺英躅。',288,'全唐诗/poet.song.16000.json','["古魏信名地，曹劉遺英躅。", "李唐三百年，悵爲干戈蹴。", "建安風不還，南皮草空綠。", "寥寥千餘祀，風流今始續。", "李杜二賢公，清猷鎮雅俗。", "詩名占唐代，二公本名族。", "聖時還並生，聲烈相薰馥。", "朝廷倚金湯，天子恃心腹。", "盛德繫物懷，威望憬夷服。", "千里無驚烽，三軍安食粟。", "休然德化厚，蒼生坐蒙福。", "先生服仁義，懷道輕爵祿。", "非其人不取，一簞亦自足。", "陳蕃知人明，文侯好士篤。", "解榻延徐孺，過門軾干木。", "今留二公館，德脩令問淑。", "熙道富天爵，孝悌聞鄉曲。", "孔孟信可蹈，聖賢良自勗。", "漢庭新射策，驟升校書局。", "魏縣方百里，君命往養育。", "二公佐世傑，二賢不碌碌。", "相與施禮讓，物歸不待宿。", "相與講道義，教行如流速。", "賢人時遘會，間不容薄縠。"]'),
('be25d6a0-f93e-4652-acb3-a16a8b7ab785','偶作','石介','宋','宋诗','song-poetry','','[]','晉公平淮西，兵出速如神。',180,'全唐诗/poet.song.16000.json','["晉公平淮西，兵出速如神。", "崇韜伐西川，六十日請臣。", "太祖初受命，諸侯未盡賓。", "蜀廣號敵國，荆潭爲彊鄰。", "王師討有罪，不聞逾十旬。", "元昊誠螻蟻，有地長一畛。", "詎足污斧鉞，尋當投荆榛。", "是何逾歲月，務行含貸仁。", "豈茲將帥間，逈無晉公倫。", "張旗發一號，豈無李處耘。", "提戈出一戰，豈無王全斌。", "容茲盈寸蟹，蕩漾於流津。", "平生讀詩書，胸中貯經綸。", "薄田四五畝，甘心耕耨勤。", "倚鉏西北望，涕淚空沾襟。"]'),
('c7b445ca-63d4-44d8-85e2-5b8a184a1445','詔罷縣令舉','石介','宋','宋诗','song-poetry','','[]','一絃獨不調，謂琴皆可廢。',64,'全唐诗/poet.song.16000.json','["一絃獨不調，謂琴皆可廢。", "一目獨不張，謂網皆可毀。", "易絃張其目，網在琴聲遂。", "舉令或非人，止當罪舉吏。", "遂令天下不得舉，廢琴毀網復何異。"]'),
('db1e5a24-b5b7-426a-97dc-cf7a6ede7cb8','植萱','石介','宋','宋诗','song-poetry','','[]','一人橫行，武王則羞。',68,'全唐诗/poet.song.16000.json','["一人橫行，武王則羞。", "今西夷之鬼，抗中國而敵萬乘。", "西夷之服，升黄堂而驕諸侯。", "尊於天子，滿於九州。", "王法不禁，四民不收。", "植萱於階兮，庶忘吾憂。"]'),
('246b2ef8-7103-4935-8876-8f34514dcdb4','贈李常李堂','石介','宋','宋诗','song-poetry','','[]','顓頊宅帝丘，放勛葬成陽。',216,'全唐诗/poet.song.16000.json','["顓頊宅帝丘，放勛葬成陽。", "有虞漁雷澤，三帝聲汪洋。", "聖人遺風烈，生民多材良。", "吾宋八十年，賢傑近相望。", "黄州號辭伯，兩朝專文章。", "尚書實大臣，朝廷畏雄剛。", "堂堂高夫子，立言肩荀揚。", "凜凜李丞相，功業齊蕭張。", "三人名未泯，相國方騰驤。", "又生不世才，李常與李堂。", "二子皆絕羣，鳳凰摩蒼蒼。", "一舉一萬里，志氣不可量。", "新文各百首，寒金敲琳琅。", "古音抱淳澹，雲和與空桑。", "豪氣邁儔匹，騕褭與飛黄。", "千里希一賢，四公乃同鄉。", "二子復穎耀，士風實深長。", "遥知濮水上，千載流聲光。"]'),
('423391de-91e7-43be-a98d-190d2703067d','愛日勉諸生','石介','宋','宋诗','song-poetry','','[]','白日如奔驥，少年不足恃。',43,'全唐诗/poet.song.16000.json','["白日如奔驥，少年不足恃。", "汲汲身未立，忽焉老將至。", "子試念及此，則晝何暇乎食，夜何暇乎寐。"]'),
('9350039d-ec2c-4006-9dcb-892099b8e892','閑興','石介','宋','宋诗','song-poetry','','[]','大匠構厦屋，取直棄曲木。',48,'全唐诗/poet.song.16000.json','["大匠構厦屋，取直棄曲木。", "如何官擇人，棄直獨取曲。", "養苗除稂莠，養民除貪垢。", "存莠苗不碩，去貪民自富。"]'),
('1866ff59-5544-4c9f-b69d-c428ea98b1e9','過潼關','石介','宋','宋诗','song-poetry','','[]','昔帝御中原，守國用三策。',168,'全唐诗/poet.song.16000.json','["昔帝御中原，守國用三策。", "上策以仁義，天下無能敵。", "其次樹屏翰，相維如盤石。", "最下恃險固，棄德任智力。", "驅馬過潼關，覽古淚潸滴。", "開元帝道明，百蠻奉周曆。", "田野富農桑，邊隅無寇賊。", "紫宸日視朝，潼關夜常闢。", "天寶君政荒，宮闈養虺蜴。", "恩愛成怨疾，心腹生毒螫。", "朝聞發漁陽，暮已卷河北。", "鳴鼓渡潼關，矢及乘輿側。", "重門徒爾設，關吏安所職。", "始知資形勢，不如脩道德。"]'),
('729e581b-b081-4454-ad33-0cf30f8ef5d0','勉師愚等','石介','宋','宋诗','song-poetry','','[]','不行一千里，安得爲良馬。',84,'全唐诗/poet.song.16000.json','["不行一千里，安得爲良馬。", "不連十五城，安得稱善價。", "汝皆有血氣，非如木偶者。", "撮髮號男兒，肯甘在人下。", "汝不聞圖王，不成猶可霸。", "舜與吾俱人，學之則舜也。", "汝等但勉旃，前賢皆可亞。"]'),
('7673363a-23ce-40e8-896e-08abce2a3d59','寄弟會等','石介','宋','宋诗','song-poetry','','[]','吾門何所喜，子衿青青多。',204,'全唐诗/poet.song.16000.json','["吾門何所喜，子衿青青多。", "豹常志古道，佩服卿與軻。", "平淑號能賦，其氣典以和。", "樞從吾日久，道德能切磋。", "澤也齒最少，已有亭亭柯。", "彰頗通典籍，所立不幺麽。", "淳乎性源濁，今亦爲清波。", "就初學誦詩，日記十板過。", "材雖有高下，異日俱甲科。", "會汝少俊異，美若玉山禾。", "看汝辭林中，枝條漸婆娑。", "合亦稍純茂，知不隨身矬。", "其流雖涓涓，可道爲江沱。", "視汝器磊磊，淳沆皆蚌螺。", "我有堇山錫，欲鑄子太阿。", "誠能來就學，穎利加銛磨。", "翹翹數子間，可與肩相摩。"]'),
('7a9d97e5-a42a-4c75-8624-9bd198e537e8','五月十日雨','石介','宋','宋诗','song-poetry','','[]','鞭下不見血，頑石雲不蒸。',48,'全唐诗/poet.song.16000.json','["鞭下不見血，頑石雲不蒸。", "鞭龍不至痛，六合雷不勝。", "吾君與吾相，威德震八紘。", "萬物各脩職，雨師獨敢寧。"]'),
('40825294-e30b-48f8-a798-ae3a00bcd94c','送李堂病歸','石介','宋','宋诗','song-poetry','','[]','春風汶水溫，曉日徂徠寒。',168,'全唐诗/poet.song.16000.json','["春風汶水溫，曉日徂徠寒。", "之子銜病歸，請予開一言。", "予知去病術，爲子陳大端。", "予嘗學聖人，試將道比論。", "道病非一日，善醫惟孔韓。", "賞罰絕于周，孔筆誅其姦。", "春秋十二經，王道復全完。", "佛老熾于唐，韓刀斷其根。", "原道千餘言，生民復眠餐。", "道病由有弊，邪僞容其間。", "身病由有隙，風邪來相干。", "子欲治斯道，絕弊道乃存。", "子欲治子身，杜隙身乃安。", "此理近古醫，吾言有本原。"]'),
('92f68c3b-0098-47ec-84ad-ee61b867850b','三子以食貧困於藜藿爲詩以勉之','石介','宋','宋诗','song-poetry','','[]','吾世本寒賤，吾身守貧約。',144,'全唐诗/poet.song.16000.json','["吾世本寒賤，吾身守貧約。", "家徒立四壁，無田負城郭。", "終歲服一衣，無裝貯囊橐。", "吾雖得一官，官微月俸薄。", "況屬歲凶荒，饑民填溝壑。", "吾幸有寸祿，不至苦隕穫。", "隨分且飽煖，不然亦流落。", "爾等勤初學，旡恥衣食惡。", "仁義足飽飫，道德堪咀嚼。", "二者肥爾軀，不同乳與酪。", "爾無嫌粗糲，爾勿厭藜藿。", "富貴自努力，青雲路非邈。"]'),
('180ca6a2-0fec-4aa2-b7e6-3955b5418692','蜀地多山而少平田因有云','石介','宋','宋诗','song-poetry','','[]','五穀無種處，蜀民土田窄。',28,'全唐诗/poet.song.16000.json','["五穀無種處，蜀民土田窄。", "癡巖頑石長不休，詵詵赤子將何食。"]'),
('63e405f3-6d40-4b9e-92c9-5350fc7402e9','彼縣吏','石介','宋','宋诗','song-poetry','','[]','嗟乎嗟乎彼縣吏，剝膚椎髓民將死。',64,'全唐诗/poet.song.16000.json','["嗟乎嗟乎彼縣吏，剝膚椎髓民將死。", "夏取麥兮秋取粟，笞匹紅兮杖匹紫。", "酒臭甕兮肉爛床，馬餘粱兮犬餘餼。", "雀腹鼠腸容幾何，虎噬狼貪胡無已。"]'),
('4fc39f77-8e51-4d29-8773-a6da71cb4e2c','蝦蟆','石介','宋','宋诗','song-poetry','','[]','夏雨下數尺，流水滿池泓。',212,'全唐诗/poet.song.16000.json','["夏雨下數尺，流水滿池泓。", "蝦蟆爲得時，晝夜鳴不停。", "幾日飽欲死，腹圓如罌瓶。", "巨吻自開闔，短項或縮盈。", "時於土坎間，突出兩眼睛。", "是何癡形骸，能吐惡音聲。", "嗟哉爾肉膻，不中爲犧牲。", "嗟哉爾聲粗，不中和人情。", "殊不自量力，更欲睥睨橫海之鱣鯨。", "自謂天地間，獨馳善鳴名。", "萬物聒皆龏，不知鐘鼓欽欽，雷霆閎閎。", "應龍戢腦入海底，鳳凰舉翼摩青冥。", "此時各默默，以避蝦蟆鳴。", "何時雨歇水澤涸，青臭泥中露醜形。", "失水無能爲，兩脚不解行。", "乾渴以至死，盡把枯殻填土坑。"]'),
('f61171a0-39b9-46f9-99a3-7c882ba94e7e','劉生病歸','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山山前有瓊圃，其中不樹蕨與薇。',112,'全唐诗/poet.song.16000.json','["泰山山前有瓊圃，其中不樹蕨與薇。", "千頭綠竹瑶實甘，百畝玉芝丹粒肥。", "麒麟于于鳳凰飽，鼓翅奮臆揚清輝。", "徂徠山下少耕鋤，蒿藜滿圃無芳菲。", "騶虞不住鸞鳥去，日暮啁啾燕雀飛。", "嗟哉劉生失所投，不住泰山徂徠依。", "經年採掇不得飽，正是新春癯瘠歸。"]'),
('cdcef629-ca68-4f60-a564-9ca2f611b929','久旱','石介','宋','宋诗','song-poetry','','[]','風伯且須戢頭角，放出龍喙萬丈長。',32,'全唐诗/poet.song.16000.json','["風伯且須戢頭角，放出龍喙萬丈長。", "喙垂一尺雨一尺，得雨萬丈成豐穰。"]'),
('253ba083-0e17-4d18-b2e0-e9616d3c0aca','永伯仲淵在獄作九十二言傷之','石介','宋','宋诗','song-poetry','','[]','吁嗟惡獸羣，蹄踏麒麟如死麏。',106,'全唐诗/poet.song.16000.json','["吁嗟惡獸羣，蹄踏麒麟如死麏。", "吁嗟惡鳥音，啅噪鳳凰伏中林。", "我願爪牙如鋒鍔，牙可噬兮爪可搏。", "直入深山驅虎狼，護取麒麟好頭角。", "又願身生兩羽翼，一夕長就萬丈長。", "直入林中護鳳凰，不使毛羽膚寸傷。", "吾願兩未遂，中夜涕下沾衣裳。"]'),
('e7b17a8d-f9b4-48cb-99e3-3a732eadd5c0','送進士高樞拱辰','石介','宋','宋诗','song-poetry','','[]','韓門有李漢，柳氏得晦之。',168,'全唐诗/poet.song.16000.json','["韓門有李漢，柳氏得晦之。", "其道卒無患，二子爲藩離。", "吾才誠駑弱，十年空孜孜。", "韓閫與柳閾，豈敢輒潛窺。", "二氏方肆行，斯文日已衰。", "手持萬丈斧，欲往斷其枝。", "以次及根柢，使不復蕃滋。", "高生吾之壻，乃肯從吾爲。", "示我文一編，言辭不葳蕤。", "翅羽雖尚短，已去磨尾箕。", "氣力雖未全，已能搏蛟螭。", "吾日覺老大，韓柳難企斯。", "吾子年始壯，勇若熊與羆。", "李漢不足慕，晦之當並馳。"]'),
('6eb15cfa-4407-487c-8afc-73875914d407','讀韓文','石介','宋','宋诗','song-poetry','','[]','眇焉五帝上，嘗觀二典辭。',276,'全唐诗/poet.song.16000.json','["眇焉五帝上，嘗觀二典辭。", "煥乎三王間，嘗觀二雅詩。", "道德既淳厚，聲光何葳蕤。", "烈烈日精散，閎閎雷聲施。", "施焉如飛龍，潜焉如蟠螭。", "祖述兼憲章，後世唯吾師。", "永言二典往，羣言或隳離。", "亦既二雅末，六義多陵遲。", "寥寥千餘年，顛危誰扶持。", "揭揭韓先生，雄雄周孔姿。", "披榛啟其塗，與古相追馳。", "沿波窮其源，與道相濱涯。", "三墳言其大，十翼暢其微。", "先生書之辭，包括無孑遺。", "春秋一王法，曲禮三千儀。", "先生載於筆，巨細咸羈縻。", "楊墨乃淪胥，曠然彰其媸。", "佛老亦顛隮，茫然復於夷。", "婉婉平蔡畫，淮西獲以依。", "淩淩逐鱷文，潮民蒙其禧。", "心將元化合，功與天地齊。", "洋洋治世音，磊磊王化基。", "悖之則幽厲，順之則軒羲。"]'),
('713fc96d-0e7d-4577-9494-e13ad4e845b8','讀石安仁學士詩','石介','宋','宋诗','song-poetry','','[]','齊梁無駿骨，李杜得秋毫。',48,'全唐诗/poet.song.16000.json','["齊梁無駿骨，李杜得秋毫。", "後世益纂組，變風堪鬰陶。", "奔遒少驥逸，禿冗如牛毛。", "試看安仁詠，秋風有怒濤。"]'),
('bd16fd97-8fc9-4196-9c07-4b6247cfa9d7','寄雷澤張從道','石介','宋','宋诗','song-poetry','','[]','不知有凍死，一室心恬如。',48,'全唐诗/poet.song.16000.json','["不知有凍死，一室心恬如。", "臘盡妻未褐，天寒子讀書。", "澆風與世薄，古道于時疎。", "事事皆同我，憶君春草初。"]'),
('2b3a3c39-fd55-476b-917e-ddbde3b2831c','竹書筒  其一','石介','宋','宋诗','song-poetry','','[]','截竹功何取，爲筒妙可談。',192,'全唐诗/poet.song.16000.json','["截竹功何取，爲筒妙可談。", "長猶不盈尺，青若出於藍。", "浮薄瓤皆去，嶔崟節獨堪。", "誰言但空洞，自是貴包含。", "虛受殊招損，多藏不類貪。", "巾箱經謾五，謗牘篋空三。", "淚有湘妃灑，書疑禹穴探。", "質曾冒霜雪，價本擅東南。", "隕籜遺輕粉，移根破凍嵐。", "龍音終不死，鳳實尚餘甘。", "僕陋我爲貴，彫鎪彼合慙。", "居常置几桉，出或繫騑驂。", "唱和友朋倦，提携童僕諳。", "純姿斥丹漆，美幹敵楩枏。", "其直如周道，虛心學老耼。", "吾徒正得用，詩筆戰方酣。"]'),
('e104a63f-dcfe-46d2-b1d3-4f09b0c85b04','竹書筒  其二','石介','宋','宋诗','song-poetry','','[]','達者創奇製，霜圓斷竹尋。',120,'全唐诗/poet.song.16000.json','["達者創奇製，霜圓斷竹尋。", "蒼筤破雲色，蕭瑟移風音。", "徑寸不爲短，探幽乃覺深。", "中間自空洞，枝幹何嶔崟。", "投恐成龍去，吹還作鳳吟。", "稜稜人有節，竅竅物無心。", "儉樸他難比，提携力易任。", "絕姿古皇道，虛受聖人襟。", "或貯諫官草，多收女史箴。", "筒兮用可貴，吾不換南金。"]'),
('e9f3ec82-d530-4d5c-9d01-c2199cf35416','訪田公不遇','石介','宋','宋诗','song-poetry','','[]','主人何處去，門外草萋萋。',48,'全唐诗/poet.song.16000.json','["主人何處去，門外草萋萋。", "獨犬睡不吠，幽禽閑自啼。", "老猿偷菓實，稚子弄鋤犁。", "日暮園林悄，春風吹藥畦。"]'),
('02c7ac2e-0ebf-4225-abed-e5e0ab346789','蘇唐詢秀才晚學於予告歸以四韻勉之','石介','宋','宋诗','song-poetry','','[]','憐我山中卧，半年相伴吟。',48,'全唐诗/poet.song.16000.json','["憐我山中卧，半年相伴吟。", "道傳諸子後，易得數爻深。", "爨或經旬絕，書猶盡日尋。", "惜哉未終業，親老忽分襟。"]'),
('c45b7b50-cbeb-489f-9cf4-11812875f97e','獵','石介','宋','宋诗','song-poetry','','[]','騎士千人集，綏旌四面張。',120,'全唐诗/poet.song.16000.json','["騎士千人集，綏旌四面張。", "凝陰慘羣物，殺氣結飛霜。", "雉守一節死，兔緣三穴藏。", "石慙羊質見，狐歎虎威亡。", "獸困猶思鬭，鴻驚不亂行。", "唯當縱猛鷙，盡使食貪狼。", "意務除田害，誰言事外荒。", "非熊得呂望，祝網遇成湯。", "近念魏知古，深思夏太康。", "吾君戒馳騁，纘事合經常。"]'),
('6d02f9c7-d97b-45b1-a483-42b3e524b1c1','大寒早行','石介','宋','宋诗','song-poetry','','[]','萬動皆休迹，五更獨鳴鞭。',151,'全唐诗/poet.song.16000.json','["萬動皆休迹，五更獨鳴鞭。", "星霜結淒色，風霰過長川。", "草暖犬猶睡，河冰馬不前。", "城牆多有穴，村屋半無煙。", "餓虎寒猶吼，妖狐怪不眠。", "山空亂猿叫，樹折一雞顛。", "幾處爐爣炭，何人坐有[H。", "70x]氊。", "崎嶇轉行路，凜冽逼窮年。", "脚指兩箇落，衫裳百孔穿。", "噓唏鼻纔潤，僵直手難拳。", "身固凍不死，志當窮且堅。", "四方丈夫事，誰爲淚潺湲。"]'),
('8dcc23c1-6a48-462e-8b83-dd8be2eb5737','遊靈泉山寺','石介','宋','宋诗','song-poetry','','[]','寺遠離朝市，同遊並結軨。',216,'全唐诗/poet.song.16000.json','["寺遠離朝市，同遊並結軨。", "堦垠盤石磴，殿影落青冥。", "地勝松筠衆，山名草藥靈。", "洞門深數里，檜樹壽千齡。", "疑有神仙聚，甯容魑魅停。", "年多養龍虎，早已蟄雷霆。", "石上生苔蘚，岩阿長茯苓。", "晴雲出幽竇，陰霧滑疎櫺。", "露滴茶芽潤，煙蒸竹汗青。", "餐霞充道味，採朮驗丹經。", "直擬陞高處，何妨陟絕陘。", "遐觀際寥廓，下視何羶腥。", "自被利名染，無因肺腑醒。", "晨興看桉牘，夜坐守窗螢。", "齪齪遵前訓，兢兢視此銘。", "沉冥若籠鳥，囚縶似拘囹。", "有願棲雲壑，相隨步翠坰。", "平生山野性，暫喜據梧瞑。"]'),
('4da0f051-4adc-4a44-b93e-5c6eadf55f5b','至日早離張村','石介','宋','宋诗','song-poetry','','[]','北闕千官集，南山萬壽長。',48,'全唐诗/poet.song.16000.json','["北闕千官集，南山萬壽長。", "何人踐文石，獨客踏寒霜。", "指凍只憂落，馬羸時恐僵。", "豐凶卜來歲，猶喜矞雲黄。"]'),
('1b9cd3a0-5027-4917-b8c2-4bb7d5f16725','歲晏村居','石介','宋','宋诗','song-poetry','','[]','歲晏有餘糧，杯盤氣味長。',48,'全唐诗/poet.song.16000.json','["歲晏有餘糧，杯盤氣味長。", "天寒酒脚落，春近臛頭香。", "菜色青仍短，茶芽嫩復黄。", "此中得深趣，真不羨膏粱。"]'),
('ca816c29-05f1-445f-a707-dc1aa6ddfaa8','病起吟殘菊','石介','宋','宋诗','song-poetry','','[]','病起重陽過，東籬菊尚黄。',48,'全唐诗/poet.song.16000.json','["病起重陽過，東籬菊尚黄。", "慇懃擷寒蕊，子細嗅清香。", "老梗防閑蝶，清油護曉霜。", "叢邊强一酌，聊不負秋光。"]'),
('60685c91-226c-4138-ac15-9139ade1bd25','和馬寺丞秋日寄明復先生','石介','宋','宋诗','song-poetry','','[]','秋陰閉秋色，何處動悲凉。',48,'全唐诗/poet.song.16000.json','["秋陰閉秋色，何處動悲凉。", "有叟傅巖隠，明時潘鬢蒼。", "殘書幾篋蠹，寒菊半籬荒。", "惟學春秋者，時時到草堂。"]'),
('f21ab20a-7d4c-4ce2-a201-387641c9fefc','嶽色','石介','宋','宋诗','song-poetry','','[]','春近滿魯分，雨餘堆汶河。',48,'全唐诗/poet.song.16000.json','["春近滿魯分，雨餘堆汶河。", "濃雲映不盡，殘照射來多。", "高與天臨縣，閑臨月上坡。", "特開西北戶，愛此鬰嵯峨。"]'),
('a6bdc3b8-7d3c-46a9-9603-7c81bc65aaef','宿村舍','石介','宋','宋诗','song-poetry','','[]','去去都城遠，蕭蕭村落秋。',72,'全唐诗/poet.song.16000.json','["去去都城遠，蕭蕭村落秋。", "饑鴟啄死鹿，鳴犢隨孳牛。", "轉徙多空屋，荒榛有亂丘。", "狐狸競恐怖，雀鼠仍啁啾。", "鬼火時明滅，旋風乍卷收。", "吾心不吐茹，忠信待姦仇。"]'),
('f31bbff2-ffc4-48cc-9d42-7b792485c1c8','和奉符知縣馬寺丞永伯捕蝗回有作','石介','宋','宋诗','song-poetry','','[]','天道不可詰，吾當責爾螟。',48,'全唐诗/poet.song.16000.json','["天道不可詰，吾當責爾螟。", "方今絕讒慝，何故播膻腥。", "野草離離盡，秋禾穗穗零。", "知君恤民意，鬢減數莖青。"]'),
('f19280e9-cb80-40a6-9318-0255e289f74e','泰山','石介','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','七百里魯望，北瞻何巖巖。',48,'全唐诗/poet.song.16000.json','["七百里魯望，北瞻何巖巖。", "諸山知峻極，五嶽獨尊嚴。", "寰宇登來小，龜蒙視覺凡。", "此爲羣物祖，草木莫鋤芟。"]'),
('5f071d88-37d8-4505-b95b-da0287ec1d00','留守待制視學  其一','石介','宋','宋诗','song-poetry','','[]','藝祖興王地，諸侯布教宮。',144,'全唐诗/poet.song.16000.json','["藝祖興王地，諸侯布教宮。", "冠纓臨曉集，文雅與時隆。", "泮水差差綠，春沂習習風。", "袍輝了衿動，旗映講紗紅。", "節鉞來門外，聲容播國中。", "分庭等威殺，更僕宴談終。", "亹亹聞諄誨，拳拳激懦衷。", "武昌尊庾亮，蜀郡樂文翁。", "王化周南始，儒縫魯俗通。", "四方觀表則，後學發童蒙。", "木鐸傳遺韻，緇衣纘舊功。", "願公持此道，黄閣弼清躬。"]'),
('e92795a3-e12e-4f82-8bc1-48ddb8c8083b','留守待制視學  其二','石介','宋','宋诗','song-poetry','','[]','演道開談席，觀文降使轓。',48,'全唐诗/poet.song.16000.json','["演道開談席，觀文降使轓。", "水寒芹葉薄，春早杏陰繁。", "喜動青青佩，親聞亹亹言。", "孤生荷樂育，終始託丘關。"]'),
('85790856-317b-4d78-abcd-9ab70554f459','留守待制視學  其三','石介','宋','宋诗','song-poetry','','[]','盛府雍容外，輕裘博雅存。',48,'全唐诗/poet.song.16000.json','["盛府雍容外，輕裘博雅存。", "席間閑布帙，鈴下晝無喧。", "首善隆儒術，諸生接討論。", "馬融南郡學，齪齪豈堪言。"]'),
('8a6bc98f-324e-4e9d-aee5-ed0d41b96c7b','留守待制視學  其四','石介','宋','宋诗','song-poetry','','[]','春早沂風暖，芹生泮水深。',48,'全唐诗/poet.song.16000.json','["春早沂風暖，芹生泮水深。", "前旌拂講樹，垂佩耀童衿。", "郁郁彌文化，循循善誘心。", "恭王不壞宅，金石有遺音。"]'),
('8230bef9-c9c6-449d-90e4-d22239d00131','留守待制視學  其五','石介','宋','宋诗','song-poetry','','[]','翼翼取則地，菁菁樂育篇。',48,'全唐诗/poet.song.16000.json','["翼翼取則地，菁菁樂育篇。", "使轓臨學舍，台席俯談筵。", "韋相傳經舊，文翁唱教先。", "諸生動觀歎，門外卓卿旃。"]'),
('0a5d9e51-93c4-4d57-a5e1-804ece522632','留守待制視學  其六','石介','宋','宋诗','song-poetry','','[]','泮水淥猶淺，春芹葉始敷。',48,'全唐诗/poet.song.16000.json','["泮水淥猶淺，春芹葉始敷。", "旌旗久停住，衿佩儼相趍。", "庾亮親臨學，哀公不詬儒。", "茲爲表則地，風教自王都。"]'),
('a0362ba4-b083-47be-a951-7e153c73cde2','寄趙庶明推官','石介','宋','宋诗','song-poetry','','[]','四十年來贊太平，君王耳畔管簫聲。',64,'全唐诗/poet.song.16000.json','["四十年來贊太平，君王耳畔管簫聲。", "定襄地域俄連震，萊牧男兒忽議兵。", "明日邊烽高百尺，同時御府出三旌。", "將軍請用多多算，能向當初見未萌。"]'),
('4f198c85-a454-48ce-9043-d1a70c397100','寄沛縣梁子高','石介','宋','宋诗','song-poetry','','[]','南海怒蛟三尺角，埋藏水底嘆吟呻。',64,'全唐诗/poet.song.16000.json','["南海怒蛟三尺角，埋藏水底嘆吟呻。", "明時直道難干祿，白首躬耕力養親。", "醉讀兵韜鬭龍豹，閑抽寶劒舞星辰。", "茅齋東是留侯廟，定有英靈還往頻。"]'),
('d866df12-6816-43e1-b889-65697113fe11','送張殿院還臺','石介','宋','宋诗','song-poetry','','[]','老柏森森節貫冬，頭冠獬豸號清雄。',64,'全唐诗/poet.song.16000.json','["老柏森森節貫冬，頭冠獬豸號清雄。", "側階簪筆書王法，當路埋輪有祖風。", "白簡剛嚴重入府，皁封切直舊留中。", "長安豪貴應相避，又識當年御史驄。"]'),
('90a0bccf-9479-448d-9a61-59311f268818','徂徠山齋熟寢家童報征西府從事田集賢書至開緘讀之因題書後','石介','宋','宋诗','song-poetry','','[]','滿徑蓬蒿懶自鋤，何人日午叩茅廬。',64,'全唐诗/poet.song.16000.json','["滿徑蓬蒿懶自鋤，何人日午叩茅廬。", "徂徠山下一枕睡，經畧府中三紙書。", "兵謀貴勝縱橫出，海鳥忘機飲啄餘。", "唯有淮夷雅宜作，文章兼不讓黄初。"]'),
('588d46f1-4272-441d-97ac-8695b2eb4ee1','元均首登賢良科因寄','石介','宋','宋诗','song-poetry','','[]','宏辭等甲賢良貴，二美翩翩落手中。',64,'全唐诗/poet.song.16000.json','["宏辭等甲賢良貴，二美翩翩落手中。", "虎子得來山穴泣，驪珠探去海濤空。", "三千安獨陳當寧，十七人甘坐下風。", "曾向當年競頭角，直從此日决雌雄。"]'),
('758c5cd3-a4eb-40b1-be92-2fe8654e21c2','安道再登制科','石介','宋','宋诗','song-poetry','','[]','雄辭磅礴壓羣英，再戰戈矛銳更精。',64,'全唐诗/poet.song.16000.json','["雄辭磅礴壓羣英，再戰戈矛銳更精。", "裴度韜鈐無失律，武侯節制是神兵。", "千人盡服徂丘議，九合誰干小白盟。", "帝宋開基八十載，連登科目獨爲榮。"]'),
('bd98d927-27e2-4aae-a18c-e66e0e67bbc3','送奉符縣監酒稅孟執中借職','石介','宋','宋诗','song-poetry','','[]','東西兩處各天涯，去國還鄉喜又嗟。',64,'全唐诗/poet.song.16000.json','["東西兩處各天涯，去國還鄉喜又嗟。", "鄒嶧山藏孟子宅，海棠花落蜀王家。", "深知周道非彝酒，可罪唐臣乞稅茶。", "三載此心無一事，聞經絳帳日常斜。"]'),
('64bac417-f2ca-48f2-953a-9b3cc8873cb2','嘉州讀邸報見張叔文由御史臺主簿改著作佐郎依舊在臺','石介','宋','宋诗','song-poetry','','[]','驚聞除目到遐荒，病眼偏明喜倍常。',64,'全唐诗/poet.song.16000.json','["驚聞除目到遐荒，病眼偏明喜倍常。", "古節舊如臺柏直，青衫新惹閣芸香。", "中廬夜宿羣經蠹，北戶朝趍滿簡霜。", "主簿雖卑官漸緊，近來應有諫書囊。"]'),
('ef3453cc-fe28-44de-9d22-491a0d0cdbe3','予與元均永叔君謨同年登科永叔尋入館閣元均今制策高第君謨復磨礪元均事業獨予駑下因寄君謨','石介','宋','宋诗','song-poetry','','[]','網羅當日得英雄，文陣三人各立功。',64,'全唐诗/poet.song.16000.json','["網羅當日得英雄，文陣三人各立功。", "海裏赤鯨疑有角，雲中騏驥欲追風。", "尋聞館閣英聲出，又見賢良大對通。", "亦說年來畜奇業，蟭螟何計逐飛鴻。"]'),
('59b4297b-b85a-466a-af52-93b9dc465591','寄元均','石介','宋','宋诗','song-poetry','','[]','君爲儒者豈知兵，何事欣隨璧馬行。',64,'全唐诗/poet.song.16000.json','["君爲儒者豈知兵，何事欣隨璧馬行。", "裴度樽前坐韓愈，趙成帳下立荀卿。", "御戎誰道全無策，對壘寧妨下一枰。", "須信乾坤養不肖，年三十七卧柴荆。"]'),
('f07c9963-8cd4-4cb9-a5c8-7b5c5598d94a','寄叔文','石介','宋','宋诗','song-poetry','','[]','幾年持筆事征西，未省樽前略展眉。',64,'全唐诗/poet.song.16000.json','["幾年持筆事征西，未省樽前略展眉。", "草檄朝慵腕勞脫，論兵夜苦舌瘡痍。", "報君自說心如石，憂國人言鬢欲絲。", "若紀成功鏤金板，能文韓愈自相隨。"]'),
('cf95214e-12d8-43f0-9bb2-7bdb1d1d3981','赴任嘉州初登棧道寄題姜潛至之讀易堂','石介','宋','宋诗','song-poetry','','[]','我不從官君下第，其間險易兩何如。',64,'全唐诗/poet.song.16000.json','["我不從官君下第，其間險易兩何如。", "連雲棧外四千里，讀易堂中一帙書。", "慈母含飴垂禿髮，先生懷道接茅廬。", "莫將清淚頻頻灑，蜀道之難欲上初。"]'),
('b10391cb-a437-413d-9828-520f10c26d6f','入蜀至左綿路次水軒暫憇','石介','宋','宋诗','song-poetry','','[]','水軒聊得恣吟哦，拂拭衣裳塵土多。',64,'全唐诗/poet.song.16000.json','["水軒聊得恣吟哦，拂拭衣裳塵土多。", "蜀道三千里巇險，宦途五十驛風波。", "暫休又作故山夢，閒唱還成勞者歌。", "幾斗米牽歸未得，空憐滿眼是煙蘿。"]'),
('49f562d4-0367-4e70-95e0-3bee05bff600','左綿席上呈知郡王虞部','石介','宋','宋诗','song-poetry','','[]','何事相逢悲喜并，倏然相別二周星。',64,'全唐诗/poet.song.16000.json','["何事相逢悲喜并，倏然相別二周星。", "主人鬢髮無多白，幕客襴衫依舊青。", "目極同思故山斷，涕危共在異鄉零。", "階前絲竹雖嘈雜，不似南湖湖上聽。"]'),
('35956b32-4eae-4494-8dcf-5169c8895678','嘉州寄左綿王虞部','石介','宋','宋诗','song-poetry','','[]','江山如畫望無窮，況屬昇平歲屢豐。',64,'全唐诗/poet.song.16000.json','["江山如畫望無窮，況屬昇平歲屢豐。", "萬樹芙蓉秋色裏，千家碪杵月明中。", "斷霞半著燕支木，零露偏留筀竹叢。", "只欠流杯曲水宴，風流未與左綿同。"]'),
('52015919-a6fd-463e-8d26-5f8bc88c9cc1','士廷評相會梓州','石介','宋','宋诗','song-poetry','','[]','道視荀楊雖未至，分於管鮑已知深。',64,'全唐诗/poet.song.16000.json','["道視荀楊雖未至，分於管鮑已知深。", "一千二百日離別，五十六驛外相尋。", "重欲同君注周易，且來共我聽胡琴。", "月留屋角不下去，似與清風憐苦吟。"]'),
('394eba92-ea58-4e17-82b8-2847230b13a2','鄭師易秀才詩奔騰遒壯殆有石曼卿學士風骨作四韻以勉之','石介','宋','宋诗','song-poetry','','[]','曼卿續得少陵絃，絃絕年來又一年。',64,'全唐诗/poet.song.16000.json','["曼卿續得少陵絃，絃絕年來又一年。", "驚起聽君諷新句，灑如開集味遺篇。", "一家氣骨疑無偶，萬丈光芒欲拂天。", "好向風騷尤著意，他時三箇地詩仙。"]'),
('461737a7-f979-4514-b2fb-76901ae34bcb','送李堂伯升病歸','石介','宋','宋诗','song-poetry','','[]','經年吾圃採珠璣，無限愁腸對落暉。',64,'全唐诗/poet.song.16000.json','["經年吾圃採珠璣，無限愁腸對落暉。", "綠竹實疎鳳凰瘦，玉芝粒小麒麟饑。", "不因芳草傷春哭，正是東風感疾歸。", "只有文章滿君腹，身雖癯瘠道全肥。"]'),
('ea09a000-8746-47d7-8995-c5e29883f29e','伯升病君逢遵道送歸','石介','宋','宋诗','song-poetry','','[]','朝來何事苦顰眉，一客越吟三子歸。',64,'全唐诗/poet.song.16000.json','["朝來何事苦顰眉，一客越吟三子歸。", "河渚徘徊感春草，山齋寂寞背斜暉。", "知心古道誰相得，洒淚東風自覺非。", "早到茅廬慰孤淡，易爻重待共參微。"]'),
('92069642-0e2c-4d77-980a-95d1f388cff2','喜雨','石介','宋','宋诗','song-poetry','','[]','學作昇平喜雨吟，東皋微破滿犂深。',64,'全唐诗/poet.song.16000.json','["學作昇平喜雨吟，東皋微破滿犂深。", "已開萬乘焦勞慮，應解三公燮理心。", "天捉乖龍鞭見血，雷驅和氣泄爲霖。", "農夫隴上閑論價，一寸甘膏一寸金。"]'),
('23eb226f-5816-4577-9c74-37cd84c58bfa','留題敏夫隠居','石介','宋','宋诗','song-poetry','','[]','三迴到此尋逋客，杯案蕭疎滋味長。',64,'全唐诗/poet.song.16000.json','["三迴到此尋逋客，杯案蕭疎滋味長。", "山飯半甌橡子熟，春蔬一筯朮苗香。", "四時泉石應無夏，滿谷雲霞別是鄉。", "終待共君結鄰里，竹邊相並兩間房。"]'),
('d58e06a8-79a7-4971-9ce6-dd6a991eb0b7','訪竹溪呈孟節兼有懷熙道','石介','宋','宋诗','song-poetry','','[]','到頭泉石是吾家，坐石聽泉日已斜。',64,'全唐诗/poet.song.16000.json','["到頭泉石是吾家，坐石聽泉日已斜。", "一片青衫非富貴，千竿綠竹好生涯。", "君曾覽照頭皆雪，我試看書眼亦花。", "便好結爲山伴侶，教他夔益佐勛華。"]'),
('97941b77-89d2-4f61-b8c2-d4030ff07f4b','招張泂明遠','石介','宋','宋诗','song-poetry','','[]','君言下第我西飛，執手都門淚滿衣。',64,'全唐诗/poet.song.16000.json','["君言下第我西飛，執手都門淚滿衣。", "萬里得歸頭半白，經年相別道應肥。", "火鑽欲遍龜難死，竹實猶多鳳不饑。", "暫到東山慰愁抱，春秋之學說深微。"]'),
('644bb99b-e68d-478f-903a-837e36860ce2','攝相','石介','宋','宋诗','song-poetry','','[]','惜無百里地封君，攝相區區道屢伸。',64,'全唐诗/poet.song.16000.json','["惜無百里地封君，攝相區區道屢伸。", "少正將身膏斧刃，侏儒流血汙車輪。", "方令魯國知王法，自此齊侯畏聖人。", "昔放四兇誅二叔，舜周功業殆同倫。"]'),
('e0b2b4b4-e406-4e43-8e1f-59de4f68e395','寄孔中丞','石介','宋','宋诗','song-poetry','','[]','諫署崢嶸有舊名，侯藩偃息政方成。',64,'全唐诗/poet.song.16000.json','["諫署崢嶸有舊名，侯藩偃息政方成。", "張綱昨日彈梁冀，文帝今朝召賈生。", "古節未慙臺栢直，仙風應對簡霜清。", "人言賤子叨知己，試把塵冠一振纓。"]'),
('d345d6a6-3f07-4a97-8f56-77563107fc64','送弟及之就彭門侍養','石介','宋','宋诗','song-poetry','','[]','城南車騎曉駸駸，欲去重留酒屢斟。',64,'全唐诗/poet.song.16000.json','["城南車騎曉駸駸，欲去重留酒屢斟。", "惜爾浪浪辭我淚，感予切切戀親心。", "庭闈最樂無妨學，風月餘閑豈廢吟。", "別後不憂書信少，但聞爲善是嘉音。"]'),
('347b00da-1874-40bd-b7bb-f1eb8bdf0981','村居','石介','宋','宋诗','song-poetry','','[]','幽居一畝枕溪稜，階下杉松纏古藤。',64,'全唐诗/poet.song.16000.json','["幽居一畝枕溪稜，階下杉松纏古藤。", "常愛園林深似隠，不嫌門戶冷如僧。", "麥宜過社猶催種，山近經秋却懶登。", "已把壯心閑頓置，少年莫要苦相憎。"]'),
('1b04b73f-104b-4b5e-899a-d11d87f9d89f','燕支板浣花牋寄合州徐文職方','石介','宋','宋诗','song-poetry','','[]','合州太守鬢將絲，聞說歡情尚不衰。',128,'全唐诗/poet.song.16000.json','["合州太守鬢將絲，聞說歡情尚不衰。", "板與歌娘拍新調，牋供狎客寫芳辭。", "木成文理差差動，花映溪光瑟瑟奇。", "名得只從嘉郡樹，樣傳仍自薛濤時。", "奇章磊磊馳聲價，江令翩翩落酒巵。", "幾首詩成卷魚子，誰人唱罷泣燕支。", "紅牙管好同牀置，紫竹笙宜一處施。", "願助風流向罇席，杏花況是未離披。"]'),
('9eb127de-2a9f-4032-97ac-d3e585311737','御史臺牒督光臺錢牒云以憑石柱鎸名因戲書呈通判寺丞景元','石介','宋','宋诗','song-poetry','','[]','幕中久次無他術，銜內兼官带憲司。',64,'全唐诗/poet.song.16000.json','["幕中久次無他術，銜內兼官带憲司。", "石柱鎸名誠似是，豸冠加首竟何爲。", "幾曾執簡抨彈去，空被光臺督責隨。", "一起鴛鴦戛雲漢，應嗤燕雀守籓籬。"]'),
('768fca5a-31fd-4ed0-bd79-f876864a7c87','送馮司理之任彭州','石介','宋','宋诗','song-poetry','','[]','李白詩中蜀道難，把詩試讀淚汍瀾。',64,'全唐诗/poet.song.16000.json','["李白詩中蜀道難，把詩試讀淚汍瀾。", "江形詰曲千迴折，嶺路崚嶒萬屈盤。", "登陟去年腰僅折，追思今日鼻猶酸。", "此行君不同屯蹇，五馬相知舊長官。"]'),
('a8fcb39a-7cfa-4fab-9fa4-6acd7b518ee2','赴任嘉州待闕左綿七十日通判呂國博日相從吟酌至嘉陽因成四韻寄之','石介','宋','宋诗','song-poetry','','[]','鼎來豈敢道能詩，一見何因便解頤。',64,'全唐诗/poet.song.16000.json','["鼎來豈敢道能詩，一見何因便解頤。", "鄉國三千里離別，杯盤七十日相知。", "送人江外馬馱妓，垂釣寺中魚竭池。", "別後中秋又重九，與誰賞月詠東籬。"]'),
('08573a6a-0583-445a-8a54-fdf67d9441f7','顔魯公太師','石介','宋','宋诗','song-poetry','','[]','唐家六世樹威恩，外建藩翰禦不賓。',64,'全唐诗/poet.song.16000.json','["唐家六世樹威恩，外建藩翰禦不賓。", "二十三州同陷賊，平原猶有一忠臣。", "聖賢道在惟顔子，忠烈名存獨杲卿。", "甘向賊庭守節死，不羞吾祖與吾兄。"]'),
('0cf6acb6-476c-4e08-87fc-eb346b1bb4cd','褚遂良僕射','石介','宋','宋诗','song-poetry','','[]','先皇執手未多時，受詔誠深誓不違。',32,'全唐诗/poet.song.16000.json','["先皇執手未多時，受詔誠深誓不違。", "終向君前還此笏，一身視死喜如歸。"]'),
('88895963-3038-4dfe-873d-842c1202c89c','陽城諫議','石介','宋','宋诗','song-poetry','','[]','衆口喑喑血噤牙，獨將忠謇敵姦邪。',32,'全唐诗/poet.song.16000.json','["衆口喑喑血噤牙，獨將忠謇敵姦邪。", "德宗若用延齡相，敢有陽城壞白麻。"]'),
('21b10552-d5f2-419d-8823-8f247cdcce59','袁高給事','石介','宋','宋诗','song-poetry','','[]','擲毫不肯草絲綸，宰相逡巡命別人。',32,'全唐诗/poet.song.16000.json','["擲毫不肯草絲綸，宰相逡巡命別人。", "明日執迴盧杞制，始知唐室有忠臣。"]'),
('e5867c7a-b0ce-4012-a634-bbcd0e655894','溫造御史','石介','宋','宋诗','song-poetry','','[]','一言膽落折藩臣，屈强何人敢恃勳。',32,'全唐诗/poet.song.16000.json','["一言膽落折藩臣，屈强何人敢恃勳。", "闕下惟聞溫御史，蔡州自是李將軍。"]'),
('31c9e267-8f3b-4dfb-bca2-0984a5bb92ba','劉栖楚拾遺','石介','宋','宋诗','song-poetry','','[]','此節甯甘剛則折，平生不肯曲如鉤。',32,'全唐诗/poet.song.16000.json','["此節甯甘剛則折，平生不肯曲如鉤。", "革囊裹血將何用，一汙龍墀死即休。"]'),
('d2e395d5-43c0-40ce-9981-de33eaff7564','讀五王傳','石介','宋','宋诗','song-poetry','','[]','聖賢用策寧相遠，千載毫釐竟不差。',32,'全唐诗/poet.song.16000.json','["聖賢用策寧相遠，千載毫釐竟不差。", "四皓當年安漢嗣，五王今日復唐家。"]'),
('91e09d02-5458-4455-bcc4-3d51322529d1','讀魯晉二公傳','石介','宋','宋诗','song-poetry','','[]','節似魯公猶被陷，忠如裴度亦遭讒。',32,'全唐诗/poet.song.16000.json','["節似魯公猶被陷，忠如裴度亦遭讒。", "上無明主姦邪勝，我讀遺篇淚滿衫。"]'),
('4bcd03ef-9919-4ebe-916f-9acdc8b1b730','李英公勣','石介','宋','宋诗','song-poetry','','[]','一言容易廢忠謀，徇主從昏可自尤。',32,'全唐诗/poet.song.16000.json','["一言容易廢忠謀，徇主從昏可自尤。", "今日始知辜付託，當時齧指血空流。"]'),
('c4ba3fc1-1382-4d6f-beb0-4b96dfc02fae','漢成帝','石介','宋','宋诗','song-poetry','','[]','鬰鬰朱雲志不伸，上方寶劒欲生塵。',32,'全唐诗/poet.song.16000.json','["鬰鬰朱雲志不伸，上方寶劒欲生塵。", "空留折檻旌忠直，左右何嘗去佞臣。"]'),
('e4d0cc69-1716-49d0-a395-4493f8449622','文中子  其一','石介','宋','宋诗','song-poetry','','[]','龍蟄河汾道不行，訏謨經濟授諸生。',32,'全唐诗/poet.song.16000.json','["龍蟄河汾道不行，訏謨經濟授諸生。", "由來房魏皆卿相，共輔文皇致太平。"]'),
('dd124a22-02a4-4d27-9354-23545de5f8ad','文中子  其二','石介','宋','宋诗','song-poetry','','[]','獨將禮樂付程仇，房杜無才闡大猷。',32,'全唐诗/poet.song.16000.json','["獨將禮樂付程仇，房杜無才闡大猷。", "可惜唐家三百載，聲明文物愧宗周。"]'),
('991bd253-dcef-4496-9b7f-a33c8b1c37ba','初過潼關值雨','石介','宋','宋诗','song-poetry','','[]','二十年來憶華山，揚鞭西笑入秦川。',32,'全唐诗/poet.song.16000.json','["二十年來憶華山，揚鞭西笑入秦川。", "浮雲何苦深遮閉，豈是三峯不好賢。"]'),
('f6b673db-c98a-47fd-9634-2f1b2cb75180','雨晴復賦一絕','石介','宋','宋诗','song-poetry','','[]','過關何事懶摇鞭，酷愛三峯落馬前。',32,'全唐诗/poet.song.16000.json','["過關何事懶摇鞭，酷愛三峯落馬前。", "天氣清明新雨後，山光日色滿秦川。"]'),
('8acfe208-865b-4758-af08-af9bad78e521','過溫湯','石介','宋','宋诗','song-poetry','','[]','驪山山下水洋洋，一勺之多解破唐。',32,'全唐诗/poet.song.16000.json','["驪山山下水洋洋，一勺之多解破唐。", "敢告後人商鑑近，溫湯今日是唐湯。"]'),
('604e92b5-7983-4cab-8be1-9575858bd2be','初過大散關馬上作','石介','宋','宋诗','song-poetry','','[]','柰何山色牽吟思，旋被江聲破睡魔。',32,'全唐诗/poet.song.16000.json','["柰何山色牽吟思，旋被江聲破睡魔。", "吟思睡魔兩相戰，誰知馬上有干戈。"]'),
('f7ea571b-6e6a-451d-a32b-9e44fbecaf27','過飛仙嶺  其一','石介','宋','宋诗','song-poetry','','[]','入蜀牽吟景象濃，雲山萬疊與千重。',32,'全唐诗/poet.song.16000.json','["入蜀牽吟景象濃，雲山萬疊與千重。", "癡巖頑壑無奇觀，不似飛仙數朵峯。"]'),
('ccb592e8-89a6-4d72-8c98-506ef4d289d2','過飛仙嶺  其二','石介','宋','宋诗','song-poetry','','[]','御愛數峯非拔秀，當時駐蹕欲忘還。',32,'全唐诗/poet.song.16000.json','["御愛數峯非拔秀，當時駐蹕欲忘還。", "飛仙急過無真賞，始信明皇不識山。"]'),
('01f888a2-100f-4abf-bbc6-4c9a7efabad4','峽中','石介','宋','宋诗','song-poetry','','[]','路狹纔容飛鳥過，山將生合柰山何。',32,'全唐诗/poet.song.16000.json','["路狹纔容飛鳥過，山將生合柰山何。", "不知天外山長短，何事窺來一管多。"]'),
('119794da-7d8c-4829-8a66-28185393b624','劒門讀賈公疎詩石','石介','宋','宋诗','song-poetry','','[]','劒門駐馬立踟躕，讀盡新篇味有餘。',32,'全唐诗/poet.song.16000.json','["劒門駐馬立踟躕，讀盡新篇味有餘。", "關令多情兼好事，詩名留得賈公疎。"]'),
('71e9dd9a-5ff3-43a1-a8ca-f670e6fe5789','予自南京留守推官循資爲掌書記由將仕郎超階至朝奉郎得蜀嘉州友人相賀者因答之','石介','宋','宋诗','song-poetry','','[]','一循資走五千里，四遇恩超十六階。',32,'全唐诗/poet.song.16000.json','["一循資走五千里，四遇恩超十六階。", "自顧非才已過分，誰言英俊尚沉埋。"]'),
('c929793b-3437-4fcd-a8d4-b08be2418fa3','蜀道中念親有作','石介','宋','宋诗','song-poetry','','[]','東望庭闈魂欲銷，層層雲棧上岧嶤。',32,'全唐诗/poet.song.16000.json','["東望庭闈魂欲銷，層層雲棧上岧嶤。", "江聲山色情多少，相伴西來慰寂寥。"]'),
('ef380bf3-639f-4b10-8d6e-3f24104bd2e6','泥溪驛中作','石介','宋','宋诗','song-poetry','','[]','山驛蕭條酒倦傾，嘉陵相背去無情。',32,'全唐诗/poet.song.16000.json','["山驛蕭條酒倦傾，嘉陵相背去無情。", "臨流不忍輕相別，吟聽潺湲坐到明。"]'),
('258c752f-9b18-432c-adbf-1e3b0bb418e8','柳池驛中作','石介','宋','宋诗','song-poetry','','[]','二十二餘程鳥道，一千一百里江聲。',32,'全唐诗/poet.song.16000.json','["二十二餘程鳥道，一千一百里江聲。", "江聲聽盡行未盡，西去出山猶七程。"]'),
('da6ad831-5a0f-41d5-9bcc-9043c9104ad4','訪栗園有感','石介','宋','宋诗','song-poetry','','[]','遊困歸來訪栗園，栗園樹老再生孫。',32,'全唐诗/poet.song.16000.json','["遊困歸來訪栗園，栗園樹老再生孫。", "莫驚頭上見白髮，拾栗兒童長幾番。"]'),
('b37a6319-0fd7-4db1-87bb-979a11f028e3','離鄆州至壽張南村舍中有姥八十餘出拜','石介','宋','宋诗','song-poetry','','[]','老姥龍鍾八十三，猶能指點認青衫。',32,'全唐诗/poet.song.16000.json','["老姥龍鍾八十三，猶能指點認青衫。", "自言老婦嘗蒙惠，白首相將出戶參。"]'),
('333e8b4c-25ec-4dbe-958b-cf008f800ec0','句','杜杞','宋','宋诗','song-poetry','','[]','有驗如有神。',6,'全唐诗/poet.song.16000.json','["有驗如有神。"]'),
('542440ff-0409-4415-b8b8-7ec5644a1977','謹次韻和呈垂覽拙詩之作','江休復','宋','宋诗','song-poetry','','[]','朝躋天門路，暮宿白雲杪。',156,'全唐诗/poet.song.16000.json','["朝躋天門路，暮宿白雲杪。", "超然六合外，如翼鸞風矯。", "運眸極遐曠，收念息奔擾。", "盤盤上絕頂，獨立顥氣表。", "天壁涌神泉，玉龜泳靈沼。", "凌奧無螫蟲，集灌盡百鳥。", "勝景窮賞踐，陳迹嗟緬眇。", "接遯終焉托，真仙事殊窅。", "雲露相飄颻，塵途忘湫湫。", "躡屐游已屢，操觚才患少。", "思軋幾沉伏，神馳空縹緲。", "謝客興不淺，尚子計未了。", "何時出塵籠，重看衆山小。"]'),
('c387d53f-8a4e-40bc-8203-61254598977f','奉陪原甫泛汝水作','江休復','宋','宋诗','song-poetry','','[]','汝潁日滔滔，巢由絕世高。',48,'全唐诗/poet.song.16000.json','["汝潁日滔滔，巢由絕世高。", "風流雖緬邈，舟楫共遊遨。", "雉堞縈回遠，山川應接勞。", "幸陪觴詠末，旌旆駐蘭皋。"]'),
('8a8f0eaa-6bcf-44ab-921b-c4a14fd95f88','送祖龍學赴陝府酌飲贈別次歐陽永叔韻','江休復','宋','宋诗','song-poetry','','[]','西掖門外駐征軒，修書院中傾別酒。',144,'全唐诗/poet.song.16000.json','["西掖門外駐征軒，修書院中傾別酒。", "諸公磊落方具來，顧我衰遲亦何有。", "祖侯銜使才北歸，亟請甘棠復西走。", "函關候吏齊引領，翰林主人惜分手。", "高談抵掌華屋頭，賦咏題詩樂難朽。", "飛觴舉白至無算，擊楫誓清不殮九。", "著鞭壯士空後時，隠几先生仍喪偶。", "定國能飲動論石，山公雅望潛增斗。", "紛紛醉袂影就判，怊悵高陽一狂叟。"]'),
('24df28e2-0a7a-4dd4-af14-89210fd644cc','秋懷','江休復','宋','宋诗','song-poetry','','[]','西風萬里至，曠然天地秋。',120,'全唐诗/poet.song.16000.json','["西風萬里至，曠然天地秋。", "暮雨生夕凉，百蟲鳴啾啾。", "楚山曉蒼蒼，楚水亦悠悠。", "騷人試登臨，感物增離憂。", "所思在遐方，欲往路阻修。", "香草有蕙茝，嘉樹有梧楸。", "白露委芳馨，彫零使我愁。", "窮年倦羈窘，江湖思舊遊。", "紉蘭製芰荷，飄泛一葉舟。", "肆情雲水間，意適何所求。"]'),
('509f46f6-69d7-4346-b52c-4037ffd82144','同持國宿太學官舍','江休復','宋','宋诗','song-poetry','','[]','翳翳雲月薄，泠泠雪風清。',96,'全唐诗/poet.song.16000.json','["翳翳雲月薄，泠泠雪風清。", "學省夜岑寂，天街斷人行。", "廣庭層閣陰，尋廊步餘明。", "松篠遞遥響，如聞弦誦聲。", "悠悠子佩詩，講座塵埃生。", "迴就直舍休，亹亹談道精。", "心會境物融，泯然遺世營。", "寒眠屢展轉，寤言寫素誠。"]'),
('550e8325-48b7-41d2-a09f-e0bb2ed5c980','牟駝岡閱馬','江休復','宋','宋诗','song-poetry','','[]','牧馬散近坰，閱視乘高秋。',180,'全唐诗/poet.song.16000.json','["牧馬散近坰，閱視乘高秋。", "駝岡似沙苑，堆阜带川洲。", "坡陁故梁城，縈薄西南陬。", "連棚映林樾，星羅倚層丘。", "回風吹陣雲，奔騰欻來游。", "野性脫羈馬，飲齕遂所求。", "腹幹頗肥張，鬰怒何彪休。", "羣敺驟麋鹿，逸勢凌蛟虬。", "軍戎選輕捷，和鑾御調柔。", "毛物有千名，衆美歸驊騮。", "梁王愁思臺，佛剎居上頭。", "朅來一憑眺，遺墟莽悠悠。", "信陵骨已朽，巖穴誰見收。", "當時英豪輩，事逐東波流。", "置酒臨風軒，聊以紓煩憂。"]'),
('46658a17-933d-4501-856a-c2cf439a049b','君實不飲酒栽菊詩以問之','江休復','宋','宋诗','song-poetry','','[]','君實不飲酒，庭下多栽菊。',48,'全唐诗/poet.song.16000.json','["君實不飲酒，庭下多栽菊。", "不知黄花開，奈此杯中綠。", "凌晨煙露滋，後日風霜促。", "欲表君苦心，宜種子猷竹。"]'),
('f5c95503-6bad-4282-a139-5b8bfe2df8d7','王官谷司空侍郎故居','江休復','宋','宋诗','song-poetry','','[]','首陽采薇士，商代緬以遐。',120,'全唐诗/poet.song.16000.json','["首陽采薇士，商代緬以遐。", "唐季有夫子，遯世肥且嘉。", "拔迹離污險，抗志凌青霞。", "剝運扇頹風，姦雄比回邪。", "不然隨波流，橫噬猰貐牙。", "吁哉土德衰，暌乖鬼盈車。", "英英夫子賢，顯晦吾所嗟。", "相見棲隠情，遺文搴菁華。", "山藏白駒谷，水遶騷人家。", "躊躇碧峯前，寒日忽以斜。"]'),
('54e23f9a-198b-464e-8338-75684ed8ca57','句  其一','江休復','宋','宋诗','song-poetry','','[]','郡邸獄冤誰與辯，皋橋客死世同悲。',16,'全唐诗/poet.song.16000.json','["郡邸獄冤誰與辯，皋橋客死世同悲。"]'),
('c5f9dc0c-8f65-45c9-93d6-683f418edc00','句  其二','江休復','宋','宋诗','song-poetry','','[]','五十踐衰境，加我在明年。',12,'全唐诗/poet.song.16000.json','["五十踐衰境，加我在明年。"]'),
('80f76316-d867-46f5-bfc8-e0f2ac7a0d1f','聞雁','侯氏','宋','宋诗','song-poetry','','[]','何處驚飛起，雝雝過草堂。',48,'全唐诗/poet.song.16000.json','["何處驚飛起，雝雝過草堂。", "早是愁無寐，忽聞意轉傷。", "良人沙塞外，羈妾守空房。", "欲寄回文信，誰能付汝將。"]'),
('76e39c58-8570-4e09-b833-b8fba4735591','題隠圃贈蔣希魯','范師道','宋','宋诗','song-poetry','','[]','勇退人難事，明公識慮長。',72,'全唐诗/poet.song.16000.json','["勇退人難事，明公識慮長。", "波濤濟舟楫，霜雪見松篁。", "林下開前圃，花間撤亞槍。", "二疏良宴會，老杜好篇章。", "道向清來勝，機於靜處忘。", "當除印如斗，試一較閒忙。"]'),
('a95f1048-6f35-4fc8-b1c9-20574c5c0a85','天平山','范師道','宋','宋诗','song-poetry','','[]','萬物天地間，或有奇勝跡。',180,'全唐诗/poet.song.16000.json','["萬物天地間，或有奇勝跡。", "見賞能幾人，不止今與昔。", "吳門多好山，天平爲峻極。", "旦暮常白雲，表裏皆珍石。", "煙嵐十里光，松桂四時色。", "我因一縱遊，煩襟爲開釋。", "感古懷君子，翻然長太息。", "樂天賞雲泉，詩章何歷歷。", "垂今數百年，繼者漠然寂。", "間遇希文來，雙旌守鄉國。", "行春三讓原，吟哦盡所得。", "子美天與才，尋幽多採摭。", "賦百五十言，平地黄金擲。", "三賢固有名，山亦資輝赫。", "此去還幾年，不逢好事客。"]'),
('92c2e9d2-24fe-4e49-b280-35e5dcb05ae8','釣臺','范師道','宋','宋诗','song-poetry','','[]','乾坤交泰重彌綸，當日嚴陵道最淳。',64,'全唐诗/poet.song.16000.json','["乾坤交泰重彌綸，當日嚴陵道最淳。", "大漢中興得英主，先生高退作閑人。", "灘頭風月遺千古，臺上綸竿寄一身。", "今日病夫祠下過，獨知疲懦長精神。"]'),
('2f20b4d8-0bda-4cf0-94c8-f3eb74758392','題琴臺','田況','宋','宋诗','song-poetry','','[]','西漢文章世所知，相如閎麗冠當時。',32,'全唐诗/poet.song.16000.json','["西漢文章世所知，相如閎麗冠當時。", "遊人不賞凌雲賦，只說琴臺是故基。"]'),
('04177405-53c3-4ab3-96e3-5a24e8e300b9','成都遨樂詩二十一首 元日登安福寺塔','田況','宋','宋诗','song-poetry','','[]','歲曆起新元，錦里春意早。',120,'全唐诗/poet.song.16000.json','["歲曆起新元，錦里春意早。", "詰旦會朋寀，羣游候騶導。", "像塔倚中霄，翬檐結重橑。", "隨俗縱危步，超若落清昊。", "千里如指掌，萬象可窮討。", "野闊山勢迴，寒餘林色老。", "遨賞空閭巷，朅來喧稚耄。", "人物事多閒，車馬擁行道。", "顧此歡娛俗，良慰羈遠抱。", "第憂民政疎，無庸答宸造。"]'),
('a868da3d-a9cc-481d-8b45-e0e16e4200a4','成都遨樂詩二十一首 二日出城','田況','宋','宋诗','song-poetry','','[]','初歲二之日，言出東城闉。',120,'全唐诗/poet.song.16000.json','["初歲二之日，言出東城闉。", "緹騎隘重郛，淤車坌行塵。", "原野信滋腴，景物爭光新。", "青疇隠遥壩，弱柳垂芳津。", "邏卒具威械，祭墦列重茵。", "俗尚各有時，孝思情則均。", "歸途喧鼓鐃，聚觀無富貧。", "坤隅地力狹，百業常苦辛。", "設微行樂事，何由裕斯民。", "守侯其勉旃，亦足彰吾仁。"]'),
('5cb98faf-dcbe-47f8-a595-d71f39a8c107','成都遨樂詩二十一首 五日州南門蠶市','田況','宋','宋诗','song-poetry','','[]','齊民聚百貨，貿鬻貴及時。',120,'全唐诗/poet.song.16000.json','["齊民聚百貨，貿鬻貴及時。", "乘此耕桑前，以助農績資。", "物品何其夥，碎璅皆不遺。", "編䉲列箱筥，飭木柄鎡錤。", "備用誠爲急，舍器工曷施。", "名花藴天豔，靈藥昌壽祺。", "根萌漸開發，蔂載相參差。", "游人衒識賞，善賈求珍奇。", "予真徇俗者，行觀亦忘疲。", "日暮宴觴罷，衆皆云適宜。"]'),
('d32bf0d2-20c1-4321-b94b-306dac14be29','成都遨樂詩二十一首 上元燈夕','田況','宋','宋诗','song-poetry','','[]','予嘗觀四方，無不樂嬉遊。',120,'全唐诗/poet.song.16000.json','["予嘗觀四方，無不樂嬉遊。", "惟茲全蜀區，民物繁它州。", "春宵寶燈然，錦里香煙浮。", "連城悉奔騖，千里窮邊陬。", "衯裶合繡袂，轣轆馳香輈。", "人聲震雷遠，火樹華星稠。", "鼓吹匝地喧，月光斜漢流。", "懽多無永漏，坐久凭高樓。", "民心感上恩，釋唄歌神猷。", "齊音祝東北，帝壽長嵩邱。"]'),
('b6f2c462-b39f-439e-a96d-11df4f28f1e2','成都遨樂詩二十一首 二十三日聖壽寺前蠶市','田況','宋','宋诗','song-poetry','','[]','龍斷爭趨利，仁園敞邃深。',48,'全唐诗/poet.song.16000.json','["龍斷爭趨利，仁園敞邃深。", "經年儲百貨，有意享千金。", "器用先農事，人聲混樂音。", "蠶叢故祠在，致祝順民心。"]'),
('e330ff3f-4e1c-4997-ba16-5a5daabc7522','成都遨樂詩二十一首 二十八日謁生祿祠遊浄衆寺','田況','宋','宋诗','song-poetry','','[]','千騎出重闉，嚴祠浄宇鄰。',48,'全唐诗/poet.song.16000.json','["千騎出重闉，嚴祠浄宇鄰。", "映林沽酒斾，迎馬獻花人。", "豔日披江霧，香飈起路塵。", "韶華特明媚，不似遠方春。"]'),
('0befe9c8-488b-4ec4-ae73-5caba768fb91','成都遨樂詩二十一首 二月二日遊江會寶歷寺','田況','宋','宋诗','song-poetry','','[]','昔年張復之來乘寇亂餘。',119,'全唐诗/poet.song.16000.json','["昔年張復之來乘寇亂餘。", "三春雖宴賞，四野猶艱虞。", "遂移踏青會，登舟恣遊娛。", "戒備漸解弛，人情悉安舒。", "垂茲五十年，材哲不敢踰。", "愚來再更朔，遽及仲春初。", "綵舵列城隈，畫船滿江隅。", "輕橈下奔瀨，縱輿臨精廬。", "因思賢守事，所作民乃孚。", "慈惠未爲大，大者其忘諸。"]'),
('b4f5c197-6fe3-4b97-8a40-f081b4512978','成都遨樂詩二十一首 八日太慈寺前蠶市','田況','宋','宋诗','song-poetry','','[]','蜀雖云樂土，民勤過四方。',84,'全唐诗/poet.song.16000.json','["蜀雖云樂土，民勤過四方。", "寸壤不容隙，僅能充歲糧。", "間或容墮孏，曷能備凶痒。", "所以農桑具，市易時相望。", "野氓集廣鄽，衆賈趨寶坊。", "惇本誠急務，戒其靡愆常。", "茲會良足喜，後賢勿忽忘。"]'),
('793ea3d6-3ff7-4ddc-87dc-51e842ada4fc','成都遨樂詩二十一首 寒食出城','田況','宋','宋诗','song-poetry','','[]','郊外融和景，濃於城市中。',36,'全唐诗/poet.song.16000.json','["郊外融和景，濃於城市中。", "歌聲留客醉，花意盡春紅。", "遊人一何樂，歸馭莫怱怱。"]'),
('8c9f9d40-7ccf-4505-9fc7-b05595875ad6','成都遨樂詩二十一首 開西園','田況','宋','宋诗','song-poetry','','[]','春山寒食節，夜雨晝晴天。',72,'全唐诗/poet.song.16000.json','["春山寒食節，夜雨晝晴天。", "日氣薰花色，韻光徧錦川。", "臨流飛鑿落，倚榭立鞦韆。", "檻外遊人滿，林間飲帳鮮。", "衆音方雜遝，餘景更留連。", "座客無辭醉，芳菲又一年。"]'),
('29be2a50-c02c-431e-beeb-63cf408175ce','成都遨樂詩二十一首 三月三日登學射山','田況','宋','宋诗','song-poetry','','[]','麗日照芳春，良會重元巳。',120,'全唐诗/poet.song.16000.json','["麗日照芳春，良會重元巳。", "陽濱修祓除，華林程射技。", "所尚或不同，茲俗亦足喜。", "門外盛車徒，山半列鄽市。", "彩堋飛鏑遠，醉席歌聲起。", "回頭望城郭，烟靄相表裏。", "秀色滿郊原，遥景落川涘。", "目倦意猶遠，思餘情未已。", "登高貴能賦，感物暢幽旨。", "宜哉賢大夫，由斯見材美。"]'),
('f2571fe2-754a-4b4a-83db-d975cdd31000','成都遨樂詩二十一首 九日太慈寺前蠶市','田況','宋','宋诗','song-poetry','','[]','高閣長廊門四開，新晴市井絕纖埃。',32,'全唐诗/poet.song.16000.json','["高閣長廊門四開，新晴市井絕纖埃。", "老農肯信憂民意，又見笙歌入寺來。"]'),
('08d62727-2da7-4a72-9955-96e47e83aed2','成都遨樂詩二十一首 二十一日遊海雲山','田況','宋','宋诗','song-poetry','','[]','春山縹翠一谿清，滿路遊人語笑聲。',32,'全唐诗/poet.song.16000.json','["春山縹翠一谿清，滿路遊人語笑聲。", "自愧非才無異績，止隨風俗順民情。"]'),
('53a336d0-25f8-4140-b4e5-0541de73b5dc','成都遨樂詩二十一首 三月十四日太慈寺建乾元節道場','田況','宋','宋诗','song-poetry','','[]','赤精流景鑠，朱夏向清和。',48,'全唐诗/poet.song.16000.json','["赤精流景鑠，朱夏向清和。", "紺宇修祠盛，華封祝慶多。", "簪裳千載遇，鐘梵五天歌。", "遠俗尤熙泰，皇猷信不頗。"]'),
('666f5c19-2cce-4d4b-9d62-dd2dc1bdf183','成都遨樂詩二十一首 乾元節','田況','宋','宋诗','song-poetry','','[]','感帝開鴻緒，薰風正阜生。',96,'全唐诗/poet.song.16000.json','["感帝開鴻緒，薰風正阜生。", "億年逢景運，萬國贊丕平。", "瑞靄承龍闕，晨曦啟鳳城。", "臚賓趨陛墄，樂舞備韶英。", "譯導來珍貢，酺懽洽頌聲。", "曼齡均慶祝，闓澤慰羣情。", "地有捫參遠，人懷就日誠。", "願將民共樂，聊以報皇明。"]'),
('d4d81c39-2979-444d-9f54-ff1bacc233c1','成都遨樂詩二十一首 四月十九日汎浣花溪','田況','宋','宋诗','song-poetry','','[]','浣花溪上春風後，節物正宜行樂時。',64,'全唐诗/poet.song.16000.json','["浣花溪上春風後，節物正宜行樂時。", "十里綺羅青蓋密，萬家歌吹綠楊垂。", "畫船疊鼓臨芳溆，綵閣凌波汎羽巵。", "霞景漸曛歸櫂促，滿城懽醉待旌旗。"]'),
('0144908d-d78c-45cc-b0e6-d9e087d390ca','成都遨樂詩二十一首 伏日會江瀆池','田況','宋','宋诗','song-poetry','','[]','長空赤日真可畏，三庚遇火氣伏藏。',144,'全唐诗/poet.song.16000.json','["長空赤日真可畏，三庚遇火氣伏藏。", "溫風淟涊鬰不開，流背汗浹思清凉。", "江瀆祠前有流水，懽注蓄洩爲池塘。", "沈沈隆厦壓平岸，好樹蔭亞芙蕖香。", "登舟命酒賓朋集，逃暑大飲宜滿觴。", "絲竹聒耳非自樂，肆望觀者如堵牆。", "吾儕未能免俗累，近日頗困炎景長。", "今晨縱游不覺暮，形爲外役暑亦忘。", "豈如高齋滌百慮，危坐自造逍遥鄉。"]'),
('46b44662-94b4-4928-9213-3be99867c775','成都遨樂詩二十一首 七月六日晚登太慈寺閣觀夜市','田況','宋','宋诗','song-poetry','','[]','萬里銀潢貫紫虛，橋邊螭轡待星姝。',32,'全唐诗/poet.song.16000.json','["萬里銀潢貫紫虛，橋邊螭轡待星姝。", "年年巧若從人乞，未省靈恩徧得無。"]'),
('3f609ce1-7083-4805-9676-f09fc394ea58','成都遨樂詩二十一首 七月十八日太慈寺觀施盂蘭盆','田況','宋','宋诗','song-poetry','','[]','飛閣穹隆軼翠煙，盂蘭盛會衆喧闐。',32,'全唐诗/poet.song.16000.json','["飛閣穹隆軼翠煙，盂蘭盛會衆喧闐。", "且欣酷暑從茲減，漸有凉風快夕眠。"]'),
('407483a6-1640-47c2-aa89-fadbcf132246','成都遨樂詩二十一首 重陽日州南門藥市','田況','宋','宋诗','song-poetry','','[]','岷峨旁礴天西南，靈滋秀氣中潛含。',192,'全唐诗/poet.song.16000.json','["岷峨旁礴天西南，靈滋秀氣中潛含。", "草木瓌富百藥具，山民采捋知辛甘。", "成都府門重陽市，遠近湊集爭齎擔。", "市人譎獪亦射利，頗覺良惡相追參。", "旁觀有叟意氣古，肌面皯黣毛䰐鬖。", "賣藥數種人罕識，單衣結縷和陰嵐。", "成都處士足傳記，勸誡之外多奇談。", "盛言每歲重陽市，屢有仙跡交塵凡。", "俗流聞此動非覬，不識妙理徒規貪。", "惟期幸遇化金術，未肯投足栖雲嵓。", "予於神仙無所求，一離常道非所躭。", "但喜山民藥貨售，歸助農業增耡芟。"]'),
('db396ca7-868d-4f69-b267-447391bf49a5','成都遨樂詩二十一首 冬至朝拜天慶觀會太慈寺','田況','宋','宋诗','song-poetry','','[]','景至履佳辰，朝祖著國令。',120,'全唐诗/poet.song.16000.json','["景至履佳辰，朝祖著國令。", "黄宮啟潛萌，紫宇晨蔭映。", "陽德比君子，吾道實可慶。", "矧丁皇運亨，遇主堯舜聖。", "坤維最遠方，拙者此尸政。", "雅俗舊儒文，民牒少訟爭。", "幸足宣上恩，惟恐盭物性。", "良時不易得，行樂未爲病。", "高會縱嬉遊，豐歲愈繁盛。", "興衆助驩欣，寄情於俚詠。"]'),
('20c81ffc-53c6-4588-91ff-0a2b69b1f9d8','贈都監雍元規','田況','宋','宋诗','song-poetry','','[]','醒時莫憶醉時事，今日休言昨日非。',32,'全唐诗/poet.song.16000.json','["醒時莫憶醉時事，今日休言昨日非。", "池上風光宜共釂，勸君不要半酣歸。"]'),
('f309ecf4-a135-4829-888e-5f88411cfedd','潁水','田況','宋','宋诗','song-poetry','','[]','先生嘗此傲明時，綠袖清波萬古奇。',32,'全唐诗/poet.song.16000.json','["先生嘗此傲明時，綠袖清波萬古奇。", "應有好名心未息，灘頭洗耳欲人知。"]'),
('b9b6cc5c-303e-4704-ab51-d0e66e34765a','寄道士張明真','田況','宋','宋诗','song-poetry','','[]','澹靜姿儀簡曠縱，結菴深對大茅峯。',64,'全唐诗/poet.song.16000.json','["澹靜姿儀簡曠縱，結菴深對大茅峯。", "坐忘世故愁應少，道斷人情語亦慵。", "萬里信音憑鶴到，一厨煙火倩猿供。", "幾時歸侍虛皇駕，七色霞衣九色龍。"]'),
('3ab6e83a-7107-4e1a-bf3e-e086e1f160fa','句  其一','田況','宋','宋诗','song-poetry','','[]','曲終甚喜詢前事，自言本是都知子。',48,'全唐诗/poet.song.16000.json','["曲終甚喜詢前事，自言本是都知子。", "當時此地最繁華，酒酣不覺恣矜誇。", "若使斯人解感傷，豈能終老愛琵琶。"]'),
('48f23720-ba6a-43bd-9461-6c089919723c','句  其二','田況','宋','宋诗','song-poetry','','[]','丹鳳詔不起，白雲藏更深。',12,'全唐诗/poet.song.16000.json','["丹鳳詔不起，白雲藏更深。"]'),
('7d0dcecc-476f-43cc-9926-f3fd3dbc5d9f','華亭十詠 顧亭林','唐詢','宋','宋诗','song-poetry','','[]','平林標大道，曾是野王居。',48,'全唐诗/poet.song.16000.json','["平林標大道，曾是野王居。", "舊里風煙變，荒原草樹踈。", "湖波空上下，里閈已丘墟。", "往事將誰語，淒涼六代餘。"]'),
('0e0b6315-d2e9-4698-9f06-f9432f2929dc','華亭十詠 寒穴','唐詢','宋','宋诗','song-poetry','','[]','絕頂干雲峻，寒泉與穴平。',48,'全唐诗/poet.song.16000.json','["絕頂干雲峻，寒泉與穴平。", "還同帝臺味，不學隴頭聲。", "夜雨遥源漲，秋風顥氣清。", "誰云蔗漿美，纔可析朝酲。"]'),
('c9a7fcc4-5ebc-4a95-bbd5-2453d32b2227','華亭十詠 吳王獵場','唐詢','宋','宋诗','song-poetry','','[]','昔在全吳日，從禽耀甲戈。',48,'全唐诗/poet.song.16000.json','["昔在全吳日，從禽耀甲戈。", "百車嘗載羽，一目舊張羅。", "地變柔桑在，原荒蔓草多。", "思人無復見，落日下山坡。"]'),
('a34f8187-7ec0-4d7e-9327-c8e60dddd1b2','華亭十詠 柘湖','唐詢','宋','宋诗','song-poetry','','[]','世歷亡秦遠，湖連大海瀕。',48,'全唐诗/poet.song.16000.json','["世歷亡秦遠，湖連大海瀕。", "柘山標觀望，玉女見威神。", "渺渺旁無地，滔滔孰問津。", "何年化魚鼈，髣髴歷陽人。"]'),
('65b33391-a8e9-44d5-9cc0-fd9a69c0c180','華亭十詠 秦始皇馳道','唐詢','宋','宋诗','song-poetry','','[]','秦德衰千祀，江濱道不脩。',48,'全唐诗/poet.song.16000.json','["秦德衰千祀，江濱道不脩。", "相傳大堤在，曾是翠華遊。", "玉趾如將見，金椎豈復留。", "悵然尋舊跡，蔓草蔽荒丘。"]'),
('3b3e5924-85ee-4f49-80e3-994e247ef927','華亭十詠 陸瑁養魚池','唐詢','宋','宋诗','song-poetry','','[]','代異人亡久，滮池即舊居。',48,'全唐诗/poet.song.16000.json','["代異人亡久，滮池即舊居。", "未移當日地，無復故時魚。", "蒲藻依稀在，風波浩蕩餘。", "水濱如可問，一爲訪庭除。"]'),
('89e1c950-f157-46c9-9a10-09d29ee71cb4','華亭十詠 華亭谷','唐詢','宋','宋诗','song-poetry','','[]','深谷彌千里，松陵北合流。',48,'全唐诗/poet.song.16000.json','["深谷彌千里，松陵北合流。", "岸平迷晝夜，人至競方舟。", "照月方諸泣，迎風弱荇浮。", "平波無限遠，極目漲清秋。"]'),
('b8ec784c-ab1c-42ba-bda2-8ae25f164b03','華亭十詠 陸機宅','唐詢','宋','宋诗','song-poetry','','[]','舊諜傳遺趾，悠然歷祀深。',48,'全唐诗/poet.song.16000.json','["舊諜傳遺趾，悠然歷祀深。", "人無令威至，門異下邽箴。", "谷水當年溜，崑山昔日陰。", "魯堂那復見，絲竹若爲尋。"]'),
('eb6913f0-f67a-4bb6-9f11-f436d815d9e7','華亭十詠 崑山','唐詢','宋','宋诗','song-poetry','','[]','昔有人如玉，茲山得美名。',48,'全唐诗/poet.song.16000.json','["昔有人如玉，茲山得美名。", "巖扃鎖積翠，谷水斷餘聲。", "喬木今無在，高臺久已傾。", "如何嵩嶽什，獨詠甫侯生。"]'),
('af9f6719-c06f-4fc3-a12c-5b1279c4344e','華亭十詠 三女崗','唐詢','宋','宋诗','song-poetry','','[]','淑女云亡久，哀丘尚著名。',48,'全唐诗/poet.song.16000.json','["淑女云亡久，哀丘尚著名。", "九原誰可作，千載或如生。", "青骨何時化，荒榛此地平。", "空餘圖諜在，不復啟佳城。"]'),
('187cc54d-2d1c-44fe-91d1-481339c7154b','山堂偶書','唐詢','宋','宋诗','song-poetry','','[]','在處煙雲早晚生，自疑呼吸氣皆靈。',32,'全唐诗/poet.song.16000.json','["在處煙雲早晚生，自疑呼吸氣皆靈。", "十年夢寐江山裏，今見江山入戶庭。"]'),
('cf603bdf-8ca3-41ed-82f7-f32e9e7ac5f1','爲杭州日送客舟中','唐詢','宋','宋诗','song-poetry','','[]','山雨霏微不滿空，畫船來往疾輕鴻。',32,'全唐诗/poet.song.16000.json','["山雨霏微不滿空，畫船來往疾輕鴻。", "誰知獨卧珠簾裏，一榻無塵四面風。"]'),
('573d3282-0d9e-4c66-b255-cf30203f55be','題曲水閣','唐詢','宋','宋诗','song-poetry','','[]','依山營廢壤，結宇跨通溝。',48,'全唐诗/poet.song.16000.json','["依山營廢壤，結宇跨通溝。", "派引平湖遠，聲分幾曲流。", "交陰覆脩竹，照影下輕鷗。", "此日羣賢集，甯疎晉世游。"]'),
('909ac858-4722-4be7-907c-2ef00103a17e','遊五泄山  其一','唐詢','宋','宋诗','song-poetry','','[]','尋徹靈潭第五源，旋攀蘿蔦至山巔。',64,'全唐诗/poet.song.16000.json','["尋徹靈潭第五源，旋攀蘿蔦至山巔。", "寒聲昔謂來天外，巨壑今知在目前。", "峭壁無時長蔽日，重巖不雨亦生烟。", "臨觀已覺塵心盡，更欲凌雲訪列仙。"]'),
('392962ae-c16e-4fe8-bee7-4b5473bfcdea','遊五泄山  其二','唐詢','宋','宋诗','song-poetry','','[]','遊遍西潭返步遲，亂雲隨履雨沾衣。',32,'全唐诗/poet.song.16000.json','["遊遍西潭返步遲，亂雲隨履雨沾衣。", "山形相向還相背，獨有溪流共我歸。"]'),
('ac0069e1-6dd7-418a-bfc6-0a8431273680','寄五峯諫長老','唐詢','宋','宋诗','song-poetry','','[]','禪客居山患不深，五峯幽絕杳難尋。',64,'全唐诗/poet.song.16000.json','["禪客居山患不深，五峯幽絕杳難尋。", "門前流水朝還暮，堂下閒雲古復今。", "月色有時依宴坐，秋聲隨處伴謳吟。", "期師便作終焉計，忍負平生物外心。"]'),
('5fbdf536-d498-46cb-9281-4af2592accb4','題會稽谿口躬師上人房','唐詢','宋','宋诗','song-poetry','','[]','谿口相傳地最靈，其間風物與人清。',64,'全唐诗/poet.song.16000.json','["谿口相傳地最靈，其間風物與人清。", "鐘聲夜到江頭盡，雲氣朝從檻外生。", "幾副輕綃供畫筆，一林脩竹寄閒情。", "閉門終日無塵事，卧看南□自晦明。"]'),
('c44f6ebe-f485-4328-94d9-64f17a70ed73','益州州學聖訓堂','何郯','宋','宋诗','song-poetry','','[]','益爲藩捍西南隅，物衆地大稱名都。',384,'全唐诗/poet.song.16000.json','["益爲藩捍西南隅，物衆地大稱名都。", "擇守來頒茲土政，治人頗與他邦殊。", "蹉跌一有戾條教，便宜皆得行黥誅。", "羣姦帖息不敢動，無復弄兵覬穿窬。", "任威或謂一時事，立政恐非長世圖。", "豈無達識究是否，重在改作徒嗟吁。", "仲翁裔孫有偉度，敢决不以常文拘。", "當官勇欲除弊法，伊憂內惻仁心孚。", "視人無異遠方意，威刑惠政還相須。", "始時歲荒力賑救，坐使餓殍成完膚。", "既而爲俗思根本，其在立學陳師謨。", "大開儒庠務誨導，秀民聳慕紛來趨。", "遂言講署鴻生職，使演經傳傳諸徒。", "奏函一上聞法座，詔劄即日來諧俞。", "詔云信汝辨治蜀，緩任威罰先文儒。", "公心感激侈上賜，刻在金石尊神謨。", "覆之大厦牓美稱，日久傳者期無渝。", "邦人承風爲盛事，觀者填道來于于。", "嗟嗟多士其聽命，勿即邪徑安夷涂。", "師無訿聖生率教，信尚姬孔尊唐虞。", "施之鄉黨勵雅俗，仁誼得以相持扶。", "漢皇初始盛文學，起自蜀國行中區。", "本朝教化視三代，建元安可爲齊驅。", "吾君訓辭諭萬里，義均盤誥茲宣敷。"]'),
('63acc5f3-b9c0-4106-8a64-93fe5282410b','存目','何郯','宋','宋诗','song-poetry','','[]','詩題：原無題首句：按徹梁州更六幺一作蜀國佳人號細腰。',26,'全唐诗/poet.song.16000.json','["詩題：原無題首句：按徹梁州更六幺一作蜀國佳人號細腰。"]'),
('afcd1bd4-0747-4a88-af7f-5e4b02e47c64','句','潘夙','宋','宋诗','song-poetry','','[]','橐中奇物爲棋輸。',8,'全唐诗/poet.song.16000.json','["橐中奇物爲棋輸。"]'),
('05715d7d-ffab-4d38-9419-79f72a366c91','送程給事知越州','張宗益','宋','宋诗','song-poetry','','[]','仙境際雲霓，名藩獨會稽。',72,'全唐诗/poet.song.16000.json','["仙境際雲霓，名藩獨會稽。", "蓬萊住山小，星宿落簷低。", "旌節臨諸郡，樓臺瞰北齊。", "地繁秦望嶺，民阜若耶溪。", "化俗饒餘事，吟詩厭舊題。", "只愁嚴召速，榮渡浙江西。"]'),
('95ea5cce-ac32-44e1-b21d-290307955759','留題樓觀','薛周','宋','宋诗','song-poetry','','[]','結草終南下，雲蘿一逕深。',48,'全唐诗/poet.song.16000.json','["結草終南下，雲蘿一逕深。", "人窮文始跡，誰到伯陽心。", "古木含天理，清風快客襟。", "勞車行計促，空媿負長吟。"]'),
('1ea9de9e-33a6-483c-aeb1-e2b5628710c3','次唐彥猷顧亭林韻','魯晦之','宋','宋诗','song-poetry','','[]','烟雨三家市，黄門卜此居。',48,'全唐诗/poet.song.16000.json','["烟雨三家市，黄門卜此居。", "著書千紙在，祠宇幾椽疎。", "潮汐成今古，牛羊有里墟。", "舉兵鉏逆節，風烈照無餘。"]'),
('17d2df0c-4585-428e-87c4-1a413f2ca40f','春晚','蘇敖','宋','宋诗','song-poetry','','[]','芳草莫尋遊處跡，好花空認折殘枝。',32,'全唐诗/poet.song.16000.json','["芳草莫尋遊處跡，好花空認折殘枝。", "啼鶑似怨歸何速，舞蝶應憐出太遲。"]'),
('fb338162-e8ba-41c2-a703-872568591d76','鴻溝','蘇敖','宋','宋诗','song-poetry','','[]','置俎均牢彘，峨冠信沐猴。',48,'全唐诗/poet.song.16000.json','["置俎均牢彘，峨冠信沐猴。", "方矜几上肉，已墮幄中籌。", "海岳歸三尺，衣冠閟一丘。", "路人猶指似，山下是鴻溝。"]'),
('9f38a4fb-6070-4d7b-9a6a-070a8f07be85','丙子仲冬紫閣寺聯句','蘇舜元','宋','宋诗','song-poetry','','[]','白石太古水，蒼厓六月冰。',288,'全唐诗/poet.song.16000.json','["白石太古水，蒼厓六月冰。", "昏明咫尺變，身世逗留增。", "橋與飛霞亂，人間獨鳥升。", "風泉冷相搏，樓閣暮逾澄。", "反覆青冥上，躋攀赤日稜。", "唄音充別壑，塔影弔寒藤。", "仙掌挂太一，佛壇依古層。", "巖喧聞鬭虎，臺靜下饑鷹。", "晴檻通年雨，濃蘿四面罾。", "日光平午見，霧氣半天蒸。", "潭碧寒疑裂，鐘清遠自凝。", "陽陂冬聚筍，陰壁夏垂繒。", "有客饒佳思，高吟出遠凭。", "雄心翻表裏，遠目著軒騰。", "岑寂來清夜，沈冥接定僧。", "宿猿深更杳，落木靜相仍。", "松竹高無奈，煙嵐翠不勝。", "甘酸收脫實，坳隩布清塍。", "北野才沈著，南天更勃興。", "恣睢超一氣，黤黮起孤鵬。", "並澗寒堪摘，看雲重欲崩。", "行中向背失，呼處下高應。", "庭樹巢金爵，樵兒弄玉繩。", "斷香浮缺月，古像守昏燈。"]'),
('78067d86-d40d-4425-a421-7a1871d80824','水輪聯句','蘇舜元','宋','宋诗','song-poetry','','[]','痛矣真源喪，紛紜物象來。',216,'全唐诗/poet.song.16000.json','["痛矣真源喪，紛紜物象來。", "水輪今若此，世事亦宜哉。", "上下車交輻，周旋斗轉魁。", "咸淵日微墮，仙窟月初開。", "旁柅從爲用，垂絙重亦回。", "枘多初不曉，機密暗相該。", "圃外滄浪洩，庭間霹靂摧。", "玉飛千仞表，纓挂九泉隈。", "翻覆殊難定，牽連巧自媒。", "建瓴今比速，抱甕此相哀。", "平眡曾無覺，深窺遂可猜。", "團團釋子壁，軋軋燕王臺。", "解見陶埏運，寧觀將轂推。", "造端原有發，汲用始知材。", "本異道家意，定遭怡士咍。", "轉圓非雅具，欹器有深災。", "持滿忘前監，相傾自下催。", "流風無以復，視此一裴回。"]'),
('da9d5709-6b93-4770-b6ed-8ee0a57a4c30','薦福塔聯句','蘇舜元','宋','宋诗','song-poetry','','[]','踴甓皇都壯，盤基紫宙雄。',192,'全唐诗/poet.song.16000.json','["踴甓皇都壯，盤基紫宙雄。", "山河供遠目，薝戶發高風。", "梯險三休上，輪開一氣中。", "門當谷子午，影落陌西東。", "韻鐸翻天籟，危觚駐夕紅。", "側聆悲下俗，仰面識長空。", "絕若神擠至，深疑壑暗通。", "人寰如蟻垤，身世甚秋蓬。", "歎息興亡地，沈吟製作工。", "清思抱明月，狂欲把飛鴻。", "去矣登臨興，巍乎造化功。", "凉襟當爽塏，幽意入鴻濛。", "頭角峯如揖，丹青樹不同。", "城郭回迤邐，閣殿失穹隆。", "可使孤懷放，胡爲萬恨終。", "何當得壯士，提取出塵籠。"]'),
('0cd16c72-dad3-4e7c-8571-0731d18d45ba','悲二子聯句','蘇舜元','宋','宋诗','song-poetry','','[]','有客自遠方，來以二子說。',288,'全唐诗/poet.song.16000.json','["有客自遠方，來以二子說。", "穆子病疾初，家事巨細缺。", "鄰人苦其求，醫師久以决。", "案杯小大空，布被旁午裂。", "餘喘尚能鼓，老憤知已結。", "目淒望羊泓，髭斷反蝟茁。", "憂酸繫餘生，嗥嘑留永訣。", "語妻後日計，書策未可徹。", "教子勤誦讀，時命不復說。", "吾屬何流離，衆人方草竊。", "凌子久道路，十口著羈紲。", "恰旅重江間，正值大饑節。", "既無裹飯交，疾走繼粗糲。", "又無執飲人，及時沃枯竭。", "惜哉損天命，痛焉在親絰。", "帝胡生爾身，世復稱其傑。", "胸伏氣萬丈，腸貯怨百折。", "艱難汩風波，顦顇墮霜雪。", "久僕勤龍鍾，弱女癡蹩躠。", "文隨寒餓空，道與煙燄滅。", "魂兮竟何歸，去矣不得別。", "長府豈無財，莫濟醫藥切。", "太倉豈無粟，莫解腹腸熱。", "天子聖在上，海內清欲澈。"]'),
('d4953d48-5f94-4e3b-9a73-6dd7fc77a72b','地動聯句','蘇舜元','宋','宋诗','song-poetry','','[]','大荒孟冬月，末旬高舂時。',288,'全唐诗/poet.song.16000.json','["大荒孟冬月，末旬高舂時。", "日腹昏盲倀，風口鳴嗚咿。", "萬靈困陰戚，百植嗟陽衰。", "濃寒有勝氣，天凍無敗期。", "六指忽摇拽，羣蹠初奔馳。", "丸銅落蟾吻，始異張渾儀。", "列宿犯天紀，預念漢志辭。", "民甍函鼓舞，禁堞强崩離。", "坐駭市聲死，立怖人足踦。", "坦途重車僨，急傳壯馬敧。", "陵阜動撫手，礫塊當揚箕。", "停污有亂浪，僵木無靜枝。", "衆喙不暇息，沓嶂驚欲飛。", "踴塔撼鐸碎，安流蕩舟疲。", "倒壺喪午漏，顛巢駭眠鴟。", "居人眩眸子，行客勞髑兒。", "南北頓儵忽，西東播戎夷。", "四鎮一毛重，百川寸涔微。", "斗藪不知大，軒幹主者誰。", "共工豈復怒，富嫗安得爲。", "寧無折軸患，頓易崩山悲。", "衆蟄不安土，羣毛難麗皮。", "驚者去靡所，仆或如見擠。", "轟雷下檐瓦，决玉傾倉粢。"]'),
('fa823e41-2474-48e1-870e-612a9b82cda2','瓦亭聯句','蘇舜元','宋','宋诗','song-poetry','','[]','陰霜策策風呼虓，羌賊膽開凶燄豪。',384,'全唐诗/poet.song.16000.json','["陰霜策策風呼虓，羌賊膽開凶燄豪。", "赤膠脆折乳馬健，漢野秋穟黄雲高。", "驅先老尩伏壯黠，裹以山壑鬼莫招。", "烽臺屹屹百丈起，但報平安摇桔槔。", "喜聞羸師入吾地，主將踴躍士惰驕。", "神鋒前揮擁勝勢，橫陣立敵俱奔逃。", "不知餌牽落檻穽，一麾發伏如驚飆。", "重圍八面鳥難度，相顧無路惟青霄。", "地形窄束甲刺骨，眥裂不復能相鏖。", "棄兵衮衮令不殺，部曲易主無纖囂。", "慟哭皇天未厭禍，空同無色勁氣消。", "狂童得志賤物命，隴上盤馬爲嬉遨。", "蒼皇林間健兒婦，翦紙瀝酒呼嗷嗷。", "將軍疾趨占葬地，年年載柩爭咸崤。", "朝廷不惜好官爵，絳蠟刻印埋蓬蒿。", "三公悲吟困數敗，車上輕重如鴻毛。", "白衣壯士氣塞腹，憤勇不忍羞本朝。", "重瞳三顧可易得，亮輩本亦生吾曹。", "窮居哀牢厭咄咄，歲月奔激朱顔凋。", "當年請行大明下，今日頹墮思南巢。", "陽羨溪光逗蒼玉，尺半健鯽煙中跳。", "便欲買田學秧稻，不復與世爭錙毫。", "奈何三世奉恩澤，肯以軀命辭枯焦。", "以知出處繫大義，一飯四顧情如燒。"]'),
('c2cecf92-6e93-4f37-934f-a88b582b8d4e','淮上喜雨聯句','蘇舜元','宋','宋诗','song-poetry','','[]','江淮經歲旱，春暮忽然雨。',240,'全唐诗/poet.song.16000.json','["江淮經歲旱，春暮忽然雨。", "亂點踰廣津，散灑入原土。", "萬物氣稍蘇，厲妖莫能聚。", "羣山洗故塵，紫翠坐可數。", "昏如籠纖紗，媚若隠紺縷。", "碧瓦南崦中，重疊出迥覩。", "扁舟凌空飛，白鳥入煙舞。", "遥林動新滋，顔色若可取。", "碧草弄微芳，低昂欲來語。", "緐聲過沙頭，上下謳啞櫓。", "濃澹新畫成，快愜久病愈。", "念此時多虞，豈得歲少阻。", "焦心閔疲農，虛口待香稌。", "縣吏事凶貪，氣若解縛虎。", "惟於縱誅斂，乃能奮怒武。", "青天雖云明，疑不照艱苦。", "此時忽霶霈，知有神物主。", "不然諸蒼生，性命委草莽。", "本蹷邦豈寧，皮去毛安附。", "歌此告巨公，行當視前古。"]'),
('3f90f8e9-9b86-4c39-a1e0-eacdb4d3eaf1','送梁子熙聯句','蘇舜元','宋','宋诗','song-poetry','','[]','大榮大辱，能生死人。',130,'全唐诗/poet.song.16000.json','["大榮大辱，能生死人。", "二物不並，以撓厥真。", "之子病悶，腸如車輪。", "勞憂到母，饒寒著身。", "世俗鹵莽，輒置莫親。", "文彩華豔，伏不得伸。", "悽吟哀號，酸入四鄰。", "夜計破午，若燕作秦。", "腹憤軋軋，胸奇陳陳。", "淮國晚嶺，吳渠春津。", "去謝夙藴，歸逢故辛。", "雌火相丑，刮鑿遯屯。", "駕風鞭霆，以脫凡鱗。"]'),
('ba6b4d63-7c12-485d-be81-42bec7979169','題海昌安國寺','蘇舜元','宋','宋诗','song-poetry','','[]','畫堂三月初三日，絮撲紗窗燕拂簷。',64,'全唐诗/poet.song.16000.json','["畫堂三月初三日，絮撲紗窗燕拂簷。", "蓮子數杯嘗冷酒，柘枝一曲試新衫。", "階臨池面勝看鏡，屋映花叢當下簾。", "誰倚南樓指新月，玉鉤素手兩纖纖。"]'),
('523b9b90-14df-4a65-8065-41efbce4680e','仙都山','蘇舜元','宋','宋诗','song-poetry','','[]','龍車鳳輦入瑶天，轍迹高懸不可攀。',32,'全唐诗/poet.song.16000.json','["龍車鳳輦入瑶天，轍迹高懸不可攀。", "唯有風吹鼎湖水，青蓮花葉落人間。"]'),
('b69034be-06e9-4e67-9388-d0f8bd4760d1','釣鼇石','蘇舜元','宋','宋诗','song-poetry','','[]','未窮雙佛剎，先到一漁家。',48,'全唐诗/poet.song.16000.json','["未窮雙佛剎，先到一漁家。", "山雨已殘葉，溪風猶落花。", "汲泉沙脈動，敲火石痕斜。", "應是任公子，竹間曾煮茶。"]'),
('e290efc4-a04a-4d1d-8ea3-ad1bdf6b3b6f','青州資政寄示小楷伯夷頌許昌相公以詩跋尾因作詩謝二公兼呈永興觀文相公','蘇舜元','宋','宋诗','song-poetry','','[]','法書遥逐使車還，嘉句新從相府頒。',64,'全唐诗/poet.song.16000.json','["法書遥逐使車還，嘉句新從相府頒。", "牢落二賢天地外，風流三絕古今間。", "臺文競耀高逾麗，化筆交揮老更閑。", "不用悲吟恐飛去，豈無神物護重關。"]'),
('b50f448f-5c63-4526-b845-be5444b3119b','句','蘇舜元','宋','宋诗','song-poetry','','[]','斷香浮缺月，古像守昏燈。',12,'全唐诗/poet.song.16000.json','["斷香浮缺月，古像守昏燈。"]'),
('9f9b4900-0c64-42d1-8772-c9644b3aa554','和祖擇之詠震山巖彭徵君釣臺','章友直','宋','宋诗','song-poetry','','[]','巖因更號震山居，臺上猶存舊釣磯。',32,'全唐诗/poet.song.16000.json','["巖因更號震山居，臺上猶存舊釣磯。", "一派滄浪真隠處，澄清尚可濯塵衣。"]'),
('495280b2-24a0-4e60-aab8-53d89b97eb58','重建羊侯祠和王原叔句','連庠','宋','宋诗','song-poetry','','[]','大江西來遶重城，猶如叢花疋練縈。',384,'全唐诗/poet.song.16000.json','["大江西來遶重城，猶如叢花疋練縈。", "左山右阜若開避，曾是峴首當頭橫。", "江湍衝山山不動，滔滔雪浪東南傾。", "聵然巨勢壓漢境，萬楚不得專雄名。", "四時美景千百狀，登臨可以攄襟靈。", "近麓挼藍秋水綠，幽巖團纈春葩明。", "寒林蕭疎四面合，夏木延袤長川青。", "危巔碑墊龜螭蟄，陰崖檜老蛟龍形。", "俯瞰洲島相向背，風恬江面羅紋生。", "漁舠數百集其下，瞥然來往一葉輕。", "波底崢嶸沈翠影，槎頭鳬雁斂霜翎。", "天然佳致信可尚，直是丹青寫不成。", "叔子當年樂山水，每來置酒空壚罌。", "賢達勝士共愛此，謂此風景魁南荆。", "荆人被化思不已，立祠山椒共祭牲。", "爾來綿亙幾千載，瓦飛棟撓誰經營。", "守臣罕肯著脚到，遂至完固屬兼并。", "非憚鳩工繕完葺，誠知仁政難繼聲。", "帝眷襄陽曰重鎮，宜從館閣擇名卿。", "明公之來百城悅，壺漿竹馬相歡迎。", "政成公休屢登覽，山前車騎長晶熒。", "傃空寓目看不足，詩豪佚發輸精誠。", "乃敕寮屬復祠宇，仍從嶺上新虛亭。", "歲時遊憩備言詠，荆人愛之猶鉅平。"]'),
('988cf5df-e963-48c9-b306-a5c1cf8ac581','題招提院靜照堂','周孟陽','宋','宋诗','song-poetry','','[]','羨師遺世網，舊隠敞新堂。',48,'全唐诗/poet.song.16000.json','["羨師遺世網，舊隠敞新堂。", "月白秋庭小，風清晝榻凉。", "倦遊輕勢利，歸夢在滄浪。", "滿篋朝賢句，孤雲出帝鄉。"]'),
('b279af02-28d9-4475-ac5c-160fa1e5a37c','句','周孟陽','宋','宋诗','song-poetry','','[]','地高多與風雲會，天近嘗爲日月鄰。',16,'全唐诗/poet.song.16000.json','["地高多與風雲會，天近嘗爲日月鄰。"]'),
('3a025cfb-6b6a-4e6d-9c3a-766a8e3e453e','京中懷歸','羅孟郊','宋','宋诗','song-poetry','','[]','一自題名後，思歸何日歸。',48,'全唐诗/poet.song.16000.json','["一自題名後，思歸何日歸。", "雖然著宮錦，不及無斑衣。", "故里桑榆晚，他鄉雨雪霏。", "庭前停玉軫，目送鴈南歸。"]'),
('789f1927-e27e-4362-99fe-10ae97eb6047','耆英會  其一','席汝言','宋','宋诗','song-poetry','','[]','繫國安危唐上宰，功成身退漢留侯。',64,'全唐诗/poet.song.16000.json','["繫國安危唐上宰，功成身退漢留侯。", "二公閑暇開高宴，九老雍容奉勝流。", "共接雅歡恩意洽，不矜崇貴禮容優。", "賞心樂事人間盛，豈謂今稀古莫儔。"]'),
('f5818e0a-8253-4720-9113-59956ea63409','耆英會  其二','席汝言','宋','宋诗','song-poetry','','[]','壯歲塵埃祿事牽，老歸重到舊林泉。',64,'全唐诗/poet.song.16000.json','["壯歲塵埃祿事牽，老歸重到舊林泉。", "曾無勳業書青史，偶向康寧養老年。", "自分杜門居陋巷，敢期序齒預公筵。", "更慚形穢才凉薄，不稱圖真接鉅賢。"]'),
('98746bb4-635d-437d-946e-42628fd846d2','詠濯纓亭','程珦','宋','宋诗','song-poetry','','[]','西園勝跡名天下，唐相經營用意工。',64,'全唐诗/poet.song.16000.json','["西園勝跡名天下，唐相經營用意工。", "島嶼回環壓湖面，樓臺重複倚雲空。", "濯纓泉潔存遺跡，促軫亭空想舊風。", "公暇未應無客會，春遊更喜與民同。"]'),
('61e2ef9e-ae77-45ba-bf4f-375a5b002741','遊壽安山示二子頤顥','程珦','宋','宋诗','song-poetry','','[]','藏拙歸來已十年，身心世事不相關。',32,'全唐诗/poet.song.16000.json','["藏拙歸來已十年，身心世事不相關。", "洛陽山水尋須遍，更有何人似我閒。"]'),
('8de847fa-edf2-43ad-987a-3145c6ae5815','遊紫雲洞','文彥博','宋','宋诗','song-poetry','','[]','同登青雲梯，遠訪紫雲洞。',132,'全唐诗/poet.song.16000.json','["同登青雲梯，遠訪紫雲洞。", "黄冠既前導，絳韝亦後從。", "幽奇素所希，險絕曾無恐。", "況此巖谷遊，不知雙舄重。", "攝衣叩洞戶，肅若心神悚。", "兩崖勢相嶔，左右如抱擁。", "萬木傍森羅，一水中洶湧。", "信哉天下奇，豈適谷間用。", "賞景未盡興，向夕遽旋踵。", "飄然御風行，恍若遊仙夢。", "異日期再來，退閑心更勇。"]'),
('0c1a9211-b33d-4ad1-83f4-ecf87d5d209d','寄贈華清觀主大師','文彥博','宋','宋诗','song-poetry','','[]','五城三洞朝真客，紫房名隸神仙籍。',144,'全唐诗/poet.song.16000.json','["五城三洞朝真客，紫房名隸神仙籍。", "玉案晨飡沆瀣精，椒庭夜飲流霞液。", "姑山綽約冰雪容，亭亭霞外脫塵蹤。", "飚馭狂遊紫貝閣，雲裝醉入白銀宮。", "想陪桂父與金母，崑蓬春賞蟠桃紅。", "愚亦放懷隨澹泊，崑芝茹朮希彭朔。", "常秘六泥東竈丹，每求五色西山藥。", "紫臺久判浮丘袂，錦州繡嶺三千里。", "羽駕鸞驂未載逢，經年望斷函關氣。"]'),
('301888a9-d16d-4841-ad8e-d333abe27be6','彭門賢守器之度支趙鼎記余生日過形善祝并惠黄石茶甌懷素千字文一軸輒成拙詩仰答來意','文彥博','宋','宋诗','song-poetry','','[]','使從徐方來，執訊如雙魚。',132,'全唐诗/poet.song.16000.json','["使從徐方來，執訊如雙魚。", "遺我黄石器，副之懷素書。", "素書與黄石，得之宜在徐。", "或在圯橋下，或在留城墟。", "因物以達意，思賢而警愚。", "愚今所叨竊，何必承明廬。", "位歷二府重，年登七旬餘。", "陋軀賁華衮，微名得虛譽。", "三朝被寵遇，八難慚嘉謨。", "瞻言西洛汭，願繼東門疏。", "意者赤松子，果是吾之徒。"]'),
('2d665645-2507-4c85-aeb0-e2a8a9163b5e','寄致政太傅侍中曾魯公','文彥博','宋','宋诗','song-poetry','','[]','天壇小有洞，神仙稱福地。',180,'全唐诗/poet.song.16000.json','["天壇小有洞，神仙稱福地。", "草木盡翅秀，靈壽物珍異。", "孑立無附枝，挺生出羣類。", "既不假矯揉，復不煩削治。", "制杖待時用，訓鳩循古義。", "獻於君子堂，達此野人意。", "所獻雖已微，其意亦有謂。", "願公稍扶持，與國同安置。", "匪惟布私誠，茲乃出公議。", "豈圖一羽輕，復委千鈞賜。", "報之以寶鑑，百練粗明致。", "副之以雅章，二南風格備。", "蔀屋天光照，陋軀華衮賁。", "何以稱尊貺，傳家爲重器。", "何以繼希聲，陳詩言鄙志。"]'),
('11727534-4be3-4b02-b7d0-6f3790bad6c8','伏蒙僕射侍中賈寄示游潠上弊園歸至湖上詩一章研味欽服不能自已輒成拙句仰答來貺','文彥博','宋','宋诗','song-poetry','','[]','脩篁小塢潩水湄，略有亭觀體甚微。',224,'全唐诗/poet.song.16000.json','["脩篁小塢潩水湄，略有亭觀體甚微。", "陪京上宰樂幽趣，閑乘齋舫臨荆扉。", "是時仲夏之晦日，日輪停午炎炎時。", "披襟岸幘意自適，林下穆若生凉颸。", "子猷愛竹不問主，魯侯在泮因成詩。", "妍詞麗句溢累幅，金壺酒墨何淋漓。", "公適東偏訪顔陋，愚當北道承蕭規。", "魏人思公過召伯，一言一話無所遺。", "疇昔篇章僅三百，至今琬琰羅珠璣。", "跨山飛閣常逃暑，白醪滿泛黄金巵。", "沈李浮瓜信美矣，回船弄水曾無之。", "遥瞻德星方聚處，正與兩兩交光輝。", "潁川異迹冠天下，湖上勝景隣日圍。", "鹿輿桂檝亟游覽，即見零雨東山歸。"]'),
('14220016-1f23-4b9c-b12c-356205f30114','送子駿朝議歸闕','文彥博','宋','宋诗','song-poetry','','[]','累年分領西臺憲，留滯周南人共歎。',128,'全唐诗/poet.song.16000.json','["累年分領西臺憲，留滯周南人共歎。", "蚤傳文價出坤維，爲有仙才生閬苑。", "桂籍登科既已失，蘭筋飛步終難絆。", "兩持漕節賦均平，歷守藩符政寬簡。", "聖皇繼統始謀廟，哲輔官材專進善。", "巍巍雲闕此歸覲，禁嚴侍從須邦彥。", "離襟欲判重徘徊，林下相從池上杯。", "別後思君何處望，肩輿頻上紫金臺。"]'),
('e4f87899-9a42-47d8-b77f-93da0b9f185f','送乾元寺`住持實大師','文彥博','宋','宋诗','song-poetry','','[]','乾元古道場，宛在香山陽。',132,'全唐诗/poet.song.16000.json','["乾元古道場，宛在香山陽。", "實師應請去，無滯於一方。", "飄然振鐶錫，殊不事包囊。", "孤風尤可尚，靜法固有常。", "真心得正住，安重如陵岡。", "况聞師議論，博洽而精詳。", "和會禪與講，若登圭峯堂。", "迎知向學眾，汲汲趨門牆。", "洪鐘既大叩，隨宜爲發揚。", "清伊自南來，長波極渺茫。", "所謂栰喻者，利濟如僑梁。"]'),
('fb9becec-aeb7-4516-b548-8be5978136cd','某伏蒙宮師相公杜寄示新居詩齋沐捧讀不勝銘歎某謹成拙詩一章上紀盛德粗伸謝意','文彥博','宋','宋诗','song-poetry','','[]','年至即還政，賢哉近古稀。',144,'全唐诗/poet.song.16000.json','["年至即還政，賢哉近古稀。", "明哲冠四輔，謀猷翊萬微。", "名遂身乃退，意確天弗違。", "奇節煥青簡，遺法在黄扉。", "仁里開新第，德宇翔采翬。", "宴宅儉有制，丘牆高可依。", "雅言重金鼎，清音繁玉徽。", "一覽近觀徼，三復終研幾。", "私橐永緘秘，蔀室增光輝。", "信矣賢人業，發於君子機。", "孤生懷絳帳，引頸詠緇衣。", "聖神方圖任，日冀東山歸。"]'),
('84e9a069-e6ad-43e2-839f-410978ca8a48','招劉伯壽秘監','文彥博','宋','宋诗','song-poetry','','[]','君自山中來，熟見山中事。',36,'全唐诗/poet.song.16000.json','["君自山中來，熟見山中事。", "我亦山中人，素懷歸山志。", "切望青牛車，細問歸山計。"]'),
('5159ad7a-f5ac-4aa5-9242-021e2046b8df','題史館兵部傅君草堂','文彥博','宋','宋诗','song-poetry','','[]','羨君濟上墅，勝概不可名。',84,'全唐诗/poet.song.16000.json','["羨君濟上墅，勝概不可名。", "泉石與松竹，聲影交相清。", "周牆數百堵，版筑皆親營。", "箕尾出南極，直對茅軒明。", "陶廬自愛樂，蔣徑堪逢迎。", "但恐赤松子，到此難忘情。", "拾却留侯伴，從吾林下行。"]'),
('d45f4682-cb55-49f3-a1f4-cec615711e1d','過燕川渡','文彥博','宋','宋诗','song-poetry','','[]','燕川東北孔山西，借車直渡馬頭溪。',128,'全唐诗/poet.song.16000.json','["燕川東北孔山西，借車直渡馬頭溪。", "農樵引路津不迷，行行引上青雲梯。", "回頭不視林木低，谷風冷冷山鳥啼。", "巖隈泉甘土仍肥，昔人於斯卜幽棲。", "春深芝朮生新荑，采芝茹朮希夷齊。", "諸公共遊不知疲，長吟吐氣如虹蜺。", "水演石上寫此詩，手拭蒼蘚脚踏泥。", "冒寒履險不憚辭，勉欲繼踵前賢題。"]'),
('16e1718c-f494-4c44-86b8-b430f2ba8d87','寄題密州超然臺','文彥博','宋','宋诗','song-poetry','','[]','莒侯之燕處，層臺逾十尋。',96,'全唐诗/poet.song.16000.json','["莒侯之燕處，層臺逾十尋。", "俯鎮千乘國，前瞻九仙岑。", "勿作西州意，姑爲東武吟。", "名教有靜樂，紛華無動心。", "憑高肆遠目，懷往散沖襟。", "琴觴興不淺，風月情更深。", "民被袴襦惠，境絕枹鼓音。", "欲識超然意，鴒原賦擲金。"]'),
('fbce40e2-5a73-4272-8c25-d593122e8570','塞下曲  其一','文彥博','宋','宋诗','song-poetry','','[]','老上焚庭後，昆邪右衽時。',48,'全唐诗/poet.song.16000.json','["老上焚庭後，昆邪右衽時。", "休開小月陣，罷禱拂雲祠。", "徒覺筋竿勁，寧聞羽檄馳。", "祁連皆積雪，渠答夜應施。"]'),
('9818da87-fd45-4986-b776-929cd3dbe160','塞下曲  其二','文彥博','宋','宋诗','song-poetry','','[]','朔漠凝寒久，窮荒氣候賒。',48,'全唐诗/poet.song.16000.json','["朔漠凝寒久，窮荒氣候賒。", "凍雲藏虎谷，殘雪滿龍沙。", "地迴胡風急，天高漢月斜。", "何人動鄉思，垅上聽金笳。"]'),
('cb250790-b6c8-4743-bf7b-07f3c8850847','折楊柳','文彥博','宋','宋诗','song-poetry','','[]','長憶都門外，低垂拂路塵。',48,'全唐诗/poet.song.16000.json','["長憶都門外，低垂拂路塵。", "更思南陌上，攀折贈行人。", "行人經歲別，楊柳逐年新。", "何當逢塞雁，重寄一枝春。"]'),
('b4dc974b-6fa3-463e-8ff0-25a360b4f73a','關山月','文彥博','宋','宋诗','song-poetry','','[]','宕子久行役，遼西戍未還。',48,'全唐诗/poet.song.16000.json','["宕子久行役，遼西戍未還。", "佳人怨遥夜，清淚浥朱顔。", "蘚晦蘭閨寂，塵昏寶鑑閑。", "相思不相見，明月下關山。"]'),
('1dad08e5-2c66-47d0-9d81-982755797c85','采蓮曲','文彥博','宋','宋诗','song-poetry','','[]','江南秋色蚤，江上蚤蓮芳。',48,'全唐诗/poet.song.16000.json','["江南秋色蚤，江上蚤蓮芳。", "佳人采紅萼，兩槳渡橫塘。", "翳日華芝薄，隨風錦䋏長。", "蕩舟方自樂，綠水任霑裳。"]'),
('8a5fa28d-3c1c-410a-be1c-243129e1b8a7','夜夜曲','文彥博','宋','宋诗','song-poetry','','[]','明月流清漢，娟娟照洞房。',48,'全唐诗/poet.song.16000.json','["明月流清漢，娟娟照洞房。", "微風吹敗葉，颯颯下銀床。", "塵晦流黄素，鑪銷壁惡香。", "年年機杼妾，獨怨夜何長。"]'),
('4d3effe3-45d7-433d-a8e7-516579b4db5c','長相思','文彥博','宋','宋诗','song-poetry','','[]','遠別苦無悰，離居常戚戚。',48,'全唐诗/poet.song.16000.json','["遠別苦無悰，離居常戚戚。", "顧慕懷所歡，徘徊彌自惜。", "瓊蕊不可采，瑶華未堪摘。", "惟憑尺錦書，一寄長相憶。"]'),
('41a67565-1f60-46d3-97af-fbb5c90a00e4','陽春曲','文彥博','宋','宋诗','song-poetry','','[]','頗傷金管遽，仍恨緹光促。',48,'全唐诗/poet.song.16000.json','["頗傷金管遽，仍恨緹光促。", "四序若循環，百年如轉軸。", "佳人暮不歸，蘭苕春又綠。", "空持綠綺琴，愁弄陽春曲。"]'),
('30ced00b-db16-4960-94c7-0af4325e0175','陌上桑','文彥博','宋','宋诗','song-poetry','','[]','佳人名莫愁，采桑南陌頭。',48,'全唐诗/poet.song.16000.json','["佳人名莫愁，采桑南陌頭。", "困來淇水畔，應過上宮遊。", "貯葉青絲籠，攀條紫桂鈎。", "使君徒見問，五馬亦遲留。"]'),
('6aca5cc6-b298-45ef-adc3-fe31e8a54317','巫山高','文彥博','宋','宋诗','song-poetry','','[]','巫山高不極，高與碧穹齊。',48,'全唐诗/poet.song.16000.json','["巫山高不極，高與碧穹齊。", "朝雲常藹藹，暮雨復凄凄。", "髣髴聞珠佩，依稀認繡袿。", "無能留彼美，徒使夢魂迷。"]'),
('c47cc04a-6a19-4e48-978b-0ebf4ccc600c','御溝','文彥博','宋','宋诗','song-poetry','','[]','遠疏銀派浪，深入帝王州。',48,'全唐诗/poet.song.16000.json','["遠疏銀派浪，深入帝王州。", "不爲朝丹禁，何緣異眾流。", "冷穿平樂觀，清繞景陽樓。", "金屋嚴粧罷，香波苑外收。"]'),
('ccaf60ac-0f9c-432f-a73d-8ae449cb7cf7','荷花','文彥博','宋','宋诗','song-poetry','','[]','翠羽亭亭蓋，微障越鄂君。',48,'全唐诗/poet.song.16000.json','["翠羽亭亭蓋，微障越鄂君。", "錦書何日寄，繡被幾時薰。", "步穩非因學，絲輕未見棼。", "唯愁容易散，盡作楚天雲。"]'),
('4a8798ba-061a-400a-aa93-7311298ed821','讀漢史  其一','文彥博','宋','宋诗','song-poetry','','[]','漢室言中圮，咸京欲伴蕪。',48,'全唐诗/poet.song.16000.json','["漢室言中圮，咸京欲伴蕪。", "髹墀傾馺娑，齯齒笑諸于。", "未暇平青犢，旋聞奉赤符。", "貨泉誠妄改，天命本難渝。"]'),
('a69b5556-9666-4b38-862f-a882c4c6a02c','讀漢史  其二','文彥博','宋','宋诗','song-poetry','','[]','久吏皆黄髮，頻年困赤眉。',48,'全唐诗/poet.song.16000.json','["久吏皆黄髮，頻年困赤眉。", "忽逢司隸屬，重覩漢官儀。", "謳詠皆欣合，民靈共樂推。", "區區蹇囂輩，猶不悟天時。"]'),
('a519bb78-344f-4266-9ee2-cc8446a4184e','西晉','文彥博','宋','宋诗','song-poetry','','[]','馬圉言雖驗，鳧毛事亦奇。',48,'全唐诗/poet.song.16000.json','["馬圉言雖驗，鳧毛事亦奇。", "紫微纔遍植，白刃已交馳。", "星麥應無酒，私蛙尚有糜。", "銅駝休反袂，何救黍離離。"]'),
('143d56a6-a734-4e27-84c5-978c445769a5','玉階樹','文彥博','宋','宋诗','song-poetry','','[]','亭亭依玉砌，鬰鬰盡瓊枝。',48,'全唐诗/poet.song.16000.json','["亭亭依玉砌，鬰鬰盡瓊枝。", "璧月夜雖照，金風秋更吹。", "陳宮唯是唱，漢殿只應悲。", "似有君軒戀，歲寒終不移。"]'),
('82adfd18-5df4-4b84-ad01-8fa2b4d745d3','無題','文彥博','宋','宋诗','song-poetry','','[]','西陵何限栢，一一勝瑶華。',48,'全唐诗/poet.song.16000.json','["西陵何限栢，一一勝瑶華。", "幾縱青絲騎，多逢油壁車。", "香囊猶未致，春带已成賒。", "莫作雲間月，願親梁上霞。"]'),
('c235aacb-ff3f-47c4-83ae-3e86d75882f1','贈市隱者','文彥博','宋','宋诗','song-poetry','','[]','縠帔絳綃頭，牆東隱儈牛。',48,'全唐诗/poet.song.16000.json','["縠帔絳綃頭，牆東隱儈牛。", "閑門甘骯髒，薄俗重伊優。", "有頍寧須拂，無資可用游。", "故人雖茜斾，那復問前騶。"]'),
('5418d356-07e0-41bc-adf2-6587ee186dfb','山中隱者','文彥博','宋','宋诗','song-poetry','','[]','塵中久絕跡，谷口自忘機。',48,'全唐诗/poet.song.16000.json','["塵中久絕跡，谷口自忘機。", "草橋凌晨出，柴車向夕歸。", "磴泉濡蕙带，逕竹敗荷衣。", "借問何爲者，山中嘗采薇。"]'),
('2818a580-f410-4df0-9e37-73f9cb0bcf18','偶作示同志','文彥博','宋','宋诗','song-poetry','','[]','隱几清吟久，投瓢浩歡頻。',48,'全唐诗/poet.song.16000.json','["隱几清吟久，投瓢浩歡頻。", "如何爵舉日，猶是傳還人。", "膠葛終當戾，洿塗偶未伸。", "若嫌家監傲，殊不厚田仁。"]'),
('905fe036-8108-4dce-a988-126a9af278ab','夜思','文彥博','宋','宋诗','song-poetry','','[]','明河秋耿耿，小閣夜愔愔。',48,'全唐诗/poet.song.16000.json','["明河秋耿耿，小閣夜愔愔。", "魯酒不成醉，洛生唯是吟。", "簟凉初卷玉，罏暖乍薰金。", "默坐終無寐，西窗月影沉。"]'),
('25e22831-9173-4f91-a952-abfe1c96f7d7','華月','文彥博','宋','宋诗','song-poetry','','[]','皎皎新秋月，分明照洞房。',48,'全唐诗/poet.song.16000.json','["皎皎新秋月，分明照洞房。", "幾人千里別，今夜九迴腸。", "皓彩穿珠幌，澄輝上璧璫。", "畫樓兼繡戶，渾是可憐光。"]'),
('419800cf-ab73-404e-8f6d-c9c22706f6d6','閑齋偶作','文彥博','宋','宋诗','song-poetry','','[]','鼓吹盡私蛙，蓬蒿蔣徑斜。',48,'全唐诗/poet.song.16000.json','["鼓吹盡私蛙，蓬蒿蔣徑斜。", "梧高唯待鳳，柳密只容鴉。", "度暑巾裁縠，迎凉帳卷紗。", "茂陵無奈渴，猶有鎮心瓜。"]'),
('ce4eb148-e16e-4d9b-968e-ee6ce87ff79d','詠箏','文彥博','宋','宋诗','song-poetry','','[]','別院秋仍靜，高堂夜更閑。',48,'全唐诗/poet.song.16000.json','["別院秋仍靜，高堂夜更閑。", "繁絲移寶柱，數曲奏陽關。", "好薦瓊筵上，長親黼座間。", "野王雖後出，無復謝東山。"]'),
('41890f53-699f-453f-a6b8-b54afb9756f8','對雪','文彥博','宋','宋诗','song-poetry','','[]','同雲方靄靄，瓊屑已瀌瀌。',48,'全唐诗/poet.song.16000.json','["同雲方靄靄，瓊屑已瀌瀌。", "陌逈皆連璐，臺高盡結瑶。", "羽樽深酌桂，碭壁暖塗椒。", "誰念牛衣客，袁扉困一瓢。"]'),
('69eb9c22-1ca2-41be-be28-c1a4fb22ccbd','旭日','文彥博','宋','宋诗','song-poetry','','[]','乍出扶桑海，如輪隱半規。',48,'全唐诗/poet.song.16000.json','["乍出扶桑海，如輪隱半規。", "未晞槃上露，已側檻中葵。", "赫奕晨霞映，空濛曉霧披。", "君看可憐處，偏在照梁時。"]'),
('d4e2372d-918f-4e8a-80c5-952247feb9e6','秋望','文彥博','宋','宋诗','song-poetry','','[]','遠目仍秋望，依依江上風。',48,'全唐诗/poet.song.16000.json','["遠目仍秋望，依依江上風。", "煙濤寒颭白，霜葉亂翻紅。", "列岫晴霞外，遵鴻晚照中。", "覊懷同屈宋，倚立恨無窮。"]'),
('efad4b0a-6121-405b-8c06-68e81e31f35d','詠苔','文彥博','宋','宋诗','song-poetry','','[]','緜緜上釣磯，漠漠擁閑扉。',48,'全唐诗/poet.song.16000.json','["緜緜上釣磯，漠漠擁閑扉。", "石面風梳髮，垣根雨濯衣。", "不將凡卉雜，還與俗塵違。", "謝砌曾成詠，深嚴近紫微。"]'),
('918a2c6d-59dd-4e32-bf41-a09fa04bb70e','詠柳','文彥博','宋','宋诗','song-poetry','','[]','带緩何曾綰，眉長未見愁。',48,'全唐诗/poet.song.16000.json','["带緩何曾綰，眉長未見愁。", "青青緣御路，鬰鬰映金溝。", "亂絮凌空蕩，繁絲逐吹流。", "傳聞隋水上，千樹擁迷樓。"]'),
('74fd03e0-2468-4bfe-8bc6-d64117d5b535','玉梁','文彥博','宋','宋诗','song-poetry','','[]','玉梁千丈駕澄流，曾與羣仙爛熳遊。',64,'全唐诗/poet.song.16000.json','["玉梁千丈駕澄流，曾與羣仙爛熳遊。", "丹桂扶疎應近月，紫苔漫沒幾經秋。", "濛濛五里皆金霧，岌岌三休是寶樓。", "此地回驂時一望，世間塵上盡蜉蝣。"]'),
('816a2c6c-37d3-4191-aec3-f5f4c7b2be36','幽蘭','文彥博','宋','宋诗','song-poetry','','[]','燕姞夢魂唯是見，謝家庭戶本來多。',64,'全唐诗/poet.song.16000.json','["燕姞夢魂唯是見，謝家庭戶本來多。", "好將綠葉親芳穗，莫把清芬借敗荷。", "避世已爲騷客佩，繞梁還入郢人歌。", "雖然九畹能香國，不奈三秋鵜鴂何。"]'),
('93abebf2-a43b-4cfe-ad51-2f0a4dda6da9','寄友人包兼濟拯','文彥博','宋','宋诗','song-poetry','','[]','締交何止號如龍，發篋疇年絳帳同。',64,'全唐诗/poet.song.16000.json','["締交何止號如龍，發篋疇年絳帳同。", "方領聚游多雅致，幅巾嘉論有清風。", "名高闕里二三子，學繼臺城百六公。", "別後愈知琨氣大，可能持久在江東。"]'),
('350fa085-31c7-4b58-a664-cf110e9f781b','公子','文彥博','宋','宋诗','song-poetry','','[]','甲第峨峨爵觀前，對回微岸鵕鸃冠。',64,'全唐诗/poet.song.16000.json','["甲第峨峨爵觀前，對回微岸鵕鸃冠。", "錦韉飛鞚丹砂埒，蜜炬流膏紫玉槃。", "狐尾單衣常裛麝，虎頭雙綬鎮薰蘭。", "閑馳便面章臺陌，里巷兒童逐彈丸。"]'),
('c0c65496-dce0-4d6b-b5cc-2d6087a6567b','寓懷','文彥博','宋','宋诗','song-poetry','','[]','高樓閑背夕陽登，渺渺長懷不自勝。',64,'全唐诗/poet.song.16000.json','["高樓閑背夕陽登，渺渺長懷不自勝。", "錦瑟有時聞北渚，鈿車何日到西陵。", "地寒萱草猶難種，天遠瑶華豈易憑。", "多謝蘇門清嘯客，了無塵事染壺冰。"]'),
('c5ded401-8cbc-4d18-b509-1d963227a5b6','時興','文彥博','宋','宋诗','song-poetry','','[]','綸巾短袖迎凉服，繭犢笨車乘興遊。',64,'全唐诗/poet.song.16000.json','["綸巾短袖迎凉服，繭犢笨車乘興遊。", "豈謂煙霞生曠達，只緣塵土倦伊優。", "更無傾蓋將誰共，縱有吹彫不我留。", "曾達酒壚惟獨醉，幰前猶恨欠三騶。"]'),
('3420b9b2-d3f6-4abe-a709-ddc7a49b5af0','暑中書事','文彥博','宋','宋诗','song-poetry','','[]','薰飚獵獵度融紗，赫日流金樹影斜。',64,'全唐诗/poet.song.16000.json','["薰飚獵獵度融紗，赫日流金樹影斜。", "寢簟冷便鋪薤葉，門裾輕愛曳橦華。", "仙槃想挹三危露，靈漢思乘八月槎。", "雪散冰丸猶長物，鎮心堪笑茂陵瓜。"]'),
('5500ab8e-4e25-461a-9972-ecaa78996d47','初曙','文彥博','宋','宋诗','song-poetry','','[]','漢宮金掌露淋漓，椒殿裝梅欲罷時。',64,'全唐诗/poet.song.16000.json','["漢宮金掌露淋漓，椒殿裝梅欲罷時。", "宿靄空濛昏繡桷，曉暾依約上文㮰。", "九苑威鳳猶棲閣，三匝驚烏尚繞枝。", "玉女窗虛蓮燭謝，西南金魄隱殘規。"]'),
('135d55cc-dc05-4c2c-9bcb-6c07b417c908','和人留題華清宮溫泉','文彥博','宋','宋诗','song-poetry','','[]','玉唾神遊接漢京，朝元金碧照天明。',64,'全唐诗/poet.song.16000.json','["玉唾神遊接漢京，朝元金碧照天明。", "香波淺鬭龍原潤，炎液深涵雁甃清。", "狎獵亂光浮藻井，穹隆長影浸彫楹。", "聖皇勤儉無西豫，輦路經春煙草平。"]'),
('d4f4e8dc-310c-4d64-bb28-7fa76c8511f4','秋風吟','文彥博','宋','宋诗','song-poetry','','[]','獵遍蘭叢與桂枝，巢居未必有先期。',64,'全唐诗/poet.song.16000.json','["獵遍蘭叢與桂枝，巢居未必有先期。", "靈臺十仞烏隨轉，阿閣三重鳳豈知。", "度柳暗催蟬嘒嘒，出雲高送雁離離。", "漢宮玉樹知何限，爭忍重吟畫扇詩。"]'),
('49e3f68d-5ac2-4b7b-9321-7cc18317d3fb','閱史有感','文彥博','宋','宋诗','song-poetry','','[]','縹帙青箱次第開，慨然英氣轉難裁。',64,'全唐诗/poet.song.16000.json','["縹帙青箱次第開，慨然英氣轉難裁。", "莫言美事俱長往，須有清風屬後來。", "彈鋏始知皆瑣旅，枕戈方信是雄才。", "平生自况真非薄，只是休容楚鴆媒。"]'),
('40779fdf-f9c6-4a2b-b795-0b19c7ade4b9','詔開禮闈偶作呈諸友','文彥博','宋','宋诗','song-poetry','','[]','星弧首闢羣英彀，天畢初張眾目羅。',64,'全唐诗/poet.song.16000.json','["星弧首闢羣英彀，天畢初張眾目羅。", "漢傅仍聞求泛駕，周明何止育菁莪。", "碧紗已有蓬山籍，綠李將分桂殿科。", "全伏阿香推轂力，九門三月化陶梭。"]'),
('321d96b7-4536-466f-8529-27fedca4a611','省試蒲車詩','文彥博','宋','宋诗','song-poetry','','[]','漢祀精禋潔，云亭禪禮殊。',72,'全唐诗/poet.song.16000.json','["漢祀精禋潔，云亭禪禮殊。", "金泥伸秘檢，車轂尚編蒲。", "越席侔前制，文茵愧後塗。", "軟輪同致美，規地用難符。", "翠幰芳蕤集，華芝秀彩敷。", "升中儀矩盛，備物壯皇圖。"]'),
('3e1cb2ae-ff71-48fc-8924-92ab014eb4b7','天聖五年春省試獻羔開冰','文彥博','宋','宋诗','song-poetry','','[]','國重司寒祭，羔羊獻禮陳。',72,'全唐诗/poet.song.16000.json','["國重司寒祭，羔羊獻禮陳。", "開冰遵舊典，薦廟屬昌辰。", "肥羜方登俎，清壺冀饗神。", "蟲疑非蚤夏，狐聽異先春。", "鑿鑿凝光瑩，峨峨發彩新。", "何當比魚上，從此出迷津。"]'),
('aa64f6df-1b5b-4621-b82a-49919a3088f2','元日作','文彥博','宋','宋诗','song-poetry','','[]','萬壽稱觴日，天光肇祚辰。',48,'全唐诗/poet.song.16000.json','["萬壽稱觴日，天光肇祚辰。", "新陽方改故，暖律已升春。", "桃梗分朱戶，椒花獻紫宸。", "子輿方養浩，何必造盤辛。"]'),
('5dbf3c30-5e87-4b3d-b848-187a555cf4a4','春日偶作','文彥博','宋','宋诗','song-poetry','','[]','借問此何時，南園蝶又飛。',48,'全唐诗/poet.song.16000.json','["借問此何時，南園蝶又飛。", "杏梁棲紫燕，麥垅覆驚翬。", "榆莢深堆砌，楊花亂撲衣。", "洛吟經永日，還似舞雩歸。"]'),
('db1e7f8f-3c45-4d31-b3fc-36fc686ced9a','梅花','文彥博','宋','宋诗','song-poetry','','[]','洛涘幽居植，江南驛使傳。',48,'全唐诗/poet.song.16000.json','["洛涘幽居植，江南驛使傳。", "一陽初應候，萬木獨爲先。", "素萼凌繁雪，清香襲淡煙。", "欲知佳麗處，漢殿曉粧妍。"]'),
('cbbd8480-517c-4f93-af6f-26dc38f4415c','元巳阻雨','文彥博','宋','宋诗','song-poetry','','[]','林花脈脈怯朝煙，雨隔蘭庭曲水筵。',32,'全唐诗/poet.song.16000.json','["林花脈脈怯朝煙，雨隔蘭庭曲水筵。", "欲買春花無定價，東風撩亂擲榆錢。"]'),
('6311ccaf-7d98-4a6a-99fa-c1f56d7e1e55','和友人春日即事','文彥博','宋','宋诗','song-poetry','','[]','小院閑扃煦日長，靜探琅簡事虛皇。',64,'全唐诗/poet.song.16000.json','["小院閑扃煦日長，靜探琅簡事虛皇。", "依依柳蔭銀塘暗，習習風穿玳押凉。", "碧合暮雲連礎潤，綠攀奇樹透懷香。", "蒙山近得脩真訣，辟穀常飡太乙糧。"]'),
('7165da00-bbb5-48a7-8c88-0e188c269dba','酬金華山人春日見寄之什','文彥博','宋','宋诗','song-poetry','','[]','漠漠鮮雲習習風，谷鶯嬌囀小園中。',64,'全唐诗/poet.song.16000.json','["漠漠鮮雲習習風，谷鶯嬌囀小園中。", "謝塘初長如裀草，湘渚難留避弋鴻。", "輕雨落花紅撲地，惹烟垂柳綠縈空。", "尋芳好伴高陽侶，深憶東山採藥公。"]'),
('74a5207e-6b8a-43bb-8b07-c527eb2b387f','和友人春日即事','文彥博','宋','宋诗','song-poetry','','[]','青閣登臨恨已多，可堪蘭景又妍和。',64,'全唐诗/poet.song.16000.json','["青閣登臨恨已多，可堪蘭景又妍和。", "書囊閱盡應成癖，詩思狂來恐是魔。", "玉樹芬芳連霧縠，珠櫳隱映隔雲蘿。", "鸘裘貰得楊昌酒，度日無悰倚瑟歌。"]'),
('e6c75cd6-108d-4cef-b157-46c17c83368d','郡齋春日書懷','文彥博','宋','宋诗','song-poetry','','[]','煦日亭亭晝漸長，煙藏幽砌蕙蘭香。',64,'全唐诗/poet.song.16000.json','["煦日亭亭晝漸長，煙藏幽砌蕙蘭香。", "纖垂謝監園中柳，嫩折羅敷陌上桑。", "出谷曉鶯遷綺樹，入簷風燕語雕梁。", "瑶華欲寄嶺頭信，心逐白雲歸帝鄉。"]'),
('b5d7f1fd-7bdb-41f6-8f9d-426e0613785d','長平懷古','文彥博','宋','宋诗','song-poetry','','[]','此子徒能讀父書，兵降始信藺相如。',32,'全唐诗/poet.song.16000.json','["此子徒能讀父書，兵降始信藺相如。", "却令後代承家者，每到長平戒覆車。"]'),
('f3d09a36-17b4-4790-ae77-5c63fef81856','題籌筆驛','文彥博','宋','宋诗','song-poetry','','[]','卧龍纔起扶衰世，料敵謀攻後出師。',32,'全唐诗/poet.song.16000.json','["卧龍纔起扶衰世，料敵謀攻後出師。", "幃幄既持先聖術，肯來山驛旋沉思。"]'),
('76921315-af9d-407b-9b9c-30ef34cd5397','題韓溪詩  其一','文彥博','宋','宋诗','song-poetry','','[]','韓信未遭面主顧，蕭何親至此中追。',32,'全唐诗/poet.song.16000.json','["韓信未遭面主顧，蕭何親至此中追。", "君王有意爭天下，不得斯人未可知。"]'),
('eae6f103-fa1c-4e29-bc20-67f0cf3586e9','題韓溪詩  其二','文彥博','宋','宋诗','song-poetry','','[]','平日漁樵皆病涉，當年將相盡成功。',32,'全唐诗/poet.song.16000.json','["平日漁樵皆病涉，當年將相盡成功。", "淮陰未濟酇侯識，留得雄才歸漢中。"]'),
('ded493a2-3919-4291-97dd-9eda7e9d78a2','題韓溪詩  其三','文彥博','宋','宋诗','song-poetry','','[]','水濱山曲蹔盤桓，盛事臨風一據鞍。',32,'全唐诗/poet.song.16000.json','["水濱山曲蹔盤桓，盛事臨風一據鞍。", "莫訝史君頻歎詠，古來君相受知難。"]'),
('84690a89-3b8d-4c8d-aa5d-78db87b83cad','題韓溪詩  其四','文彥博','宋','宋诗','song-poetry','','[]','途中勝跡盡留題，獨有韓溪未有詩。',32,'全唐诗/poet.song.16000.json','["途中勝跡盡留題，獨有韓溪未有詩。", "直把蕪詞重疊詠，只圖流播路人知。"]'),
('cc72aa95-044e-4a81-b9f6-193d2a647d96','綠綺','文彥博','宋','宋诗','song-poetry','','[]','楚舞休飛鶴，燕歌罷繞梁。',48,'全唐诗/poet.song.16000.json','["楚舞休飛鶴，燕歌罷繞梁。", "高堂橫綠綺，上客奏明光。", "秋月華池凈，春風蕙草香。", "還卭有辭賦，仙鳳正求皇。"]'),
('d62febcd-b283-4d0d-b8df-80a0fc40cbee','蘅臯','文彥博','宋','宋诗','song-poetry','','[]','蘅薄頻牽望，陽林久駐鑣。',48,'全唐诗/poet.song.16000.json','["蘅薄頻牽望，陽林久駐鑣。", "香囊徒叩叩，雲月自苕苕。", "翠佩傳情密，曾波託意遥。", "翩鴻漸高逝，翻恨隔神霄。"]'),
('e21d97e1-3485-47e3-9cf4-91e6424f1248','深院','文彥博','宋','宋诗','song-poetry','','[]','楊柳亭臺暮，梨花院落深。',48,'全唐诗/poet.song.16000.json','["楊柳亭臺暮，梨花院落深。", "玉池波湛湛，珠幌影沈沈。", "遠思隨莊蝶，春懷怯雍琴。", "萱蘇不蠲忿，擁鼻獨清吟。"]'),
('e9c2e4aa-0ca4-46c1-99c2-07fb1a0b4f98','春曉','文彥博','宋','宋诗','song-poetry','','[]','宿靄藏飛觀，晨霞幌繡甍。',48,'全唐诗/poet.song.16000.json','["宿靄藏飛觀，晨霞幌繡甍。", "錦幃人未起，珠樹鵲先驚。", "爐暖香初燼，窗幽燭尚明。", "更開花上露，粧淚鬭盈盈。"]'),
('ed726b7e-3a48-4c68-8a3c-d0270e30f396','芳草','文彥博','宋','宋诗','song-poetry','','[]','綺節初抽翠，金塘久託根。',48,'全唐诗/poet.song.16000.json','["綺節初抽翠，金塘久託根。", "何堪混蕭艾，自合比蘭蓀。", "碧映龍池水，青迷楚澤魂。", "年年增恨處，長信與長門。"]'),
('8d176486-e7c1-4167-8fb4-97aa60e2dee3','公子','文彥博','宋','宋诗','song-poetry','','[]','朝罷章台陌，追隨紫燕光。',48,'全唐诗/poet.song.16000.json','["朝罷章台陌，追隨紫燕光。", "鴈陂冠綠幘，洛浦授明璫。", "下士營三窟，名姬號四香。", "十千沽斗酒，結客少年場。"]'),
('d80598d9-a0bb-41c9-91db-9d578edcd0e0','井上桐','文彥博','宋','宋诗','song-poetry','','[]','擢幹殊瓊巘，託根非嶧陽。',48,'全唐诗/poet.song.16000.json','["擢幹殊瓊巘，託根非嶧陽。", "發華臨玉甃，倒影覆銀牀。", "方待高朋集，寧容眾鳥翔。", "尾焦期入爨，誰識蔡中郎。"]'),
('e07bb5d3-7818-46d2-b41b-3eccc18ae0b6','柳絮','文彥博','宋','宋诗','song-poetry','','[]','拂地高陽翠影濃，楊花斷續蔽香紅。',64,'全唐诗/poet.song.16000.json','["拂地高陽翠影濃，楊花斷續蔽香紅。", "密和微雨粘沙坂，亂逐輕風透綺籠。", "漆圃旋驚飛蝶夢，玉庭頻擬散鹽空。", "青門一望依依處，千里金堤二月中。"]'),
('4880a9c9-d9b0-4865-af9e-7e3f41315089','宮詞  其一','文彥博','宋','宋诗','song-poetry','','[]','金屋無人夜未央，獨吟團扇倚椒房。',32,'全唐诗/poet.song.16000.json','["金屋無人夜未央，獨吟團扇倚椒房。", "辟寒猶待君王意，鶴燄熒煌龍漏長。"]'),
('e2623869-3980-48d3-b1f0-77ce1a1b820a','宮詞  其二','文彥博','宋','宋诗','song-poetry','','[]','體輕全不勝鸞釵，常羨同心上苑梅。',32,'全唐诗/poet.song.16000.json','["體輕全不勝鸞釵，常羨同心上苑梅。", "翠輦未來珠箔卷，漆盤猶貯夜明苔。"]'),
('541767a0-6b41-4725-bc59-a16a8f62bc95','登江樓','文彥博','宋','宋诗','song-poetry','','[]','飛觀接江干，乘閑獨憑欄。',48,'全唐诗/poet.song.16000.json','["飛觀接江干，乘閑獨憑欄。", "鮮雲橫列岫，芳草蔽遥灘。", "梅笛吹漁浦，荃橈泛鷺湍。", "登臨謝康樂，寄遠折瑶蘭。"]'),
('489b4bb4-1a7a-4b2b-84a3-97ea8a3f247a','春遊','文彥博','宋','宋诗','song-poetry','','[]','紫燕動光輝，春遊鴈鶩陂。',48,'全唐诗/poet.song.16000.json','["紫燕動光輝，春遊鴈鶩陂。", "鶴天方爛熳，鴻蓋任追隨。", "促席開瑶瑟，當歌泛羽巵。", "言歸將薄暮，不羨習家池。"]'),
('281a595f-22e5-4bd2-819f-ee509c2af620','夜讌','文彥博','宋','宋诗','song-poetry','','[]','清夜開良讌，金缾泛羽觴。',48,'全唐诗/poet.song.16000.json','["清夜開良讌，金缾泛羽觴。", "蕙肴芬潔俎，蘭焰耿華堂。", "妙舞流風雪，妍歌繞棟梁。", "西園堪賞玩，明月照銀塘。"]'),
('2c16176a-3f1f-425c-94ac-773c14d625bb','從軍行','文彥博','宋','宋诗','song-poetry','','[]','汗馬出長城，橫行十萬兵。',48,'全唐诗/poet.song.16000.json','["汗馬出長城，橫行十萬兵。", "晨驅左賢陣，夕掩亞夫營。", "雪壓龍沙白，雲遮瀚海平。", "燕山紀功後，麟閣耀鴻名。"]'),
('d7544ba2-1332-491e-a6d4-b25f4b4c72b2','俠少行','文彥博','宋','宋诗','song-poetry','','[]','錦带佩吳鈎，翩翩躍紫騮。',48,'全唐诗/poet.song.16000.json','["錦带佩吳鈎，翩翩躍紫騮。", "垂鞭度永埒，挾彈過長楸。", "平樂十千酒，南城百尺樓。", "荆娥拂雙袖，日夕又遲留。"]'),
('31667bf5-fae8-4c8c-99ab-4557b94d9acd','桃花','文彥博','宋','宋诗','song-poetry','','[]','雨過新含灼灼華，煙籠芳樹勢交加。',64,'全唐诗/poet.song.16000.json','["雨過新含灼灼華，煙籠芳樹勢交加。", "狂飛粉蝶穿朱檻，巧囀流鶯傍碧紗。", "露井細香飄烈麝，霜林濃艷散餘霞。", "嚙毫更近成陰處，似入仙源一逕斜。"]'),
('e7aa87b6-c2d4-4e5f-b2da-909e3616ad18','早夏言懷','文彥博','宋','宋诗','song-poetry','','[]','碧檻初榮槿，芳園已莠葽。',168,'全唐诗/poet.song.16000.json','["碧檻初榮槿，芳園已莠葽。", "翠岑應解鹿，高樹欲鳴蜩。", "霞綺籠飛觀，雲峯映瑣寮。", "霜紈徒比月，仙馭好凌飚。", "寒水沉朱李，新吟寄綠蕉。", "藥房清氣爽，荃壁冷香消。", "玉沼賀荷嫩，蘭禳乳燕嬌。", "薄帷安畫石，幽徑採神虈。", "每欲求飛雪，常思造結瑶。", "浩歌頻倚瑟，長袖幾炊彫。", "靜對黄梅雨，閑吹紫玉簫。", "砌榴紅爛熳，窗岫碧岧嶢。", "袁趾疏還往，顔居正寂寥。", "且傾光祿酒，莫發采菱謠。"]'),
('46bdc367-445d-4b00-8fa1-034479a2e08e','秋夕偶懷','文彥博','宋','宋诗','song-poetry','','[]','小檻風驚葉，幽庭露泫柯。',48,'全唐诗/poet.song.16000.json','["小檻風驚葉，幽庭露泫柯。", "芳塵千里遠，幽恨九迴多。", "螢影穿簾押，蛩聲出砌莎。", "寸心無以寫，愬月但長歌。"]'),
('1c20e1dd-3244-4803-92d0-81d73203f074','秋夕偶作','文彥博','宋','宋诗','song-poetry','','[]','獨誦潘郎秋興賦，閑吟謝守怨情詩。',32,'全唐诗/poet.song.16000.json','["獨誦潘郎秋興賦，閑吟謝守怨情詩。", "風摇紅樹啼螿急，月照綠窗清漏遲。"]'),
('178f0a8f-463b-4cb7-aada-368179f01a3b','秋夜聞笛','文彥博','宋','宋诗','song-poetry','','[]','秋宵萬籟沉，羌笛似龍吟。',48,'全唐诗/poet.song.16000.json','["秋宵萬籟沉，羌笛似龍吟。", "向秀忽思舊，馬融方好音。", "細聲寒入牖，殘韻半和砧。", "莫奏梅花曲，旅人情更深。"]'),
('8f115ba5-e577-4079-913b-7e6741bb9479','古寺清秋日  其一','文彥博','宋','宋诗','song-poetry','','[]','古寺清秋日，微凉寶殿中。',48,'全唐诗/poet.song.16000.json','["古寺清秋日，微凉寶殿中。", "玉題高納月，金鐸碎摇風。", "翠蘚緣階碧，幽蘭裛露紅。", "閑聽連葉漏，吟對惠休公。"]'),
('d5534396-d63e-4bb6-988d-522094b427e1','古寺清秋日  其二','文彥博','宋','宋诗','song-poetry','','[]','古寺清秋日，幽閑景倍殊。',48,'全唐诗/poet.song.16000.json','["古寺清秋日，幽閑景倍殊。", "晚雲遮鷲嶺，新月照蝦鬚。", "玉露霑籬菊，金風落井梧。", "武泥求泛駕，張翰莫思鱸。"]'),
('1dcb1052-756d-4311-9790-1c0806425986','古寺清秋日  其三','文彥博','宋','宋诗','song-poetry','','[]','古寺清秋日，登樓擁鼻吟。',48,'全唐诗/poet.song.16000.json','["古寺清秋日，登樓擁鼻吟。", "微凉生柰苑，輕吹動香林。", "窗外螢飛火，籬邊菊散金。", "靜彈流水曲，何處有知音。"]'),
('6dd810fa-67d9-4d85-82e7-bd6bc1495948','古寺清秋日  其四','文彥博','宋','宋诗','song-poetry','','[]','古寺清秋日，潘郎興倍長。',48,'全唐诗/poet.song.16000.json','["古寺清秋日，潘郎興倍長。", "院閑披鶴氅，人靜掩鷹房。", "密樹驚晨鵲，幽軒耿夜螿。", "班姬應詠扇，通夕恨昭陽。"]'),
('d363ebd1-f447-4b4c-84b4-51f24a7db4c3','古寺清秋日  其五','文彥博','宋','宋诗','song-poetry','','[]','古寺清秋日，含毫凭小樓。',48,'全唐诗/poet.song.16000.json','["古寺清秋日，含毫凭小樓。", "雨微滋石蘚，煙淡落霜楸。", "紫燕休巢幙，蒼鷹已下韝。", "閑傾浮蟻酎，時典鷫鸘裘。"]'),
('dea7422e-0513-45e0-a5db-500d69171021','重陽前五日探菊','文彥博','宋','宋诗','song-poetry','','[]','比到重陽猶五日，露披金菊滿東籬。',64,'全唐诗/poet.song.16000.json','["比到重陽猶五日，露披金菊滿東籬。", "莫言預賞非真賞，大抵先時勝後時。", "密蕊不容羣蝶采，清香未許眾人知。", "幕中婉畫應多暇，來伴淵明把酒巵。"]'),
('f00ae30c-693c-4ec7-9f40-44e75cf62842','重陽前兩日登樓望月','文彥博','宋','宋诗','song-poetry','','[]','寶剎翬飛切紫霄，況蓮開士木綿袍。',32,'全唐诗/poet.song.16000.json','["寶剎翬飛切紫霄，況蓮開士木綿袍。", "黄昏尚倚危樓望，反照南榮唄梵高。"]'),
('2bf1c37d-c7a3-4a26-9781-da7309135258','翫月吟寄友人  其一','文彥博','宋','宋诗','song-poetry','','[]','桂魄騰車朱戶深，瑣寮珠箔夜沉沉。',64,'全唐诗/poet.song.16000.json','["桂魄騰車朱戶深，瑣寮珠箔夜沉沉。", "慵聽北里吹竽燕，閑倚南樓擁鼻吟。", "玉宇暗銷紅燭影，銀床斜轉碧桐陰。", "金缾剩貯程鄉酒，留待龍交滿滿斟。"]'),
('08d848e8-da0a-413f-9657-b959ff3bdb11','翫月吟寄友人  其二','文彥博','宋','宋诗','song-poetry','','[]','薄宦覊塵事，勞生困夏畦。',48,'全唐诗/poet.song.16000.json','["薄宦覊塵事，勞生困夏畦。", "偶來遊日觀，更喜躡雲梯。", "便擬紉蘭佩，相招隱竹谿。", "回看廣津路，欲問轉多迷。"]'),
('cddfe487-c2f5-4461-9760-92bff0bbe228','翫月吟寄友人  其三','文彥博','宋','宋诗','song-poetry','','[]','聞道頻揮霹靂手，定知不費琰之才。',32,'全唐诗/poet.song.16000.json','["聞道頻揮霹靂手，定知不費琰之才。", "且投丹筆携詩筆，來就花間把一杯。"]'),
('41c024b4-f887-43bd-b1e6-b36cfbedfe1f','遊仙詠','文彥博','宋','宋诗','song-poetry','','[]','十二瑶樓切絳雲，醉遊崑閬碧桃春。',64,'全唐诗/poet.song.16000.json','["十二瑶樓切絳雲，醉遊崑閬碧桃春。", "煙藏玉樹棲鸞穩，露浥芝田唳鶴頻。", "閑訪五城騎白鹿，靜尋三洞駕黄麟。", "紫房求看登真錄，說是明晨第一人。"]'),
('07d184eb-7649-4b1b-885e-bd24699dca38','送胡秀才歸絳臺','文彥博','宋','宋诗','song-poetry','','[]','飄飄詞賦已還卭，法牖推賢繼祖風。',64,'全唐诗/poet.song.16000.json','["飄飄詞賦已還卭，法牖推賢繼祖風。", "緩頰且驚儀舌在，隻輪休歎阮途窮。", "佇觀振翼遷喬木，忍學棲衡嗜晚菘。", "楚寶定須三獻遇，肯教煩歲泣如虹。"]'),
('cdaba908-9e54-491b-966e-5692dba4095a','贈孫莊秀才','文彥博','宋','宋诗','song-poetry','','[]','麗藻遒文絕比肩，買符新自帝州遷。',64,'全唐诗/poet.song.16000.json','["麗藻遒文絕比肩，買符新自帝州遷。", "四溟浪闊鵾須化，三島路長鸞暫閑。", "桂玉擅名將繼却，簞瓢樂道且晞顔。", "前春定奮沖天翼，休抱如虹泣楚山。"]'),
('c75c33e7-980d-4cfe-a433-60f77f789e07','送郭屯田牧涪陵','文彥博','宋','宋诗','song-poetry','','[]','涪陵古群接青臺，巴俗頻思叔度來。',64,'全唐诗/poet.song.16000.json','["涪陵古群接青臺，巴俗頻思叔度來。", "魚竹乍分天顧息，星軺初動隼旟開。", "一麾暫輟含香職，雙筆猶淹視草才。", "佇聽陜棠民頌洽，紫泥對詔下蓬萊。"]'),
('3a3537d6-bd02-46e4-ae94-be96a21adccb','和張嶢秀才勉弟之什','文彥博','宋','宋诗','song-poetry','','[]','棣萼聯華繼昔賢，素園遊想已多年。',64,'全唐诗/poet.song.16000.json','["棣萼聯華繼昔賢，素園遊想已多年。", "方觀藪鳳翱千仞，將見牀鸞上九天。", "寬詔已聞求泛駕，盛時休憶賦歸田。", "來春定中穿楊箭，好約抽毫玉陛前。"]'),
('c4c59dec-3f3e-4290-a473-19186183f406','送昌黎先生歸秦亭','文彥博','宋','宋诗','song-poetry','','[]','獨駕輕鴻返故園，冠霞曾醉錦江煙。',64,'全唐诗/poet.song.16000.json','["獨駕輕鴻返故園，冠霞曾醉錦江煙。", "五圖金記何年授，九籥丹經幾處傳。", "曉別閬州飛玉斝，暮登秦嶺挹紅泉。", "椒庭他日重相見，應許壺中看列仙。"]'),
('091634f0-acb7-4a3e-9a43-d52e44d68bfb','送果州李推官赴闕','文彥博','宋','宋诗','song-poetry','','[]','德滿椒蘭學滿籝，升堂鴻藻繼雲卿。',64,'全唐诗/poet.song.16000.json','["德滿椒蘭學滿籝，升堂鴻藻繼雲卿。", "舜庠蚤中巍峨選，儉府還馳醞藉名。", "捧詔定趨文石陛，揚鞭將度洛陽城。", "麟台馬署期高步，閑繹蕓籤聽苑鶯。"]'),
('686f34a6-0809-4102-a6f2-5a91bd9a03f0','送友人','文彥博','宋','宋诗','song-poetry','','[]','携手北梁道，送君南浦春。',48,'全唐诗/poet.song.16000.json','["携手北梁道，送君南浦春。", "斜陽沉璧彩，流水濯纓塵。", "郢酒頻揚觶，燕歌旋愴神。", "瑶華如可折，堪寄隴頭人。"]'),
('cf07d26b-e0ad-4c02-b674-a5222603b85e','送浦上人遊川','文彥博','宋','宋诗','song-poetry','','[]','火宅清凉廕慧雲，海潮芳論更難倫。',64,'全唐诗/poet.song.16000.json','["火宅清凉廕慧雲，海潮芳論更難倫。", "鷹房暫鎖巴山下，虎錫還飛錦水濱。", "貝葉文皆收縹帙，林蘭衣不染紅塵。", "亭臯欲別偏多感，緣是雙林社裏人。"]'),
('422273ac-ee48-440f-bddb-f3767b732779','登通山閣有懷寄呈同人','文彥博','宋','宋诗','song-poetry','','[]','小閣登臨春暮時，綺欄飛闥映遊絲。',64,'全唐诗/poet.song.16000.json','["小閣登臨春暮時，綺欄飛闥映遊絲。", "鶯喧曲檻韓馮樹，蘚晦幽庭貢禹綦。", "閑對碧雲吟桂水，狂思長袂宿蘭池。", "徘徊望斷江邊客，采得瑶華寄與誰。"]'),
('0d0f2a34-112b-4ba9-87d3-b08a58e8b2b4','送劉推官歸冶源棲真館','文彥博','宋','宋诗','song-poetry','','[]','高情樂幽趣，遂與塵事違。',48,'全唐诗/poet.song.16000.json','["高情樂幽趣，遂與塵事違。", "巖谷久潛照，魚鳥知忘機。", "方邀栗里會，却指冶源歸。", "借問歸何遽，山中芝朮肥。"]'),
('fb14d9af-b274-4931-9c64-1a8b0e1083ef','送福州通判陳鑄殿丞','文彥博','宋','宋诗','song-poetry','','[]','澤宮登甲第，殿省滯時英。',48,'全唐诗/poet.song.16000.json','["澤宮登甲第，殿省滯時英。", "閩國題輿貴，稽山晝錦榮。", "軼才猶絆驥，美俗仰誠衡。", "壽母平返喜，迎知訟牒清。"]'),
('0a902e96-eadb-4575-9e90-503a15df11e6','贈會稽尊師','文彥博','宋','宋诗','song-poetry','','[]','藐姑容化三陰館，勾漏砂封六乙泥。',64,'全唐诗/poet.song.16000.json','["藐姑容化三陰館，勾漏砂封六乙泥。", "五練夜窮蒼玉几，七明晨采碧雲梯。", "冠霞高挹浮丘袂，握髓深藏鬼谷谿。", "如有西山駐靈藥，何妨相贈一刀圭。"]'),
('7af1bf74-db53-470e-9def-5f6367535fd7','贈自然表白大師  其一','文彥博','宋','宋诗','song-poetry','','[]','千仞清溪絕世紛，先生高卧白雲根。',32,'全唐诗/poet.song.16000.json','["千仞清溪絕世紛，先生高卧白雲根。", "近來名係丹臺籍，多向蒙山見羨門。"]'),
('8c7d257a-82a7-4fa4-af38-3e8399fbe32c','贈自然表白大師  其二','文彥博','宋','宋诗','song-poetry','','[]','紫府仙人每馭飇，朝遊三島暮三茅。',32,'全唐诗/poet.song.16000.json','["紫府仙人每馭飇，朝遊三島暮三茅。", "他年內史功成後，願結山陰世外交。"]'),
('e98af989-7511-4d33-baf8-36dba6ee2394','贈自然表白大師  其三','文彥博','宋','宋诗','song-poetry','','[]','常感真公傳隱訣，每言凡骨是仙材。',32,'全唐诗/poet.song.16000.json','["常感真公傳隱訣，每言凡骨是仙材。", "他時載挹浮丘袂，直在崑峯十二臺。"]'),
('91da3190-7e4a-49c8-bc24-35f1f1230e56','某天聖四年叨充鄉賦明道二年夏假副車於本郡今年夏忝外計於本道寔嗣世職八月行部率遵故常鄉老懽迎邀留累日徘徊舊地追惟疇曩因成拙詩二章題於行署','文彥博','宋','宋诗','song-poetry','','[]','不才惟侍高門慶，奕世皆爲外計臣。',64,'全唐诗/poet.song.16000.json','["不才惟侍高門慶，奕世皆爲外計臣。", "鄉老相逢頻教我，盡忠思孝報君親。", "昔年鄉賦議興賢，曾接諸君硯席間。", "屈指歲華逾一紀，錦衣懷綬過稽山。"]'),
('c71dc5fd-9126-4141-82c1-65587631b23b','送益利路承受梁供奉回京','文彥博','宋','宋诗','song-poetry','','[]','二星同入蜀，三歲復還臺。',48,'全唐诗/poet.song.16000.json','["二星同入蜀，三歲復還臺。", "秋晚華軒去，江濱祖席開。", "歸途雖日遠，別酒任山頹。", "思渥迎知厚，當朝重使才。"]'),
('93c2de17-0146-47d3-a758-c730ad484653','雷簡夫自辰溪還除國子博士鹽鐵判官以書見謝并寄杜鵑鳥一隻偶成二章答之  其一','文彥博','宋','宋诗','song-poetry','','[]','學省新開用退之，陽城司業定相知。',64,'全唐诗/poet.song.16000.json','["學省新開用退之，陽城司業定相知。", "休思杜曲仙鄉隱，好獻元和聖德詩。", "三部共推鹽鐵論，五溪曾制虎貔師。", "濟源處士功成後，始信書生善出奇。"]'),
('11d33b2d-8b31-4811-895d-332b1a175762','雷簡夫自辰溪還除國子博士鹽鐵判官以書見謝并寄杜鵑鳥一隻偶成二章答之  其二','文彥博','宋','宋诗','song-poetry','','[]','山人遠寄杜鵑禽，因寄山禽遂寄心。',32,'全唐诗/poet.song.16000.json','["山人遠寄杜鵑禽，因寄山禽遂寄心。", "應謂不如歸去好，高飛却入舊雲休。"]'),
('c79976b6-184a-45ee-ad82-982368e170cb','送中舍蒲君致政西歸','文彥博','宋','宋诗','song-poetry','','[]','閬苑當年硯席同，別來三十八秋風。',32,'全唐诗/poet.song.16000.json','["閬苑當年硯席同，別來三十八秋風。", "東朝新命西歸去，珍重賢哉鶴髮翁。"]'),
('c645b3ef-5828-405f-89c7-1ec0cff5be7b','送分司少卿歸洪井  其一','文彥博','宋','宋诗','song-poetry','','[]','囊奏祈分務，綸恩寵亞卿。',48,'全唐诗/poet.song.16000.json','["囊奏祈分務，綸恩寵亞卿。", "揮金還故里，脫屣謝浮榮。", "綵服趨庭學，彤襜解榻迎。", "送言慙有味，何有答希聲。"]'),
('c37ca696-1e39-4520-ad27-d352873bba38','送分司少卿歸洪井  其二','文彥博','宋','宋诗','song-poetry','','[]','知止遺榮世所稀，帆風美滿浩然歸。',32,'全唐诗/poet.song.16000.json','["知止遺榮世所稀，帆風美滿浩然歸。", "江邊聞有梅真宅，吟對西山不掩扉。"]'),
('546d3a3e-d5d1-4bbe-bc4a-22e0913c44d6','送知府給事赴闕','文彥博','宋','宋诗','song-poetry','','[]','紞如驚曉鼓，仙斾戒晨興。',144,'全唐诗/poet.song.16000.json','["紞如驚曉鼓，仙斾戒晨興。", "萬臂攀朱轂，千兵擁綠縢。", "歸途非杳邈，高步即嚴凝。", "竹馬光前迹，蒲鞭掩舊稱。", "睿襟思啟沃，宸扆佇疑丞。", "輿論方盈耳，僉謀盡伏膺。", "公乎調大鼎，皇矣賚良肱。", "屬吏垂三異，微才僅五能。", "梁園暫未至，燕舘愧先登。", "北海難充薦，西曹久見矜。", "頑金雖自況，巧冶欲誰憑。", "深結君軒戀，翻思附驥蠅。"]'),
('731689f2-79b8-499e-b479-249c5528b2cd','和太師相公重九日讌府僚之什','文彥博','宋','宋诗','song-poetry','','[]','不獨龍山勝致全，黄樞開宴盡時賢。',64,'全唐诗/poet.song.16000.json','["不獨龍山勝致全，黄樞開宴盡時賢。", "風回綺席鸞觴泛，日上彤襜虎幄鮮。", "陶菊香濃侵玳押，吳歈聲緩倚鵾絃。", "雲牋一幅西園什，如聽鈞韶下九天。"]'),
('86489d5e-54a5-48b7-923d-fdadef6bd6e5','小園即事','文彥博','宋','宋诗','song-poetry','','[]','閑脫蕉衫挂樹椏，竹冠芒屩自耘瓜。',64,'全唐诗/poet.song.16000.json','["閑脫蕉衫挂樹椏，竹冠芒屩自耘瓜。", "心形散傲如園吏，椑榼縱橫似酒家。", "古檜婆娑張碧蓋，流泉詰屈動青蛇。", "風清日落未歸舍，待得東南見月華。"]'),
('4fbc8eeb-e935-4c4f-b786-31e6db509495','宮保相公之役與有勞焉及聞非才忝爰立之命貽詩加獎有晉公親討衛國專謀之句稱述大過擬議非倫輒成拙惡一章以達謝意','文彥博','宋','宋诗','song-poetry','','[]','平淮伐潞皆殊績，靖亂夷兇著往編。',64,'全唐诗/poet.song.16000.json','["平淮伐潞皆殊績，靖亂夷兇著往編。", "今以薄才叨重任，改將微效覬前賢。", "人慙肖象求商野，德謝非熊起渭川。", "惟有安昌念高第，雅章稱述愛彭宣。"]'),
('255ce4cd-302d-4c67-9539-fc9e0a364b15','題高平公親書伯夷頌卷後','文彥博','宋','宋诗','song-poetry','','[]','書從北海寄西豪，開卷纔窺竦髮毛。',32,'全唐诗/poet.song.16000.json','["書從北海寄西豪，開卷纔窺竦髮毛。", "范墨韓文傳不朽，首陽風節轉孤高。"]'),
('105edb5d-227d-4443-ade6-ebf49547ceb9','春日湖上偶作  其一','文彥博','宋','宋诗','song-poetry','','[]','地勝當春早，身閑愛景幽。',48,'全唐诗/poet.song.16000.json','["地勝當春早，身閑愛景幽。", "微風吹積水，盡日颺虛舟。", "客至解懸榻，魚來避直鈎。", "機心本不動，猶恐駭羣鷗。"]'),
('09a91de2-c164-44b3-9c2b-6391e8e0a15f','春日湖上偶作  其二','文彥博','宋','宋诗','song-poetry','','[]','岸幘長吟坐釣磯，花香漠漠柳依依。',32,'全唐诗/poet.song.16000.json','["岸幘長吟坐釣磯，花香漠漠柳依依。", "夕陽湖面光如鑑，風送虛舟自在歸。"]'),
('3fc29f82-0e46-48dd-9a1f-e469c5891832','謝太傅相公以近詩三十首寄示','文彥博','宋','宋诗','song-poetry','','[]','一軸詩三十，詞高氣格雄。',48,'全唐诗/poet.song.16000.json','["一軸詩三十，詞高氣格雄。", "文通推雜體，吉甫讓清風。", "平日丹青筆，當年造化工。", "安車有餘力，移向二南中。"]'),
('e9f6f2d7-feb7-4d28-8ff7-1a8f6fadfbb6','湖上獨酌','文彥博','宋','宋诗','song-poetry','','[]','盡日觀魚坐水邊，悠然獨酌望青山。',32,'全唐诗/poet.song.16000.json','["盡日觀魚坐水邊，悠然獨酌望青山。", "罇前解下淵明帢，起就東奚濯膩顔。"]'),
('89997e0e-c1c5-4b03-a51c-dfb00dd9fbc9','外計蘇度支示古銅器形製甚雅輒書五十六字還之','文彥博','宋','宋诗','song-poetry','','[]','古鼎良金齊法精，未知何代勒功名。',64,'全唐诗/poet.song.16000.json','["古鼎良金齊法精，未知何代勒功名。", "更須梓匠爲鳧杓，堪與仙翁作酒鎗。", "滌濯尚應勞犢鼻，腥羶不復染羊羹。", "水邊林下風清處，長伴薰然醉玉傾。"]'),
('c8336c5b-0701-46d7-941c-893f6822c87a','雨中湖上緋桃盛開舟子維纜於樹因書二十八言','文彥博','宋','宋诗','song-poetry','','[]','灼灼穠華照碧流，素煙絲雨助妖柔。',32,'全唐诗/poet.song.16000.json','["灼灼穠華照碧流，素煙絲雨助妖柔。", "武陵不放劉郎去，更就桃根繫小舟。"]'),
('1842a6bf-f5da-4e67-a66f-a64d3e97cbb7','得告赴洛展省松楸往還寓宿於陽翟程密學新第因成四十言寄高陽','文彥博','宋','宋诗','song-poetry','','[]','公臨趙北際，宅據許西偏。',48,'全唐诗/poet.song.16000.json','["公臨趙北際，宅據許西偏。", "來往由通德，逢迎阻見賢。", "嵩高當牖外，潁樹出牆顛。", "信宿依華廕，身居賀燕前。"]'),
('4634db03-f2ff-423d-9e42-ee00f8daeb86','提刑司封垂訪郡齋會於湖上道舊爲樂兼貺雅章輒成四十言以答來惠','文彥博','宋','宋诗','song-poetry','','[]','昔忝西州牧，驅車經劍門。',48,'全唐诗/poet.song.16000.json','["昔忝西州牧，驅車經劍門。", "見君新鑿沼，延我共開罇。", "治岸依山麓，疏泉透樹根。", "鴨湖今日會，往事喜重論。"]'),
('37555e8d-dfd4-48eb-bb89-cf39987dfe10','予移守青社同年宋學士代予守壁田會有來詩因成四十言爲答','文彥博','宋','宋诗','song-poetry','','[]','舊許陪原郡，時清偃息優。',48,'全唐诗/poet.song.16000.json','["舊許陪原郡，時清偃息優。", "羨君熊軾去，奪我鴨坡游。", "草樹秋方密，禽魚晚思幽。", "相憑皆與問，猶憶醉翁不。"]'),
('2edf73e0-e60d-4365-843d-61e6be2ae9cc','答南都致太傅相公','文彥博','宋','宋诗','song-poetry','','[]','雪苑揮毫寄雪宮，丘門褒寵過華蟲。',64,'全唐诗/poet.song.16000.json','["雪苑揮毫寄雪宮，丘門褒寵過華蟲。", "希聲遠奪霜鍾韻，妙墨高踰禊帖工。", "辱韻頗慚才陋薄，玩辭彌見意勤隆。", "西南跂望安昌館，何日陪隨似戴崇。"]'),
('a316bf02-f502-4bb9-951e-d85139e3c4b3','偶題看山樓新畫山水','文彥博','宋','宋诗','song-poetry','','[]','盡日望西山，扶筇復倚欄。',24,'全唐诗/poet.song.16000.json','["盡日望西山，扶筇復倚欄。", "遠觀猶未足，更作畫圖看。"]'),
('79841733-fceb-4f49-a1ae-ef1524c8d2ad','太原府統平殿朝拜','文彥博','宋','宋诗','song-poetry','','[]','逆壘彌天甚，君王駐翠鑾。',48,'全唐诗/poet.song.16000.json','["逆壘彌天甚，君王駐翠鑾。", "荆榛親剪伐，家業信艱難。", "一劍山河定，千年廟社安。", "故城禾黍美，無復驗泥丸。"]'),
('fc6f1c73-d12c-4d3a-b3a9-a8bdeef222f8','寄太原韓太尉','文彥博','宋','宋诗','song-poetry','','[]','舊說男兒本分官，更將詩句報長安。',32,'全唐诗/poet.song.16000.json','["舊說男兒本分官，更將詩句報長安。", "虛庸自省尤非據，深玷君家漢上壇。"]'),
('24b0c673-51d8-4e31-a76c-984c1e6467fa','和梅公儀待制 登驪山見連理木','文彥博','宋','宋诗','song-poetry','','[]','長生私語都無益，芳樹交柯自表奇。',32,'全唐诗/poet.song.16000.json','["長生私語都無益，芳樹交柯自表奇。", "就使玉真如素願，山陰拱木竟何知。"]'),
('7906b205-ff63-432d-9005-74779764585b','和梅公儀待制 宿西谿寺','文彥博','宋','宋诗','song-poetry','','[]','地占蓮華麓，谿環鷲嶺巔。',48,'全唐诗/poet.song.16000.json','["地占蓮華麓，谿環鷲嶺巔。", "密林含細籟，巍剎照清漣。", "獨賞寧妨醉，幽吟定廢眠。", "支郎諳雅尚，掃榻就潺湲。"]'),
('4b8b603d-129c-4ed6-bcaf-cdf66abc4ef0','公僕天章書示暫往藍田兼閱山水以答來貺','文彥博','宋','宋诗','song-poetry','','[]','暫枉觀風斾，從容賞物華。',48,'全唐诗/poet.song.16000.json','["暫枉觀風斾，從容賞物華。", "藍山青有玉，輞水碧無沙。", "林靜聞啼狖，川長見落霞。", "宜尋幽徑處，竹里到南坨。"]'),
('7781f3a1-8c8c-4de7-8d0b-e0139cd63d9f','和公儀天章雪中游藍田山悟真寺','文彥博','宋','宋诗','song-poetry','','[]','古寺依山構，高車冒雪游。',72,'全唐诗/poet.song.16000.json','["古寺依山構，高車冒雪游。", "穿林皆玉樹，倚檻盡瓊樓。", "景勝煩詩筆，財豐緩計籌。", "巖阿聊寄傲，物外恣尋幽。", "韁鎖慙羈擊，匏瓜歎滯留。", "無因陪雅躅，清唱復難酬。"]'),
('5c3e40b0-cad8-4fd9-8dc5-3379cf911cb3','寄青州田龍圖況','文彥博','宋','宋诗','song-poetry','','[]','東秦假手裁經歲，偃息山齋興味長。',64,'全唐诗/poet.song.16000.json','["東秦假手裁經歲，偃息山齋興味長。", "怪石罅中栽薜荔，碧梧陰裏種麻黄。", "吟牽翠蔓秋煙潤，醉擷纖英曉露凉。", "內省非才寡遺愛，爭教所憩似甘棠。"]'),
('418364ef-f2f7-4eed-a022-da7b40694155','雨後游華嚴川馬上作','文彥博','宋','宋诗','song-poetry','','[]','雨後城南路，無泥未有塵。',48,'全唐诗/poet.song.16000.json','["雨後城南路，無泥未有塵。", "因觀曲江樹，更憶杏園春。", "草色遥侵水，山光翠逼人。", "劭農兼訪古，攬轡緩朱輪。"]'),
('91317da7-bd4d-4fc2-b2d6-9e746074f726','題中山郎中華嚴川墅','文彥博','宋','宋诗','song-poetry','','[]','城南風物勝，最勝是華嚴。',48,'全唐诗/poet.song.16000.json','["城南風物勝，最勝是華嚴。", "謝墅偏幽寂，顔郎此退潜。", "流泉清遶砌，列岫翠當簷。", "更愛村橋畔，楊花撲酒帘。"]'),
('6d517d80-4943-489a-80f1-dc13727001c6','謝公儀待制惠黄石枕','文彥博','宋','宋诗','song-poetry','','[]','得時應在穀城山，蒸栗溫姿照席間。',32,'全唐诗/poet.song.16000.json','["得時應在穀城山，蒸栗溫姿照席間。", "助我漱流高卧意，曲肱從此不晞顔。"]'),
('0be94542-be48-4c26-a9d7-33f1aeb5cef5','和公儀隱廳書事','文彥博','宋','宋诗','song-poetry','','[]','跡貴雖軒冕，心閑似隱淪。',48,'全唐诗/poet.song.16000.json','["跡貴雖軒冕，心閑似隱淪。", "林間新葺宇，公退此頤神。", "蘚色青緣砌，池光碧照人。", "愛君高雅趣，琴酒屢相親。"]'),
('24a5d01e-c896-4aea-abe1-f3d2241a534d','月夕挈新釀并文石酒罇就公儀南湖雅飲','文彥博','宋','宋诗','song-poetry','','[]','桃花石器榴花釀，携就南湖訪飲朋。',32,'全唐诗/poet.song.16000.json','["桃花石器榴花釀，携就南湖訪飲朋。", "雅論清吟凉月滿，山翁不惜醉騰騰。"]'),
('210f4f4b-f344-4e55-9421-1af7e43b3a83','次韻和公儀月夕游南湖','文彥博','宋','宋诗','song-poetry','','[]','凉夜南湖飲，林端月上初。',48,'全唐诗/poet.song.16000.json','["凉夜南湖飲，林端月上初。", "樽罍既古雅，亭榭復清虛。", "靜賞興無盡，劇談歡有餘。", "羣騶不熹事，應厭久停車。"]'),
('238e2ab7-f343-4d67-b007-a1769100a847','和公儀詠蒲葵扇','文彥博','宋','宋诗','song-poetry','','[]','不取歸資厚，仁風藉爾揚。',48,'全唐诗/poet.song.16000.json','["不取歸資厚，仁風藉爾揚。", "論財雖儉薄，應用極清凉。", "六角價非重，九華名未光。", "傾心既已久，安石勿相忘。"]'),
('598c5d6b-afa2-43f0-b3e9-2a9d5da04094','和登飛橋觀游艇','文彥博','宋','宋诗','song-poetry','','[]','爲愛高橋月色多，飛觴捉塵對吟哦。',32,'全唐诗/poet.song.16000.json','["爲愛高橋月色多，飛觴捉塵對吟哦。", "輕舠一葉時來往，驚散雙鴛動碧荷。"]'),
('5946c434-b0fe-469d-9c7f-95a275cb089d','和公儀重到隱廳偶書絕句','文彥博','宋','宋诗','song-poetry','','[]','重訪隱齋留雅詠，將歸禁署促東轅。',32,'全唐诗/poet.song.16000.json','["重訪隱齋留雅詠，將歸禁署促東轅。", "曉猿夜鶴君家物，不戀南湖只戀軒。"]'),
('358a2c93-b26a-4c29-b2db-450c0a78d87c','和公儀湖上烹蒙頂新茶作','文彥博','宋','宋诗','song-poetry','','[]','蒙頂露牙春味美，湖頭月舘夜吟清。',32,'全唐诗/poet.song.16000.json','["蒙頂露牙春味美，湖頭月舘夜吟清。", "煩酲滌盡沖襟爽，蹔適蕭然物外情。"]'),
('2189cf11-9bb7-476b-aefa-247c6a41eb7b','與公儀會飲南湖作','文彥博','宋','宋诗','song-poetry','','[]','湖上高樓對遠山，一罇清醑且開顔。',64,'全唐诗/poet.song.16000.json','["湖上高樓對遠山，一罇清醑且開顔。", "今朝尚作林塘主，明日將歸侍從班。", "心向白雲雖自樂，身趨丹禁未容閑。", "爲君不惜厭厭醉，賞盡銀蟾秉燭還。"]'),
('64409d03-00b8-4307-a575-e89d47aac5ca','和公儀游太華','文彥博','宋','宋诗','song-poetry','','[]','山水清音步步隨，謝家歌舞豈須携。',64,'全唐诗/poet.song.16000.json','["山水清音步步隨，謝家歌舞豈須携。", "深游霧市身應潤，直上蓮峯路不迷。", "細草舒茵承蠟屐，長松傾蓋護雲梯。", "巖隈靈藥皆堪采，采得盈箱亦自提。"]'),
('79428e1d-f968-4ed9-a0f5-0a585684747c','見山樓小飲偶作','文彥博','宋','宋诗','song-poetry','','[]','雲淡天迷楚，樓高地占秦。',48,'全唐诗/poet.song.16000.json','["雲淡天迷楚，樓高地占秦。", "哀箏一行鴈，小字數鈎銀。", "巷陌三條月，池塘十步春。", "府門初夜閉，多少夜游人。"]'),
('0377cacd-c94c-4028-8afb-2b05cd6f8309','邛竹杖','文彥博','宋','宋诗','song-poetry','','[]','孤筠勁質異纖柔，欲假携持助勝遊。',32,'全唐诗/poet.song.16000.json','["孤筠勁質異纖柔，欲假携持助勝遊。", "不爲凌霜高節在，對公靈壽合包羞。"]'),
('e9bd8b5c-a908-42cc-bdc4-26edf47b0034','蜀牋','文彥博','宋','宋诗','song-poetry','','[]','素牋明潤如溫玉，新樣翻傳號冷金。',32,'全唐诗/poet.song.16000.json','["素牋明潤如溫玉，新樣翻傳號冷金。", "遠寄南都豈無意，緣公揮翰似山陰。"]'),
('469886cf-1160-4f2e-8935-cefdc1adad19','華陽巾','文彥博','宋','宋诗','song-poetry','','[]','華陽山相遺巾法，蜀國烏紗學製成。',32,'全唐诗/poet.song.16000.json','["華陽山相遺巾法，蜀國烏紗學製成。", "公厭貂裘今已久，定知野服稱高情。"]'),
('3eb9bf97-02af-45f8-8496-41742ebe2754','蒙頂茶','文彥博','宋','宋诗','song-poetry','','[]','舊譜最稱蒙頂味，露牙雲液勝醍醐。',32,'全唐诗/poet.song.16000.json','["舊譜最稱蒙頂味，露牙雲液勝醍醐。", "公家藥籠雖多品，略采甘滋助道腴。"]'),
('a8e62bd1-5787-48ee-855b-94d974d780cb','近以蜀物寄獻復以雅章爲報輒課蕪音仰酬來貺','文彥博','宋','宋诗','song-poetry','','[]','微物達誠方愧極，雅章流惠見情深。',64,'全唐诗/poet.song.16000.json','["微物達誠方愧極，雅章流惠見情深。", "野夫自是甘芹味，國老何嘗靳玉音。", "伸紙恣窺藍肆寶，登函頻作洛生吟。", "辭清墨妙真雙絕，韞匵傳家勵子孫。"]'),
('615b9c1b-6011-479c-9da2-eb0ae0ee50f7','天平相公遠寄佳章謹依韻和呈  其一','文彥博','宋','宋诗','song-poetry','','[]','曉闢天閽出帝綸，麾幢誤委不才臣。',64,'全唐诗/poet.song.16000.json','["曉闢天閽出帝綸，麾幢誤委不才臣。", "六條頒詔專臨雍，一道全師別制秦。", "雖受深恩辭北闕，擬將何術撫西人。", "他年遂解簪纓去，乞去伊川號散民。"]'),
('8a34c89b-ac75-41ae-b702-4ca02096d8a7','天平相公遠寄佳章謹依韻和呈  其二','文彥博','宋','宋诗','song-poetry','','[]','昔年公掌秦中漕，虎節尋提四鎮師。',64,'全唐诗/poet.song.16000.json','["昔年公掌秦中漕，虎節尋提四鎮師。", "從此功成爲漢相，至今闕內仰蕭規。", "新詩遠寄音盈耳，累牘頻窺喜見眉。", "更問春遊何處好，夾城西面景龍池。"]'),
('1fe58229-daae-4b99-a418-b98fb66a1974','次韻答平凉龍圖王諫議','文彥博','宋','宋诗','song-poetry','','[]','凜然威望讋西戎，十萬貔貅節制中。',64,'全唐诗/poet.song.16000.json','["凜然威望讋西戎，十萬貔貅節制中。", "從古藩垣謀帥重，于今詩禮得才雄。", "勤歸定是推優賞，靜勝由來保上功。", "不獨韋平稱世美，緇衣兼詠武桓公。"]'),
('ded593e1-0afa-47d5-9764-5d044ba69b66','答王龍圖詠山見寄','文彥博','宋','宋诗','song-poetry','','[]','分得魚符守雍州，垂帷閉閣再經秋。',64,'全唐诗/poet.song.16000.json','["分得魚符守雍州，垂帷閉閣再經秋。", "眼看巖岫將登覽，身似匏瓜苦滯留。", "杜曲朱坡雖已到，圭峯紫閣未曾遊。", "却輸假道歸朝客，上遍終南寺寺樓。"]'),
('e15729a3-262c-49a7-ba35-6537300bd7c9','題紀太尉廟','文彥博','宋','宋诗','song-poetry','','[]','死節古來雖有矣，大都死節少如公。',64,'全唐诗/poet.song.16000.json','["死節古來雖有矣，大都死節少如公。", "惟圖救主重圍內，不憚焚身烈焰中。", "龍準有因方脫禍，猴冠無計復爭雄。", "如何置酒咸陽會，只說蕭何第一功。"]'),
('08cabaa5-ab17-429f-9cdb-8bd31eead01a','過滎陽玉像院','文彥博','宋','宋诗','song-poetry','','[]','瑞相雙刊玉，仁祠側布金。',48,'全唐诗/poet.song.16000.json','["瑞相雙刊玉，仁祠側布金。", "輪蹄一道過，風雨二山嶔。", "密蘚蒼緣壁，喬松秀出林。", "村僧不可語，難問祖師心。"]'),
('003cfa44-8de3-4dfc-be4f-28230cbbafcd','過汜水關','文彥博','宋','宋诗','song-poetry','','[]','濟世安民主，擒充執竇歸。',72,'全唐诗/poet.song.16000.json','["濟世安民主，擒充執竇歸。", "山川遺氣象，史冊動光輝。", "原廟今昭德，羣雄昔畏威。", "虎牢名自久，牛口諺應非。", "關塞侔天險，封疆介日圍。", "特吟摩詰句，度水柳依依。"]'),
('2bb3de78-5f28-4e46-af13-d2389833bbca','某伏蒙昭文相公以某方忝瀍洛之寄因有嵩少之行惠賜遊山器一副質輕而制雅外華而中堅匪惟便於齎持實爲林下之珍玩也輒成拙詩一章報謝','文彥博','宋','宋诗','song-poetry','','[]','上公遺我游嵩具，匜盥杯盂色色全。',64,'全唐诗/poet.song.16000.json','["上公遺我游嵩具，匜盥杯盂色色全。", "拂拭便須延隱逸，潔清那敢污腥羶。", "行齎每度雲巖側，器使當居蠟屐前。", "林叟谿翁皆竊玩，山厨因此識嘉籩。"]'),
('e4d982d9-e9e4-4600-acaa-d48637ef8144','答青州相公二首  其一','文彥博','宋','宋诗','song-poetry','','[]','非才久玷鈞衡重，乞得麟符守洛師。',64,'全唐诗/poet.song.16000.json','["非才久玷鈞衡重，乞得麟符守洛師。", "聖造如天從素欲，愚衷何地報鴻慈。", "先塋松檟躬時省，私廟萍蘩潔仲祠。", "相國情深最知我，郵筒千里貺新詩。"]'),
('ed75e460-7cdb-4d02-b948-7034f53645be','答青州相公二首  其二','文彥博','宋','宋诗','song-poetry','','[]','雅章追念栢臺遊，屈指今逾二十秋。',64,'全唐诗/poet.song.16000.json','["雅章追念栢臺遊，屈指今逾二十秋。", "初奉南牀持大憲，後陪東閣告嘉猷。", "心如金石同謀國，路出風波免覆舟。", "聞欲堅隨赤松去，擬携靈壽從留侯。"]'),
('3b4f1adf-106d-42f6-9e3c-866b36f1a961','梅公儀見寄華亭鶴一隻','文彥博','宋','宋诗','song-poetry','','[]','子真仙裔富高情，遠寄仙禽至洛城。',64,'全唐诗/poet.song.16000.json','["子真仙裔富高情，遠寄仙禽至洛城。", "昔向華亭常警露，今來緱嶺伴吹笙。", "稻粱猶憶嘉禾美，竹樹應憐履道清。", "已遣吾家伊水墅，旋營莎薦似咸京。"]'),
('d7b8aaec-1033-4eee-8c1c-9ed54092fd00','游平泉作','文彥博','宋','宋诗','song-poetry','','[]','一崦抱溪斜，前朝輔相家。',96,'全唐诗/poet.song.16000.json','["一崦抱溪斜，前朝輔相家。", "遺基皆瓦礫，古木尚煙霞。", "夙昔東山墅，留連上殿車。", "雖云營退隱，未免逐豪夸。", "事往如飛鳥，林空噪暮鴉。", "池平無舊鳳，堤壞有殘沙。", "野叟猶能說，樵夫亦共嗟。", "至今巖石下，多長紫薇花。"]'),
('47f36012-77f2-42c3-97b6-684c928492ea','又讀平泉花木記  其一','文彥博','宋','宋诗','song-poetry','','[]','歷覽平泉記，文饒性苦奢。',48,'全唐诗/poet.song.16000.json','["歷覽平泉記，文饒性苦奢。", "如何伊上墅，多是日南花。", "美蔭皆奇樹，清芬悉異葩。", "安知桃李盛，不及晉公家。"]'),
('1e6d31e8-0c5d-40c6-82c8-a556f6627a13','又讀平泉花木記  其二','文彥博','宋','宋诗','song-poetry','','[]','竹樹環青嶂，樓台生碧煙。',48,'全唐诗/poet.song.16000.json','["竹樹環青嶂，樓台生碧煙。", "珍奇窮四海，景象冠三川。", "上黨夷兇日，太和歸國年。", "此時能勇退，應遂老平泉。"]'),
('bc12956f-5242-453c-bb64-641a381057d2','又讀平泉花木記  其三','文彥博','宋','宋诗','song-poetry','','[]','吾觀李太尉，所失在誇權。',48,'全唐诗/poet.song.16000.json','["吾觀李太尉，所失在誇權。", "名遂不知退，膏明惟自煎。", "終身戀華組，何日到平泉。", "徒有思歸意，歌詩盈百篇。"]'),
('0bcf3df3-2097-44ab-be84-a1ae2ccdc8ba','游盧溪','文彥博','宋','宋诗','song-poetry','','[]','一徑極幽深，清泉響竹陰。',96,'全唐诗/poet.song.16000.json','["一徑極幽深，清泉響竹陰。", "昔人曾隱霧，衰世偶爲霖。", "謀國無長策，論兵肆褊心。", "王師遂不振，物議愈難任。", "仰藥身雖殞，攻關盜轉侵。", "傳家絕諸藐，遺業變雙林。", "僧朴俱難問，碑昏尚可尋。", "徘徊念陳迹，不爲歎人琴。"]'),
('51161d93-409f-4ba1-9895-a6b4a83496f5','寒食日早發赴積慶莊拜掃過龍門馬上作','文彥博','宋','宋诗','song-poetry','','[]','赫奕晨霞照萬燈，路穿闕口勢如吞。',64,'全唐诗/poet.song.16000.json','["赫奕晨霞照萬燈，路穿闕口勢如吞。", "橋邊楊柳垂青線，林下鞦韆掛綵繩。", "平地伊流不一抹，半天嵩嶽翠千層。", "行行漸入吾疆理，竹塢松阡間綺塍。"]'),
('25a91a4a-2643-4d1b-aac0-5eca2ebb46c0','秋日登闕塞','文彥博','宋','宋诗','song-poetry','','[]','鞅掌公庭暇，登臨闕塞秋。',96,'全唐诗/poet.song.16000.json','["鞅掌公庭暇，登臨闕塞秋。", "清談不廢務，遠望略消憂。", "二室欖前見，長伊天際流。", "僧歸下樵徑，客去上漁舟。", "返照明金剎，飛泉響石樓。", "放懷真趣得，縱目滯情休。", "像列三龕密，波翻入節稠。", "悵然高世意，不減冶城遊。"]'),
('be445a0c-06b1-4485-97a4-799e6a3e3d0e','游潛溪','文彥博','宋','宋诗','song-poetry','','[]','脩竹蔭清溪，潺湲闕塞西。',48,'全唐诗/poet.song.16000.json','["脩竹蔭清溪，潺湲闕塞西。", "石床平有蘚，沙路潤無泥。", "粉白松圍古，藍生草带齊。", "難留批勅字，救旱作雲霓。"]'),
('64e7c6ab-60fc-447c-9a86-5284ec9b4c8b','登廣化閣','文彥博','宋','宋诗','song-poetry','','[]','寶剎層峯上，危欄凈界中。',48,'全唐诗/poet.song.16000.json','["寶剎層峯上，危欄凈界中。", "登臨近霄漢，子細見伊嵩。", "谷迥傳清梵，川長沒遠鴻。", "黄昏不忍去，月在石樓東。"]'),
('aa0287d0-c435-4da0-8a75-508d18238b1c','宿少林寺','文彥博','宋','宋诗','song-poetry','','[]','六六仙峯繞靜居，俗塵至此暫消除。',64,'全唐诗/poet.song.16000.json','["六六仙峯繞靜居，俗塵至此暫消除。", "西來未悟禪師意，北去還馳使者車。", "五品封槐今尚在，九年面壁昔何如。", "心知一宿猶難覺，花藏重尋貝葉書。"]'),
('8d1edc94-691a-4a72-9ffe-508ac2e9336d','游金星觀','文彥博','宋','宋诗','song-poetry','','[]','鶴髮龐眉二老仙，林間老屋十餘間。',64,'全唐诗/poet.song.16000.json','["鶴髮龐眉二老仙，林間老屋十餘間。", "齋糧不蓄惟栽菊，道眼長明祇看山。", "朋侶過從應綺用，比鄰掩映是嵩轅。", "蹔游自愧塵勞跡，解帢臨溪濯膩顔。"]'),
('1715b8d7-af7d-492d-a554-251e603815bf','游嶽寺','文彥博','宋','宋诗','song-poetry','','[]','寺占嵩顔景最多，奇峯列剎共嵬峨。',64,'全唐诗/poet.song.16000.json','["寺占嵩顔景最多，奇峯列剎共嵬峨。", "依巖寶砌礱清礎，出谷飛泉逗素波。", "下瞰長川窮渺邈，傍觀列岫極陂陁。", "緇林法樂堪隨喜，鐘磬聲清唄梵和。"]'),
('e24e45cd-ff41-4e2c-a803-5e493fd32781','過潁陽山墅作','文彥博','宋','宋诗','song-poetry','','[]','平生箕潁志，未免困名韁。',48,'全唐诗/poet.song.16000.json','["平生箕潁志，未免困名韁。", "賴此營山墅，頻年至潁陽。", "相鄰紫雲洞，不羨白蓮莊。", "却愧耕夫問，歸軒作底忙。"]'),
('88148d7e-010d-41e6-8463-76fdd67d019a','大名府舍創作茅齋因題八句太師相公太保相公','文彥博','宋','宋诗','song-poetry','','[]','勿謂茅茨陋，棲心即有餘。',48,'全唐诗/poet.song.16000.json','["勿謂茅茨陋，棲心即有餘。", "非同諸葛卧，頗類靜名居。", "面壁思禪理，向陽觀道書。", "迴頭視華屋，韁瑣宿蘧廬。"]'),
('443b81e1-4bc0-4f4b-9bcc-04a4aae20360','留守端明尚書遠示贈闍梨漸師詩依韻和成','文彥博','宋','宋诗','song-poetry','','[]','常隨凈侶呌禪關，熟聽潮音丈室間。',64,'全唐诗/poet.song.16000.json','["常隨凈侶呌禪關，熟聽潮音丈室間。", "身逐孤雲辭隴首，心如皎月照香山。", "儒空兩悟言無滯，覺望雙除性本閑。", "居守意勤當應現，不須祇到虎溪還。"]'),
('dabab5b3-04d8-4351-acf8-3cc09bc3dd8d','僕射侍中榮過潩上小園兼題嘉句謹成十六言仰謝賁飾','文彥博','宋','宋诗','song-poetry','','[]','上相尋芳駐畫輪，華貂玉節耀松筠。',64,'全唐诗/poet.song.16000.json','["上相尋芳駐畫輪，華貂玉節耀松筠。", "二南雅麗音盈耳，八體遒妍妙入神。", "魯壁再傳科斗字，稽山長詠永和春。", "小園從此增光價，一室熒煌照乘珍。"]'),
('d163bd72-28bf-4571-aa5d-4903b7669224','小園池上偶作','文彥博','宋','宋诗','song-poetry','','[]','微吟岸幘思悠然，近對方塘遠見山。',32,'全唐诗/poet.song.16000.json','["微吟岸幘思悠然，近對方塘遠見山。", "恩施洛陽均逸地，莫言此地是偷閑。"]'),
('3e41fd78-cd39-4511-bc4e-483c3129bbba','詩寄龍門寶應寺證大師','文彥博','宋','宋诗','song-poetry','','[]','山人去作山西將，岫幌巖扉掩翠嵐。',32,'全唐诗/poet.song.16000.json','["山人去作山西將，岫幌巖扉掩翠嵐。", "欲問證師求正住，憑師改作潞公庵。"]'),
('5f44d015-448c-4902-b8c6-089dcbd66f59','依韻和答文裕羣牧侍郎','文彥博','宋','宋诗','song-poetry','','[]','華軒過陋巷，良讌集西園。',48,'全唐诗/poet.song.16000.json','["華軒過陋巷，良讌集西園。", "雅飲金罍耻，高吟墨客喧。", "初晴山色靜，早夏木陰繁。", "酷愛君揮麈，清言有會元。"]'),
('4689cf5b-8340-41e6-ac30-9e8617a76016','晝寢夢歸洛宅','文彥博','宋','宋诗','song-poetry','','[]','位高才薄困疲癃，竹影泉聲夢寐中。',32,'全唐诗/poet.song.16000.json','["位高才薄困疲癃，竹影泉聲夢寐中。", "定去洛城爲逸客，近來書翰學揚風。"]'),
('2ce6f283-3d2d-4a15-ba27-6b825888b1c2','汝州王端明寄示竹亭詩二十章披玩歎賞不能自已輒成四十言仰答來惠','文彥博','宋','宋诗','song-poetry','','[]','窈窕竹間路，清虛池上亭。',48,'全唐诗/poet.song.16000.json','["窈窕竹間路，清虛池上亭。", "高情愛寂寂，終日玩青青。", "汝水環近郭，箕山開畫屏。", "知君於此興，極目送鴻冥。"]'),
('30405b21-ac36-4d1b-a309-1fec44e83f64','中書宿齋偶作  其一','文彥博','宋','宋诗','song-poetry','','[]','齋潔奉祠事，深嚴宿禁扃。',48,'全唐诗/poet.song.16000.json','["齋潔奉祠事，深嚴宿禁扃。", "露盤雲表見，鈞奏夢中聽。", "慎獨虔君命，清心重禮經。", "顧慚溫室樹，忽此集鷦螟。"]'),
('68f6350d-b595-4cc0-a0b1-f79f5815d02e','中書宿齋偶作  其二','文彥博','宋','宋诗','song-poetry','','[]','鳳閣容棲集，心無外慮侵。',48,'全唐诗/poet.song.16000.json','["鳳閣容棲集，心無外慮侵。", "夜凉秋氣早，人靜禁門深。", "大政慚無補，微才恐不任。", "歌眠聽宮漏，蘭焰照青衾。"]'),
('f20dc403-bd78-436a-9883-121cad3dbe00','太廟宿齋作','文彥博','宋','宋诗','song-poetry','','[]','孟秋嚴廟饗，公衮攝祠官。',48,'全唐诗/poet.song.16000.json','["孟秋嚴廟饗，公衮攝祠官。", "達嚮來風迥，方諸遡月寒。", "剪茅重屋峻，藂甓繚牆寬。", "仰念靈台厚，恭思王業難。"]'),
('c4c55208-897c-4784-a449-e1c5105a5154','寄題龍門臨伊堂兼呈奉先寺興公','文彥博','宋','宋诗','song-poetry','','[]','山僧知我思歸意，爲我臨伊創草堂。',64,'全唐诗/poet.song.16000.json','["山僧知我思歸意，爲我臨伊創草堂。", "聞說繞階叢巨石，更須當檻植脩篁。", "窗間東望乾元剎，門外南趨積慶莊。", "便擬半移生計去，不知何似暢師房。"]'),
('04168a7a-1f5c-4d1b-992a-5bd13837dba5','東樞後軒列植花草隨時競秀種類寔繁滋蔓因依未易圖也然昔之造化者爲不少矣故錄其名數牓於北垣意欲後之人勿剪勿伐且無忘於封植也因觀其牓偶作小詩三章曰嘲曰解曰斷云 嘲','文彥博','宋','宋诗','song-poetry','','[]','百種閑花草，皆非藥籠材。',24,'全唐诗/poet.song.16000.json','["百種閑花草，皆非藥籠材。", "如何桃與李，曾不預栽培。"]'),
('318dc6b8-8f62-453c-949c-0d46f92c3f52','東樞後軒列植花草隨時競秀種類寔繁滋蔓因依未易圖也然昔之造化者爲不少矣故錄其名數牓於北垣意欲後之人勿剪勿伐且無忘於封植也因觀其牓偶作小詩三章曰嘲曰解曰斷云 解','文彥博','宋','宋诗','song-poetry','','[]','勿謂閑花草，色成各有宜。',24,'全唐诗/poet.song.16000.json','["勿謂閑花草，色成各有宜。", "君看桃與李，未是歲寒姿。"]'),
('9c77cc81-83c0-46ae-b84d-f4a6f96e0b9c','東樞後軒列植花草隨時競秀種類寔繁滋蔓因依未易圖也然昔之造化者爲不少矣故錄其名數牓於北垣意欲後之人勿剪勿伐且無忘於封植也因觀其牓偶作小詩三章曰嘲曰解曰斷云 斷','文彥博','宋','宋诗','song-poetry','','[]','天地育萬物，物物遂其生。',24,'全唐诗/poet.song.16000.json','["天地育萬物，物物遂其生。", "何須强分別，不若兩忘情。"]'),
('ae20d995-a174-4d13-b63a-2e83d7c02460','九月十日西園會范內翰李紫微已下諸公惠雅章謹成拙詩仰答厚意','文彥博','宋','宋诗','song-poetry','','[]','今日西園集，聯裾蜀國英。',48,'全唐诗/poet.song.16000.json','["今日西園集，聯裾蜀國英。", "爲君聊置醴，念我昔專城。", "麗句皆新意，高談多故情。", "報君雖拙陋，所應在同聲。"]'),
('a477ba45-c0ca-4975-8c9d-99f2a6d89717','端明尚書垂訪弊居會於西園兼蒙賦詩賁飾輒成四十字奉呈','文彥博','宋','宋诗','song-poetry','','[]','重陽節始過，佳菊色猶親。',48,'全唐诗/poet.song.16000.json','["重陽節始過，佳菊色猶親。", "東籬把酒客，西園飛蓋賓。", "共此林下宴，可類商顔人。", "清罇幸未燥，無所獻酬頻。"]'),
('288bee5a-9b2f-4655-92e8-f1a53f00ce90','和副樞吳諫議上元夜從駕至集禧觀','文彥博','宋','宋诗','song-poetry','','[]','順時同樂慰邦民，協氣和風應早春。',64,'全唐诗/poet.song.16000.json','["順時同樂慰邦民，協氣和風應早春。", "斗運帝車遵大路，雲從天步絕纖塵。", "民瞻玉色欣遊豫，岳峙琳宮望省巡。", "回御端闈張鎬飲，蘭燈桂魄耀星津。"]'),
('ac346ae7-fed3-45ec-84d7-69a477b4bb72','和致政侍郎二府詩','文彥博','宋','宋诗','song-poetry','','[]','潭潭相府方高啟，岌岌樞闈亦對開。',64,'全唐诗/poet.song.16000.json','["潭潭相府方高啟，岌岌樞闈亦對開。", "棋布司存鄰象闕，星分位表拱天臺。", "樂天善頌傳嘉句，虔命叨居媿薄才。", "仰認聖皇優待意，先時曾枉翠華來。"]'),
('c495c9e7-ea0d-4411-bfe0-02157528a307','送秘書劉監歸嵩陽隱居  其一','文彥博','宋','宋诗','song-poetry','','[]','昔年寶應茅齋主，別後炎凉已屢經。',64,'全唐诗/poet.song.16000.json','["昔年寶應茅齋主，別後炎凉已屢經。", "暫入城來緣買藥，却騎牛去似飄萍。", "緱山重訪吹笙伴，秘省長虛畫鶴廳。", "一任洛陽人白眼，且看三十六峯青。"]'),
('5383ddc8-7f07-407c-8c2e-0ab20c85a88b','送秘書劉監歸嵩陽隱居  其二','文彥博','宋','宋诗','song-poetry','','[]','四明疇昔稱狂客，二室於今號散仙。',32,'全唐诗/poet.song.16000.json','["四明疇昔稱狂客，二室於今號散仙。", "子晉料登緱嶺望，待君笙鶴共昇天。"]'),
('2868d0a8-3320-4fb6-acf0-86491ae0f23e','和副樞吳諫議寄題廣化寺東軒','文彥博','宋','宋诗','song-poetry','','[]','凈居高出四禪天，更對伊嵩闢廣軒。',64,'全唐诗/poet.song.16000.json','["凈居高出四禪天，更對伊嵩闢廣軒。", "塔聳千花依鷲嶺，舟浮一葉上龍門。", "雲藏古木當危檻，風遞疎鐘過遠村。", "我有草堂南澗口，一回西望一銷魂。"]'),
('f24f97f5-9e68-4c91-bd12-34f317fa9668','伏覩致政太傅侍郎答樞密諫議留題齋閣詩依韻和呈  其一','文彥博','宋','宋诗','song-poetry','','[]','三朝光輔仰耆年，謝政歸來作散仙。',64,'全唐诗/poet.song.16000.json','["三朝光輔仰耆年，謝政歸來作散仙。", "筑室尚依雙鳳闕，放懷何必五湖船。", "清談傾座簪纓盛，綵服趨庭子舍賢。", "公伴赤松應念我，早教西去老伊川。"]'),
('3d66f98c-1b9c-40eb-bd89-28bed2401632','伏覩致政太傅侍郎答樞密諫議留題齋閣詩依韻和呈  其二','文彥博','宋','宋诗','song-poetry','','[]','華顛相顧最相親，同是三朝二府人。',64,'全唐诗/poet.song.16000.json','["華顛相顧最相親，同是三朝二府人。", "曾忝政堂陪大論，又叨樞筦繼清塵。", "我慙蒲柳衰殘質，公稱夔龍强健身。", "把酒觀言兼戀德，春暉不覺漸西淪。"]'),
('ef351a1b-1c7e-46d0-8e04-53b308340913','雪中樞密蔡諫議借示范寬雪景圖','文彥博','宋','宋诗','song-poetry','','[]','梁園深雪裏，更看范寬山。',48,'全唐诗/poet.song.16000.json','["梁園深雪裏，更看范寬山。", "迥出關荆上，如游嵩少間。", "雲愁萬木老，漁罷一簑還。", "此景堪延客，擁爐傾小蠻。"]'),
('67a0ee9f-c9df-4bc9-bb89-39ab0aa91069','和副樞蔡諫議植山芋','文彥博','宋','宋诗','song-poetry','','[]','平臺山芋傳區種，久餌能令玉壽延。',64,'全唐诗/poet.song.16000.json','["平臺山芋傳區種，久餌能令玉壽延。", "欲長深根培客土，便期珍味薦賓筵。", "吳蓴頓覺名稱減，楚芰須慙嗜好偏。", "況是丹頭推絕品，百金供費亦宜然。"]'),
('85ac382f-58f0-4116-8a89-f6c75aced6ca','竊知今日於家園種山芋輒成拙詩奉呈副樞諫議','文彥博','宋','宋诗','song-poetry','','[]','聞說家完樂，仍携山芋來。',48,'全唐诗/poet.song.16000.json','["聞說家完樂，仍携山芋來。", "何煩心助長，惟喜手親栽。", "若務豐根本，應須薙草萊。", "迎知冬薦味，决不減平臺。"]'),
('7d073630-7036-417a-919f-22ed91922ac9','和副樞蔡諫議贈副樞吳諫議謝惠新宅雜花之什','文彥博','宋','宋诗','song-poetry','','[]','百卉千花淑景新，主人吟嘯惜芳辰。',64,'全唐诗/poet.song.16000.json','["百卉千花淑景新，主人吟嘯惜芳辰。", "依依綠減隨隄色，灼灼紅移洛浦春。", "已愛清香飄宴席，更分穠艷與交親。", "鄒陽本是梁園客，醉賞猶思濉水濱。"]'),
('c3ae00da-e111-4627-b9e0-146ce12dc982','新釀酴醾酒送吳蔡二副樞','文彥博','宋','宋诗','song-poetry','','[]','此花猶未發，此酒已先香。',24,'全唐诗/poet.song.16000.json','["此花猶未發，此酒已先香。", "獨有甘芹意，開罇略爲嘗。"]'),
('ca4205cb-1560-4670-aec6-a095815c51b9','和副樞蔡諫議孟夏旦日右府書事','文彥博','宋','宋诗','song-poetry','','[]','杲日無虧彰睿聖，前星有慶耀東朝。',64,'全唐诗/poet.song.16000.json','["杲日無虧彰睿聖，前星有慶耀東朝。", "皇明燭遠羣羌服，火德乘時眾慝消。", "丹扆焦榮猶損膳，華顛尸素合歸樵。", "夔牙共奏康哉囗，雅詠和聲徹九霄。"]'),
('1c3d5895-a6ba-4449-bf58-d3dc1b0f4bfd','去春蒙西都致政李少師惠詩五首追敘舊遊因而招隱某尚羈樞務請退未諧深味來章未知所答遷延宿留遂涉歲時今蒙聖慈俯從人欲聽解重柄均逸便藩仰西河之上遊瞻仁宅之實邇即當胥會彌積欣怡輒成小詩三章代書見意且答去春之賜','文彥博','宋','宋诗','song-poetry','','[]','新詩五首緣招隱，未得西歸未敢酬。',96,'全唐诗/poet.song.16000.json','["新詩五首緣招隱，未得西歸未敢酬。", "今許均勞解樞柄，期君同伴赤松遊。", "伊西古寺茅庵靜，不到經今八九春。", "巖谷定知雲水冷，宮師常作獨遊人。", "斗藪緇塵捋白髭，緘書先去問宮師。", "仙舟東下能相訪，同上平嵩把酒巵。"]'),
('821adfe6-b637-4041-86d3-aad86f682b25','過魯太師廟作','文彥博','宋','宋诗','song-poetry','','[]','墨綬前朝宰，桑郊鄭圃東。',120,'全唐诗/poet.song.16000.json','["墨綬前朝宰，桑郊鄭圃東。", "叢祠臨大道，遺烈凜清風。", "顧我才尤薄，與君時不同。", "歷官無一異，得位亦三公。", "屑屑刑名內，區區薄領中。", "循良誰復道，貪刻自爲功。", "哲后方勤治，愚臣合盡忠。", "承流奉寬大，宣澤務龐鴻。", "此意緣思古，何人爲發蒙。", "神交儻來鑒，潛願啟其衷。"]'),
('3fd98f25-f9a3-4b41-873f-fce02b69f2a5','再到積慶墳莊即事偶成  其一','文彥博','宋','宋诗','song-poetry','','[]','不到伊川八九年，重來風物盡依然。',64,'全唐诗/poet.song.16000.json','["不到伊川八九年，重來風物盡依然。", "驚回俗夢鳴臯鶴，洗凈塵襟漱玉泉。", "綠篠侵階當蕙帳，蒼霞滿目對松阡。", "天憐老懶優深處，罷聽晨雞徹曉眠。"]'),
('5bd8111b-375b-4cde-aab3-b5c8255dcb37','再到積慶墳莊即事偶成  其二','文彥博','宋','宋诗','song-poetry','','[]','郊園乍適疎慵意，勉强逢迎已不能。',64,'全唐诗/poet.song.16000.json','["郊園乍適疎慵意，勉强逢迎已不能。", "赤米白鹽充野饌，蕉衫芒蹻見山僧。", "含風古木遮簷角，漱玉清泉瀉石稜。", "田父相過復相勸，早歸林下醉騰騰。"]'),
('6a7cb23e-e89c-4462-9645-234089c99962','東溪泛舟','文彥博','宋','宋诗','song-poetry','','[]','東溪伊水東，溪水丘溶溶。',96,'全唐诗/poet.song.16000.json','["東溪伊水東，溪水丘溶溶。", "兩槳夷猶去，雙鳧上下逢。", "餘波通洛浦，倒影浸嵩峯。", "荷動聞魚躍，沙平見鶴蹤。", "島蒲森劍戟，岸柳亞虬龍。", "並載惟禪客，隨觀有牧童。", "風傳櫂謳遠，露濕釣蓑濃。", "不是迷津處，何煩問老農。"]'),
('d397ac36-f4ec-48d5-872d-d829c40132a9','遊楚諫議園宅呈留守宣徽留台端明','文彥博','宋','宋诗','song-poetry','','[]','五里依仁宅，西鄰數仞牆。',96,'全唐诗/poet.song.16000.json','["五里依仁宅，西鄰數仞牆。", "主人爲屏翰，園吏占風光。", "地勝金甌小，林深錦襻長。", "輕煙罩叢桂，幽鳥入脩篁。", "蘚色沿茶竈，松陰覆石床。", "一區誠可樂，三徑莫令荒。", "有木皆交蔭，無花不並芳。", "相期掛冠後，同此事琴觴。"]'),
('ad7e8634-81cf-4893-93b9-1379a918bc52','遊史館張大卿致政李少卿史館傅兵部濟上郊園','文彥博','宋','宋诗','song-poetry','','[]','疇昔常聞處士莊，林泉勝景甲山陽。',64,'全唐诗/poet.song.16000.json','["疇昔常聞處士莊，林泉勝景甲山陽。", "一渠寒水流清濟，千仞濃嵐聳太行。", "枋口雲歸穿古木，燕川風過入脩篁。", "前賢舊業何人繼，分與三賢作醉鄉。"]'),
('6e24655a-d4c9-4443-9d1d-6b557ac13b3e','題龍潭寺','文彥博','宋','宋诗','song-poetry','','[]','古寺依青障，高軒俯碧潭。',24,'全唐诗/poet.song.16000.json','["古寺依青障，高軒俯碧潭。", "山僧如有待，先掃侍中庵。"]'),
('57be9fd8-9783-4459-9078-b8522ea1a7bb','謁濟祠作','文彥博','宋','宋诗','song-poetry','','[]','導沇靈源祀典尊，湛然凝碧浸雲根。',64,'全唐诗/poet.song.16000.json','["導沇靈源祀典尊，湛然凝碧浸雲根。", "遠潮滄海殊無礙，橫貫洪河自不渾。", "一派平流滋稼穡，四時精享薦萍蘩。", "未嘗輕作風濤險，惟有涵濡及物恩。"]'),
('df36dc07-b1e5-4b7e-8e97-971dd53763ea','登平崧閣右崧亭作','文彥博','宋','宋诗','song-poetry','','[]','不較平崧與右崧，大都亭閣盡穹崇。',32,'全唐诗/poet.song.16000.json','["不較平崧與右崧，大都亭閣盡穹崇。", "太行太室當前後，俱是山家入望中。"]'),
('ed11af60-00c7-4479-b434-e2bdf15b9b87','遊碧漣堂偶作寄致政司空相公聊布所懷','文彥博','宋','宋诗','song-poetry','','[]','公以心如水，開軒俯碧漣。',48,'全唐诗/poet.song.16000.json','["公以心如水，開軒俯碧漣。", "嘗虛濟川檝，却就釣璜淵。", "北倚平崧閣，南臨種黍田。", "緣經冶城望，到此即懷賢。"]'),
('720b312a-8978-4419-b977-961f770172cd','詩寄相州侍中韓魏公','文彥博','宋','宋诗','song-poetry','','[]','鼎邑從來事足誇，冰臺近歲景尤嘉。',64,'全唐诗/poet.song.16000.json','["鼎邑從來事足誇，冰臺近歲景尤嘉。", "天平峰秀堪圖畫，晝錦堂高可宴衙。", "新表門閭通德里，舊栽桃李相君家。", "仍聞降志相希慕，林下時乘洛樣車。"]'),
('26f710e7-555c-40a6-87fa-0367266ad1c3','詩寄西都致政司空相公','文彥博','宋','宋诗','song-poetry','','[]','燕居堂北虛閑地，蔾藿森森欲柱天。',64,'全唐诗/poet.song.16000.json','["燕居堂北虛閑地，蔾藿森森欲柱天。", "中有紅梨最翹秀，削成鳩杖佐衰年。", "初同野叟甘芹味，終學狂翁掛酒錢。", "分寄一枝公必訝，提携不稱葛陂仙。"]'),
('af4c3046-ed97-4bf0-a719-9a17d41579e5','詩寄答致政司空相公','文彥博','宋','宋诗','song-poetry','','[]','眾卉羣芳品自奇，遍形歌詠殆無遺。',64,'全唐诗/poet.song.16000.json','["眾卉羣芳品自奇，遍形歌詠殆無遺。", "名過衛國平泉記，數協江淹雜體詩。", "蘇頲祗誇長樂賦，元輿惟咤牡丹詞。", "豈知哲匠風騷美，不間鴻纖盡物宜。"]'),
('adbb37c8-ed06-470f-8144-1d2713ba7c24','知郡傅學士將赴彭門蒙貺佳什次韻奉答','文彥博','宋','宋诗','song-poetry','','[]','史局郎曹得俊賢，稔聞高譽已多年。',64,'全唐诗/poet.song.16000.json','["史局郎曹得俊賢，稔聞高譽已多年。", "山陽松菊拋三徑，泗水衣冠戴二天。", "合作商霖光祖構，猶持漢節滯英躔。", "河梁欲上難輕別，亦望遲遲駐曲旃。"]'),
('db53ef74-cfe7-4f3a-a0ea-1a4bf7edf57b','致政仲損張工部詢及孟醞之味因寄數器副以小詩','文彥博','宋','宋诗','song-poetry','','[]','醽淥如澠味似飴，朝回何必典春衣。',64,'全唐诗/poet.song.16000.json','["醽淥如澠味似飴，朝回何必典春衣。", "序賓留飲觴無算，速父供甘羜更肥。", "不惜郫筒令遠寄，惟憂遼豕得深譏。", "小家麴糵君諳在，莫使邯鄲枉見圍。"]'),
('39a2decc-86f7-4f0b-a3cf-a52da73baa6b','西都留守宣徽祈謝嵩祠往還敝莊因成雅章爲貺謹次嚴韻  其一','文彥博','宋','宋诗','song-poetry','','[]','臘雪應祈沾下土，府公遵命祀中天。',64,'全唐诗/poet.song.16000.json','["臘雪應祈沾下土，府公遵命祀中天。", "定陪仙馭經緱嶺，應訪禪林過玉泉。", "和氣隨風生二室，歡謠繼日滿三川。", "悠悠大斾纍纍印，却愛蘇家負郭田。"]'),
('c44559d8-f7b1-430c-b9c2-2b33fde400fd','西都留守宣徽祈謝嵩祠往還敝莊因成雅章爲貺謹次嚴韻  其二','文彥博','宋','宋诗','song-poetry','','[]','若比揚雄多一廛，僅同徐勉葺東田。',32,'全唐诗/poet.song.16000.json','["若比揚雄多一廛，僅同徐勉葺東田。", "溝塍萬畝言之過，却恐增添助役錢。"]'),
('d85a112f-513d-4093-a174-206dd747a8e8','前朔憲孔嗣宗太博過孟云近於洛下結窮九老會凡職事稍重生事稍豐者不得與焉其宴集之式率稱其名其事誠可嘉尚其語多資嗢噱因作小詩以紀之亦以見河南士人有名教之樂簡貪薄之風輒錄呈留守宣徽聊資解頤','文彥博','宋','宋诗','song-poetry','','[]','洛城冠蓋敦名教，任是清貧節轉高。',32,'全唐诗/poet.song.16000.json','["洛城冠蓋敦名教，任是清貧節轉高。", "見說近添窮九老，從初便不要山濤。"]'),
('1266178d-2b05-4db4-967f-8242561d7045','謝留守王宣徽寄花','文彥博','宋','宋诗','song-poetry','','[]','遠惠奇花自洛城，吟觀醉賞動鄉情。',32,'全唐诗/poet.song.16000.json','["遠惠奇花自洛城，吟觀醉賞動鄉情。", "開編讀到安仁傳，方信河陽浪得名。"]'),
('ff3a7ead-de2a-468e-a7e1-f2a419532182','再和','文彥博','宋','宋诗','song-poetry','','[]','惟有陳園接府城，池塘花竹可娛情。',32,'全唐诗/poet.song.16000.json','["惟有陳園接府城，池塘花竹可娛情。", "雖然不及芙蓉萼，猶得河橋史舘名。"]'),
('e415688b-2678-49b6-aab6-442d2964274e','詩謝留守王宣徽遠惠牡丹','文彥博','宋','宋诗','song-poetry','','[]','姚黄左紫狀元紅，打剝栽培久用功。',64,'全唐诗/poet.song.16000.json','["姚黄左紫狀元紅，打剝栽培久用功。", "采折乍經微雨後，緘封仍在小奩中。", "勤勤賞玩傾蘭醑，漠漠馨香逐蕙風。", "猶恐花心懷舊土，戴時頻與望青嵩。"]'),
('e3ca8d81-897d-452c-bd87-7c5b3e6517b5','熙寧癸丑季冬十有三日某被旨謝雪於濟祠已事與秘書監光祿卿直史館太常少卿屯田郎中祕書丞同遊枋口泛舟沁水至峴石而登岸歷觀巖谷間前賢之題名翌日遊化成寺以車渡沁回入盤谷窮覽山水之嘉處由燕川而歸 枋口作','文彥博','宋','宋诗','song-poetry','','[]','下馬入枋口，漾舟緣碧溪。',48,'全唐诗/poet.song.16000.json','["下馬入枋口，漾舟緣碧溪。", "雪消山骨瘦，風定浪頭低。", "數里復登岸，羣賢俱杖藜。", "徘徊巖石畔，尋覓退之題。"]'),
('c679891d-219a-4e8d-9c32-8421e41234ea','熙寧癸丑季冬十有三日某被旨謝雪於濟祠已事與秘書監光祿卿直史館太常少卿屯田郎中祕書丞同遊枋口泛舟沁水至峴石而登岸歷觀巖谷間前賢之題名翌日遊化成寺以車渡沁回入盤谷窮覽山水之嘉處由燕川而歸 化成寺作唐裴相之山墅捨爲寺','文彥博','宋','宋诗','song-poetry','','[]','昔覽傳心法，知公素學禪。',96,'全唐诗/poet.song.16000.json','["昔覽傳心法，知公素學禪。", "今遊化成寺，使我復思賢。", "大捨傾高產，多生結勝緣。", "人琴雖已矣，松菊尚依然。", "寶地侵蒼蘚，巍峰柱碧天。", "撮衣書久失，礱石像猶全。", "境寂遺塵慮，僧閑足晝眠。", "欲歸情戀戀，緩轡出燕川。"]'),
('aa5a325c-99d1-4516-9a73-30fc6adde341','熙寧癸丑季冬十有三日某被旨謝雪於濟祠已事與秘書監光祿卿直史館太常少卿屯田郎中祕書丞同遊枋口泛舟沁水至峴石而登岸歷觀巖谷間前賢之題名翌日遊化成寺以車渡沁回入盤谷窮覽山水之嘉處由燕川而歸 過燕川渡','文彥博','宋','宋诗','song-poetry','','[]','早過燕川渡，千峰插太虛。',48,'全唐诗/poet.song.16000.json','["早過燕川渡，千峰插太虛。", "雲開微見日，水淺不漸車。", "風急樵歌響，霜嚴木葉踈。", "緣溪東北去，巖腹有精廬。"]'),
('77e0269f-1d27-4c0e-871d-e569cb2d4cbe','熙寧癸丑季冬十有三日某被旨謝雪於濟祠已事與秘書監光祿卿直史館太常少卿屯田郎中祕書丞同遊枋口泛舟沁水至峴石而登岸歷觀巖谷間前賢之題名翌日遊化成寺以車渡沁回入盤谷窮覽山水之嘉處由燕川而歸 盤谷作 其一','文彥博','宋','宋诗','song-poetry','','[]','昔有幽棲士，茲焉遂考槃。',48,'全唐诗/poet.song.16000.json','["昔有幽棲士，茲焉遂考槃。", "驚眠澗泉響，醒酒谷風寒。", "列岫開窗見，冥鴻倚杖觀。", "韓文傳已久，合在翠巖刊。"]'),
('0faa709b-2698-47ac-a322-982c3e32de3f','熙寧癸丑季冬十有三日某被旨謝雪於濟祠已事與秘書監光祿卿直史館太常少卿屯田郎中祕書丞同遊枋口泛舟沁水至峴石而登岸歷觀巖谷間前賢之題名翌日遊化成寺以車渡沁回入盤谷窮覽山水之嘉處由燕川而歸 盤谷作 其二','文彥博','宋','宋诗','song-poetry','','[]','願也乖真隱，韓文旨趣深。',48,'全唐诗/poet.song.16000.json','["願也乖真隱，韓文旨趣深。", "本非逃富貴，豈是愛雲林。", "已失豪華望，方萌退縮心。", "歸來老窮谷，村叟共浮沈。"]'),
('46f3a596-1bb8-4f81-b7d4-d6d5e5ce0606','自濟源回及中道得通守郎中詩跂羨山水之遊以不得陪從爲恨因以詩答之','文彥博','宋','宋诗','song-poetry','','[]','奉祀靈源臘雪餘，薄寒風景似春初。',64,'全唐诗/poet.song.16000.json','["奉祀靈源臘雪餘，薄寒風景似春初。", "因尋山下游三日，惟恨罇前欠貳車。", "南望思君回五馬，北來遺我得雙魚。", "新詩兩首連城貴，百斛驪珠價不如。"]'),
('b4aecc85-4e9d-4d1c-9dc6-2aa09e0f3b44','司空相公特貺雅章俯光陋跡依韻和呈以答厚意','文彥博','宋','宋诗','song-poetry','','[]','一代勳賢孰擬倫，惟公爵德齒俱尊。',64,'全唐诗/poet.song.16000.json','["一代勳賢孰擬倫，惟公爵德齒俱尊。", "顧慙參魯辭樞筦，輒繼蕭規偃輔藩。", "每到碧漣思召茇，時傾綠醑憶曹樽。", "平嵩極目西南望，仁里高閎近鼎門。"]'),
('5ed71085-6bb7-461b-8bd7-879ece20d561','初泛舟新池觀子弟輩作詩因爲此示之','文彥博','宋','宋诗','song-poetry','','[]','舊池疏引透新池，轉覺澄瀾勢渺瀰。',64,'全唐诗/poet.song.16000.json','["舊池疏引透新池，轉覺澄瀾勢渺瀰。", "得志魚蝦爭跳躍，無根萍梗任推移。", "船頭欲過衝橋脚，柳眼初開映水湄。", "借問阿連春草句，何人先把紫毫摛。"]'),
('77224266-4546-4b4b-b471-48b0411c94fc','將赴大名奉寄西都留守王宣徽','文彥博','宋','宋诗','song-poetry','','[]','驟易銅臺守，脂車冒藴隆。',48,'全唐诗/poet.song.16000.json','["驟易銅臺守，脂車冒藴隆。", "北行如拾魯，南望倚平嵩。", "畏日臨傾藿，驚飚走斷蓬。", "伊流舊親友，應亦念衰翁。"]'),
('e29cefca-01dc-4402-b2d4-65249b10d8b2','春旱既甚禱祈未應小園即事','文彥博','宋','宋诗','song-poetry','','[]','渴望甘膏蘇旱歲，日趨祠廟罄虔祈。',32,'全唐诗/poet.song.16000.json','["渴望甘膏蘇旱歲，日趨祠廟罄虔祈。", "春風也解相欺罔，鼓扇楊花學雪飛。"]'),
('0b948139-e94f-43d4-a7c6-7e470c7239c7','寄相州侍中韓魏公','文彥博','宋','宋诗','song-poetry','','[]','晉公名畫魯公書，高出張吳與柳虞。',32,'全唐诗/poet.song.16000.json','["晉公名畫魯公書，高出張吳與柳虞。", "幸得魏公揮寶墨，緣公楷法亦顔徒。"]'),
('c8fccb09-7829-4ed9-8d6f-5aecd5df1500','題韓晉公村田歌舞圖後','文彥博','宋','宋诗','song-poetry','','[]','治世舒長日，田家事力蘇。',48,'全唐诗/poet.song.16000.json','["治世舒長日，田家事力蘇。", "干戈久不識，簫鼓共爲娛。", "濁酒行無算，酡顔倒更扶。", "將求太平象，此是太平圖。"]'),
('a0cec0c6-409d-4fda-ba2b-e37dc269353f','題輞川圖後','文彥博','宋','宋诗','song-poetry','','[]','吾家伊上塢，亦自有椒園。',48,'全唐诗/poet.song.16000.json','["吾家伊上塢，亦自有椒園。", "漠漠清香遠，離離丹實繁。", "盈襜常要采，折柳不須藩。", "每看輞川畫，起予商可言。"]'),
('1122965d-6c02-41e7-b1ad-aae6c8d00a63','即事偶書','文彥博','宋','宋诗','song-poetry','','[]','世道逢消長，人情徇愛憎。',48,'全唐诗/poet.song.16000.json','["世道逢消長，人情徇愛憎。", "光華如石火，明滅似風燈。", "巢幕堪憂燕，垂天不羨鵬。", "危心戒行險，視履益兢兢。"]'),
('306c0b1d-e861-424d-9bc0-8629fd4c2f37','昨夜飲散未眠偶成拙頌錄呈武功寺丞若猶未棄無惜開示','文彥博','宋','宋诗','song-poetry','','[]','以幻能除幻，居塵不染塵。',48,'全唐诗/poet.song.16000.json','["以幻能除幻，居塵不染塵。", "略於歌舞地，聊現宰官身。", "有法猶爲滯，無心乃是真。", "還將所得趣，試問悟空人。"]'),
('a44f31d9-1e0c-4b4c-947f-24b4464750e6','再答','文彥博','宋','宋诗','song-poetry','','[]','說幻緣知幻，言塵爲覺塵。',48,'全唐诗/poet.song.16000.json','["說幻緣知幻，言塵爲覺塵。", "覺知今亦遣，塵幻豈關身。", "獨體方無對，雙脩未是真。", "因君祗夜頌，自愧小乘人。"]'),
('8efe17d5-239f-477f-9184-917d62f6844b','提舉劉司封訪別將赴滏陽輒成五十六言','文彥博','宋','宋诗','song-poetry','','[]','乞領琳宮作散仙，雲情鶴態任天然。',64,'全唐诗/poet.song.16000.json','["乞領琳宮作散仙，雲情鶴態任天然。", "榮驅軒馭歸仁里，懇拜封章解計權。", "尺璧時光須愛惜，寸金鄉土且留連。", "銅臺事事君誇詫，莫望西山緊著鞭。"]'),
('90e41205-3cbc-47e3-9807-49dcfff3b944','偶成小詩贈提舉劉司封','文彥博','宋','宋诗','song-poetry','','[]','向上應無快活人，斯言未敢便當仁。',32,'全唐诗/poet.song.16000.json','["向上應無快活人，斯言未敢便當仁。", "留君且住非他意，好作熙寧第八春。"]'),
('fe381699-c646-41cb-960e-2ae872e3cb14','家園酴醾自京寄至奉送提舉劉司封','文彥博','宋','宋诗','song-poetry','','[]','小圃酴醾爛熳開，盈箱採得寄銅臺。',32,'全唐诗/poet.song.16000.json','["小圃酴醾爛熳開，盈箱採得寄銅臺。", "當花對酒熏然意，似到清香洞裏來。"]'),
('ef5699ea-a7bd-4425-bb07-83673c49e34a','提舉劉司封監牧張職方詠酴醾詩皆以微文形於善謔輒成累句奉呈聊用解紛  其一','文彥博','宋','宋诗','song-poetry','','[]','蠻牋往復寫瓊瑰，皆是論都作賦才。',32,'全唐诗/poet.song.16000.json','["蠻牋往復寫瓊瑰，皆是論都作賦才。", "花本無情亦無語，清香自到鄴城來。"]'),
('f88f16bc-1050-41af-b92e-58e0b38c8ee9','提舉劉司封監牧張職方詠酴醾詩皆以微文形於善謔輒成累句奉呈聊用解紛  其二','文彥博','宋','宋诗','song-poetry','','[]','已折素華迷雪苑，更將瓊艷照冰臺。',32,'全唐诗/poet.song.16000.json','["已折素華迷雪苑，更將瓊艷照冰臺。", "劉郎曾入仙源路，又到唐昌觀裏來。"]'),
('227af050-398b-471a-95a7-8a479a9ccf21','招仲通司封府園避暑','文彥博','宋','宋诗','song-poetry','','[]','騎山樓下水軒東，一室初開待白公。',64,'全唐诗/poet.song.16000.json','["騎山樓下水軒東，一室初開待白公。", "雖是不如南澗上，都緣却有北窗風。", "銜杯避暑稱河朔，飛蓋延賓在鄴中。", "解榻况逢徐孺子，饋漿如飯與君同。"]'),
('b3a7f9b0-84a5-4821-bc53-b8121d1422d6','金宿樓望月呈仲通司封  其一','文彥博','宋','宋诗','song-poetry','','[]','滿滿十分酒，高高百尺樓。',48,'全唐诗/poet.song.16000.json','["滿滿十分酒，高高百尺樓。", "於茲賞圓月，況乃值仲秋。", "天宇浩無際，露華光欲流。", "西園清夜景，公幹不同遊。"]'),
('42fe65b6-1ef6-4af4-bdd7-d0e438004e51','金宿樓望月呈仲通司封  其二','文彥博','宋','宋诗','song-poetry','','[]','緬想建安盛，西園飛蓋遊。',48,'全唐诗/poet.song.16000.json','["緬想建安盛，西園飛蓋遊。", "初筵會才雅，今夕繼風流。", "月伴昏星出，雲隨晚吹收。", "老生於此興，不減庾荆州。"]'),
('ac4c8b8a-f811-4302-9da7-ea39b8504b76','詩贈提舉竇侍郎','文彥博','宋','宋诗','song-poetry','','[]','紫髯真將白雲卿，總領琳宮道氣清。',64,'全唐诗/poet.song.16000.json','["紫髯真將白雲卿，總領琳宮道氣清。", "蘄竹一林曾斷買，青溪三弄得遺聲。", "季倫自作思歸曲，向秀方深感舊情。", "雖恨功名非謝傅，樽前更欲聽君箏。"]'),
('8281c524-a3d1-4420-8ea5-73295c1b3274','舟中別後中夕無寐偶成四十言奉寄中輝大卿聊致黯然之懷','文彥博','宋','宋诗','song-poetry','','[]','五十年親友，如今兩鬢霜。',48,'全唐诗/poet.song.16000.json','["五十年親友，如今兩鬢霜。", "相逢在淇澳，所樂似瀟湘。", "話舊如春夢，聽歌放酒狂。", "壓關樓下別，一夕九回腸。"]'),
('6b658853-67f1-4bc4-87d0-f2d34c36e87f','依韻謝運使陳虞部生日惠雙鶴靈壽杖  其一','文彥博','宋','宋诗','song-poetry','','[]','仙禽壽杖垂佳貺，麗句雕章煥列星。',32,'全唐诗/poet.song.16000.json','["仙禽壽杖垂佳貺，麗句雕章煥列星。", "深悉至懷形善禱，擬延西景駐頹齡。"]'),
('af218319-11ee-4097-8e42-4973498062b4','依韻謝運使陳虞部生日惠雙鶴靈壽杖  其二','文彥博','宋','宋诗','song-poetry','','[]','青田雙戲九臯鳴，屈降仙姿入戶庭。',32,'全唐诗/poet.song.16000.json','["青田雙戲九臯鳴，屈降仙姿入戶庭。", "宜與衰翁爲老伴，雪毛霜鬢共星星。"]'),
('aeb6d812-698f-4e5a-9593-6a3b8f3b273e','依韻謝運使陳虞部生日惠雙鶴靈壽杖  其三','文彥博','宋','宋诗','song-poetry','','[]','瑰奇擢秀從王屋，靈壽傳名自漢庭。',32,'全唐诗/poet.song.16000.json','["瑰奇擢秀從王屋，靈壽傳名自漢庭。", "仁者存心安老者，欲扶蹇步得長寧。"]'),
('0ae26fb5-dc32-4f90-bab0-e10f183cca0e','依韻謝運使陳虞部生日惠雙鶴靈壽杖  其四','文彥博','宋','宋诗','song-poetry','','[]','美幹非緣削治成，挺然脩直體堅輕。',32,'全唐诗/poet.song.16000.json','["美幹非緣削治成，挺然脩直體堅輕。", "仙郎曲借扶持力，使助登山蠟屐行。"]'),
('bf34ae45-b89c-42d2-af27-34552aa410f5','熙寧丙辰十一月二十八日安正堂喜雪','文彥博','宋','宋诗','song-poetry','','[]','凍雲濃厚朔風嚴，粉揉瓊霙撲綺簷。',64,'全唐诗/poet.song.16000.json','["凍雲濃厚朔風嚴，粉揉瓊霙撲綺簷。", "斗變至和緣帝力，迎知上瑞協人占。", "晚歸漁市蓑衣重，曉上旗亭酒價添。", "更待三英同勝賞，翩翩賦筆紫毫銛。"]'),
('85c37a59-5bb6-4d10-8fd5-72729ded79b6','雪霽金宿樓閒望偶作','文彥博','宋','宋诗','song-poetry','','[]','盈尺初晴皓采鮮，長空極望勢漫漫。',64,'全唐诗/poet.song.16000.json','["盈尺初晴皓采鮮，長空極望勢漫漫。", "銅臺不憚三休上，冰井須添一倍寒。", "舟檝似從雲外過，園林如在鑑中看。", "冬來景象今方好，未到黄昏且凭欄。"]'),
('d8a794bc-7ea4-462a-9785-1f3db7a17b53','詩答鄆州分司李待制許中春寵訪','文彥博','宋','宋诗','song-poetry','','[]','念昔多聞友，于今四紀强。',48,'全唐诗/poet.song.16000.json','["念昔多聞友，于今四紀强。", "滯才君絆驥，叨命我循牆。", "二月芳期近，三台淑景長。", "東郊望飛蓋，原隰有輝光。"]'),
('fc087451-bdc0-4bbb-b7ea-3303d2e2b853','謝假新舟','文彥博','宋','宋诗','song-poetry','','[]','使艦新成泛碧瀾，更陪李郭共登仙。',32,'全唐诗/poet.song.16000.json','["使艦新成泛碧瀾，更陪李郭共登仙。", "深慚一水如衣带，不稱君家舊濟川。"]'),
('4a73c197-6b3e-43f7-a808-b937a147cae5','寒食游壓沙寺雨中席上偶作  其一','文彥博','宋','宋诗','song-poetry','','[]','魏公前歲朝真去，寂寞闌干尚有情。',32,'全唐诗/poet.song.16000.json','["魏公前歲朝真去，寂寞闌干尚有情。", "莫道甘棠無異種，至今留得雪香名。"]'),
('6d8f2d73-04ce-405f-9853-499ae90c9d11','寒食游壓沙寺雨中席上偶作  其二','文彥博','宋','宋诗','song-poetry','','[]','沙路無泥地側金，滿園香雪照瓊林。',32,'全唐诗/poet.song.16000.json','["沙路無泥地側金，滿園香雪照瓊林。", "一枝带雨樽前看，還是去年寒食心。"]'),
('247452e9-9c3b-4d7a-8f7b-e5b048f697af','機宜職方見示三月十八日遊船場見許公亭詩追惟文靖公之舊蹟輒成四十言以繼善聲','文彥博','宋','宋诗','song-poetry','','[]','文靖居留日，于茲事勝遊。',48,'全唐诗/poet.song.16000.json','["文靖居留日，于茲事勝遊。", "春塘雖有草，夜壑已無舟。", "召伯昔所憩，魏人今再脩。", "不緣從眾樂，爭忍過西州。"]'),
('ecf0892a-85d5-4dbd-86fe-2fbac781d4a9','某伏覩運使金部運判秘丞運同贊善贈長老元師詩一首舉唱三觀圓成叵測精微但深讚歎輒不自揆願繼善聲素昧宗乘頗慙蕪陋','文彥博','宋','宋诗','song-poetry','','[]','北土久無臨濟嗣，宗風不振至于今。',160,'全唐诗/poet.song.16000.json','["北土久無臨濟嗣，宗風不振至于今。", "方當魏俗依僧寶，須訪堯山禮道林。", "東去懇邀香象駕，西來頓識祖師心。", "紺園變色慈雲庇，蔀屋容光惠日臨。", "理事融通周法界，處時同就聽潮音。", "不分孔老爲三教，欲使瓶盤作一金。", "得度皆欣龜值木，當機盡許芥投針。", "伽佗孤起開晨景，伊字齊脩照溟陰。", "獨愧鈍根非了了，宛同眢井自沉沉。", "願將天鉢清凉水，浄洗昏眸與濁襟。"]'),
('13605725-b1af-42b6-af53-a90a45f484a4','效唐杜牧之對酒絕句','文彥博','宋','宋诗','song-poetry','','[]','醒時忙事醉時閑，隨分傾盃也破顔。',32,'全唐诗/poet.song.16000.json','["醒時忙事醉時閑，隨分傾盃也破顔。", "若使玉樓休釀酒，春風應不到人間。"]'),
('7cc61ed3-d9ce-4940-8998-e95eeb8fdeb0','追和','文彥博','宋','宋诗','song-poetry','','[]','銷磨歲月功名內，檢束身心禮法中。',32,'全唐诗/poet.song.16000.json','["銷磨歲月功名內，檢束身心禮法中。", "除却高陽詩酒伴，人間誰解惜春風。"]'),
('93e7d324-b781-468d-974e-6e79557daae9','問石楠','文彥博','宋','宋诗','song-poetry','','[]','遣使赴西洛，因書問石楠。',48,'全唐诗/poet.song.16000.json','["遣使赴西洛，因書問石楠。", "栽培既已久，圍徑必須添。", "布葉應籠檻，抽梢定出簷。", "丹心與勁節，無憚雪霜嚴。"]'),
('fa1cc4a0-dc6d-46aa-bd70-f1b583d5f1dc','問栝','文彥博','宋','宋诗','song-poetry','','[]','酷愛池南栝，當年手自栽。',48,'全唐诗/poet.song.16000.json','["酷愛池南栝，當年手自栽。", "出藍常有望，生白固難催。", "得地根彌固，凌霜勢不摧。", "楸梧皆不問，爲爾亦凡材。"]'),
('6976ff91-41e8-4a39-a105-99381bcfc1e2','書扇','文彥博','宋','宋诗','song-poetry','','[]','莫結新情斷舊情，斯言明載坐忘篇。',32,'全唐诗/poet.song.16000.json','["莫結新情斷舊情，斯言明載坐忘篇。", "心名口誦爲深戒，祗恐迷情逐景牽。"]'),
('11917a69-755c-4a7d-919b-07e5cf12def3','詩答致政范侍郎致政內翰侍郎榮過郊居少駐軒馭兼留詩詠俯賁丘樊輒次元韵','文彥博','宋','宋诗','song-poetry','','[]','郊居誠敝陋，平地見伊光。',144,'全唐诗/poet.song.16000.json','["郊居誠敝陋，平地見伊光。", "適值華軒過，仍當煦景長。", "幸能留憩止，豈敢謂高凉。", "綠篠緣荒徑，青蘿補壞牆。", "勸耕周厥土，問稼保斯箱。", "處擇仁爲里，歸尋醉作鄉。", "老懷從放達，宴坐絕稀望。", "後躅承相顧，交情孰可方。", "清吟委珠玉，雅奏協宮商。", "似震驚羣蟄，如牷薦大房。", "畏塗逢善友，酷暑得寒漿。", "三復勞鉆仰，詞雄韻更强。"]'),
('b12716fd-4fa6-4425-bb2f-1d8c8e22b89f','運判秘丞黄以某自大水後久無燕集聲酒之樂貽書問念繼以佳章輒依來韻和呈黄莗','文彥博','宋','宋诗','song-poetry','','[]','下水關樓張別宴，別來惟是寄雙鱗。',64,'全唐诗/poet.song.16000.json','["下水關樓張別宴，別來惟是寄雙鱗。", "近緣荒政須藩樂，趣辦輿梁爲濟人。", "歌罷貫珠收畫扇，舞停回雪卷文裀。", "蓬山叔度憐勤瘁，繼走郵筒惠訊頻。"]'),
('67ffdde1-4d43-4044-87ca-d30cc6b2d90b','謝運使陳金部生日惠繡壽仙香爐合依韻和二絕句  其一','文彥博','宋','宋诗','song-poetry','','[]','絺繡爲章古法傳，刺文肖象用功專。',32,'全唐诗/poet.song.16000.json','["絺繡爲章古法傳，刺文肖象用功專。", "他時携去伊川塢，欲並西方皤叟仙。"]'),
('b1468728-2061-4617-bd3f-e8033e2a13db','謝運使陳金部生日惠繡壽仙香爐合依韻和二絕句  其二','文彥博','宋','宋诗','song-poetry','','[]','詩緣大雅成歌傾，器自良工得範模。',32,'全唐诗/poet.song.16000.json','["詩緣大雅成歌傾，器自良工得範模。", "珍重星郎爲壽意，更從蘭省輟薰爐。"]'),
('c00041d4-4539-446d-b1f4-de0821af9eed','龍圖給事使還過魏少留仙斾道舊爲樂因及北史魏收之語作爲雅章輒敢寄聲聊資一噱','文彥博','宋','宋诗','song-poetry','','[]','劇談亹亹倍塵麾，奇表堂堂對伏犀。',64,'全唐诗/poet.song.16000.json','["劇談亹亹倍塵麾，奇表堂堂對伏犀。", "易作詩章頻有得，難爲逋峭豈無稽。", "回驅大旆龍沙北，歸直清廂虎帳西。", "久困土山緣直道，侃然常耻病于畦。"]'),
('2db1cc91-2753-4031-897b-0f8f6c3a7868','路上舟中作','文彥博','宋','宋诗','song-poetry','','[]','詔乘巨艦濟安流，聖念偏於老者優。',32,'全唐诗/poet.song.16000.json','["詔乘巨艦濟安流，聖念偏於老者優。", "堪笑霸臣何瑣瑣，五湖歸去一扁舟。"]'),
('09868b3d-dec1-42d1-a786-7c498f3099dc','行及白馬寺捧留守相公康國韓公手翰且云名園例惜好花以俟同賞因成小詩  其一','文彥博','宋','宋诗','song-poetry','','[]','公書苦惜春光晚，柳絮榆錢撲面飛。',32,'全唐诗/poet.song.16000.json','["公書苦惜春光晚，柳絮榆錢撲面飛。", "惟說名園絕奇品，留花未發待翁歸。"]'),
('11d6b6e4-8e21-4e53-b6b3-3f4da0b985d9','行及白馬寺捧留守相公康國韓公手翰且云名園例惜好花以俟同賞因成小詩  其二','文彥博','宋','宋诗','song-poetry','','[]','去歲曾吟怨別詩，今春醉賞又參差。',32,'全唐诗/poet.song.16000.json','["去歲曾吟怨別詩，今春醉賞又參差。", "洛城雖是歸來晚，趁得姚黄正發時。"]'),
('cfe0dd8f-1bf8-4764-9d3e-954fde9b7598','留守相公寵召同賞花歡飲兼示雅章次韻','文彥博','宋','宋诗','song-poetry','','[]','洛表衡臯穀雨天，歸來景物尚鮮妍。',64,'全唐诗/poet.song.16000.json','["洛表衡臯穀雨天，歸來景物尚鮮妍。", "喜隨使旆尋花圃，急趁賓簪赴綺筵。", "酒撥嫩醅傾綠液，曲調新譜促朱絃。", "玉堂仙客應潜笑，强作風情學少年。"]'),
('964833bd-20e9-4a22-89e7-615f6d033884','留守相公寵示東田讌集詩依韻和呈','文彥博','宋','宋诗','song-poetry','','[]','嘗同徐勉構東田，花竹成陰雨後天。',64,'全唐诗/poet.song.16000.json','["嘗同徐勉構東田，花竹成陰雨後天。", "爲愛憲臺寬白簡，得隨相府賞紅蓮。", "清樽屢釂吟情逸，紅袖頻翻舞態妍。", "歸興直須三鼓盡，月華況是十分圓。"]'),
('2180ffc4-d4b5-4a08-9bcc-1282c371fc07','端午日招諸公於敝園爲角黍之會獨堯夫不至因成小詩奉呈用資一笑','文彥博','宋','宋诗','song-poetry','','[]','藥餌從來多客至，人情大抵見榮觀。',32,'全唐诗/poet.song.16000.json','["藥餌從來多客至，人情大抵見榮觀。", "戴崇貪赴安昌會，必爲東田不足歡。"]'),
('67f539ab-3a23-4e14-9ff5-6c8a1c4688c9','留守相公寵賜雅章召赴東樓真率之會次韻和呈','文彥博','宋','宋诗','song-poetry','','[]','朱樓華閣府園東，蝸陋仍依美庇中。',64,'全唐诗/poet.song.16000.json','["朱樓華閣府園東，蝸陋仍依美庇中。", "儉幕深嚴依綠水，楚臺高迥快雄風。", "四絃清切呈新曲，雙袖蹁躚試小童。", "況是元規興不淺，歸軒爭敢便怱怱。"]'),
('ba8b7199-372a-4873-be30-b751a958ce1f','次韻留守相公同遊龍門','文彥博','宋','宋诗','song-poetry','','[]','鑿開青障啟天門，直瀉伊流洩汝墳。',256,'全唐诗/poet.song.16000.json','["鑿開青障啟天門，直瀉伊流洩汝墳。", "八節驚濤鼉振鼓，千花寶塔鴈翔雲。", "巖隈雨過飛泉漲，谷口風回墮葉紛。", "龕穴隆穹三像列，樓臺華煥兩崖分。", "方陪茜旆來尋勝，不就蒲飱趁茹葷。", "北里笙竽皆擁從，東山羅綺半酣醺。", "升堂共覩皤仙貌，策杖同尋古士墳。", "喜脫貂冠親野老，幸隨態軾附邦君。", "林巒岑寂真堪賞，市井喧譁漸厭聞。", "人度長川猶隱映，香銷古殿尚氛氳。", "周生歸後蘭重佩，荀令行時蕙更薰。", "曉露未晞珠滴淚，秋花爭發錦挑文。", "羣娃散步塵生襪，小舫爭登水濺裙。", "釣叟傍觀皆歎羨，禪師迎謁盡歡欣。", "既無冗局羈閑迹，忍促回軒背夕曛。", "得向石頭溪上飲，從今遂不畏移文。"]'),
('7990c905-04df-415d-9e17-372c23064773','次韻留守相公佳雪應時','文彥博','宋','宋诗','song-poetry','','[]','同雲瑞雪符丘禱，喜氣歡聲動洛師。',64,'全唐诗/poet.song.16000.json','["同雲瑞雪符丘禱，喜氣歡聲動洛師。", "農事迎知春後望，時寒順應臘前期。", "抽毫未見三英賦，貴紙先傳六義詩。", "賢者與民同此樂，下民無復共嗟咨。"]'),
('022a0d5f-0e69-47c4-8a98-dd74880b6cb0','次韻留守相公以羅門新渠並成喜而成詠','文彥博','宋','宋诗','song-poetry','','[]','萬艘潭匯嘉猷里，分洛疏伊盡北馳。',64,'全唐诗/poet.song.16000.json','["萬艘潭匯嘉猷里，分洛疏伊盡北馳。", "遠引駃風通越貨，肇營勝跡在唐時。", "通渠中梗年滋久，美利重興勢亦遲。", "漕口羅門今並復，相君一一授成規。"]'),
('fb320d4b-9a11-4ddf-972d-92fcd8284118','知府學士遠寄雅章曲念衰老謹依高韻和呈粗伸感佩之意','文彥博','宋','宋诗','song-poetry','','[]','幾年洛社盍朋簪，照席瓊枝秀出林。',64,'全唐诗/poet.song.16000.json','["幾年洛社盍朋簪，照席瓊枝秀出林。", "月夕同遊詩筆健，花時共賞酒杯深。", "帝綸中出榮開府，使節西馳愴判襟。", "遠寄佳章念衰朽，知君最有歲寒心。"]'),
('4cc5aaff-8f61-464e-8a6a-675a1f736c1a','和致政張大夫見貽之什','文彥博','宋','宋诗','song-poetry','','[]','自愧無才濟世難，貂蟬掛了謝朝班。',64,'全唐诗/poet.song.16000.json','["自愧無才濟世難，貂蟬掛了謝朝班。", "襟形散逸塵埃外，杖履逍遥水石間。", "君亦早拋華省貴，人皆仰羨白雲閑。", "湖溪聞與郊居近，不用拈錢剩買山。"]'),
('aa3cae39-8c03-4859-8824-a1f8dbe0795f','送順師赴積慶院寂照庵結夏偶成二頌','文彥博','宋','宋诗','song-poetry','','[]','原夏南歸寂照庵，潜移性海入華嚴。',64,'全唐诗/poet.song.16000.json','["原夏南歸寂照庵，潜移性海入華嚴。", "從來野寺門風拙，頻與西堂受小參。", "西堂舊有牧牛圖，七祖真容列座隅。", "雖是宗門粗淺法，從粗入細到無餘。"]'),
('a4ae3e56-bac6-4753-8acd-ca34719e8c42','送彌陀實師訪積慶西堂順老','文彥博','宋','宋诗','song-poetry','','[]','好去三摩地，相逢兩會家。',48,'全唐诗/poet.song.16000.json','["好去三摩地，相逢兩會家。", "禪心究實際，慧眼絕空花。", "聞在東林日，常烹北苑茶。", "願將甘露味，餘潤濟河沙。"]'),
('b4587552-64da-4746-afe1-c5667d81441a','頌寄實師順師','文彥博','宋','宋诗','song-poetry','','[]','傳聞二禪伯，共是一家風。',48,'全唐诗/poet.song.16000.json','["傳聞二禪伯，共是一家風。", "悟處頭頭悟，通時事事通。", "西堂入妙用，寂照舍真空。", "更有青青竹，菩提法眼中。"]'),
('24c93525-3a65-4d44-8ac1-d42cd9748439','余前此二紀保釐西郊與判臺李少師及洛社諸君遊龍門飲伊上有漁者獻鱖魚十數尾因作羹鱠坐客有思鱸之興余後守魏累請休致久而未遂曾爲憶鱖詩寄洛下諸賢今年秋累與諸君飲於東田池上葦間鱠魚炊香稻以佐酒浩然有江湖之趣因作是詩并錄憶鱖詩如左','文彥博','宋','宋诗','song-poetry','','[]','一罇江上思鱸酒，兩首伊濱憶鱖詩。',32,'全唐诗/poet.song.16000.json','["一罇江上思鱸酒，兩首伊濱憶鱖詩。", "今日東田遂前請，香梗綠蟻鱠紅絲。"]'),
('485c7f1f-7ec7-46df-8a7f-abf22d37ccb5','嘉祐中余尹河南與少師李公明龍圖董巨源集賢王伯初同遊龍門漁者得鱖魚數十尾以助杯柈飲興皆歡日月云邁幾二十年感舊念游作憶鱸詩乃思鱸之比也  其一','文彥博','宋','宋诗','song-poetry','','[]','西風一棹思鱸興，抖擻塵纓歸舊廬。',32,'全唐诗/poet.song.16000.json','["西風一棹思鱸興，抖擻塵纓歸舊廬。", "最憶香山石樓下，清伊深處釣寒魚。"]'),
('0616af58-12e2-4153-b313-5a94d00ffb87','嘉祐中余尹河南與少師李公明龍圖董巨源集賢王伯初同遊龍門漁者得鱖魚數十尾以助杯柈飲興皆歡日月云邁幾二十年感舊念游作憶鱸詩乃思鱸之比也  其二','文彥博','宋','宋诗','song-poetry','','[]','追思洛社閑遊伴，屈指于今太半亡。',32,'全唐诗/poet.song.16000.json','["追思洛社閑遊伴，屈指于今太半亡。", "若到龍門更聞笛，定知悲感似山陽。"]'),
('39725460-4f60-4554-a504-b1b1a479566e','堯夫惠簟','文彥博','宋','宋诗','song-poetry','','[]','使指及門傳惠賜，蘄春薤葉水紋寒。',32,'全唐诗/poet.song.16000.json','["使指及門傳惠賜，蘄春薤葉水紋寒。", "相君鼎意多兼濟，欲使炎天老者安。"]'),
('5c19c14e-2321-4bdf-8f51-28b4028c2475','清明日玉津園賜宴即席','文彥博','宋','宋诗','song-poetry','','[]','節應桐華始，筵開禁苑新。',72,'全唐诗/poet.song.16000.json','["節應桐華始，筵開禁苑新。", "推恩緣舊物，如惠及陳人。", "眾樂聞天奏，同寅會柄臣。", "蘭肴享豐潔，桂醑釂芳醇。", "覆育需雲廣，涵濡湛露均。", "桑榆垂晚景，何路報堯仁。"]'),
('89d6b2fa-8560-4907-8818-f9859d5ab7af','西歸日瓊林苑賜宴即席','文彥博','宋','宋诗','song-poetry','','[]','竊祿叨榮四紀餘，退思僥倖亦無如。',64,'全唐诗/poet.song.16000.json','["竊祿叨榮四紀餘，退思僥倖亦無如。", "趨朝再覩新宮省，解紱還歸舊里廬。", "報國丹心明皎皎，戀軒疲足去徐徐。", "羣公盡出都門祖，盛事光於漢二疏。"]'),
('a4ce08c5-c1fe-4bf1-bff5-e60694a471ef','臣得請致政赴闕謝恩脩覲禮成回歸西洛感恩戀聖情激於中謹成五言十二韻詩一首齋沐繕寫上進','文彥博','宋','宋诗','song-poetry','','[]','遭時方筮仕，涉道未逢源。',144,'全唐诗/poet.song.16000.json','["遭時方筮仕，涉道未逢源。", "四紀叨榮祿，三朝忝聖恩。", "華顛固一節，厚載託孤根。", "得謝緣矜老，求全愧達尊。", "懋官非尚德，進秩玷維垣。", "海納推涵育，天容示保存。", "賜筵臨黼座，別旨釂金罇。", "獻替蒭詞拙，詳延玉色溫。", "雲章訓深厚，日接寵便藩。", "穆穆辭宸扆，遲遲去國門。", "戀深惟有涕，感極却無言。", "誓竭忠懃志，書紳戒子孫。"]'),
('d59c6ec0-68e2-44f7-9af1-cee94877bfc3','臣伏蒙聖恩今月二日就瓊林苑特遣中使寵賜御詩仰味聖言恭披宸翰曲推恩禮過獎愚臣感愧之深負荷弗克輒課愚陋恭和聖製','文彥博','宋','宋诗','song-poetry','','[]','老臣爲感聖恩殊，趣治輕裝覲帝居。',64,'全唐诗/poet.song.16000.json','["老臣爲感聖恩殊，趣治輕裝覲帝居。", "錫宴便藩親鳳扆，賜章重疊捧龜書。", "康時有志才終短，報國無功術已疎。", "身在洛陽心魏闕，願傾丹懇上公車。"]'),
('826ea981-11a2-4bd4-b84d-0ca5f32b7e0d','次韻留守相公光和運使度支詩','文彥博','宋','宋诗','song-poetry','','[]','今古雖殊事不殊，古今賢相事相符。',64,'全唐诗/poet.song.16000.json','["今古雖殊事不殊，古今賢相事相符。", "昔惟晉國今康國，皆自西都鎮北都。", "奕葉公台緣世濟，累朝名德與功俱。", "鎔成九鼎歸良冶，玉季金昆動一鑪。"]'),
('d95c5268-1a9c-4832-a479-c652760303dd','送圓明大師歸吳興','文彥博','宋','宋诗','song-poetry','','[]','數曲清琴達舜聰，瑶津仙苑助薰風。',64,'全唐诗/poet.song.16000.json','["數曲清琴達舜聰，瑶津仙苑助薰風。", "朝端多士知音久，霅上故棲歸思濃。", "命服鮮華新爛椹，行裝輕簡舊焦桐。", "鄉人若問大檀越，盡在食經千部中。"]'),
('d167e2f9-0799-4725-83e4-478ef232dda4','某再獲謝事歸老洛師留守相公寵惠台什過形獎予謹達來貺','文彥博','宋','宋诗','song-poetry','','[]','二聖恩深念老臣，許從休退樂伊濱。',64,'全唐诗/poet.song.16000.json','["二聖恩深念老臣，許從休退樂伊濱。", "重觀景物皆塵迹，喜見居留是故人。", "林下放懷無檢束，樽前道舊長精神。", "公難久作東田伴，却作黄樞秉化鈞。"]'),
('1906fc4c-7671-42e9-84b5-808ea0cb292e','留守相公寵示喜雨雅章曲有推借謹抒鄙意上答','文彥博','宋','宋诗','song-poetry','','[]','嵩陰累晝結層陰，一夕霶沱濟物深。',64,'全唐诗/poet.song.16000.json','["嵩陰累晝結層陰，一夕霶沱濟物深。", "稼穡首資千畝籍，焦勞頓釋兩宮心。", "高臺便有凉風至，奧室全無暑氣侵。", "利澤定知均率土，保釐再起作商霖。"]'),
('d7dc83ef-6027-4564-93a9-a260528b6dbc','留守相公','文彥博','宋','宋诗','song-poetry','','[]','荐捧佳章頻歎服，洋洋盈耳類鏘金。',32,'全唐诗/poet.song.16000.json','["荐捧佳章頻歎服，洋洋盈耳類鏘金。", "老昏拙滯無才思，勉强難爲繼大音。"]'),
('b7487668-b17b-42d4-862a-781f444d4c81','余於洛城建春門內循城得池數百畝其池乃唐之藥園因學徐勉作東田引水一支灌其中歲月漸久景物已老喬木脩竹森然四合菱蓮蒲芰于沼于沚結茅構宇務實去華野意山情頗以自適故作是詩','文彥博','宋','宋诗','song-poetry','','[]','引得清伊一派通，三灣相接勢無窮。',64,'全唐诗/poet.song.16000.json','["引得清伊一派通，三灣相接勢無窮。", "便成渺渺江湖趣，更有蕭蕭蘆葦風。", "西洛故年爲勝地，東田今日屬衰翁。", "藥園事迹分明在，盡見雲卿舊記中。"]'),
('dbc296b3-2286-454d-b434-1f21585cdc0f','遊東田八韻','文彥博','宋','宋诗','song-poetry','','[]','文物平津閣，風流太傅山。',96,'全唐诗/poet.song.16000.json','["文物平津閣，風流太傅山。", "勝游松島外，故迹藥園間。", "霜蔀編爲屋，寒荆刈作關。", "窗欞雲漠漠，畦竇水潺潺。", "蘆渚炊煙起，萍漚釣艇還。", "竹經朝雨翠，荷借夕陽殷。", "幽興能招隱，高情自愛閑。", "從來行樂處，携手一開顔。"]'),
('91d0e0d6-dd89-430d-b586-98566e90812a','與之珍朝議秋日東田觀魚擲餅水中魚食者眾  其一','文彥博','宋','宋诗','song-poetry','','[]','觀魚最是樂，莫作羨魚心。',24,'全唐诗/poet.song.16000.json','["觀魚最是樂，莫作羨魚心。", "退而能結網，所得過千金。"]'),
('dc016c28-af7a-42ff-b3c2-ba01dfe56126','與之珍朝議秋日東田觀魚擲餅水中魚食者眾  其二','文彥博','宋','宋诗','song-poetry','','[]','垂釣與施食，乃是兩般心。',24,'全唐诗/poet.song.16000.json','["垂釣與施食，乃是兩般心。", "莫作魯人意，公張取百金。"]'),
('bbce8fb9-c987-45b3-a210-601196e8253e','與之珍朝議秋日東田觀魚擲餅水中魚食者眾  其三','文彥博','宋','宋诗','song-poetry','','[]','鳧鷗兩閑暇，知我無機心。',24,'全唐诗/poet.song.16000.json','["鳧鷗兩閑暇，知我無機心。", "躍淵宜自在，直莫上鈎金。"]'),
('640b495f-d374-41c3-9aa2-f759b72d79a6','前日蒙留守相公玉汝延飲于中和新堂仍別設氈幄欲令羸老暫憩翌日小娃已傳其說輒成小詩','文彥博','宋','宋诗','song-poetry','','[]','新堂仍設舊青氈，欲使劉伶暫醉眠。',32,'全唐诗/poet.song.16000.json','["新堂仍設舊青氈，欲使劉伶暫醉眠。", "何似奇章南澗上，別開一室待焦先。"]'),
('5815cd85-4569-4698-a3af-7352d9b43b8d','留守相公','文彥博','宋','宋诗','song-poetry','','[]','中和堂飲夜厭厭，逸客峨冠欲墮簪。',32,'全唐诗/poet.song.16000.json','["中和堂飲夜厭厭，逸客峨冠欲墮簪。", "深荷相君憐老意，改題氈幄醉眠庵。"]'),
('70b99b96-3a38-4c5e-8f4c-1158d5100807','留守相公玉汝寵示嘉篇有棠陰舊游之句過獎難當輒敢和呈','文彥博','宋','宋诗','song-poetry','','[]','曹酒清醇飲易酣，接䍦倒著不須簪。',32,'全唐诗/poet.song.16000.json','["曹酒清醇飲易酣，接䍦倒著不須簪。", "甘棠舊憩人無詠，何似退歸伊上庵。"]'),
('437036d4-4587-42df-866c-068ef4015348','再和留守相公惠雅章','文彥博','宋','宋诗','song-poetry','','[]','蝸舍歸來多閉戶，貂冠掛了不留簪。',32,'全唐诗/poet.song.16000.json','["蝸舍歸來多閉戶，貂冠掛了不留簪。", "每登丞相潭潭府，常憩西廂大隱庵。"]'),
('c7572654-bba2-4edf-a189-98aea1ebc5f0','再和留守相公繼示雅章','文彥博','宋','宋诗','song-poetry','','[]','兩兩台符世仰瞻，高懷沖淡厭華簪。',32,'全唐诗/poet.song.16000.json','["兩兩台符世仰瞻，高懷沖淡厭華簪。", "經綸器業時方賴，難遂南陽卧草庵。"]'),
('8865b1a2-eff9-42c7-96c1-3a84f23ea84e','送留守相公','文彥博','宋','宋诗','song-poetry','','[]','樽前不制淚汍瀾，大抵人情老別難。',64,'全唐诗/poet.song.16000.json','["樽前不制淚汍瀾，大抵人情老別難。", "東閣賓朋漸分散，西都風景便闌珊。", "惟憑魚鴈通書問，祗對松筠想歲寒。", "公衮還朝副公望，永將天下置之安。"]'),
('b6c97aa8-1d8d-4e8b-b250-a92d92739c4c','次韻致政中散寵惠雅章','文彥博','宋','宋诗','song-poetry','','[]','承枉安車訪孟津，披雲喜睹舊風神。',64,'全唐诗/poet.song.16000.json','["承枉安車訪孟津，披雲喜睹舊風神。", "昔年交會心相契，今日朋從意轉親。", "華髮並蒙難老福，清罇莫作獨醒人。", "高門積慶簪纓盛，世上尊榮孰比倫。"]'),
('d8cdf9d3-87dc-4851-b8de-797a7d023366','致政中散荀龍連惠三篇俯光衰老輒亦依韻和呈再鼓羸師其氣已竭止希一覽而棄之可也','文彥博','宋','宋诗','song-poetry','','[]','郢樓高唱麗陽春，重疊三章妙入神。',64,'全唐诗/poet.song.16000.json','["郢樓高唱麗陽春，重疊三章妙入神。", "席上縱歡殊不倦，樽前道舊轉相親。", "故交共是休閑客，令子今爲輔弼人。", "河內仙居頗優逸，風流雅尚有誰倫。"]'),
('d22a3d0b-657e-4948-bfcf-0dd89a29d6f0','河陽寄留守相公','文彥博','宋','宋诗','song-poetry','','[]','蹔別熒煌座，初爲半月期。',24,'全唐诗/poet.song.16000.json','["蹔別熒煌座，初爲半月期。", "洛城歸意切，不獨爲花時。"]'),
('1317b21f-3a5c-435c-80e6-cd3a02ed1571','次韻留守相公促令歸洛','文彥博','宋','宋诗','song-poetry','','[]','自古錦城雖可樂，猶言不若早還家。',32,'全唐诗/poet.song.16000.json','["自古錦城雖可樂，猶言不若早還家。", "三城爭似洛城樂，只是安仁一縣花。"]'),
('e091f5a8-5e80-4b59-bb50-10bbbb5e17ee','謝留守相公堯夫惠書及詩意愛勤重  其一','文彥博','宋','宋诗','song-poetry','','[]','河陽滿縣花稱好，仰望山川難比肩。',64,'全唐诗/poet.song.16000.json','["河陽滿縣花稱好，仰望山川難比肩。", "留鑰惠詩鏘玉振，采毫灑墨燦星聯。", "樽前畢集鄒枚客，舟上同登李郭仙。", "伊叟依劉心更切，柴車促駕即言還。"]'),
('75fc419e-726b-4b4e-ac87-5c10b8ec8a59','謝留守相公堯夫惠書及詩意愛勤重  其二','文彥博','宋','宋诗','song-poetry','','[]','雨後全無京洛塵，名園勝景好遊人。',32,'全唐诗/poet.song.16000.json','["雨後全無京洛塵，名園勝景好遊人。", "東田兼有春毬探，來就三城報得春。"]'),
('7c30b58d-07ee-4b24-a0ad-2a0bdf1ee429','題河陽太師堂  其一','文彥博','宋','宋诗','song-poetry','','[]','自別三城十九年，重來舊跡總依然。',32,'全唐诗/poet.song.16000.json','["自別三城十九年，重來舊跡總依然。", "鯉庭兼是魚符守，戲綵承顔慰目前。"]'),
('f551c574-e6b5-482d-beea-1d65ab143cef','題河陽太師堂  其二','文彥博','宋','宋诗','song-poetry','','[]','河橋洛宅近相望，三月花時日又長。',32,'全唐诗/poet.song.16000.json','["河橋洛宅近相望，三月花時日又長。", "蹔整安車來子舍，爲吾特啟太師堂。"]'),
('dfd851b9-f112-47b9-9bb4-499921cbe771','游花市示之珍','文彥博','宋','宋诗','song-poetry','','[]','去年春夜游花市，今日重來事宛然。',64,'全唐诗/poet.song.16000.json','["去年春夜游花市，今日重來事宛然。", "列肆千燈爭閃爍，長廊萬蕊鬭鮮妍。", "交馳翠幰新羅綺，迎獻芳樽細管絃。", "人道洛陽爲樂國，醉歸恍若夢鈞天。"]'),
('c2846ad8-c3e5-4256-9739-323c6440cdf8','題伊叟庵  其一','文彥博','宋','宋诗','song-poetry','','[]','斯干室上上方北，巖伴自爲伊叟庵。',32,'全唐诗/poet.song.16000.json','["斯干室上上方北，巖伴自爲伊叟庵。", "每到庵中須熟寢，覺來惟共老僧談。"]'),
('0c242d04-42cf-4ff5-b14d-390a5743a440','題伊叟庵  其二','文彥博','宋','宋诗','song-poetry','','[]','此庵庵北望伊堂，南望伊川極目長。',32,'全唐诗/poet.song.16000.json','["此庵庵北望伊堂，南望伊川極目長。", "更有箕山并潁水，連延直入掛瓢鄉。"]'),
('bf18b88d-1ffb-4bf2-a71d-8a5f8bd27f8d','清明後同秦帥端明會飲於李氏園池偶作','文彥博','宋','宋诗','song-poetry','','[]','洛浦林塘春暮時，暫同游賞莫相違。',32,'全唐诗/poet.song.16000.json','["洛浦林塘春暮時，暫同游賞莫相違。", "風光不要人傳語，一任花前盡醉歸。"]'),
('afb1d989-4804-4b05-bc2c-a5a5d322161f','賢大師以諸巨公畫像見示傳神寫照曲盡其妙兼丐拙詩輒成一首奉呈','文彥博','宋','宋诗','song-poetry','','[]','用志專精妙入神，援毫肖象奪天真。',64,'全唐诗/poet.song.16000.json','["用志專精妙入神，援毫肖象奪天真。", "能將繪素傳奇表，似與公侯結勝因。", "婁德高僧通夙命，王維善畫記前身。", "師緣素習今生悟，曾寫雲臺四七人。"]'),
('3fe43725-f24b-4968-9ea7-9977b77727a9','題郭熙畫樵夫渡水扇','文彥博','宋','宋诗','song-poetry','','[]','淺水深山一徑通，樵夫涉水出林中。',32,'全唐诗/poet.song.16000.json','["淺水深山一徑通，樵夫涉水出林中。", "可憐畫筆多情思，寫在霜紈一扇風。"]'),
('bdd0412c-7e6a-4c0a-b86f-1371dbeec97c','經略大觀文相公寄示東田別後一篇謹次元韻','文彥博','宋','宋诗','song-poetry','','[]','出處交游數十年，故情勤重見矜憐。',64,'全唐诗/poet.song.16000.json','["出處交游數十年，故情勤重見矜憐。", "東田屢涉求羊徑，西洛頻陪李郭仙。", "四路連城歸節制，萬兵開府壯威權。", "雅章垂貺尤奇絕，走筆如風似湧泉。"]'),
('e5cca664-e651-46d7-8bb9-14cdb1e1bb85','次韻留守相公以某赴東莊特賜佳篇','文彥博','宋','宋诗','song-poetry','','[]','東郊瘠土纔千畝，繞舍團椒僅百家。',64,'全唐诗/poet.song.16000.json','["東郊瘠土纔千畝，繞舍團椒僅百家。", "地接玉泉多草木，路經緱嶺少風沙。", "能留過客雖無餌，時對清罇亦有花。", "昔日相君曾降顧，常憂蝸陋不容車。"]'),
('d16e82f6-b2db-4dd6-b8f2-99a196c8df85','駕經略太尉相公移鎮太原  其一','文彥博','宋','宋诗','song-poetry','','[]','國節移全晉，階符應列星。',48,'全唐诗/poet.song.16000.json','["國節移全晉，階符應列星。", "新開大幕府，俗號小朝廷。", "風偃殊鄰服，威加絕塞寧。", "歸來煙閣上，肖象炳丹青。"]'),
('47af524d-e6d5-445d-94b2-d9d8baf495c9','駕經略太尉相公移鎮太原  其二','文彥博','宋','宋诗','song-poetry','','[]','北首并州路，旌幢擁畫輪。',48,'全唐诗/poet.song.16000.json','["北首并州路，旌幢擁畫輪。", "萬兵嚴後從，百吏拜前塵。", "漢相儀刑重，堯風氣俗淳。", "政成期月報，四海望洪鈞。"]'),
('6158c7e1-b0a8-4ba3-bdb6-04d8f3dd785e','駕經略太尉相公移鎮太原  其三','文彥博','宋','宋诗','song-poetry','','[]','將軍號令柳營傳，緩带投壺自適然。',32,'全唐诗/poet.song.16000.json','["將軍號令柳營傳，緩带投壺自適然。", "一片笙歌聞四面，晉公舊事在龍泉。"]'),
('e9c0ecfd-991a-47ec-a9c7-0d4bebe584c8','駕經略太尉相公移鎮太原  其四','文彥博','宋','宋诗','song-poetry','','[]','晉陽襦袴歌來暮，洛宅衣冠動去思。',32,'全唐诗/poet.song.16000.json','["晉陽襦袴歌來暮，洛宅衣冠動去思。", "若到參虛念嵩少，北園南望下樓遲。"]'),
('a1612037-4d11-451d-a6a5-17948463ac62','憶東溪','文彥博','宋','宋诗','song-poetry','','[]','常憶東溪溪上坐，相從惟有野僧來。',32,'全唐诗/poet.song.16000.json','["常憶東溪溪上坐，相從惟有野僧來。", "可憐鷗鳥知人意，料得無機總不猜。"]'),
('f93f81d0-bd12-4ac9-8f84-ee0c9a435f8c','某以端居多暇懷洛成詩伏蒙運使兵部俯垂屬和拙詩伸謝','文彥博','宋','宋诗','song-poetry','','[]','倦翼念歸林，幽懷動越吟。',48,'全唐诗/poet.song.16000.json','["倦翼念歸林，幽懷動越吟。", "更回谿叟信，深契野雲心。", "巴里傳高唱，英韶繼善音。", "便須傳洛社，紙價重千金。"]');
